export default function AdminAssistantPage() {
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const [conversationId, setConversationId] = useState<string | null>(null);
  const [threads, setThreads] = useState<ConversationThread[]>([]);
  const [showSidebar, setShowSidebar] = useState(true);
  const [loadingHistory, setLoadingHistory] = useState(false);
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [fileType, setFileType] = useState<string>("document");
  const [isUploading, setIsUploading] = useState(false);
  const bottomRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Schedule dialog state
  const [scheduleOpen, setScheduleOpen] = useState(false);
  const [scheduleTitle, setScheduleTitle] = useState("");
  const [scheduleDate, setScheduleDate] = useState<Date | undefined>();
  const [scheduleTime, setScheduleTime] = useState("10:00");
  const [scheduleParticipants, setScheduleParticipants] = useState("");
  const [scheduleLink, setScheduleLink] = useState("");
  const [scheduleDatePickerOpen, setScheduleDatePickerOpen] = useState(false);
  const [scheduleSaving, setScheduleSaving] = useState(false);
  const [scheduleCreatedId, setScheduleCreatedId] = useState<string | null>(null);

  const stripTags = (text: string) =>
    text
      .replace(/\[ADMIN_MEMO:[\s\S]*?\]/g, "")
      .replace(/\[ED:[\s\S]*?\]/g, "")
      .replace(/\[DEBUG:[\s\S]*?\]/g, "")
      .trim();

  const sanitize = (text: string) =>
    text.replace(/[\u0000-\u001F\u007F]/g, "").slice(0, 4000);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  // Load past conversation threads on mount
  const loadThreads = useCallback(async () => {
    try {
      const res = await client.get("/api/v1/admin/ai/conversations");
      const data = res.data.data ?? res.data;
      setThreads(Array.isArray(data) ? data : []);
    } catch {
      // threads unavailable — non-critical
    }
  }, []);

  useEffect(() => {
    loadThreads();
  }, [loadThreads]);

  // Load a specific conversation thread
  const loadConversation = async (id: string) => {
    setLoadingHistory(true);
    setConversationId(id);
    setMessages([]);
    try {
      const res = await client.get(`/api/v1/admin/ai/conversations/${id}`);
      const data: Array<{ role: string; content: string; created_at: string }> =
        res.data.data ?? res.data;
      const loaded: Message[] = data.map((m, i) => ({
        id: `loaded-${i}`,
        role: m.role as "user" | "assistant",
        content: m.content,
        timestamp: new Date(m.created_at),
      }));
      setMessages(loaded);
    } catch {
      toast({ title: "Error", description: "Failed to load conversation.", variant: "destructive" });
    } finally {
      setLoadingHistory(false);
    }
  };

  const startNewConversation = () => {
    setConversationId(null);
    setMessages([]);
  };

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    // Validate file size (10MB limit)
    if (file.size > 10 * 1024 * 1024) {
      toast({
        title: "File too large",
        description: "Please select a file smaller than 10MB.",
        variant: "destructive",
      });
      return;
    }

    setSelectedFile(file);

    // Auto-detect file type based on extension
    const extension = file.name.split('.').pop()?.toLowerCase();
    if (extension) {
      if (['pdf', 'doc', 'docx', 'txt', 'csv'].includes(extension)) {
        setFileType('document');
      } else if (['jpg', 'jpeg', 'png'].includes(extension)) {
        setFileType('image');
      } else if (['mp3', 'wav'].includes(extension)) {
        setFileType('audio');
      }
    }
  };

  const removeSelectedFile = () => {
    setSelectedFile(null);
    if (fileInputRef.current) {
      fileInputRef.current.value = '';
    }
  };

  const sendMessage = async () => {
    const text = sanitize(input.trim());
    if (!text || isLoading) return;

    const userMsg: Message = {
      id: `user-${Date.now()}`,
      role: "user",
      content: text + (selectedFile ? `\n\n[File: ${selectedFile.name}]` : ""),
      timestamp: new Date(),
    };

    setMessages((prev) => [...prev, userMsg]);
    setInput("");
    setIsLoading(true);
    setIsUploading(true);

    try {
      // Create FormData for file upload
      const formData = new FormData();
      formData.append('message', text);
      formData.append('conversation_id', conversationId || '');

      if (selectedFile) {
        formData.append('file', selectedFile);
        formData.append('file_type', fileType);
      }

      const response = await client.post("/api/v1/admin/ai/chat", formData, {
        headers: {
          'Content-Type': 'multipart/form-data',
        },
      });

      const payload = response.data.data ?? response.data;
      const replyText: string =
        payload?.reply ??
        payload?.message ??
        "I'm unable to generate a response right now. Please try again.";

      const newConvId: string = payload?.conversation_id ?? conversationId;
      if (newConvId && newConvId !== conversationId) {
        setConversationId(newConvId);
        // Refresh thread list after first message of a new conversation
        loadThreads();
      }

      const assistantMsg: Message = {
        id: `assistant-${Date.now()}`,
        role: "assistant",
        content: stripTags(replyText),
        timestamp: new Date(),
      };

      setMessages((prev) => [...prev, assistantMsg]);

      // Scheduling intent — offer to create calendar event
      if (detectSchedulingIntent(text)) {
        const seed = parseSchedulingHints(text);
        const seedMsg: Message = {
          id: `schedule-${Date.now()}`,
          role: "assistant",
          content: "",
          timestamp: new Date(),
          scheduleSeed: seed,
        };
        setMessages((prev) => [...prev, seedMsg]);
      }

      // Clear selected file after successful upload
      setSelectedFile(null);
      if (fileInputRef.current) {
        fileInputRef.current.value = '';
      }
    } catch {
      toast({
        title: "Error",
        description: "Failed to get a response. Please try again.",
        variant: "destructive",
      });
      setMessages((prev) => prev.filter((m) => m.id !== userMsg.id));
    } finally {
      setIsLoading(false);
      setIsUploading(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      sendMessage();
    }
  };

  const formatTime = (d: Date) =>
    d.toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" });

  const formatRelative = (iso: string) => {
    const d = new Date(iso);
    const now = Date.now();
    const diff = now - d.getTime();
    if (diff < 60_000) return "Just now";
    if (diff < 3_600_000) return `${Math.floor(diff / 60_000)}m ago`;
    if (diff < 86_400_000) return `${Math.floor(diff / 3_600_000)}h ago`;
    return d.toLocaleDateString([], { month: "short", day: "numeric" });
  };

  const handleScheduleCreate = async () => {
    if (!scheduleTitle || !scheduleDate) {
      toast({ title: "Missing fields", description: "Please fill in a title and date.", variant: "destructive" });
      return;
    }
    setScheduleSaving(true);
    try {
      const [h, m] = scheduleTime.split(":").map(Number);
      const start = new Date(scheduleDate);
      start.setHours(h, m, 0, 0);
      const end = new Date(start);
      end.setMinutes(end.getMinutes() + 60);

      const created = await calendarService.addEvent({
        title: scheduleTitle,
        startTime: start.toISOString(),
        endTime: end.toISOString(),
        date: format(scheduleDate, "yyyy-MM-dd"),
        participants: scheduleParticipants
          ? scheduleParticipants.split(",").map((s) => s.trim()).filter(Boolean)
          : [],
        meetingLink: scheduleLink || undefined,
      });
      setScheduleCreatedId(created?.id ?? "ok");
      toast({ title: "Event created", description: `"${scheduleTitle}" added to your calendar.` });
    } catch {
      toast({ title: "Error", description: "Could not create the event. Please try again.", variant: "destructive" });
    } finally {
      setScheduleSaving(false);
    }
  };

  const isNewChat = messages.length === 0 && !conversationId;

  return (
    <div className="flex h-[calc(100vh-4rem)] overflow-hidden">
      {/* ── Sidebar: conversation threads ── */}
      <aside
        className={`${
          showSidebar ? "w-64" : "w-0"
        } transition-all duration-200 overflow-hidden border-r bg-muted/30 flex flex-col shrink-0`}
      >
        <div className="p-3 border-b flex items-center justify-between">
          <span className="text-sm font-semibold">Conversations</span>
          <Button size="sm" variant="ghost" onClick={startNewConversation} className="h-7 px-2 gap-1 text-xs">
            <Plus className="h-3.5 w-3.5" />
            New
          </Button>
        </div>
        <ScrollArea className="flex-1">
          {threads.length === 0 ? (
            <p className="text-xs text-muted-foreground p-4 text-center">No conversations yet</p>
          ) : (
            threads.map((t) => (
              <button
                key={t.conversation_id}
                onClick={() => loadConversation(t.conversation_id)}
                className={`w-full text-left px-3 py-2.5 border-b hover:bg-muted/60 transition-colors ${
                  conversationId === t.conversation_id ? "bg-muted" : ""
                }`}
              >
                <p className="text-xs font-medium truncate leading-tight">{t.preview || "Conversation"}</p>
                <p className="text-[10px] text-muted-foreground mt-0.5">{formatRelative(t.last_at)}</p>
              </button>
            ))
          )}
        </ScrollArea>
      </aside>

      {/* ── Main area ── */}
      <div className="flex flex-col flex-1 min-w-0">
        {/* Header */}
        <div className="flex items-center gap-3 px-4 py-3 border-b bg-background">
          <Button
            variant="ghost"
            size="icon"
            className="h-8 w-8 shrink-0"
            onClick={() => setShowSidebar((v) => !v)}
          >
            {showSidebar ? <ChevronLeft className="h-4 w-4" /> : <MessageSquare className="h-4 w-4" />}
          </Button>
          <div className="flex-1 min-w-0">
            <h2 className="text-base font-bold flex items-center gap-2 leading-tight">
              <Sparkles className="h-5 w-5 text-primary shrink-0" />
              Onwynd Admin Intelligence
            </h2>
            <p className="text-xs text-muted-foreground truncate">Strategic AI co-pilot · memory-enabled</p>
          </div>
          {conversationId && (
            <Badge variant="outline" className="text-[10px] hidden sm:flex shrink-0">
              Thread active
            </Badge>
          )}
          {messages.length > 0 && (
            <Button variant="ghost" size="sm" onClick={startNewConversation} className="h-8 px-2 gap-1 text-xs shrink-0">
              <Plus className="h-3.5 w-3.5" />
              New chat
            </Button>
          )}
        </div>

        {/* Chat area */}
        <Card className="flex-1 flex flex-col overflow-hidden rounded-none border-0 border-b">
          <ScrollArea className="flex-1 px-4 py-4">
            {/* Welcome / capabilities screen */}
            {isNewChat && (
              <div className="max-w-xl mx-auto pt-8 space-y-6">
                <div className="text-center space-y-2">
                  <div className="inline-flex items-center justify-center w-14 h-14 rounded-2xl bg-primary/10 mb-2">
                    <Sparkles className="h-7 w-7 text-primary" />
                  </div>
                  <h3 className="text-xl font-bold">Onwynd Admin Intelligence</h3>
                  <p className="text-sm text-muted-foreground">
                    Your AI co-pilot for platform strategy, analytics, operations, and growth.
                    Start typing to begin — I&apos;ll remember your preferences and insights over time.
                  </p>
                </div>
                <div className="grid gap-3">
                  {CAPABILITIES.map(({ icon: Icon, label, desc }) => (
                    <div key={label} className="flex items-start gap-3 p-3 rounded-xl bg-muted/40 border">
                      <div className="mt-0.5 p-1.5 rounded-lg bg-primary/10 shrink-0">
                        <Icon className="h-4 w-4 text-primary" />
                      </div>
                      <div>
                        <p className="text-sm font-semibold leading-tight">{label}</p>
                        <p className="text-xs text-muted-foreground mt-0.5">{desc}</p>
                      </div>
                    </div>
                  ))}
                </div>
                <div className="grid grid-cols-2 gap-2">
                  {[
                    "Show me today's platform performance",
                    "What are our top 3 growth opportunities?",
                    "Analyse revenue trends this month",
                    "Draft a therapist onboarding policy",
                  ].map((prompt) => (
                    <button
                      key={prompt}
                      onClick={() => { setInput(prompt); }}
                      className="text-left text-xs p-2.5 rounded-lg border bg-background hover:bg-muted/50 transition-colors leading-snug"
                    >
                      {prompt}
                    </button>
                  ))}
                </div>
              </div>
            )}

            {/* Loading history */}
            {loadingHistory && (
              <div className="flex justify-center py-8">
                <Loader2 className="h-5 w-5 animate-spin text-muted-foreground" />
              </div>
            )}

            {/* Messages */}
            <div className="space-y-4 pb-2 max-w-3xl mx-auto">
              {messages.map((msg) => (
                <div
                  key={msg.id}
                  className={`flex gap-3 ${msg.role === "user" ? "flex-row-reverse" : "flex-row"}`}
                >
                  <Avatar className="h-8 w-8 shrink-0 mt-0.5">
                    <AvatarFallback
                      className={
                        msg.role === "assistant"
                          ? "bg-primary text-primary-foreground text-xs"
                          : "bg-muted text-muted-foreground text-xs"
                      }
                    >
                      {msg.role === "assistant" ? (
                        <Sparkles className="h-4 w-4" />
                      ) : (
                        <User className="h-4 w-4" />
                      )}
                    </AvatarFallback>
                  </Avatar>
                  {msg.scheduleSeed ? (
                    /* ── Schedule suggestion card ── */
                    <div className="max-w-[80%] rounded-xl border bg-background shadow-sm overflow-hidden">
                      <div className="flex items-center gap-2 px-4 py-2.5 bg-primary/8 border-b">
                        <CalendarPlus className="h-4 w-4 text-primary shrink-0" />
                        <span className="text-sm font-semibold">Schedule an event</span>
                      </div>
                      <div className="px-4 py-3 space-y-1 text-sm">
                        <p><span className="text-muted-foreground text-xs">Title</span><br /><strong>{msg.scheduleSeed.title}</strong></p>
                        {msg.scheduleSeed.date && (
                          <p><span className="text-muted-foreground text-xs">Date</span><br />{format(msg.scheduleSeed.date, "EEE, MMM d yyyy")}</p>
                        )}
                        <p><span className="text-muted-foreground text-xs">Time</span><br />{msg.scheduleSeed.time}</p>
                      </div>
                      <div className="px-4 pb-3">
                        <Button
                          size="sm"
                          className="w-full gap-2"
                          onClick={() => {
                            setScheduleTitle(msg.scheduleSeed!.title);
                            setScheduleDate(msg.scheduleSeed!.date);
                            setScheduleTime(msg.scheduleSeed!.time);
                            setScheduleParticipants("");
                            setScheduleLink("");
                            setScheduleCreatedId(null);
                            setScheduleOpen(true);
                          }}
                        >
                          <CalendarPlus className="h-4 w-4" />
                          Open in calendar
                        </Button>
                      </div>
                      <p className="text-[10px] text-muted-foreground px-4 pb-2">{formatTime(msg.timestamp)}</p>
                    </div>
                  ) : (
                  <div
                    className={`max-w-[80%] rounded-xl px-4 py-2.5 text-sm leading-relaxed ${
                      msg.role === "user"
                        ? "bg-primary text-primary-foreground"
                        : "bg-muted text-foreground"
                    }`}
                    style={{ overflowWrap: "anywhere" }}
                  >
                    {msg.role === "assistant" && msg.content ? (
                      <div
                        dangerouslySetInnerHTML={{ __html: renderMarkdown(msg.content) }}
                        className="text-sm leading-relaxed [&_strong]:font-semibold [&_ul]:list-disc [&_ol]:list-decimal [&_li]:ml-4 [&_pre]:my-2"
                      />
                    ) : (
                      <p className="whitespace-pre-wrap text-sm">{msg.content}</p>
                    )}
                    <p
                      className={`text-[10px] mt-1.5 ${
                        msg.role === "user"
                          ? "text-primary-foreground/60"
                          : "text-muted-foreground"
                      }`}
                    >
                      {formatTime(msg.timestamp)}
                    </p>
                  </div>
                  )}
                </div>
              ))}

              {isLoading && (
                <div className="flex gap-3">
                  <Avatar className="h-8 w-8 shrink-0 mt-0.5">
                    <AvatarFallback className="bg-primary text-primary-foreground text-xs">
                      <Sparkles className="h-4 w-4" />
                    </AvatarFallback>
                  </Avatar>
                  <div className="bg-muted rounded-xl px-4 py-3 flex items-center gap-2">
                    <Loader2 className="h-4 w-4 animate-spin text-muted-foreground" />
                    <span className="text-xs text-muted-foreground">Thinking…</span>
                  </div>
                </div>
              )}

              <div ref={bottomRef} />
            </div>
          </ScrollArea>

          <CardContent className="border-t pt-3 pb-3">
            {/* File upload preview */}
            {selectedFile && (
              <div className="max-w-3xl mx-auto mb-3">
                <div className="flex items-center gap-3 p-3 bg-muted/50 rounded-lg border">
                  <div className="flex items-center gap-2 flex-1">
                    {fileType === 'document' && <FileText className="h-4 w-4 text-blue-500" />}
                    {fileType === 'image' && <Image className="h-4 w-4 text-green-500" />}
                    {fileType === 'audio' && <Music className="h-4 w-4 text-purple-500" />}
                    <div className="flex-1 min-w-0">
                      <p className="text-sm font-medium truncate">{selectedFile.name}</p>
                      <p className="text-xs text-muted-foreground">
                        {fileType} • {(selectedFile.size / 1024 / 1024).toFixed(1)} MB
                      </p>
                    </div>
                  </div>
                  <Button
                    variant="ghost"
                    size="icon"
                    className="h-8 w-8 shrink-0"
                    onClick={removeSelectedFile}
                    title="Remove file"
                  >
                    <X className="h-4 w-4" />
                  </Button>
                </div>
              </div>
            )}

            <div className="flex items-end gap-2 max-w-3xl mx-auto">
              {messages.length > 0 && (
                <Button
                  variant="ghost"
                  size="icon"
                  className="h-10 w-10 shrink-0 text-muted-foreground hover:text-destructive"
                  onClick={startNewConversation}
                  title="Clear and start new chat"
                >
                  <Trash2 className="h-4 w-4" />
                </Button>
              )}

              {/* File upload button */}
              <Button
                variant="ghost"
                size="icon"
                className="h-10 w-10 shrink-0"
                onClick={() => fileInputRef.current?.click()}
                disabled={isLoading || isUploading}
                title="Attach file"
              >
                {isUploading ? (
                  <Loader2 className="h-4 w-4 animate-spin" />
                ) : (
                  <Paperclip className="h-4 w-4" />
                )}
              </Button>

              {/* Hidden file input */}
              <input
                ref={fileInputRef}
                type="file"
                className="hidden"
                accept=".pdf,.doc,.docx,.txt,.csv,.jpg,.jpeg,.png,.mp3,.wav"
                onChange={handleFileSelect}
              />

              <Textarea
                placeholder={selectedFile ? "File attached. Ask anything about the platform…" : "Ask anything about the platform… (Enter to send, Shift+Enter for new line)"}
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={handleKeyDown}
                rows={2}
                className="resize-none flex-1"
                disabled={isLoading || loadingHistory}
                maxLength={4000}
              />
              <Button
                onClick={sendMessage}
                disabled={!input.trim() || isLoading || loadingHistory}
                size="icon"
                className="h-10 w-10 shrink-0"
              >
                {isLoading ? (
                  <Loader2 className="h-4 w-4 animate-spin" />
                ) : (
                  <Send className="h-4 w-4" />
                )}
              </Button>
            </div>
          </CardContent>
        </Card>
      </div>

      {/* ── Schedule event dialog ── */}
      <Dialog open={scheduleOpen} onOpenChange={setScheduleOpen}>
        <DialogContent className="sm:max-w-md">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <CalendarPlus className="h-5 w-5 text-primary" />
              Create Calendar Event
            </DialogTitle>
          </DialogHeader>

          <div className="space-y-4 py-2">
            {scheduleCreatedId ? (
              <div className="flex flex-col items-center gap-3 py-6 text-center">
                <CheckCircle2 className="h-10 w-10 text-green-500" />
                <p className="font-semibold">Event created!</p>
                <p className="text-sm text-muted-foreground">&ldquo;{scheduleTitle}&rdquo; has been added to your calendar.</p>
                <Button variant="outline" onClick={() => setScheduleOpen(false)}>Close</Button>
              </div>
            ) : (
              <>
                <div className="space-y-1.5">
                  <Label htmlFor="sch-title">Title</Label>
                  <Input
                    id="sch-title"
                    value={scheduleTitle}
                    onChange={(e) => setScheduleTitle(e.target.value)}
                    placeholder="Meeting title"
                  />
                </div>

                <div className="grid grid-cols-2 gap-3">
                  <div className="space-y-1.5">
                    <Label>Date</Label>
                    <Popover open={scheduleDatePickerOpen} onOpenChange={setScheduleDatePickerOpen}>
                      <PopoverTrigger asChild>
                        <Button
                          variant="outline"
                          className={cn("w-full justify-start text-left font-normal", !scheduleDate && "text-muted-foreground")}
                        >
                          <CalendarIcon className="mr-2 h-4 w-4" />
                          {scheduleDate ? format(scheduleDate, "MMM d, yyyy") : "Pick a date"}
                        </Button>
                      </PopoverTrigger>
                      <PopoverContent className="w-auto p-0" align="start">
                        <Calendar
                          mode="single"
                          selected={scheduleDate}
                          onSelect={(d) => { setScheduleDate(d); setScheduleDatePickerOpen(false); }}
                          initialFocus
                        />
                      </PopoverContent>
                    </Popover>
                  </div>

                  <div className="space-y-1.5">
                    <Label>Time</Label>
                    <Select value={scheduleTime} onValueChange={(v) => setScheduleTime(v ?? scheduleTime)}>
                      <SelectTrigger>
                        <SelectValue />
                      </SelectTrigger>
                      <SelectContent>
                        {TIME_SLOTS_AI.map((t) => (
                          <SelectItem key={t} value={t}>{t}</SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  </div>
                </div>

                <div className="space-y-1.5">
                  <Label htmlFor="sch-participants">Participants <span className="text-muted-foreground text-xs">(comma-separated emails)</span></Label>
                  <Input
                    id="sch-participants"
                    value={scheduleParticipants}
                    onChange={(e) => setScheduleParticipants(e.target.value)}
                    placeholder="alice@company.com, bob@company.com"
                  />
                </div>

                <div className="space-y-1.5">
                  <Label htmlFor="sch-link">Meeting link <span className="text-muted-foreground text-xs">(optional)</span></Label>
                  <Input
                    id="sch-link"
                    value={scheduleLink}
                    onChange={(e) => setScheduleLink(e.target.value)}
                    placeholder="https://meet.google.com/…"
                  />
                </div>
              </>
            )}
          </div>

          {!scheduleCreatedId && (
            <DialogFooter className="gap-2">
              <Button variant="outline" onClick={() => setScheduleOpen(false)} disabled={scheduleSaving}>Cancel</Button>
              <Button onClick={handleScheduleCreate} disabled={scheduleSaving || !scheduleTitle || !scheduleDate} className="gap-2">
                {scheduleSaving ? <Loader2 className="h-4 w-4 animate-spin" /> : <CalendarPlus className="h-4 w-4" />}
                Create event
              </Button>
            </DialogFooter>
          )}
        </DialogContent>
      </Dialog>
    </div>
  );
}

"use client";

import { useEffect, useState, useCallback } from "react";
import { adminService } from "@/lib/api/admin";
import { Card, CardContent } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import { toast } from "@/components/ui/use-toast";
import { Loader2, RefreshCw, Search, Wifi, WifiOff, ShieldOff, LogOut, Smartphone, Monitor, Tablet } from "lucide-react";
import { format, formatDistanceToNow } from "date-fns";

interface AuthSession {
  id: number;
  token_name: string;
  created_at: string;
  last_used_at: string | null;
  user_id: number;
  user_name: string;
  user_email: string;
  last_seen_at: string | null;
  is_online: boolean;
  // New fields (optional — backend may not yet return them)
  device_type?: string;
  browser?: string;
  os?: string;
  ip_address?: string;
  location?: string;
  auth_provider?: string;
}

function SessionDeviceIcon({ deviceType }: { deviceType?: string }) {
  if (deviceType === "mobile") return <Smartphone className="h-4 w-4 shrink-0 text-muted-foreground" />;
  if (deviceType === "tablet") return <Tablet className="h-4 w-4 shrink-0 text-muted-foreground" />;
  return <Monitor className="h-4 w-4 shrink-0 text-muted-foreground" />;
}

export default function AuthSessionsPage() {
  const [sessions, setSessions] = useState<AuthSession[]>([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState("");
  const [revoking, setRevoking] = useState<number | null>(null);
  const [confirmRevoke, setConfirmRevoke] = useState<{ type: "token" | "user"; id: number; label: string } | null>(null);

  const fetchSessions = useCallback(async () => {
    setLoading(true);
    try {
      const data = await adminService.getAuthSessions() as any;
      const list = Array.isArray(data) ? data : Array.isArray(data?.data) ? data.data : [];
      setSessions(list);
    } catch {
      toast({ title: "Error", description: "Failed to load active sessions.", variant: "destructive" });
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchSessions();
    const iv = setInterval(fetchSessions, 30_000);
    return () => clearInterval(iv);
  }, [fetchSessions]);

  const handleRevokeToken = async (id: number) => {
    setRevoking(id);
    try {
      await adminService.revokeAuthSession(id);
      setSessions((prev) => prev.filter((s) => s.id !== id));
      toast({ title: "Session revoked", description: "The token has been invalidated." });
    } catch {
      toast({ title: "Error", description: "Failed to revoke session.", variant: "destructive" });
    } finally {
      setRevoking(null);
      setConfirmRevoke(null);
    }
  };

  const handleRevokeUser = async (userId: number) => {
    setRevoking(userId);
    try {
      await adminService.revokeUserSessions(userId);
      setSessions((prev) => prev.filter((s) => s.user_id !== userId));
      toast({ title: "All sessions revoked", description: "All tokens for this user have been invalidated." });
    } catch {
      toast({ title: "Error", description: "Failed to revoke user sessions.", variant: "destructive" });
    } finally {
      setRevoking(null);
      setConfirmRevoke(null);
    }
  };

  const filtered = sessions.filter((s) => {
    const q = search.toLowerCase();
    return (
      s.user_name?.toLowerCase().includes(q) ||
      s.user_email?.toLowerCase().includes(q) ||
      s.token_name?.toLowerCase().includes(q)
    );
  });

  const onlineCount = sessions.filter((s) => s.is_online).length;

  return (
    <div className="flex-1 space-y-6 p-4 md:p-8 pt-6">
      {/* Header */}
      <div className="flex items-center justify-between flex-wrap gap-3">
        <div>
          <h2 className="text-3xl font-bold tracking-tight">Active Sessions</h2>
          <p className="text-muted-foreground">
            All active Sanctum tokens issued in the last 24 hours.
            {!loading && (
              <span className="ml-2 text-xs">
                {onlineCount} online · {sessions.length} total sessions
              </span>
            )}
          </p>
        </div>
        <div className="flex items-center gap-2">
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-gray-400" />
            <Input
              placeholder="Search by user or token…"
              className="pl-9 w-64"
              value={search}
              onChange={(e) => setSearch(e.target.value)}
            />
          </div>
          <Button variant="outline" size="sm" onClick={fetchSessions} disabled={loading}>
            {loading ? <Loader2 className="h-4 w-4 animate-spin" /> : <RefreshCw className="h-4 w-4" />}
          </Button>
        </div>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
        {[
          { label: "Total Sessions", value: sessions.length },
          { label: "Online Now", value: onlineCount },
          { label: "Offline", value: sessions.length - onlineCount },
          { label: "Unique Users", value: new Set(sessions.map((s) => s.user_id)).size },
        ].map(({ label, value }) => (
          <Card key={label}>
            <CardContent className="pt-4 pb-4 text-center">
              <p className="text-2xl font-bold">{value}</p>
              <p className="text-xs text-muted-foreground mt-1">{label}</p>
            </CardContent>
          </Card>
        ))}
      </div>

      {/* Table */}
      <Card>
        <CardContent className="p-0">
          <div className="overflow-x-auto">
            <Table>
              <TableHeader>
                <TableRow className="bg-gray-50">
                  <TableHead className="px-4 py-3 text-xs uppercase">User</TableHead>
                  <TableHead className="px-4 py-3 text-xs uppercase">Status</TableHead>
                  <TableHead className="px-4 py-3 text-xs uppercase">Token</TableHead>
                  <TableHead className="px-4 py-3 text-xs uppercase">Device</TableHead>
                  <TableHead className="px-4 py-3 text-xs uppercase">Location</TableHead>
                  <TableHead className="px-4 py-3 text-xs uppercase">Created</TableHead>
                  <TableHead className="px-4 py-3 text-xs uppercase">Last Active</TableHead>
                  <TableHead className="px-4 py-3 text-xs uppercase text-right">Actions</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {loading ? (
                  Array.from({ length: 5 }).map((_, i) => (
                    <TableRow key={i}>
                      {Array.from({ length: 8 }).map((_, j) => (
                        <TableCell key={j} className="px-4 py-3">
                          <div className="h-4 w-24 bg-gray-200 rounded animate-pulse" />
                        </TableCell>
                      ))}
                    </TableRow>
                  ))
                ) : filtered.length === 0 ? (
                  <TableRow>
                    <TableCell colSpan={8} className="text-center py-16 text-muted-foreground">
                      <Wifi className="w-10 h-10 mx-auto mb-3 opacity-30" />
                      {search ? "No sessions match your search." : "No active sessions found."}
                    </TableCell>
                  </TableRow>
                ) : (
                  filtered.map((s) => (
                    <TableRow key={s.id}>
                      <TableCell className="px-4 py-3">
                        <p className="text-sm font-medium">{s.user_name}</p>
                        <p className="text-xs text-muted-foreground">{s.user_email}</p>
                      </TableCell>
                      <TableCell className="px-4 py-3">
                        {s.is_online ? (
                          <Badge className="bg-green-100 text-green-700 hover:bg-green-100 gap-1">
                            <Wifi className="h-3 w-3" /> Online
                          </Badge>
                        ) : (
                          <Badge className="bg-gray-100 text-gray-600 hover:bg-gray-100 gap-1">
                            <WifiOff className="h-3 w-3" /> Offline
                          </Badge>
                        )}
                      </TableCell>
                      <TableCell className="px-4 py-3 text-sm text-muted-foreground font-mono">
                        {s.token_name}
                      </TableCell>
                      <TableCell className="px-4 py-3">
                        <div className="flex items-center gap-2">
                          <SessionDeviceIcon deviceType={s.device_type} />
                          <span className="text-sm text-muted-foreground">
                            {s.browser && s.os
                              ? `${s.browser} on ${s.os}`
                              : s.browser || s.os || s.token_name}
                          </span>
                        </div>
                      </TableCell>
                      <TableCell className="px-4 py-3">
                        {s.location || s.ip_address ? (
                          <div>
                            <p className="text-sm text-muted-foreground">{s.location || "—"}</p>
                            {s.ip_address && (
                              <p className="text-xs font-mono text-muted-foreground">{s.ip_address}</p>
                            )}
                          </div>
                        ) : (
                          <span className="text-sm text-muted-foreground">—</span>
                        )}
                      </TableCell>
                      <TableCell className="px-4 py-3 text-sm text-muted-foreground">
                        {format(new Date(s.created_at), "MMM d, HH:mm")}
                      </TableCell>
                      <TableCell className="px-4 py-3 text-sm text-muted-foreground">
                        {s.last_seen_at
                          ? formatDistanceToNow(new Date(s.last_seen_at), { addSuffix: true })
                          : s.last_used_at
                          ? formatDistanceToNow(new Date(s.last_used_at), { addSuffix: true })
                          : "—"}
                      </TableCell>
                      <TableCell className="px-4 py-3 text-right">
                        <div className="flex items-center justify-end gap-2">
                          <Button
                            variant="ghost"
                            size="sm"
                            className="text-red-600 hover:text-red-700 hover:bg-red-50 gap-1"
                            disabled={revoking === s.id}
                            onClick={() =>
                              setConfirmRevoke({ type: "token", id: s.id, label: `token for ${s.user_name}` })
                            }
                          >
                            {revoking === s.id ? (
                              <Loader2 className="h-3 w-3 animate-spin" />
                            ) : (
                              <ShieldOff className="h-3 w-3" />
                            )}
                            Revoke
                          </Button>
                          <Button
                            variant="ghost"
                            size="sm"
                            className="text-orange-600 hover:text-orange-700 hover:bg-orange-50 gap-1"
                            disabled={revoking === s.user_id}
                            onClick={() =>
                              setConfirmRevoke({
                                type: "user",
                                id: s.user_id,
                                label: `all sessions for ${s.user_name}`,
                              })
                            }
                          >
                            {revoking === s.user_id ? (
                              <Loader2 className="h-3 w-3 animate-spin" />
                            ) : (
                              <LogOut className="h-3 w-3" />
                            )}
                            Log Out All
                          </Button>
                        </div>
                      </TableCell>
                    </TableRow>
                  ))
                )}
              </TableBody>
            </Table>
          </div>
        </CardContent>
      </Card>

      {/* Confirm dialog */}
      <AlertDialog open={!!confirmRevoke} onOpenChange={() => setConfirmRevoke(null)}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Revoke {confirmRevoke?.type === "user" ? "all sessions" : "session"}?</AlertDialogTitle>
            <AlertDialogDescription>
              This will immediately invalidate the {confirmRevoke?.label}. The user will be signed out.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancel</AlertDialogCancel>
            <AlertDialogAction
              className="bg-red-600 hover:bg-red-700"
              onClick={() => {
                if (!confirmRevoke) return;
                if (confirmRevoke.type === "token") handleRevokeToken(confirmRevoke.id);
                else handleRevokeUser(confirmRevoke.id);
              }}
            >
              Revoke
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
}

"use client";

import { useState, useEffect, useCallback } from "react";
import { useRouter, useParams } from "next/navigation";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { toast } from "@/components/ui/use-toast";
import { adminService } from "@/lib/api/admin";
import client from "@/lib/api/client";

interface Center {
  id?: string;
  name: string;
  address: string;
  phone: string;
  email: string;
  description?: string;
  manager_id?: string;
  status: "active" | "inactive";
}

interface Manager {
  id: string;
  name: string;
  email: string;
}

export default function AdminCenterFormPage() {
  const router = useRouter();
  const params = useParams();
  const centerId = params?.id as string;
  const isEdit = !!centerId;

  const [formData, setFormData] = useState<Center>({
    name: "",
    address: "",
    phone: "",
    email: "",
    description: "",
    manager_id: "",
    status: "active",
  });
  const [managers, setManagers] = useState<Manager[]>([]);
  const [loading, setLoading] = useState(false);
  const [submitting, setSubmitting] = useState(false);

  const fetchCenter = useCallback(async () => {
    try {
      setLoading(true);
      const data = await adminService.getCenter(centerId) as any;
      setFormData(data);
    } catch {
      toast({
        title: "Error",
        description: "Failed to fetch center details",
        variant: "destructive",
      });
    } finally {
      setLoading(false);
    }
  }, [centerId]);

  const fetchManagers = async () => {
    try {
      const res = await client.get("/api/v1/admin/centers/available-managers");
      setManagers(res.data?.data ?? res.data ?? []);
    } catch {
      // Non-critical — manager picker simply shows empty
    }
  };

  useEffect(() => {
    fetchManagers();
    if (isEdit) {
      fetchCenter();
    }
  }, [isEdit, centerId, fetchCenter]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setSubmitting(true);

    try {
      if (isEdit) {
        await adminService.updateCenter(centerId, formData as unknown as Record<string, unknown>);
      } else {
        await adminService.createCenter(formData as unknown as Record<string, unknown>);
      }

      toast({
        title: "Success",
        description: `Center ${isEdit ? "updated" : "created"} successfully`,
      });

      router.push("/admin/centers");
    } catch (error) {
      toast({
        title: "Error",
        description: error instanceof Error ? error.message : `Failed to ${isEdit ? "update" : "create"} center`,
        variant: "destructive",
      });
    } finally {
      setSubmitting(false);
    }
  };

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  if (loading && isEdit) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary"></div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h1 className="text-3xl font-bold">
          {isEdit ? "Edit Center" : "Create Center"}
        </h1>
        <Button variant="outline" onClick={() => router.push("/admin/centers")}>
          Back to Centers
        </Button>
      </div>

      <Card>
        <CardHeader>
          <CardTitle>Center Information</CardTitle>
        </CardHeader>
        <CardContent>
          <form onSubmit={handleSubmit} className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-2">
                <Label htmlFor="name">Center Name *</Label>
                <Input
                  id="name"
                  name="name"
                  value={formData.name}
                  onChange={handleInputChange}
                  required
                  placeholder="Enter center name"
                />
              </div>

              <div className="space-y-2">
                <Label htmlFor="email">Email *</Label>
                <Input
                  id="email"
                  name="email"
                  type="email"
                  value={formData.email}
                  onChange={handleInputChange}
                  required
                  placeholder="center@example.com"
                />
              </div>

              <div className="space-y-2">
                <Label htmlFor="phone">Phone *</Label>
                <Input
                  id="phone"
                  name="phone"
                  value={formData.phone}
                  onChange={handleInputChange}
                  required
                  placeholder="(555) 123-4567"
                />
              </div>

              <div className="space-y-2">
                <Label htmlFor="status">Status</Label>
                <Select
                  value={formData.status}
                  onValueChange={(value) => setFormData(prev => ({ ...prev, status: (value ?? "active") as "active" | "inactive" }))}
                >
                  <SelectTrigger>
                    <SelectValue placeholder="Select status" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="active">Active</SelectItem>
                    <SelectItem value="inactive">Inactive</SelectItem>
                  </SelectContent>
                </Select>
              </div>
            </div>

            <div className="space-y-2">
              <Label htmlFor="address">Address *</Label>
              <Textarea
                id="address"
                name="address"
                value={formData.address}
                onChange={handleInputChange}
                required
                placeholder="Enter full address"
                rows={3}
              />
            </div>

            <div className="space-y-2">
              <Label htmlFor="description">Description</Label>
              <Textarea
                id="description"
                name="description"
                value={formData.description}
                onChange={handleInputChange}
                placeholder="Enter center description (optional)"
                rows={3}
              />
            </div>

            {managers.length > 0 && (
              <div className="space-y-2">
                <Label htmlFor="manager_id">Manager</Label>
                <Select
                  value={formData.manager_id || ""}
                  onValueChange={(value) => setFormData(prev => ({ ...prev, manager_id: value || undefined }))}
                >
                  <SelectTrigger>
                    <SelectValue placeholder="Select a manager (optional)" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="">No Manager</SelectItem>
                    {managers.map((manager) => (
                      <SelectItem key={manager.id} value={manager.id}>
                        {manager.name} ({manager.email})
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
            )}

            <div className="flex justify-end space-x-4">
              <Button type="button" variant="outline" onClick={() => router.push("/admin/centers")}>
                Cancel
              </Button>
              <Button type="submit" disabled={submitting}>
                {submitting ? "Saving..." : (isEdit ? "Update Center" : "Create Center")}
              </Button>
            </div>
          </form>
        </CardContent>
      </Card>
    </div>
  );
}

"use client";

"use client";

import { useState, useEffect } from "react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Switch } from "@/components/ui/switch";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Dialog, DialogContent, DialogFooter, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { toast } from "@/components/ui/use-toast";
import { Save, RefreshCw, Plus, Loader2, Trash2 } from "lucide-react";
import { adminService } from "@/lib/api/admin";

interface LandingPageContent {
  id?: number;
  section: string;
  key: string;
  value: string;
  metadata?: Record<string, unknown>;
  is_active: boolean;
}

const SECTIONS = {
  header: "Header",
  hero: "Hero Section",
  features: "Features",
  testimonials: "Testimonials",
  pricing: "Pricing",
  footer: "Footer",
  seo: "SEO & Meta",
};

export default function LandingPageContentPage() {
  const [content, setContent] = useState<Record<string, LandingPageContent[]>>({});
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);

  useEffect(() => {
    fetchContent();
  }, []);

  const fetchContent = async () => {
    try {
      setLoading(true);
      const data = await adminService.getLandingPageContent();
      setContent(typeof data === 'object' && data !== null ? data as Record<string, LandingPageContent[]> : {});
    } catch (error) {
      toast({
        title: "Error",
        description: "Failed to fetch landing page content",
        variant: "destructive",
      });
    } finally {
      setLoading(false);
    }
  };

  const handleSaveSection = async (section: string, items: LandingPageContent[]) => {
    try {
      setSaving(true);
      const contentToUpdate = items.map(item => ({
        id: item.id,
        value: item.value,
        metadata: item.metadata,
        is_active: item.is_active,
      }));

      await adminService.bulkUpdateLandingPageContent(contentToUpdate);
      toast({
        title: "Success",
        description: `${SECTIONS[section as keyof typeof SECTIONS]} section updated successfully`,
      });
    } catch (error) {
      toast({
        title: "Error",
        description: "Failed to update section",
        variant: "destructive",
      });
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async (id: number) => {
    if (!confirm("Are you sure you want to delete this content item?")) return;

    try {
      await adminService.deleteLandingPageContent(id);
      toast({
        title: "Success",
        description: "Content item deleted successfully",
      });
      fetchContent();
    } catch (error) {
      toast({
        title: "Error",
        description: "Failed to delete content item",
        variant: "destructive",
      });
    }
  };

  const ContentEditor = ({ section, items }: { section: string; items: LandingPageContent[] }) => {
    const [localItems, setLocalItems] = useState(items);
    const [showAdd, setShowAdd] = useState(false);
    const [newKey, setNewKey] = useState("");
    const [newValue, setNewValue] = useState("");
    const [addSaving, setAddSaving] = useState(false);

    useEffect(() => { setLocalItems(items); }, [items]);

    const handleAddNew = async () => {
      if (!newKey.trim()) return;
      setAddSaving(true);
      try {
        await adminService.createLandingPageContent({ section, key: newKey.trim(), value: newValue, is_active: true });
        toast({ title: "Success", description: "Content item created successfully." });
        setShowAdd(false);
        setNewKey("");
        setNewValue("");
        fetchContent();
      } catch {
        toast({ title: "Error", description: "Failed to create content item.", variant: "destructive" });
      } finally {
        setAddSaving(false);
      }
    };

    return (
      <div className="space-y-4">
        <div className="flex justify-between items-center">
          <h3 className="text-lg font-semibold">{SECTIONS[section as keyof typeof SECTIONS]}</h3>
          <div className="flex gap-2">
            <Button
              variant="outline"
              size="sm"
              onClick={() => setShowAdd(true)}
            >
              <Plus className="h-4 w-4 mr-1" />
              Add Item
            </Button>
            <Button
              size="sm"
              onClick={() => handleSaveSection(section, localItems)}
              disabled={saving}
            >
              <Save className="h-4 w-4 mr-1" />
              Save Changes
            </Button>
          </div>
        </div>

        <div className="space-y-4">
          {localItems.map((item, index) => (
            <Card key={item.id || index}>
              <CardHeader className="pb-3">
                <div className="flex justify-between items-center">
                  <CardTitle className="text-base">{item.key}</CardTitle>
                  <div className="flex items-center gap-2">
                    <Switch
                      checked={item.is_active}
                      onCheckedChange={(checked) => {
                        const newItems = [...localItems];
                        newItems[index].is_active = checked;
                        setLocalItems(newItems);
                      }}
                    />
                    <span className="text-sm text-muted-foreground">
                      {item.is_active ? 'Active' : 'Inactive'}
                    </span>
                  </div>
                </div>
              </CardHeader>
              <CardContent className="space-y-4">
                <div>
                  <Label htmlFor={`value-${item.id}`}>Content Value</Label>
                  <Textarea
                    id={`value-${item.id}`}
                    value={item.value || ''}
                    onChange={(e) => {
                      const newItems = [...localItems];
                      newItems[index].value = e.target.value;
                      setLocalItems(newItems);
                    }}
                    rows={3}
                    placeholder="Enter content value..."
                  />
                </div>

                {item.metadata && (
                  <div>
                    <Label htmlFor={`metadata-${item.id}`}>Metadata (JSON)</Label>
                    <Textarea
                      id={`metadata-${item.id}`}
                      value={JSON.stringify(item.metadata, null, 2)}
                      onChange={(e) => {
                        try {
                          const metadata = JSON.parse(e.target.value);
                          const newItems = [...localItems];
                          newItems[index].metadata = metadata;
                          setLocalItems(newItems);
                        } catch (error) {
                          // Invalid JSON, don't update
                        }
                      }}
                      rows={2}
                      placeholder='{"key": "value"}'
                    />
                  </div>
                )}

                <div className="flex justify-end">
                  <Button
                    variant="destructive"
                    size="sm"
                    onClick={() => item.id && handleDelete(item.id)}
                  >
                    <Trash2 className="h-4 w-4 mr-1" />
                    Delete
                  </Button>
                </div>
              </CardContent>
            </Card>
          ))}
        </div>

        <Dialog open={showAdd} onOpenChange={(open) => !open && setShowAdd(false)}>
          <DialogContent className="sm:max-w-md">
            <DialogHeader>
              <DialogTitle>Add Content Item — {SECTIONS[section as keyof typeof SECTIONS]}</DialogTitle>
            </DialogHeader>
            <div className="space-y-3 py-2">
              <div className="space-y-1">
                <Label>Key <span className="text-muted-foreground text-xs">(e.g. headline, subtext)</span></Label>
                <Input value={newKey} onChange={(e) => setNewKey(e.target.value)} placeholder="content_key" />
              </div>
              <div className="space-y-1">
                <Label>Value</Label>
                <Textarea rows={3} value={newValue} onChange={(e) => setNewValue(e.target.value)} placeholder="Content value…" />
              </div>
            </div>
            <DialogFooter>
              <Button variant="outline" onClick={() => setShowAdd(false)}>Cancel</Button>
              <Button onClick={handleAddNew} disabled={addSaving || !newKey.trim()}>
                {addSaving ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <Plus className="mr-2 h-4 w-4" />}
                Create
              </Button>
            </DialogFooter>
          </DialogContent>
        </Dialog>
      </div>
    );
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <RefreshCw className="h-8 w-8 animate-spin" />
      </div>
    );
  }

  return (
    <div className="container mx-auto py-6 space-y-6">
      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-3xl font-bold tracking-tight">Landing Page Content</h1>
          <p className="text-muted-foreground">
            Manage the content displayed on your landing page
          </p>
        </div>
        <Button variant="outline" onClick={fetchContent}>
          <RefreshCw className="h-4 w-4 mr-2" />
          Refresh
        </Button>
      </div>

      <Tabs defaultValue="hero" className="space-y-4">
        <TabsList className="grid grid-cols-4 lg:grid-cols-9">
          {Object.entries(SECTIONS).map(([key]) => (
            <TabsTrigger key={key} value={key} className="text-xs">
              {SECTIONS[key as keyof typeof SECTIONS]}
            </TabsTrigger>
          ))}
        </TabsList>

        {Object.entries(SECTIONS).map(([key]) => (
          <TabsContent key={key} value={key}>
            <ContentEditor
              section={key}
              items={content[key] || []}
            />
          </TabsContent>
        ))}
      </Tabs>
    </div>
  );
}

