export default function CorporatesPage() {
  const [corporates, setCorporates] = useState<Corporate[]>([]);
  const [pagination, setPagination] = useState<Pagination>({
    total: 0,
    last_page: 1,
    current_page: 1,
    per_page: 20,
  });
  const [isLoading, setIsLoading] = useState(true);
  const [isError, setIsError] = useState(false);
  const [search, setSearch] = useState("");

  // Extend pilot modal
  const [extendTarget, setExtendTarget] = useState<Corporate | null>(null);
  const [extendDays, setExtendDays] = useState("14");
  const [extendLoading, setExtendLoading] = useState(false);

  // Send email modal
  const [emailTarget, setEmailTarget] = useState<Corporate | null>(null);
  const [emailType, setEmailType] = useState<string>("");
  const [emailLoading, setEmailLoading] = useState(false);

  // Convert to paid modal
  const [convertTarget, setConvertTarget] = useState<Corporate | null>(null);
  const [planTier, setPlanTier] = useState<string>("");
  const [billingCycle, setBillingCycle] = useState<string>("");
  const [convertLoading, setConvertLoading] = useState(false);

  const fetchCorporates = useCallback(async (page = 1) => {
    setIsLoading(true);
    setIsError(false);
    try {
      const params: Record<string, unknown> = { page, per_page: pagination.per_page };
      if (search) params.search = search;
      const data = await adminService.getCorporates(params) as any;
      const list: Corporate[] = Array.isArray(data)
        ? data
        : Array.isArray(data?.data)
        ? data.data
        : [];
      setCorporates(list);
      if (data?.meta || data?.last_page) {
        const meta = data.meta ?? data;
        setPagination({
          total:        meta.total ?? list.length,
          last_page:    meta.last_page ?? 1,
          current_page: meta.current_page ?? page,
          per_page:     meta.per_page ?? 20,
        });
      }
    } catch {
      setIsError(true);
      toast({ title: "Error", description: "Failed to load corporate accounts.", variant: "destructive" });
    } finally {
      setIsLoading(false);
    }
  }, [search, pagination.per_page]);

  useEffect(() => {
    fetchCorporates();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // --- Extend pilot ---
  const handleExtendSubmit = async () => {
    if (!extendTarget) return;
    const days = parseInt(extendDays, 10);
    if (isNaN(days) || days < 1 || days > 90) {
      toast({ title: "Invalid input", description: "Days must be between 1 and 90.", variant: "destructive" });
      return;
    }
    setExtendLoading(true);
    try {
      await adminService.extendCorporatePilot(extendTarget.id, days);
      toast({ title: "Pilot extended", description: `Added ${days} days for ${extendTarget.name}.` });
      setExtendTarget(null);
      fetchCorporates(pagination.current_page);
    } catch {
      toast({ title: "Error", description: "Failed to extend pilot.", variant: "destructive" });
    } finally {
      setExtendLoading(false);
    }
  };

  // --- Send email ---
  const handleEmailSubmit = async () => {
    if (!emailTarget || !emailType) {
      toast({ title: "Invalid input", description: "Please select an email type.", variant: "destructive" });
      return;
    }
    setEmailLoading(true);
    try {
      await adminService.sendCorporateLifecycleEmail(emailTarget.id, emailType);
      toast({ title: "Email queued", description: `"${emailType}" email queued for ${emailTarget.name}.` });
      setEmailTarget(null);
      setEmailType("");
      fetchCorporates(pagination.current_page);
    } catch {
      toast({ title: "Error", description: "Failed to send email.", variant: "destructive" });
    } finally {
      setEmailLoading(false);
    }
  };

  // --- Convert to paid ---
  const handleConvertSubmit = async () => {
    if (!convertTarget || !planTier || !billingCycle) {
      toast({ title: "Invalid input", description: "Please select plan tier and billing cycle.", variant: "destructive" });
      return;
    }
    setConvertLoading(true);
    try {
      await adminService.convertCorporateToPaid(convertTarget.id, planTier, billingCycle);
      toast({ title: "Converted", description: `${convertTarget.name} converted to paid plan.` });
      setConvertTarget(null);
      setPlanTier("");
      setBillingCycle("");
      fetchCorporates(pagination.current_page);
    } catch {
      toast({ title: "Error", description: "Failed to convert account.", variant: "destructive" });
    } finally {
      setConvertLoading(false);
    }
  };

  return (
    <div className="flex-1 space-y-5 p-4 md:p-8 pt-6">
      {/* Header */}
      <div className="flex items-center justify-between flex-wrap gap-3">
        <div>
          <h2 className="text-3xl font-bold tracking-tight">Corporate Accounts</h2>
          <p className="text-muted-foreground">
            Manage corporate pilot accounts — extend contracts, send lifecycle emails, convert to paid.
          </p>
        </div>
        <Button
          variant="outline"
          size="sm"
          onClick={() => fetchCorporates(pagination.current_page)}
          disabled={isLoading}
        >
          <RefreshCw className={`mr-2 h-4 w-4 ${isLoading ? "animate-spin" : ""}`} />
          Refresh
        </Button>
      </div>

      {/* Summary cards */}
      <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
        {[
          { label: "Total",   value: pagination.total },
          { label: "Active",  value: corporates.filter((c) => c.pilot_status === "active").length },
          { label: "Expired", value: corporates.filter((c) => c.pilot_status === "expired").length },
          { label: "Paid",    value: corporates.filter((c) => c.pilot_status === "paid").length },
        ].map(({ label, value }) => (
          <Card key={label}>
            <CardContent className="pt-4 flex items-center justify-between">
              <div>
                <p className="text-xs text-muted-foreground">{label}</p>
                <p className="text-2xl font-bold">{value}</p>
              </div>
              <Building2 className="h-7 w-7 opacity-20 text-foreground" />
            </CardContent>
          </Card>
        ))}
      </div>

      {/* Search */}
      <div className="flex items-center gap-3">
        <div className="relative flex-1 min-w-[180px] max-w-sm">
          <Search className="absolute left-2.5 top-2.5 h-4 w-4 text-muted-foreground" />
          <Input
            className="pl-8"
            placeholder="Search company name or email…"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            onKeyDown={(e) => e.key === "Enter" && fetchCorporates()}
          />
        </div>
        <Button variant="secondary" size="sm" onClick={() => fetchCorporates()}>
          Search
        </Button>
      </div>

      {isError && (
        <Alert variant="destructive">
          <AlertTitle>Failed to load corporate accounts</AlertTitle>
          <AlertDescription>Please try refreshing the page.</AlertDescription>
        </Alert>
      )}

      {/* Table */}
      <Card>
        <CardHeader>
          <CardTitle>Corporate Accounts ({pagination.total})</CardTitle>
        </CardHeader>
        <CardContent className="p-0">
          {isLoading ? (
            <div className="flex h-48 items-center justify-center">
              <Loader2 className="h-8 w-8 animate-spin text-primary" />
            </div>
          ) : corporates.length === 0 ? (
            <div className="flex flex-col items-center justify-center py-16 text-muted-foreground">
              <Building2 className="w-12 h-12 opacity-20 mb-4" />
              <p>No corporate accounts found.</p>
            </div>
          ) : (
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>Company</TableHead>
                  <TableHead>Tier</TableHead>
                  <TableHead>Status</TableHead>
                  <TableHead>Pilot End</TableHead>
                  <TableHead>Seats</TableHead>
                  <TableHead>Emails Sent</TableHead>
                  <TableHead className="text-right">Actions</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {corporates.map((corp) => (
                  <TableRow key={corp.id}>
                    {/* Company */}
                    <TableCell>
                      <div className="flex items-center gap-3">
                        <div className="w-8 h-8 rounded-lg flex items-center justify-center shrink-0 bg-indigo-50">
                          <Building2 className="w-4 h-4 text-indigo-600" />
                        </div>
                        <div>
                          <p className="font-medium">{corp.name}</p>
                          {corp.contact_email && (
                            <p className="text-xs text-muted-foreground">{corp.contact_email}</p>
                          )}
                        </div>
                      </div>
                    </TableCell>

                    {/* Tier */}
                    <TableCell>
                      {corp.plan_tier ? (
                        <Badge variant="outline" className="capitalize text-xs">
                          {corp.plan_tier}
                        </Badge>
                      ) : (
                        <span className="text-muted-foreground text-xs">—</span>
                      )}
                    </TableCell>

                    {/* Status */}
                    <TableCell>
                      <Badge
                        className={
                          PILOT_STATUS_STYLES[corp.pilot_status] ??
                          "bg-gray-100 text-gray-600"
                        }
                      >
                        {corp.pilot_status}
                      </Badge>
                    </TableCell>

                    {/* Pilot End */}
                    <TableCell className="text-sm">
                      {corp.contract?.end_date ? (
                        <span>{new Date(corp.contract.end_date).toLocaleDateString()}</span>
                      ) : (
                        <span className="text-muted-foreground">—</span>
                      )}
                    </TableCell>

                    {/* Seats */}
                    <TableCell className="text-sm">
                      {corp.contracted_seats != null ? (
                        <span>
                          {corp.current_seats ?? 0} / {corp.contracted_seats}
                        </span>
                      ) : (
                        <span className="text-muted-foreground">—</span>
                      )}
                    </TableCell>

                    {/* Emails Sent */}
                    <TableCell>
                      <div className="flex flex-wrap gap-1">
                        <EmailSentBadge
                          label="Activated"
                          sentAt={corp.contract?.activated_notified_at ?? null}
                        />
                        <EmailSentBadge
                          label="Midpoint"
                          sentAt={corp.contract?.midpoint_notified_at ?? null}
                        />
                        <EmailSentBadge
                          label="Pre-Renewal"
                          sentAt={corp.contract?.pre_renewal_notified_at ?? null}
                        />
                        <EmailSentBadge
                          label="Expired"
                          sentAt={corp.contract?.expiry_notified_at ?? null}
                        />
                      </div>
                    </TableCell>

                    {/* Actions */}
                    <TableCell className="text-right">
                      <div className="flex justify-end gap-2 flex-wrap">
                        <Button
                          size="sm"
                          variant="outline"
                          className="gap-1.5"
                          onClick={() => {
                            setExtendTarget(corp);
                            setExtendDays("14");
                          }}
                        >
                          <CalendarPlus className="h-3.5 w-3.5" />
                          Extend
                        </Button>
                        <Button
                          size="sm"
                          variant="outline"
                          className="gap-1.5"
                          onClick={() => {
                            setEmailTarget(corp);
                            setEmailType("");
                          }}
                        >
                          <Mail className="h-3.5 w-3.5" />
                          Send Email
                        </Button>
                        {corp.pilot_status !== "paid" && (
                          <Button
                            size="sm"
                            variant="outline"
                            className="gap-1.5"
                            onClick={() => {
                              setConvertTarget(corp);
                              setPlanTier("");
                              setBillingCycle("");
                            }}
                          >
                            <ArrowRightLeft className="h-3.5 w-3.5" />
                            Convert
                          </Button>
                        )}
                      </div>
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          )}
        </CardContent>
      </Card>

      {/* Pagination */}
      {pagination.last_page > 1 && (
        <div className="flex items-center justify-center gap-2">
          <Button
            variant="outline"
            size="sm"
            disabled={pagination.current_page <= 1}
            onClick={() => fetchCorporates(pagination.current_page - 1)}
          >
            Previous
          </Button>
          <span className="text-sm text-muted-foreground">
            Page {pagination.current_page} of {pagination.last_page}
          </span>
          <Button
            variant="outline"
            size="sm"
            disabled={pagination.current_page >= pagination.last_page}
            onClick={() => fetchCorporates(pagination.current_page + 1)}
          >
            Next
          </Button>
        </div>
      )}

      {/* Extend Pilot Modal */}
      <Dialog open={!!extendTarget} onOpenChange={(open) => { if (!open) setExtendTarget(null); }}>
        <DialogContent className="max-w-sm">
          <DialogHeader>
            <DialogTitle>Extend Pilot — {extendTarget?.name}</DialogTitle>
          </DialogHeader>
          <div className="space-y-4 py-2">
            <div className="space-y-1.5">
              <Label htmlFor="extend-days">Number of days (1–90)</Label>
              <Input
                id="extend-days"
                type="number"
                min={1}
                max={90}
                value={extendDays}
                onChange={(e) => setExtendDays(e.target.value)}
              />
            </div>
            {extendTarget?.contract?.end_date && (
              <p className="text-sm text-muted-foreground">
                Current end date:{" "}
                <strong>{new Date(extendTarget.contract.end_date).toLocaleDateString()}</strong>
              </p>
            )}
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setExtendTarget(null)} disabled={extendLoading}>
              Cancel
            </Button>
            <Button onClick={handleExtendSubmit} disabled={extendLoading}>
              {extendLoading && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              Extend Pilot
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Send Email Modal */}
      <Dialog open={!!emailTarget} onOpenChange={(open) => { if (!open) { setEmailTarget(null); setEmailType(""); } }}>
        <DialogContent className="max-w-sm">
          <DialogHeader>
            <DialogTitle>Send Lifecycle Email — {emailTarget?.name}</DialogTitle>
          </DialogHeader>
          <div className="space-y-4 py-2">
            <div className="space-y-1.5">
              <Label htmlFor="email-type-select">Email type</Label>
              <Select value={emailType} onValueChange={(v) => v !== null && setEmailType(v)}>
                <SelectTrigger id="email-type-select">
                  <SelectValue placeholder="Select email type…" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="activated">Activated</SelectItem>
                  <SelectItem value="midpoint">Midpoint</SelectItem>
                  <SelectItem value="pre_renewal">Pre-Renewal</SelectItem>
                  <SelectItem value="expired">Expired</SelectItem>
                </SelectContent>
              </Select>
            </div>
            {emailTarget?.contact_email && (
              <p className="text-sm text-muted-foreground">
                Will be sent to: <strong>{emailTarget.contact_email}</strong>
              </p>
            )}
          </div>
          <DialogFooter>
            <Button
              variant="outline"
              onClick={() => { setEmailTarget(null); setEmailType(""); }}
              disabled={emailLoading}
            >
              Cancel
            </Button>
            <Button onClick={handleEmailSubmit} disabled={emailLoading || !emailType}>
              {emailLoading && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              Send Email
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Convert to Paid Modal */}
      <Dialog
        open={!!convertTarget}
        onOpenChange={(open) => {
          if (!open) {
            setConvertTarget(null);
            setPlanTier("");
            setBillingCycle("");
          }
        }}
      >
        <DialogContent className="max-w-sm">
          <DialogHeader>
            <DialogTitle>Convert to Paid — {convertTarget?.name}</DialogTitle>
          </DialogHeader>
          <div className="space-y-4 py-2">
            <div className="space-y-1.5">
              <Label htmlFor="plan-tier-select">Plan tier</Label>
              <Select value={planTier} onValueChange={(v) => v !== null && setPlanTier(v)}>
                <SelectTrigger id="plan-tier-select">
                  <SelectValue placeholder="Select plan…" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="starter">Starter (5–20 seats)</SelectItem>
                  <SelectItem value="growth">Growth (21–100 seats)</SelectItem>
                  <SelectItem value="enterprise">Enterprise (100+ seats)</SelectItem>
                </SelectContent>
              </Select>
            </div>
            <div className="space-y-1.5">
              <Label htmlFor="billing-cycle-select">Billing cycle</Label>
              <Select value={billingCycle} onValueChange={(v) => v !== null && setBillingCycle(v)}>
                <SelectTrigger id="billing-cycle-select">
                  <SelectValue placeholder="Select cycle…" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="monthly">Monthly</SelectItem>
                  <SelectItem value="annual">Annual</SelectItem>
                </SelectContent>
              </Select>
            </div>
          </div>
          <DialogFooter>
            <Button
              variant="outline"
              onClick={() => {
                setConvertTarget(null);
                setPlanTier("");
                setBillingCycle("");
              }}
              disabled={convertLoading}
            >
              Cancel
            </Button>
            <Button
              onClick={handleConvertSubmit}
              disabled={convertLoading || !planTier || !billingCycle}
            >
              {convertLoading && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              Convert to Paid
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

"use client";

/**
 * Demo Leads — /admin/demo-leads
 *
 * Shows all demo requests from the public site.
 * Admin / CEO / COO can schedule the call and assign it to a sales rep.
 * On save the backend creates a CalendarEvent in the sales rep's calendar
 * and sends them a bell notification.
 */

import { useEffect, useState, useCallback } from "react";
import { format } from "date-fns";
import client from "@/lib/api/client";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Badge } from "@/components/ui/badge";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { Calendar } from "@/components/ui/calendar";
import {
  Select, SelectContent, SelectItem,
  SelectTrigger, SelectValue,
} from "@/components/ui/select";
import {
  Dialog, DialogContent, DialogFooter,
  DialogHeader, DialogTitle,
} from "@/components/ui/dialog";
import {
  Loader2, CalendarPlus, CalendarIcon, CheckCircle2,
  Building2, User, Mail, Phone, RefreshCw, Users,
} from "lucide-react";
import { toast } from "@/components/ui/use-toast";
import { cn } from "@/lib/utils";

// ── Types ────────────────────────────────────────────────────────────────────

interface DemoLead {
  id: number;
  first_name: string;
  last_name: string;
  email: string;
  phone?: string;
  company: string;
  status: string;
  source: string;
  assigned_to?: number;
  notes?: string;
  created_at: string;
  assigned_user?: { id: number; first_name: string; last_name: string; email: string };
}

interface SalesUser {
  id: number;
  first_name: string;
  last_name: string;
  email: string;
  role: string;
}

// ── Time slots ───────────────────────────────────────────────────────────────

const TIME_SLOTS = [
  "07:00","08:00","08:30","09:00","09:30","10:00","10:30","11:00","11:30",
  "12:00","13:00","13:30","14:00","14:30","15:00","15:30","16:00","16:30",
  "17:00","17:30","18:00",
];

const STATUS_COLORS: Record<string, string> = {
  new:       "bg-blue-100 text-blue-800",
  contacted: "bg-amber-100 text-amber-800",
  qualified: "bg-green-100 text-green-800",
  lost:      "bg-gray-100 text-gray-600",
};

// ── Page ─────────────────────────────────────────────────────────────────────

export default function DemoLeadsPage() {
  const [leads, setLeads] = useState<DemoLead[]>([]);
  const [salesUsers, setSalesUsers] = useState<SalesUser[]>([]);
  const [loading, setLoading] = useState(true);

  // Assign dialog
  const [selected, setSelected] = useState<DemoLead | null>(null);
  const [dialogOpen, setDialogOpen] = useState(false);
  const [assignUserId, setAssignUserId] = useState("");
  const [scheduleDate, setScheduleDate] = useState<Date | undefined>();
  const [scheduleTime, setScheduleTime] = useState("10:00");
  const [meetingLink, setMeetingLink] = useState("");
  const [notes, setNotes] = useState("");
  const [datePickerOpen, setDatePickerOpen] = useState(false);
  const [saving, setSaving] = useState(false);
  const [saved, setSaved] = useState(false);

  const fetchLeads = useCallback(async () => {
    setLoading(true);
    try {
      const res = await client.get("/api/v1/admin/demo-leads");
      const data = res.data.data ?? res.data;
      setLeads(Array.isArray(data?.data) ? data.data : Array.isArray(data) ? data : []);
    } catch {
      toast({ title: "Error", description: "Failed to load demo leads.", variant: "destructive" });
    } finally {
      setLoading(false);
    }
  }, []);

  const fetchSalesUsers = useCallback(async () => {
    try {
      const res = await client.get("/api/v1/admin/users", {
        params: { role: "sales,finder,closer,builder", per_page: 100 },
      });
      const data = res.data.data ?? res.data;
      setSalesUsers(Array.isArray(data?.data) ? data.data : Array.isArray(data) ? data : []);
    } catch {
      // non-critical
    }
  }, []);

  useEffect(() => {
    fetchLeads();
    fetchSalesUsers();
  }, [fetchLeads, fetchSalesUsers]);

  const openAssign = (lead: DemoLead) => {
    setSelected(lead);
    setAssignUserId(lead.assigned_to?.toString() ?? "");
    setScheduleDate(undefined);
    setScheduleTime("10:00");
    setMeetingLink("");
    setNotes("");
    setSaved(false);
    setDialogOpen(true);
  };

  const handleAssign = async () => {
    if (!selected || !assignUserId) return;
    setSaving(true);
    try {
      let scheduledAt: string | undefined;
      if (scheduleDate) {
        const [h, m] = scheduleTime.split(":").map(Number);
        const dt = new Date(scheduleDate);
        dt.setHours(h, m, 0, 0);
        scheduledAt = dt.toISOString();
      }

      await client.post(`/api/v1/admin/leads/${selected.id}/assign-demo`, {
        user_id:      parseInt(assignUserId),
        scheduled_at: scheduledAt,
        meeting_link: meetingLink || undefined,
        notes:        notes || undefined,
      });

      setSaved(true);
      fetchLeads();
      toast({ title: "Demo assigned", description: "Calendar event created and sales rep notified." });
    } catch {
      toast({ title: "Error", description: "Failed to assign demo.", variant: "destructive" });
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className="p-6 space-y-6 max-w-5xl mx-auto">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold">Demo Leads</h1>
          <p className="text-sm text-muted-foreground mt-0.5">
            Incoming demo requests from onwynd.com — schedule and assign to your sales team.
          </p>
        </div>
        <Button variant="outline" size="sm" onClick={fetchLeads} disabled={loading} className="gap-2">
          <RefreshCw className={cn("h-4 w-4", loading && "animate-spin")} />
          Refresh
        </Button>
      </div>

      {/* Lead cards */}
      {loading ? (
        <div className="flex justify-center py-16">
          <Loader2 className="h-6 w-6 animate-spin text-muted-foreground" />
        </div>
      ) : leads.length === 0 ? (
        <Card>
          <CardContent className="flex flex-col items-center gap-3 py-16 text-center">
            <Users className="h-10 w-10 text-muted-foreground/40" />
            <p className="text-muted-foreground text-sm">No demo requests yet.</p>
          </CardContent>
        </Card>
      ) : (
        <div className="grid gap-4 sm:grid-cols-2">
          {leads.map((lead) => (
            <Card key={lead.id} className="relative">
              <CardHeader className="pb-2">
                <div className="flex items-start justify-between gap-2">
                  <div className="min-w-0">
                    <CardTitle className="text-base truncate">
                      {lead.first_name} {lead.last_name}
                    </CardTitle>
                    <p className="text-sm text-muted-foreground font-medium mt-0.5 flex items-center gap-1.5">
                      <Building2 className="h-3.5 w-3.5 shrink-0" />
                      <span className="truncate">{lead.company}</span>
                    </p>
                  </div>
                  <Badge className={cn("shrink-0 text-xs", STATUS_COLORS[lead.status] ?? "bg-gray-100 text-gray-600")}>
                    {lead.status}
                  </Badge>
                </div>
              </CardHeader>
              <CardContent className="space-y-2">
                <div className="text-xs text-muted-foreground space-y-1">
                  <p className="flex items-center gap-1.5"><Mail className="h-3 w-3" />{lead.email}</p>
                  {lead.phone && <p className="flex items-center gap-1.5"><Phone className="h-3 w-3" />{lead.phone}</p>}
                  <p className="flex items-center gap-1.5">
                    <User className="h-3 w-3" />
                    {lead.assigned_user
                      ? `Assigned to ${lead.assigned_user.first_name} ${lead.assigned_user.last_name}`
                      : "Unassigned"}
                  </p>
                  <p className="text-[10px] text-muted-foreground/70">
                    Received {format(new Date(lead.created_at), "MMM d, yyyy")}
                  </p>
                </div>
                <Button
                  size="sm"
                  className="w-full gap-2 mt-2"
                  variant={lead.assigned_to ? "outline" : "default"}
                  onClick={() => openAssign(lead)}
                >
                  <CalendarPlus className="h-4 w-4" />
                  {lead.assigned_to ? "Reassign / Reschedule" : "Schedule & Assign"}
                </Button>
              </CardContent>
            </Card>
          ))}
        </div>
      )}

      {/* Assign dialog */}
      <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
        <DialogContent className="sm:max-w-md">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <CalendarPlus className="h-5 w-5 text-primary" />
              {saved ? "Assigned!" : `Schedule Demo — ${selected?.company}`}
            </DialogTitle>
          </DialogHeader>

          {saved ? (
            <div className="flex flex-col items-center gap-3 py-6 text-center">
              <CheckCircle2 className="h-10 w-10 text-green-500" />
              <p className="font-semibold">Demo scheduled</p>
              <p className="text-sm text-muted-foreground">
                The sales rep has been notified and the event is on their calendar.
              </p>
              <Button variant="outline" onClick={() => setDialogOpen(false)}>Close</Button>
            </div>
          ) : (
            <>
              <div className="space-y-4 py-2">
                {/* Sales rep */}
                <div className="space-y-1.5">
                  <Label>Assign to sales rep</Label>
                  <Select value={assignUserId} onValueChange={(v) => v !== null && setAssignUserId(v)}>
                    <SelectTrigger>
                      <SelectValue placeholder="Select a rep…" />
                    </SelectTrigger>
                    <SelectContent>
                      {salesUsers.map((u) => (
                        <SelectItem key={u.id} value={u.id.toString()}>
                          {u.first_name} {u.last_name} — {u.role}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>

                {/* Date + Time */}
                <div className="grid grid-cols-2 gap-3">
                  <div className="space-y-1.5">
                    <Label>Date <span className="text-muted-foreground text-xs">(optional)</span></Label>
                    <Popover open={datePickerOpen} onOpenChange={setDatePickerOpen}>
                      <PopoverTrigger asChild>
                        <Button
                          variant="outline"
                          className={cn("w-full justify-start text-left font-normal", !scheduleDate && "text-muted-foreground")}
                        >
                          <CalendarIcon className="mr-2 h-4 w-4" />
                          {scheduleDate ? format(scheduleDate, "MMM d, yyyy") : "Pick date"}
                        </Button>
                      </PopoverTrigger>
                      <PopoverContent className="w-auto p-0" align="start">
                        <Calendar
                          mode="single"
                          selected={scheduleDate}
                          onSelect={(d) => { setScheduleDate(d); setDatePickerOpen(false); }}
                          initialFocus
                        />
                      </PopoverContent>
                    </Popover>
                  </div>
                  <div className="space-y-1.5">
                    <Label>Time</Label>
                    <Select value={scheduleTime} onValueChange={(v) => v !== null && setScheduleTime(v)}>
                      <SelectTrigger><SelectValue /></SelectTrigger>
                      <SelectContent>
                        {TIME_SLOTS.map((t) => <SelectItem key={t} value={t}>{t}</SelectItem>)}
                      </SelectContent>
                    </Select>
                  </div>
                </div>

                {/* Meeting link */}
                <div className="space-y-1.5">
                  <Label>Meeting link <span className="text-muted-foreground text-xs">(optional)</span></Label>
                  <Input
                    value={meetingLink}
                    onChange={(e) => setMeetingLink(e.target.value)}
                    placeholder="https://meet.google.com/…"
                  />
                </div>

                {/* Notes */}
                <div className="space-y-1.5">
                  <Label>Notes for rep <span className="text-muted-foreground text-xs">(optional)</span></Label>
                  <Input
                    value={notes}
                    onChange={(e) => setNotes(e.target.value)}
                    placeholder="Context, talking points…"
                  />
                </div>
              </div>

              <DialogFooter className="gap-2">
                <Button variant="outline" onClick={() => setDialogOpen(false)} disabled={saving}>
                  Cancel
                </Button>
                <Button onClick={handleAssign} disabled={saving || !assignUserId} className="gap-2">
                  {saving ? <Loader2 className="h-4 w-4 animate-spin" /> : <CalendarPlus className="h-4 w-4" />}
                  Assign demo
                </Button>
              </DialogFooter>
            </>
          )}
        </DialogContent>
      </Dialog>
    </div>
  );
}

"use client";

import { useEffect, useState, useCallback, useRef } from "react";
import { adminService } from "@/lib/api/admin";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { Badge } from "@/components/ui/badge";
import {
  Loader2,
  RefreshCw,
  TrendingUp,
  DollarSign,
  Building2,
  Wrench,
  Download,
  FileText,
  Users,
  GraduationCap,
  Stethoscope,
  Briefcase,
  ShoppingBag,
} from "lucide-react";
import { toast } from "@/components/ui/use-toast";
import { PageHeader } from "@/components/shared/page-header";

// ─── Types ───────────────────────────────────────────────────────────────────

interface RevenueStream {
  key: string;
  label: string;
  description: string;
  revenue: number;
}

interface MonthlyPoint {
  month: string;
  commission_revenue: number;
  booking_fee_revenue: number;
  subscription_revenue: number;
  session_count: number;
}

interface BreakdownData {
  period: { start: string; end: string };
  streams: RevenueStream[];
  total_platform_revenue: number;
  total_session_revenue: number;
  total_therapist_payouts: number;
  session_count: number;
  monthly_breakdown: MonthlyPoint[];
}

// ─── Helpers ─────────────────────────────────────────────────────────────────

const STREAM_ICONS: Record<string, React.ElementType> = {
  d2c_subscriptions: Users,
  corporate:         Briefcase,
  commission:        Stethoscope,
  institutional:     GraduationCap,
  physical_wellness: Building2,
  booking_fees:      DollarSign,
  ancillary:         ShoppingBag,
};

const STREAM_COLORS: Record<string, string> = {
  d2c_subscriptions: "bg-teal-100 text-teal-800",
  corporate:         "bg-blue-100 text-blue-800",
  commission:        "bg-violet-100 text-violet-800",
  institutional:     "bg-amber-100 text-amber-800",
  physical_wellness: "bg-emerald-100 text-emerald-800",
  booking_fees:      "bg-orange-100 text-orange-800",
  ancillary:         "bg-gray-100 text-gray-700",
};

const fmt = (n: number) =>
  new Intl.NumberFormat("en-NG", {
    style: "currency",
    currency: "NGN",
    maximumFractionDigits: 0,
  }).format(n ?? 0);

const pct = (part: number, total: number) =>
  total > 0 ? ((part / total) * 100).toFixed(1) + "%" : "0%";

// ─── Component ───────────────────────────────────────────────────────────────

export default function AdminRevenuePage() {
  const [data, setData]         = useState<BreakdownData | null>(null);
  const [isLoading, setLoading] = useState(true);
  const [period, setPeriod]     = useState("30days");
  const [exporting, setExporting] = useState(false);
  const printRef = useRef<HTMLDivElement>(null);

  const dateRange = useCallback(() => {
    const end   = new Date();
    const start = new Date();
    if (period === "7days")  start.setDate(end.getDate() - 7);
    else if (period === "30days") start.setDate(end.getDate() - 30);
    else if (period === "90days") start.setDate(end.getDate() - 90);
    else if (period === "1year")  start.setFullYear(end.getFullYear() - 1);
    return {
      start_date: start.toISOString().split("T")[0],
      end_date:   end.toISOString().split("T")[0],
    };
  }, [period]);

  const fetchAll = useCallback(async () => {
    setLoading(true);
    try {
      const params = dateRange();
      const result = await adminService.getRevenueBreakdown(params);
      setData(result as BreakdownData);
    } catch {
      toast({ title: "Error", description: "Failed to load revenue data", variant: "destructive" });
    } finally {
      setLoading(false);
    }
  }, [dateRange]);

  useEffect(() => { fetchAll(); }, [fetchAll]);

  const handleCsvExport = async () => {
    setExporting(true);
    try {
      const params = { ...dateRange(), format: "csv" as const };
      const blob   = await adminService.fullExportRevenue(params);
      const url    = URL.createObjectURL(new Blob([blob], { type: "text/csv" }));
      const a      = document.createElement("a");
      a.href       = url;
      a.download   = `onwynd-revenue-${params.start_date}-to-${params.end_date}.csv`;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);
      toast({ title: "Exported", description: "CSV download started." });
    } catch {
      toast({ title: "Error", description: "Failed to export revenue data.", variant: "destructive" });
    } finally {
      setExporting(false);
    }
  };

  const handlePdfPrint = () => {
    window.print();
  };

  // Peak month from monthly breakdown
  const peakMonth = data?.monthly_breakdown?.reduce(
    (best, m) => {
      const total = m.commission_revenue + m.booking_fee_revenue + m.subscription_revenue;
      const bestTotal = best.commission_revenue + best.booking_fee_revenue + best.subscription_revenue;
      return total > bestTotal ? m : best;
    },
    data.monthly_breakdown[0] ?? { month: "", commission_revenue: 0, booking_fee_revenue: 0, subscription_revenue: 0, session_count: 0 }
  );

  return (
    <>
      {/* ── Print styles injected inline so they work without Tailwind print: ── */}
      <style>{`
        @media print {
          body * { visibility: hidden !important; }
          #revenue-print-area, #revenue-print-area * { visibility: visible !important; }
          #revenue-print-area { position: absolute; inset: 0; padding: 32px; }
          .no-print { display: none !important; }
        }
      `}</style>

      <div className="flex-1 space-y-6 p-4 md:p-8 pt-6">
        {/* Header */}
        <div className="flex items-center justify-between flex-wrap gap-3 no-print">
          <PageHeader
            title="Revenue Report"
            subtitle="All 7 revenue streams — real-time platform financial overview"
          />
          <div className="flex items-center gap-2">
            <Select value={period} onValueChange={(v: string | null) => setPeriod(v ?? "30days")}>
              <SelectTrigger className="w-36">
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="7days">Last 7 days</SelectItem>
                <SelectItem value="30days">Last 30 days</SelectItem>
                <SelectItem value="90days">Last 90 days</SelectItem>
                <SelectItem value="1year">Last year</SelectItem>
              </SelectContent>
            </Select>
            <Button variant="outline" size="sm" onClick={handleCsvExport} disabled={exporting || isLoading}>
              {exporting ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <Download className="mr-2 h-4 w-4" />}
              Export CSV
            </Button>
            <Button variant="outline" size="sm" onClick={handlePdfPrint} disabled={isLoading}>
              <FileText className="mr-2 h-4 w-4" />
              Print / PDF
            </Button>
            <Button variant="outline" size="icon" onClick={fetchAll} title="Refresh" disabled={isLoading}>
              <RefreshCw className={`h-4 w-4 ${isLoading ? "animate-spin" : ""}`} />
            </Button>
          </div>
        </div>

        {isLoading ? (
          <div className="flex h-48 items-center justify-center">
            <Loader2 className="h-8 w-8 animate-spin text-primary" />
          </div>
        ) : data ? (
          <div id="revenue-print-area" ref={printRef}>
            {/* ── Branded print header (only visible when printing) ── */}
            <div className="hidden print:block mb-8 border-b pb-4">
              <div className="flex items-center justify-between">
                <div>
                  <h1 className="text-2xl font-bold text-teal-700">Onwynd</h1>
                  <p className="text-sm text-gray-500">Mental Health & Wellness Platform</p>
                </div>
                <div className="text-right text-sm text-gray-500">
                  <p className="font-semibold text-gray-700">Revenue Report</p>
                  <p>{data.period.start} – {data.period.end}</p>
                  <p>Generated {new Date().toLocaleDateString("en-NG", { dateStyle: "long" })}</p>
                </div>
              </div>
            </div>

            {/* ── KPI summary row ── */}
            <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 mb-6">
              {[
                { label: "Total Platform Revenue", value: fmt(data.total_platform_revenue), icon: DollarSign, color: "text-teal-600" },
                { label: "Total Sessions", value: data.session_count.toLocaleString(), icon: TrendingUp, color: "text-violet-600" },
                { label: "Therapist Payouts", value: fmt(data.total_therapist_payouts), icon: Stethoscope, color: "text-orange-500" },
                { label: "Gross Session Revenue", value: fmt(data.total_session_revenue), icon: DollarSign, color: "text-blue-600" },
              ].map(({ label, value, icon: Icon, color }) => (
                <Card key={label}>
                  <CardContent className="pt-4 flex items-center justify-between">
                    <div>
                      <p className="text-xs text-muted-foreground">{label}</p>
                      <p className="text-2xl font-bold">{value}</p>
                    </div>
                    <Icon className={`h-8 w-8 opacity-30 ${color}`} />
                  </CardContent>
                </Card>
              ))}
            </div>

            {/* ── 7 Revenue Streams table ── */}
            <Card className="mb-6">
              <CardHeader>
                <CardTitle className="text-base">Revenue by Stream</CardTitle>
                <CardDescription>All 7 platform revenue streams — {data.period.start} to {data.period.end}</CardDescription>
              </CardHeader>
              <CardContent className="p-0">
                <Table>
                  <TableHeader>
                    <TableRow className="bg-gray-50">
                      <TableHead className="px-4 py-3 text-xs uppercase tracking-wide">#</TableHead>
                      <TableHead className="px-4 py-3 text-xs uppercase tracking-wide">Revenue Stream</TableHead>
                      <TableHead className="px-4 py-3 text-xs uppercase tracking-wide">Description</TableHead>
                      <TableHead className="px-4 py-3 text-xs uppercase tracking-wide text-right">Amount</TableHead>
                      <TableHead className="px-4 py-3 text-xs uppercase tracking-wide text-right">% of Total</TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {data.streams.map((stream, idx) => {
                      const Icon = STREAM_ICONS[stream.key] ?? DollarSign;
                      const badgeClass = STREAM_COLORS[stream.key] ?? "bg-gray-100 text-gray-700";
                      return (
                        <TableRow key={stream.key} className={idx % 2 === 0 ? "bg-white" : "bg-gray-50/50"}>
                          <TableCell className="px-4 py-3 text-xs text-gray-400">{idx + 1}</TableCell>
                          <TableCell className="px-4 py-3">
                            <div className="flex items-center gap-2">
                              <span className={`inline-flex items-center justify-center w-7 h-7 rounded-full ${badgeClass}`}>
                                <Icon className="w-3.5 h-3.5" />
                              </span>
                              <span className="text-sm font-medium text-gray-900">{stream.label}</span>
                            </div>
                          </TableCell>
                          <TableCell className="px-4 py-3 text-xs text-gray-500">{stream.description}</TableCell>
                          <TableCell className="px-4 py-3 text-right font-semibold text-gray-900 tabular-nums">
                            {fmt(stream.revenue)}
                          </TableCell>
                          <TableCell className="px-4 py-3 text-right">
                            <Badge variant="outline" className="font-mono text-xs">
                              {pct(stream.revenue, data.total_platform_revenue)}
                            </Badge>
                          </TableCell>
                        </TableRow>
                      );
                    })}
                    <TableRow className="bg-teal-50 border-t-2 border-teal-200 font-bold">
                      <TableCell className="px-4 py-3" />
                      <TableCell className="px-4 py-3 text-sm text-teal-900 font-bold" colSpan={2}>
                        Total Platform Revenue
                      </TableCell>
                      <TableCell className="px-4 py-3 text-right text-teal-900 font-bold tabular-nums text-base">
                        {fmt(data.total_platform_revenue)}
                      </TableCell>
                      <TableCell className="px-4 py-3 text-right">
                        <Badge className="bg-teal-600 text-white font-mono text-xs">100%</Badge>
                      </TableCell>
                    </TableRow>
                  </TableBody>
                </Table>
              </CardContent>
            </Card>

            {/* ── Monthly trend ── */}
            {data.monthly_breakdown?.length > 0 && (
              <Card className="mb-6">
                <CardHeader>
                  <CardTitle className="text-base">Monthly Breakdown (Last 12 Months)</CardTitle>
                  <CardDescription>Commission + Booking Fees + Subscriptions per month</CardDescription>
                </CardHeader>
                <CardContent className="p-0">
                  <Table>
                    <TableHeader>
                      <TableRow className="bg-gray-50">
                        <TableHead className="px-4 py-3 text-xs uppercase tracking-wide">Month</TableHead>
                        <TableHead className="px-4 py-3 text-xs uppercase tracking-wide text-right">Commission</TableHead>
                        <TableHead className="px-4 py-3 text-xs uppercase tracking-wide text-right">Booking Fees</TableHead>
                        <TableHead className="px-4 py-3 text-xs uppercase tracking-wide text-right">Subscriptions</TableHead>
                        <TableHead className="px-4 py-3 text-xs uppercase tracking-wide text-right">Sessions</TableHead>
                        <TableHead className="px-4 py-3 text-xs uppercase tracking-wide text-right">Month Total</TableHead>
                      </TableRow>
                    </TableHeader>
                    <TableBody>
                      {data.monthly_breakdown.map((m, idx) => {
                        const monthTotal = m.commission_revenue + m.booking_fee_revenue + m.subscription_revenue;
                        const isPeak = peakMonth?.month === m.month && monthTotal > 0;
                        return (
                          <TableRow
                            key={m.month}
                            className={`${idx % 2 === 0 ? "bg-white" : "bg-gray-50/50"} ${isPeak ? "ring-1 ring-inset ring-teal-300" : ""}`}
                          >
                            <TableCell className="px-4 py-2.5 text-sm font-medium text-gray-700">
                              {m.month}
                              {isPeak && <Badge className="ml-2 text-xs bg-teal-100 text-teal-700 border-teal-200" variant="outline">Peak</Badge>}
                            </TableCell>
                            <TableCell className="px-4 py-2.5 text-right tabular-nums text-xs text-gray-600">{fmt(m.commission_revenue)}</TableCell>
                            <TableCell className="px-4 py-2.5 text-right tabular-nums text-xs text-gray-600">{fmt(m.booking_fee_revenue)}</TableCell>
                            <TableCell className="px-4 py-2.5 text-right tabular-nums text-xs text-gray-600">{fmt(m.subscription_revenue)}</TableCell>
                            <TableCell className="px-4 py-2.5 text-right tabular-nums text-xs text-gray-500">{m.session_count}</TableCell>
                            <TableCell className="px-4 py-2.5 text-right tabular-nums text-sm font-semibold text-gray-900">{fmt(monthTotal)}</TableCell>
                          </TableRow>
                        );
                      })}
                    </TableBody>
                  </Table>
                </CardContent>
              </Card>
            )}

            {/* ── Print footer ── */}
            <div className="hidden print:block mt-8 pt-4 border-t text-xs text-gray-400 flex justify-between">
              <span>Confidential — Onwynd Internal Financial Report</span>
              <span>onwynd.com</span>
            </div>
          </div>
        ) : (
          <div className="flex h-48 items-center justify-center text-muted-foreground text-sm">
            No revenue data available for the selected period.
          </div>
        )}
      </div>
    </>
  );
}

