"use client";

import { useEffect, useState, useMemo } from "react";
import { User, usersService } from "@/lib/api/users";
import { getColumns } from "@/components/admin-dashboard/users/columns";
import { DataTable } from "@/components/admin-dashboard/users/data-table";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Tabs, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Plus, Download, Upload, Loader2, Building2, FileText } from "lucide-react";
import { UserForm } from "@/components/admin-dashboard/users/user-form";
import { toast } from "@/components/ui/use-toast";
import { downloadImportTemplate } from "@/lib/import-templates";
import Cookies from "js-cookie";
import { Lock } from "lucide-react";

export default function InstitutionsPage() {
  const [users, setUsers] = useState<User[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedUser, setSelectedUser] = useState<User | null>(null);
  const [institutionType, setInstitutionType] = useState<'all' | 'school' | 'company'>('all');
  const [isReadOnly, setIsReadOnly] = useState(false);

  useEffect(() => {
    const role = Cookies.get('user_role');
    if (role === 'coo' || role === 'cgo') {
      setIsReadOnly(true);
    }
  }, []);

  const fetchUsers = async () => {
    setIsLoading(true);
    try {
      const response = await usersService.getUsers({ role: 'institution', institution_type: institutionType });
      const data = response.data || response;
      setUsers(Array.isArray(data) ? data : data.data || []);
    } catch (error) {
      console.error("Failed to fetch institutions", error);
      toast({ title: "Error", description: "Failed to fetch institutions", variant: "destructive" });
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchUsers();
  }, [institutionType]);

  const handleCreate = () => {
    setSelectedUser(null);
    setIsModalOpen(true);
  };

  const handleEdit = (user: User) => {
    setSelectedUser(user);
    setIsModalOpen(true);
  };

  const handleSubmit = async (data: unknown) => {
    try {
      // Force role to institution
      const base = (data as Partial<User> & { password?: string }) || {};
      const userData = { ...base, role: 'institution' };

      if (selectedUser) {
        await usersService.updateUser(selectedUser.id, userData);
        toast({ title: "Success", description: "Institution updated successfully" });
      } else {
        await usersService.createUser(userData);
        toast({ title: "Success", description: "Institution created successfully" });
      }
      fetchUsers();
    } catch (error) {
      console.error(error);
      toast({ title: "Error", description: "Operation failed", variant: "destructive" });
      throw error; 
    }
  };

  const handleExport = () => {
    const headers = ["ID", "Name", "Email", "Status", "Created At"];
    const csvContent = [
      headers.join(","),
      ...users.map(u => 
        [u.id, `"${u.name}"`, u.email, u.is_active ? "Active" : "Inactive", u.created_at].join(",")
      )
    ].join("\n");

    const blob = new Blob([csvContent], { type: "text/csv;charset=utf-8;" });
    const link = document.createElement("a");
    if (link.download !== undefined) {
      const url = URL.createObjectURL(blob);
      link.setAttribute("href", url);
      link.setAttribute("download", "institutions_export.csv");
      link.style.visibility = "hidden";
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
    }
  };

  const handleImport = () => {
    const input = document.createElement("input");
    input.type = "file";
    input.accept = ".csv";
    input.onchange = async (e) => {
      const file = (e.target as HTMLInputElement).files?.[0];
      if (!file) return;
      toast({ title: "Import Started", description: `Uploading ${file.name}…` });
      try {
        const form = new FormData();
        form.append("file", file);
        const endpoint = institutionType === "school"
          ? "/api/v1/institutional/universities/import"
          : "/api/v1/institutional/corporates/import";
        const res = await (await import("@/lib/api/client")).default.post(endpoint, form, {
          headers: { "Content-Type": "multipart/form-data" },
        });
        const { created = 0, skipped = 0 } = res.data?.data ?? {};
        toast({ title: "Import Complete", description: `${created} created, ${skipped} skipped.` });
        fetchUsers();
      } catch (err: unknown) {
        const msg = (err as { response?: { data?: { message?: string } } })?.response?.data?.message ?? "Import failed.";
        toast({ title: "Import Failed", description: msg, variant: "destructive" });
      }
    };
    input.click();
  };

  const handleDownloadTemplate = () => {
    downloadImportTemplate('institutions');
    toast({ title: "Template Downloaded", description: "Institutions import template downloaded successfully" });
  };

  const columns = useMemo(() => getColumns({ onEdit: handleEdit, onRefresh: fetchUsers, isReadOnly, showStudentVerification: institutionType === 'school' }), [fetchUsers, isReadOnly, institutionType]);

  return (
    <div className="flex-1 space-y-4 p-4 md:p-8 pt-6">
      <div className="flex items-center justify-between space-y-2">
        <div className="flex items-center gap-2">
            <Building2 className="h-6 w-6 text-primary" />
            <h2 className="text-3xl font-bold tracking-tight flex items-center gap-2">
              Institutions
              {isReadOnly && <Badge variant="outline" className="ml-2 gap-1 text-xs font-normal opacity-70"><Lock className="w-3 h-3" /> Read-Only</Badge>}
            </h2>
        </div>
        <div className="flex items-center space-x-2">
          <Tabs value={institutionType} onValueChange={(val) => setInstitutionType((val as 'all' | 'school' | 'company') || 'all')}>
            <TabsList>
              <TabsTrigger value="all">All</TabsTrigger>
              <TabsTrigger value="school">School</TabsTrigger>
              <TabsTrigger value="company">Company</TabsTrigger>
            </TabsList>
          </Tabs>
          {!isReadOnly && (
            <>
              <Button variant="outline" onClick={handleDownloadTemplate}>
                <FileText className="mr-2 h-4 w-4" /> Template
              </Button>
              <Button variant="outline" onClick={handleImport}>
                <Upload className="mr-2 h-4 w-4" /> Import
              </Button>
            </>
          )}
          <Button variant="outline" onClick={handleExport}>
            <Download className="mr-2 h-4 w-4" /> Export
          </Button>
          {!isReadOnly && (
            <Button onClick={handleCreate}>
              <Plus className="mr-2 h-4 w-4" /> Add New Institution
            </Button>
          )}
        </div>
      </div>

      {isLoading ? (
        <div className="flex h-96 items-center justify-center">
          <Loader2 className="h-8 w-8 animate-spin text-primary" />
        </div>
      ) : (
        <DataTable columns={columns} data={users} />
      )}

      <UserForm 
        open={isModalOpen} 
        onOpenChange={setIsModalOpen} 
        onSubmit={handleSubmit}
        initialData={selectedUser}
      />
    </div>
  );
}

"use client";

import { useEffect, useState, useCallback } from "react";
import { adminService } from "@/lib/api/admin";
import { Card, CardContent } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { toast } from "@/components/ui/use-toast";
import { PageHeader } from "@/components/shared/page-header";
import { TableBodyShimmer } from "@/components/shared/shimmer-skeleton";
import {
  History,
  Mail,
  Search,
  RefreshCw,
  Smartphone,
  Monitor,
  Tablet,
  ChevronLeft,
  ChevronRight,
} from "lucide-react";
import { formatDistanceToNow, isAfter, subDays } from "date-fns";

interface LoginHistoryRow {
  id: number;
  user_id: number;
  user_name: string;
  user_email: string;
  auth_provider: string;
  event_type: string;
  device_type: string;
  browser: string;
  os: string;
  ip_address: string;
  location: string;
  created_at: string;
}

interface PaginationMeta {
  current_page: number;
  last_page: number;
  per_page: number;
  total: number;
}

const PROVIDER_CONFIG: Record<
  string,
  { label: string; className: string; icon?: React.ReactNode }
> = {
  email: {
    label: "Email",
    className: "bg-gray-100 text-gray-700 hover:bg-gray-100",
    icon: <Mail className="h-3 w-3" />,
  },
  google: {
    label: "Google",
    className: "bg-blue-100 text-blue-700 hover:bg-blue-100",
  },
  apple: {
    label: "Apple",
    className: "bg-gray-900 text-white hover:bg-gray-900",
  },
  facebook: {
    label: "Facebook",
    className: "bg-indigo-100 text-indigo-700 hover:bg-indigo-100",
  },
  firebase: {
    label: "Firebase",
    className: "bg-orange-100 text-orange-700 hover:bg-orange-100",
  },
};

const EVENT_CONFIG: Record<string, { label: string; className: string }> = {
  login: {
    label: "Login",
    className: "bg-green-100 text-green-700 hover:bg-green-100",
  },
  register: {
    label: "Register",
    className: "bg-teal-100 text-teal-700 hover:bg-teal-100",
  },
  password_changed: {
    label: "Password Changed",
    className: "bg-amber-100 text-amber-700 hover:bg-amber-100",
  },
  logout: {
    label: "Logout",
    className: "bg-gray-100 text-gray-600 hover:bg-gray-100",
  },
  sso: {
    label: "SSO",
    className: "bg-purple-100 text-purple-700 hover:bg-purple-100",
  },
};

function DeviceIcon({ deviceType }: { deviceType: string }) {
  if (deviceType === "mobile") return <Smartphone className="h-4 w-4 shrink-0 text-muted-foreground" />;
  if (deviceType === "tablet") return <Tablet className="h-4 w-4 shrink-0 text-muted-foreground" />;
  return <Monitor className="h-4 w-4 shrink-0 text-muted-foreground" />;
}

function ProviderBadge({ provider }: { provider: string }) {
  const cfg = PROVIDER_CONFIG[provider] ?? {
    label: provider,
    className: "bg-gray-100 text-gray-700 hover:bg-gray-100",
  };
  return (
    <Badge className={`gap-1 font-normal ${cfg.className}`}>
      {cfg.icon}
      {cfg.label}
    </Badge>
  );
}

function EventBadge({ event }: { event: string }) {
  const cfg = EVENT_CONFIG[event] ?? {
    label: event,
    className: "bg-gray-100 text-gray-600 hover:bg-gray-100",
  };
  return <Badge className={`font-normal ${cfg.className}`}>{cfg.label}</Badge>;
}

export default function LoginHistoryPage() {
  const [rows, setRows] = useState<LoginHistoryRow[]>([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState("");
  const [eventType, setEventType] = useState("all");
  const [authProvider, setAuthProvider] = useState("all");
  const [deviceType, setDeviceType] = useState("all");
  const [page, setPage] = useState(1);
  const [meta, setMeta] = useState<PaginationMeta | null>(null);

  const fetchHistory = useCallback(
    async (p = 1) => {
      setLoading(true);
      try {
        const params: Record<string, unknown> = { page: p, per_page: 20 };
        if (search) params.search = search;
        if (eventType !== "all") params.event_type = eventType;
        if (authProvider !== "all") params.auth_provider = authProvider;
        if (deviceType !== "all") params.device_type = deviceType;

        const data = (await adminService.getLoginHistory(params)) as any;
        const list: LoginHistoryRow[] = Array.isArray(data)
          ? data
          : Array.isArray(data?.data)
          ? data.data
          : [];
        setRows(list);
        if (data?.meta) setMeta(data.meta);
        else if (data?.current_page !== undefined) setMeta(data as PaginationMeta);
        else setMeta(null);
        setPage(p);
      } catch {
        toast({
          title: "Error",
          description: "Failed to load login history.",
          variant: "destructive",
        });
      } finally {
        setLoading(false);
      }
    },
    [search, eventType, authProvider, deviceType]
  );

  useEffect(() => {
    fetchHistory(1);
  }, [fetchHistory]);

  // Compute stats from current data (or API could return aggregate counts)
  const totalEvents = meta?.total ?? rows.length;
  const uniqueUsers = new Set(rows.map((r) => r.user_id)).size;
  const firebaseSignups = rows.filter(
    (r) => r.auth_provider === "firebase" && r.event_type === "register"
  ).length;
  const weekAgo = subDays(new Date(), 7);
  const passwordChangesThisWeek = rows.filter(
    (r) =>
      r.event_type === "password_changed" &&
      isAfter(new Date(r.created_at), weekAgo)
  ).length;

  const currentPage = meta?.current_page ?? page;
  const lastPage = meta?.last_page ?? 1;

  return (
    <div className="flex-1 space-y-6 p-4 md:p-8 pt-6">
      <PageHeader
        title="Login History"
        subtitle="Signup method, device, browser, and location for every auth event"
      >
        <Button
          variant="outline"
          size="sm"
          onClick={() => fetchHistory(currentPage)}
          disabled={loading}
        >
          {loading ? (
            <RefreshCw className="h-4 w-4 animate-spin" />
          ) : (
            <RefreshCw className="h-4 w-4" />
          )}
        </Button>
      </PageHeader>

      {/* Stats */}
      <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
        {[
          { label: "Total Events", value: totalEvents },
          { label: "Unique Users", value: uniqueUsers },
          { label: "Firebase Signups", value: firebaseSignups },
          { label: "Password Changes (this week)", value: passwordChangesThisWeek },
        ].map(({ label, value }) => (
          <Card key={label}>
            <CardContent className="pt-4 pb-4 text-center">
              <p className="text-2xl font-bold">{value}</p>
              <p className="text-xs text-muted-foreground mt-1">{label}</p>
            </CardContent>
          </Card>
        ))}
      </div>

      {/* Filter bar */}
      <div className="flex flex-wrap items-center gap-3">
        <div className="relative">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-gray-400" />
          <Input
            placeholder="Search by name or email…"
            className="pl-9 w-64"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />
        </div>

        <Select value={eventType} onValueChange={(v) => setEventType(v ?? eventType)}>
          <SelectTrigger className="w-44">
            <SelectValue placeholder="Event type" />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="all">All Events</SelectItem>
            <SelectItem value="login">Login</SelectItem>
            <SelectItem value="register">Register</SelectItem>
            <SelectItem value="password_changed">Password Changed</SelectItem>
            <SelectItem value="sso">SSO</SelectItem>
          </SelectContent>
        </Select>

        <Select value={authProvider} onValueChange={(v) => setAuthProvider(v ?? authProvider)}>
          <SelectTrigger className="w-40">
            <SelectValue placeholder="Auth provider" />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="all">All Providers</SelectItem>
            <SelectItem value="email">Email</SelectItem>
            <SelectItem value="google">Google</SelectItem>
            <SelectItem value="apple">Apple</SelectItem>
            <SelectItem value="facebook">Facebook</SelectItem>
            <SelectItem value="firebase">Firebase</SelectItem>
          </SelectContent>
        </Select>

        <Select value={deviceType} onValueChange={(v) => setDeviceType(v ?? deviceType)}>
          <SelectTrigger className="w-36">
            <SelectValue placeholder="Device" />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="all">All Devices</SelectItem>
            <SelectItem value="mobile">Mobile</SelectItem>
            <SelectItem value="desktop">Desktop</SelectItem>
            <SelectItem value="tablet">Tablet</SelectItem>
          </SelectContent>
        </Select>
      </div>

      {/* Table */}
      <Card>
        <CardContent className="p-0">
          <div className="overflow-x-auto">
            <Table>
              <TableHeader>
                <TableRow className="bg-gray-50">
                  <TableHead className="px-4 py-3 text-xs uppercase">User</TableHead>
                  <TableHead className="px-4 py-3 text-xs uppercase">Auth Provider</TableHead>
                  <TableHead className="px-4 py-3 text-xs uppercase">Event</TableHead>
                  <TableHead className="px-4 py-3 text-xs uppercase">Device &amp; Browser</TableHead>
                  <TableHead className="px-4 py-3 text-xs uppercase">Location</TableHead>
                  <TableHead className="px-4 py-3 text-xs uppercase">IP Address</TableHead>
                  <TableHead className="px-4 py-3 text-xs uppercase">Time</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {loading ? (
                  <TableBodyShimmer rows={8} cols={7} />
                ) : rows.length === 0 ? (
                  <TableRow>
                    <TableCell
                      colSpan={7}
                      className="text-center py-16 text-muted-foreground"
                    >
                      <History className="w-10 h-10 mx-auto mb-3 opacity-30" />
                      No login history found.
                    </TableCell>
                  </TableRow>
                ) : (
                  rows.map((row) => (
                    <TableRow key={row.id}>
                      <TableCell className="px-4 py-3">
                        <p className="text-sm font-medium">{row.user_name}</p>
                        <p className="text-xs text-muted-foreground">{row.user_email}</p>
                      </TableCell>
                      <TableCell className="px-4 py-3">
                        <ProviderBadge provider={row.auth_provider} />
                      </TableCell>
                      <TableCell className="px-4 py-3">
                        <EventBadge event={row.event_type} />
                      </TableCell>
                      <TableCell className="px-4 py-3">
                        <div className="flex items-center gap-2">
                          <DeviceIcon deviceType={row.device_type} />
                          <div>
                            <p className="text-sm">{row.browser || "—"}</p>
                            <p className="text-xs text-muted-foreground">{row.os || ""}</p>
                          </div>
                        </div>
                      </TableCell>
                      <TableCell className="px-4 py-3 text-sm text-muted-foreground">
                        {row.location || "—"}
                      </TableCell>
                      <TableCell className="px-4 py-3 text-sm font-mono text-muted-foreground">
                        {row.ip_address || "—"}
                      </TableCell>
                      <TableCell className="px-4 py-3 text-sm text-muted-foreground whitespace-nowrap">
                        {row.created_at
                          ? formatDistanceToNow(new Date(row.created_at), { addSuffix: true })
                          : "—"}
                      </TableCell>
                    </TableRow>
                  ))
                )}
              </TableBody>
            </Table>
          </div>

          {/* Pagination */}
          {meta && lastPage > 1 && (
            <div className="flex items-center justify-between px-4 py-3 border-t">
              <p className="text-xs text-muted-foreground">
                Page {currentPage} of {lastPage} · {meta.total} events
              </p>
              <div className="flex items-center gap-2">
                <Button
                  variant="outline"
                  size="sm"
                  disabled={currentPage <= 1 || loading}
                  onClick={() => fetchHistory(currentPage - 1)}
                >
                  <ChevronLeft className="h-4 w-4" />
                </Button>
                <Button
                  variant="outline"
                  size="sm"
                  disabled={currentPage >= lastPage || loading}
                  onClick={() => fetchHistory(currentPage + 1)}
                >
                  <ChevronRight className="h-4 w-4" />
                </Button>
              </div>
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import {
  Mail,
  Inbox,
  Send,
  File,
  Trash2,
  AlertCircle,
  Search,
  RefreshCw,
  Plus,
  ChevronLeft,
  ChevronRight,
  MoreVertical,
  Paperclip,
  Reply,
  Archive,
  ArrowLeft,
  Loader2
} from "lucide-react";
import { Card } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import { ScrollArea } from "@/components/ui/scroll-area";
import { 
  DropdownMenu, 
  DropdownMenuContent, 
  DropdownMenuItem, 
  DropdownMenuTrigger 
} from "@/components/ui/dropdown-menu";
import { Skeleton } from "@/components/ui/skeleton";
import client from "@/lib/api/client";
import { toast } from "@/components/ui/use-toast";
import { formatDistanceToNow } from "date-fns";
import { MailStatus } from "@/components/shared/mail-status";

export default function MailPage() {
  const [folder, setFolder] = useState("INBOX");
  const [messages, setMessages] = useState<any[]>([]);
  const [selectedMessage, setSelectedMessage] = useState<any>(null);
  const [loading, setLoading] = useState(true);
  const [page, setPage] = useState(1);
  const [total, setTotal] = useState(0);
  const [folders, setFolders] = useState<any[]>([]);

  const fetchFolders = async () => {
    try {
      const res = await client.get("/api/v1/admin/mail/folders");
      setFolders(res.data);
    } catch (err) {}
  };

  const fetchMessages = async (f = folder, p = page) => {
    setLoading(true);
    try {
      const res = await client.get(`/api/v1/admin/mail/inbox?folder=${f}&page=${p}`);
      setMessages(res.data.messages || []);
      setTotal(res.data.total || 0);
    } catch (err: any) {
      toast({ 
        title: "Mail Error", 
        description: err.response?.data?.error || "Failed to fetch messages", 
        variant: "destructive" 
      });
    } finally {
      setLoading(false);
    }
  };

  const fetchMessageDetail = async (id: string) => {
    try {
      const res = await client.get(`/api/v1/admin/mail/${id}`);
      setSelectedMessage(res.data);
      // Mark as read in list
      setMessages(prev => prev.map(m => m.id === id ? { ...m, is_read: true } : m));
    } catch (err) {
      toast({ title: "Error", description: "Failed to load message body", variant: "destructive" });
    }
  };

  useEffect(() => {
    fetchFolders();
    fetchMessages();
  }, []);

  const handleFolderChange = (f: string) => {
    setFolder(f);
    setPage(1);
    setSelectedMessage(null);
    fetchMessages(f, 1);
  };

  const handleRefresh = () => {
    fetchFolders();
    fetchMessages();
  };

  const handleTrash = async (id: string) => {
    if (!confirm("Move this message to trash?")) return;
    try {
      await client.delete(`/api/v1/admin/mail/${id}`);
      toast({ description: "Message moved to trash" });
      setSelectedMessage(null);
      fetchMessages();
    } catch {
      toast({ title: "Error", description: "Failed to move message to trash", variant: "destructive" });
    }
  };

  const handleMarkUnread = async (id: string) => {
    try {
      await client.patch(`/api/v1/admin/mail/${id}/read`, { read: false });
      setMessages(prev => prev.map(m => m.id === id ? { ...m, is_read: false } : m));
      toast({ description: "Marked as unread" });
    } catch {
      toast({ title: "Error", description: "Failed to mark as unread", variant: "destructive" });
    }
  };

  return (
    <div className="flex h-[calc(100vh-8rem)] gap-4 overflow-hidden">
      {/* Sidebar Folders */}
      <div className="w-64 flex flex-col gap-2 shrink-0">
        <Button 
          className="w-full justify-start gap-2 mb-2" 
          onClick={() => toast({ description: "Compose via Mail Settings — connect your mail provider first." })}
        >
          <Plus className="w-4 h-4" />
          Compose
        </Button>

        <div className="space-y-1">
          {folders.length === 0 ? (
            ['Inbox', 'Sent', 'Drafts', 'Trash', 'Spam'].map(f => (
              <Button 
                key={f} 
                variant={folder === f.toUpperCase() ? "secondary" : "ghost"} 
                className="w-full justify-start gap-3"
                onClick={() => handleFolderChange(f.toUpperCase())}
              >
                {f === 'Inbox' && <Inbox className="w-4 h-4" />}
                {f === 'Sent' && <Send className="w-4 h-4" />}
                {f === 'Drafts' && <File className="w-4 h-4" />}
                {f === 'Trash' && <Trash2 className="w-4 h-4" />}
                {f === 'Spam' && <AlertCircle className="w-4 h-4" />}
                {f}
              </Button>
            ))
          ) : (
            folders.map(f => (
              <Button 
                key={f.name} 
                variant={folder === f.name ? "secondary" : "ghost"} 
                className="w-full justify-start gap-3 relative"
                onClick={() => handleFolderChange(f.name)}
              >
                {f.name === 'INBOX' ? <Inbox className="w-4 h-4" /> : <File className="w-4 h-4" />}
                <span className="truncate">{f.display_name}</span>
                {f.unread > 0 && (
                  <Badge variant="secondary" className="ml-auto text-[10px] h-5 px-1.5">
                    {f.unread}
                  </Badge>
                )}
              </Button>
            ))
          )}
        </div>
      </div>

      {/* Message List */}
      <Card className="w-96 flex flex-col shrink-0 overflow-hidden">
        <div className="p-4 border-b space-y-4">
          <div className="flex items-center justify-between">
            <div className="flex flex-col">
              <h2 className="font-semibold text-lg flex items-center gap-2">
                {folder}
                {loading && <Loader2 className="w-4 h-4 animate-spin opacity-50" />}
              </h2>
              <MailStatus />
            </div>
            <Button variant="ghost" size="icon" onClick={handleRefresh}>
              <RefreshCw className="w-4 h-4" />
            </Button>
          </div>
          <div className="relative">
            <Search className="absolute left-2 top-2.5 h-4 w-4 text-muted-foreground" />
            <Input placeholder="Search messages..." className="pl-8" />
          </div>
        </div>
        <ScrollArea className="flex-1">
          <div className="divide-y">
            {loading ? (
              Array.from({ length: 8 }).map((_, i) => (
                <div key={i} className="p-4 space-y-2">
                  <div className="flex justify-between">
                    <Skeleton className="h-4 w-24" />
                    <Skeleton className="h-3 w-12" />
                  </div>
                  <Skeleton className="h-4 w-full" />
                  <Skeleton className="h-3 w-2/3" />
                </div>
              ))
            ) : messages.length === 0 ? (
              <div className="p-8 text-center text-muted-foreground">
                No messages found.
              </div>
            ) : (
              messages.map(msg => (
                <div 
                  key={msg.id} 
                  className={`p-4 cursor-pointer hover:bg-accent transition-colors ${selectedMessage?.id === msg.id ? 'bg-accent' : ''} ${!msg.is_read ? 'border-l-4 border-l-primary' : ''}`}
                  onClick={() => fetchMessageDetail(msg.id)}
                >
                  <div className="flex justify-between items-start mb-1">
                    <span className={`text-sm truncate max-w-[180px] ${!msg.is_read ? 'font-bold' : 'text-muted-foreground'}`}>
                      {msg.from}
                    </span>
                    <span className="text-[10px] text-muted-foreground whitespace-nowrap">
                      {formatDistanceToNow(new Date(msg.date), { addSuffix: true })}
                    </span>
                  </div>
                  <div className={`text-sm truncate mb-1 ${!msg.is_read ? 'font-semibold' : ''}`}>
                    {msg.subject || "(No Subject)"}
                  </div>
                  <div className="text-xs text-muted-foreground line-clamp-2">
                    {msg.snippet}
                  </div>
                </div>
              ))
            )}
          </div>
        </ScrollArea>
        <div className="p-2 border-t flex items-center justify-between text-xs text-muted-foreground">
          <span>{total} messages</span>
          <div className="flex gap-1">
            <Button variant="ghost" size="icon" className="h-6 w-6" disabled={page <= 1} onClick={() => { setPage(p => p - 1); fetchMessages(folder, page - 1); }}>
              <ChevronLeft className="w-4 h-4" />
            </Button>
            <Button variant="ghost" size="icon" className="h-6 w-6" disabled={messages.length < 20} onClick={() => { setPage(p => p + 1); fetchMessages(folder, page + 1); }}>
              <ChevronRight className="w-4 h-4" />
            </Button>
          </div>
        </div>
      </Card>

      {/* Message Content */}
      <Card className="flex-1 flex flex-col overflow-hidden">
        {selectedMessage ? (
          <>
            <div className="p-4 border-b flex items-center justify-between shrink-0">
              <div className="flex items-center gap-2">
                <Button variant="ghost" size="icon" onClick={() => setSelectedMessage(null)} className="lg:hidden">
                  <ArrowLeft className="w-4 h-4" />
                </Button>
                <div className="flex gap-1">
                  <Button variant="ghost" size="icon" title="Archive" onClick={() => handleTrash(selectedMessage.id)}><Archive className="w-4 h-4" /></Button>
                  <Button variant="ghost" size="icon" title="Delete" className="text-destructive" onClick={() => handleTrash(selectedMessage.id)}><Trash2 className="w-4 h-4" /></Button>
                </div>
              </div>
              <div className="flex items-center gap-2">
                <Button variant="outline" size="sm" className="gap-2">
                  <Reply className="w-4 h-4" />
                  Reply
                </Button>
                <DropdownMenu>
                  <DropdownMenuTrigger asChild>
                    <Button variant="ghost" size="icon"><MoreVertical className="w-4 h-4" /></Button>
                  </DropdownMenuTrigger>
                  <DropdownMenuContent align="end">
                    <DropdownMenuItem onClick={() => handleMarkUnread(selectedMessage.id)}>Mark as unread</DropdownMenuItem>
                    <DropdownMenuItem className="text-destructive" onClick={() => handleTrash(selectedMessage.id)}>Delete</DropdownMenuItem>
                  </DropdownMenuContent>
                </DropdownMenu>
              </div>
            </div>

            <ScrollArea className="flex-1">
              <div className="p-6">
                <div className="flex justify-between items-start mb-6">
                  <div>
                    <h1 className="text-xl font-bold mb-2">{selectedMessage.subject}</h1>
                    <div className="flex items-center gap-2 text-sm">
                      <span className="font-semibold">{selectedMessage.from}</span>
                      <span className="text-muted-foreground">&lt;{selectedMessage.from_email || selectedMessage.from}&gt;</span>
                    </div>
                    <div className="text-xs text-muted-foreground mt-1">
                      To: {selectedMessage.to}
                    </div>
                  </div>
                  <div className="text-sm text-muted-foreground">
                    {new Date(selectedMessage.date).toLocaleString()}
                  </div>
                </div>

                {selectedMessage.attachments?.length > 0 && (
                  <div className="mb-6 flex flex-wrap gap-2">
                    {selectedMessage.attachments.map((att: any) => (
                      <Badge key={att.id} variant="outline" className="gap-2 py-1.5 px-3 cursor-pointer hover:bg-accent">
                        <Paperclip className="w-3 h-3" />
                        {att.name}
                        <span className="text-[10px] opacity-50">({Math.round(att.size / 1024)} KB)</span>
                      </Badge>
                    ))}
                  </div>
                )}

                <div 
                  className="prose prose-sm max-w-none dark:prose-invert"
                  dangerouslySetInnerHTML={{ __html: selectedMessage.body_html || selectedMessage.body_text?.replace(/\n/g, '<br>') }}
                />
              </div>
            </ScrollArea>
          </>
        ) : (
          <div className="flex-1 flex flex-col items-center justify-center text-muted-foreground p-8 text-center">
            <Mail className="w-16 h-16 mb-4 opacity-10" />
            <h3 className="text-lg font-medium">Select an email to read</h3>
            <p className="max-w-xs text-sm mt-2">
              Select a message from the list to view its contents, attachments, and options.
            </p>
          </div>
        )}
      </Card>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import client from "@/lib/api/client";
import { format } from "date-fns";
import { toast } from "sonner";
import { Bell, RefreshCw, Send } from "lucide-react";
import { PageHeader } from "@/components/shared/page-header";
import { TableBodyShimmer } from "@/components/shared/shimmer-skeleton";

const CHANNEL_STYLES: Record<string, string> = {
  push:      "bg-blue-50 text-blue-700",
  email:     "bg-indigo-50 text-indigo-700",
  whatsapp:  "bg-green-50 text-green-700",
};

const TARGET_LABELS: Record<string, string> = {
  all_patients:    "All Patients",
  all_therapists:  "All Therapists",
  premium_users:   "Premium Subscribers",
  inactive_30d:    "Inactive (30+ days)",
};

export default function NotificationsPage() {
  const [notifications, setNotifications] = useState<unknown[]>([]);
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [formData, setFormData] = useState<{
    title: string;
    message: string;
    target_type: string | null;
    channel: string | null;
  }>({
    title: "",
    message: "",
    target_type: "all_patients",
    channel: "push",
  });

  useEffect(() => {
    fetchNotifications();
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  const fetchNotifications = async () => {
    setLoading(true);
    try {
      const res = await client.get("/api/v1/admin/notifications");
      // sendResponse wraps paginated data: { success, data: { current_page, data: [...] } }
      const raw = res.data?.data;
      setNotifications(Array.isArray(raw) ? raw : Array.isArray(raw?.data) ? raw.data : []);
    } catch (error) {
      console.error("Failed to fetch notifications", error);
    } finally {
      setLoading(false);
    }
  };

  const handleSendBroadcast = async () => {
    if (!formData.title || !formData.message) {
      toast.error("Title and message are required");
      return;
    }
    setSubmitting(true);
    try {
      await client.post("/api/v1/marketing/broadcast/send", formData);
      toast.success("Broadcast notification sent successfully");
      setFormData({ title: "", message: "", target_type: "all_patients", channel: "push" });
      fetchNotifications();
    } catch (error) {
      console.error("Failed to send broadcast", error);
      toast.error("Failed to send broadcast notification");
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <main className="p-6 space-y-6">
      <PageHeader
        title="Push & Email Campaigns"
        subtitle="Broadcast notifications to users across the platform"
      >
        <Button onClick={fetchNotifications} variant="outline" size="sm" className="gap-2">
          <RefreshCw className={`w-4 h-4 ${loading ? "animate-spin" : ""}`} />
          Refresh
        </Button>
      </PageHeader>

      <div className="grid lg:grid-cols-3 gap-6">
        {/* Compose panel */}
        <Card className="lg:col-span-1">
          <CardHeader>
            <CardTitle className="flex items-center gap-2 text-base">
              <Send className="w-4 h-4 text-teal" />
              Send New Broadcast
            </CardTitle>
            <CardDescription>Target all users or specific groups</CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="space-y-2">
              <Label htmlFor="target">Target Group</Label>
              <Select
                value={formData.target_type}
                onValueChange={(v: string | null) => setFormData({ ...formData, target_type: v ?? "" })}
              >
                <SelectTrigger id="target">
                  <SelectValue placeholder="Select target group" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all_patients">All Patients</SelectItem>
                  <SelectItem value="all_therapists">All Therapists</SelectItem>
                  <SelectItem value="premium_users">Premium Subscribers</SelectItem>
                  <SelectItem value="inactive_30d">Inactive Users (30+ days)</SelectItem>
                </SelectContent>
              </Select>
            </div>

            <div className="space-y-2">
              <Label htmlFor="channel">Channel</Label>
              <Select
                value={formData.channel}
                onValueChange={(v: string | null) => setFormData({ ...formData, channel: v ?? "" })}
              >
                <SelectTrigger id="channel">
                  <SelectValue placeholder="Select channel" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="push">Push Notification</SelectItem>
                  <SelectItem value="email">Email Campaign</SelectItem>
                  <SelectItem value="whatsapp">WhatsApp Broadcast</SelectItem>
                </SelectContent>
              </Select>
            </div>

            <div className="space-y-2">
              <Label htmlFor="notif-title">Campaign Title</Label>
              <Input
                id="notif-title"
                placeholder="Short, catchy title…"
                value={formData.title}
                onChange={(e) => setFormData({ ...formData, title: e.target.value })}
              />
            </div>

            <div className="space-y-2">
              <Label htmlFor="message">Message Body</Label>
              <Textarea
                id="message"
                placeholder="What do you want to say?"
                rows={4}
                value={formData.message}
                onChange={(e) => setFormData({ ...formData, message: e.target.value })}
              />
            </div>

            <Button
              className="w-full gap-2 bg-teal text-white hover:bg-teal-mid"
              onClick={handleSendBroadcast}
              disabled={submitting}
            >
              <Send className="w-4 h-4" />
              {submitting ? "Sending…" : "Launch Campaign"}
            </Button>
          </CardContent>
        </Card>

        {/* History panel */}
        <Card className="lg:col-span-2">
          <CardHeader>
            <CardTitle className="flex items-center gap-2 text-base">
              <Bell className="w-4 h-4 text-gray-500" />
              Notification History
            </CardTitle>
            <CardDescription>Log of recent broadcasts and system alerts</CardDescription>
          </CardHeader>
          <CardContent className="p-0">
            <div className="overflow-x-auto">
              <Table>
                <TableHeader>
                  <TableRow className="bg-gray-50">
                    <TableHead className="px-4 py-3 text-xs font-medium text-gray-500 uppercase tracking-wide">Date</TableHead>
                    <TableHead className="px-4 py-3 text-xs font-medium text-gray-500 uppercase tracking-wide">Target</TableHead>
                    <TableHead className="px-4 py-3 text-xs font-medium text-gray-500 uppercase tracking-wide">Message</TableHead>
                    <TableHead className="px-4 py-3 text-xs font-medium text-gray-500 uppercase tracking-wide">Channel</TableHead>
                    <TableHead className="px-4 py-3 text-xs font-medium text-gray-500 uppercase tracking-wide">Status</TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {loading ? (
                    <TableBodyShimmer rows={5} cols={5} />
                  ) : notifications.length === 0 ? (
                    <TableRow>
                      <TableCell colSpan={5}>
                        <div className="flex flex-col items-center justify-center py-14">
                          <Bell className="w-10 h-10 text-gray-200 mb-3" />
                          <p className="text-sm font-medium text-gray-500">No notifications sent yet</p>
                          <p className="text-xs text-gray-400 mt-1">Your sent campaigns will appear here</p>
                        </div>
                      </TableCell>
                    </TableRow>
                  ) : (
                    (notifications as Record<string, unknown>[]).map((notif, idx) => (
                      <TableRow
                        key={notif.id as string}
                        className={idx % 2 === 0 ? "bg-white hover:bg-teal/5" : "bg-gray-50/50 hover:bg-teal/5"}
                      >
                        <TableCell className="px-4 py-3 text-xs text-gray-500 whitespace-nowrap">
                          {notif.created_at ? format(new Date(notif.created_at as string), "MMM d, HH:mm") : "—"}
                        </TableCell>
                        <TableCell className="px-4 py-3">
                          <span className="text-xs font-medium capitalize text-gray-700">
                            {TARGET_LABELS[(notif.target_type as string) || ""] || (notif.target_type as string) || "System"}
                          </span>
                        </TableCell>
                        <TableCell className="px-4 py-3 max-w-xs">
                          <p className="text-sm font-semibold text-gray-900 truncate">{notif.title as string}</p>
                          <p className="text-xs text-gray-400 truncate">{notif.message as string}</p>
                        </TableCell>
                        <TableCell className="px-4 py-3">
                          <span className={`inline-flex items-center px-2 py-0.5 rounded-full text-xs font-medium capitalize ${CHANNEL_STYLES[(notif.channel as string) || "push"] ?? "bg-gray-50 text-gray-600"}`}>
                            {(notif.channel as string) || "Push"}
                          </span>
                        </TableCell>
                        <TableCell className="px-4 py-3">
                          <span className="inline-flex items-center px-2 py-0.5 rounded-full text-xs font-medium bg-emerald-50 text-emerald-700">
                            Sent
                          </span>
                        </TableCell>
                      </TableRow>
                    ))
                  )}
                </TableBody>
              </Table>
            </div>
          </CardContent>
        </Card>
      </div>
    </main>
  );
}

