"use client";

import { useEffect, useState, useCallback } from "react";
import client from "@/lib/api/client";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Skeleton } from "@/components/ui/skeleton";
import { PageHeader } from "@/components/shared/page-header";
import { ShieldAlert, CheckCircle2, Clock, AlertTriangle, Search, RefreshCw, ExternalLink } from "lucide-react";
import Link from "next/link";
import { formatDistanceToNow } from "date-fns";

interface AuditLog {
  id: number;
  session_uuid: string;
  audit_status: "pending" | "processing" | "clean" | "flagged" | "error";
  risk_score: number | null;
  violations: Violation[] | null;
  reviewed: boolean;
  reviewed_at: string | null;
  duration_seconds: number | null;
  created_at: string;
  session?: { uuid: string; scheduled_at: string; status: string };
}

interface Violation {
  type: string;
  severity: "low" | "medium" | "high" | "critical";
  quote: string;
  recommendation: string;
}

const STATUS_CONFIG = {
  pending:    { label: "Pending",    icon: Clock,          color: "bg-gray-100 text-gray-600" },
  processing: { label: "Processing", icon: Clock,          color: "bg-blue-100 text-blue-600" },
  clean:      { label: "Clean",      icon: CheckCircle2,   color: "bg-emerald-100 text-emerald-700" },
  flagged:    { label: "Flagged",    icon: ShieldAlert,    color: "bg-red-100 text-red-700" },
  error:      { label: "Error",      icon: AlertTriangle,  color: "bg-orange-100 text-orange-700" },
};

const SEVERITY_COLOR: Record<string, string> = {
  critical: "bg-red-600 text-white",
  high:     "bg-red-100 text-red-700",
  medium:   "bg-orange-100 text-orange-700",
  low:      "bg-yellow-100 text-yellow-700",
};

function RiskBar({ score }: { score: number | null }) {
  if (score === null) return <span className="text-xs text-muted-foreground">—</span>;
  const pct = Math.round(score * 100);
  const color = pct >= 70 ? "bg-red-500" : pct >= 40 ? "bg-orange-400" : "bg-emerald-500";
  return (
    <div className="flex items-center gap-2">
      <div className="w-16 h-1.5 rounded-full bg-muted overflow-hidden">
        <div className={`h-full rounded-full ${color}`} style={{ width: `${pct}%` }} />
      </div>
      <span className="text-xs font-medium tabular-nums">{pct}%</span>
    </div>
  );
}

export default function SessionAuditsPage() {
  const [audits, setAudits]     = useState<AuditLog[]>([]);
  const [loading, setLoading]   = useState(true);
  const [status, setStatus]     = useState<string>("all");
  const [search, setSearch]     = useState("");

  const load = useCallback(async () => {
    setLoading(true);
    try {
      const params: Record<string, string> = {};
      if (status !== "all") params.status = status;
      const res = await client.get("/api/v1/admin/session-audits", { params });
      const data = res.data?.data ?? res.data;
      setAudits(Array.isArray(data?.data) ? data.data : Array.isArray(data) ? data : []);
    } catch {
      setAudits([]);
    } finally {
      setLoading(false);
    }
  }, [status]);

  useEffect(() => { load(); }, [load]);

  const filtered = audits.filter((a) => {
    if (!search) return true;
    return a.session_uuid.includes(search);
  });

  const flaggedCount = audits.filter((a) => a.audit_status === "flagged" && !a.reviewed).length;

  return (
    <div className="space-y-6 p-4 md:p-8 pt-6">
      <PageHeader
        title="AI Session Audits"
      />

      {/* Stats strip */}
      <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
        {(["flagged", "clean", "processing", "error"] as const).map((s) => {
          const cfg = STATUS_CONFIG[s];
          const count = audits.filter((a) => a.audit_status === s).length;
          return (
            <Card key={s} className="p-3 flex items-center gap-3">
              <cfg.icon className="size-5 shrink-0 text-muted-foreground" />
              <div>
                <p className="text-xs text-muted-foreground capitalize">{cfg.label}</p>
                <p className="text-xl font-bold">{count}</p>
              </div>
            </Card>
          );
        })}
      </div>

      {flaggedCount > 0 && (
        <div className="flex items-center gap-2 rounded-lg border border-red-200 bg-red-50 px-4 py-2.5 text-sm text-red-700">
          <ShieldAlert className="size-4 shrink-0" />
          <span><strong>{flaggedCount}</strong> flagged session{flaggedCount !== 1 ? "s" : ""} awaiting review.</span>
        </div>
      )}

      {/* Filters */}
      <div className="flex flex-wrap items-center gap-3">
        <div className="relative flex-1 min-w-[200px]">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 size-3.5 text-muted-foreground" />
          <Input
            placeholder="Search by session UUID…"
            className="pl-8 h-8 text-sm"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />
        </div>
        <Select value={status} onValueChange={(v) => v !== null && setStatus(v)}>
          <SelectTrigger className="w-40 h-8 text-sm">
            <SelectValue />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="all">All statuses</SelectItem>
            <SelectItem value="flagged">Flagged</SelectItem>
            <SelectItem value="clean">Clean</SelectItem>
            <SelectItem value="processing">Processing</SelectItem>
            <SelectItem value="error">Error</SelectItem>
          </SelectContent>
        </Select>
        <Button variant="outline" size="sm" onClick={load} disabled={loading} className="h-8">
          <RefreshCw className={`size-3.5 mr-1.5 ${loading ? "animate-spin" : ""}`} />
          Refresh
        </Button>
      </div>

      {/* Table */}
      <Card>
        <CardContent className="p-0">
          <div className="overflow-x-auto">
            <table className="w-full text-sm">
              <thead>
                <tr className="border-b bg-muted/30">
                  <th className="text-left px-4 py-2.5 font-medium text-muted-foreground text-xs">Session</th>
                  <th className="text-left px-4 py-2.5 font-medium text-muted-foreground text-xs">Status</th>
                  <th className="text-left px-4 py-2.5 font-medium text-muted-foreground text-xs">Risk</th>
                  <th className="text-left px-4 py-2.5 font-medium text-muted-foreground text-xs">Top violation</th>
                  <th className="text-left px-4 py-2.5 font-medium text-muted-foreground text-xs">Duration</th>
                  <th className="text-left px-4 py-2.5 font-medium text-muted-foreground text-xs">Reviewed</th>
                  <th className="text-left px-4 py-2.5 font-medium text-muted-foreground text-xs">Age</th>
                  <th className="px-4 py-2.5" />
                </tr>
              </thead>
              <tbody>
                {loading ? (
                  Array.from({ length: 6 }).map((_, i) => (
                    <tr key={i} className="border-b">
                      {Array.from({ length: 8 }).map((_, j) => (
                        <td key={j} className="px-4 py-3">
                          <Skeleton className="h-3 w-full" />
                        </td>
                      ))}
                    </tr>
                  ))
                ) : filtered.length === 0 ? (
                  <tr>
                    <td colSpan={8} className="px-4 py-12 text-center text-muted-foreground text-sm">
                      No audit logs found.
                    </td>
                  </tr>
                ) : (
                  filtered.map((a) => {
                    const cfg = STATUS_CONFIG[a.audit_status] ?? STATUS_CONFIG.pending;
                    const topViolation = a.violations?.[0];
                    return (
                      <tr key={a.id} className="border-b hover:bg-muted/20 transition-colors">
                        <td className="px-4 py-3 font-mono text-xs text-muted-foreground">
                          {a.session_uuid.slice(0, 8)}…
                        </td>
                        <td className="px-4 py-3">
                          <span className={`inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-xs font-medium ${cfg.color}`}>
                            <cfg.icon className="size-3" />
                            {cfg.label}
                          </span>
                        </td>
                        <td className="px-4 py-3">
                          <RiskBar score={a.risk_score} />
                        </td>
                        <td className="px-4 py-3">
                          {topViolation ? (
                            <span className={`inline-flex px-1.5 py-0.5 rounded text-[10px] font-semibold uppercase tracking-wide ${SEVERITY_COLOR[topViolation.severity] ?? ""}`}>
                              {topViolation.type.replace(/_/g, " ")}
                            </span>
                          ) : (
                            <span className="text-xs text-muted-foreground">—</span>
                          )}
                        </td>
                        <td className="px-4 py-3 text-xs text-muted-foreground">
                          {a.duration_seconds ? `${Math.round(a.duration_seconds / 60)}m` : "—"}
                        </td>
                        <td className="px-4 py-3">
                          {a.reviewed ? (
                            <span className="text-xs text-emerald-600 font-medium">Reviewed</span>
                          ) : a.audit_status === "flagged" ? (
                            <span className="text-xs text-red-600 font-medium">Pending</span>
                          ) : (
                            <span className="text-xs text-muted-foreground">—</span>
                          )}
                        </td>
                        <td className="px-4 py-3 text-xs text-muted-foreground">
                          {formatDistanceToNow(new Date(a.created_at), { addSuffix: true })}
                        </td>
                        <td className="px-4 py-3">
                          <Link href={`/admin/sessions/${a.session_uuid}/review`}>
                            <Button variant="ghost" size="icon" className="size-7">
                              <ExternalLink className="size-3.5" />
                            </Button>
                          </Link>
                        </td>
                      </tr>
                    );
                  })
                )}
              </tbody>
            </table>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { Card, CardContent, CardHeader, CardTitle, CardDescription, CardFooter } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Switch } from "@/components/ui/switch";
import client from "@/lib/api/client";
import { format } from "date-fns";
import { useParams, useRouter } from "next/navigation";
import { toast } from "sonner";

export default function SessionReviewPage() {
  const params = useParams();
  const router = useRouter();
  const uuid = params.uuid;
  const [session, setSession] = useState<any>(null);
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [formData, setFormData] = useState<{
    status: string | null;
    admin_notes: string;
    generate_commission: boolean;
  }>({
    status: "",
    admin_notes: "",
    generate_commission: false
  });

  useEffect(() => {
    fetchSession();
  }, [uuid]);

  const fetchSession = async () => {
    setLoading(true);
    try {
      const res = await client.get(`/api/v1/admin/sessions/${uuid}/review`);
      setSession(res.data?.data || null);
      if (res.data?.data) {
        setFormData({
          status: res.data.data.status,
          admin_notes: res.data.data.notes || "",
          generate_commission: false
        });
      }
    } catch (error) {
      console.error("Failed to fetch session", error);
      toast.error("Failed to load session details");
    } finally {
      setLoading(false);
    }
  };

  const handleSubmit = async () => {
    setSubmitting(true);
    try {
      await client.put(`/api/v1/admin/sessions/${uuid}/review`, formData);
      toast.success("Session review updated successfully");
      router.push("/admin/sessions");
    } catch (error) {
      console.error("Failed to update session review", error);
      toast.error("Failed to update review");
    } finally {
      setSubmitting(false);
    }
  };

  if (loading) return <div className="p-8 text-center">Loading session details...</div>;
  if (!session) return <div className="p-8 text-center">Session not found.</div>;

  return (
    <main className="p-6 max-w-4xl mx-auto space-y-6">
      <div className="flex items-center gap-4 mb-4">
        <Button variant="outline" size="sm" onClick={() => router.back()}>← Back</Button>
        <h1 className="text-3xl font-bold">Session Review</h1>
      </div>

      <div className="grid md:grid-cols-2 gap-6">
        <Card>
          <CardHeader>
            <CardTitle>Session Details</CardTitle>
            <CardDescription>System recorded information</CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="flex justify-between border-b pb-2">
              <span className="text-sm font-medium text-muted-foreground">Session UUID</span>
              <span className="text-sm font-mono">{session.uuid.slice(0, 8)}...</span>
            </div>
            <div className="flex justify-between border-b pb-2">
              <span className="text-sm font-medium text-muted-foreground">Patient</span>
              <span className="text-sm">{session.patient?.full_name}</span>
            </div>
            <div className="flex justify-between border-b pb-2">
              <span className="text-sm font-medium text-muted-foreground">Therapist</span>
              <span className="text-sm">{session.therapist?.user?.full_name}</span>
            </div>
            <div className="flex justify-between border-b pb-2">
              <span className="text-sm font-medium text-muted-foreground">Scheduled At</span>
              <span className="text-sm">{format(new Date(session.scheduled_at), "MMM d, yyyy HH:mm")}</span>
            </div>
            <div className="flex justify-between border-b pb-2">
              <span className="text-sm font-medium text-muted-foreground">Type</span>
              <span className="text-sm capitalize">{session.session_type}</span>
            </div>
            <div className="flex justify-between border-b pb-2">
              <span className="text-sm font-medium text-muted-foreground">System Status</span>
              <Badge variant={session.status === 'completed' ? 'default' : 'secondary'}>{session.status}</Badge>
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader>
            <CardTitle>Join Analytics</CardTitle>
            <CardDescription>Actual participant activity</CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="flex justify-between border-b pb-2">
              <span className="text-sm font-medium text-muted-foreground">Patient Joined At</span>
              <span className="text-sm">{session.patient_joined_at ? format(new Date(session.patient_joined_at), "HH:mm:ss") : "NEVER"}</span>
            </div>
            <div className="flex justify-between border-b pb-2">
              <span className="text-sm font-medium text-muted-foreground">Therapist Joined At</span>
              <span className="text-sm">{session.therapist_joined_at ? format(new Date(session.therapist_joined_at), "HH:mm:ss") : "NEVER"}</span>
            </div>
            <div className="flex justify-between border-b pb-2">
              <span className="text-sm font-medium text-muted-foreground">Session Started At</span>
              <span className="text-sm">{session.session_started_at ? format(new Date(session.session_started_at), "HH:mm:ss") : "N/A"}</span>
            </div>
            <div className="flex justify-between border-b pb-2">
              <span className="text-sm font-medium text-muted-foreground">Actual Duration</span>
              <span className="text-sm font-bold">{session.actual_duration_minutes || 0} minutes</span>
            </div>
            <div className="pt-2">
              {session.actual_duration_minutes < 25 && (
                <div className="bg-red-50 text-red-600 p-3 rounded-lg text-xs font-bold flex items-center gap-2">
                  ⚠️ SHORT DURATION ALERT: Session lasted less than 25 minutes.
                </div>
              )}
              {!session.patient_joined_at && (
                <div className="bg-orange-50 text-orange-600 p-3 rounded-lg text-xs font-bold mt-2 flex items-center gap-2">
                  ⚠️ NO-SHOW ALERT: Patient never joined the room.
                </div>
              )}
            </div>
          </CardContent>
        </Card>
      </div>

      <Card>
        <CardHeader>
          <CardTitle>Review & Decision</CardTitle>
          <CardDescription>Admin override for session status and payouts</CardDescription>
        </CardHeader>
        <CardContent className="space-y-6">
          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label htmlFor="status">Final Status</Label>
              <Select value={formData.status} onValueChange={(v: string | null) => setFormData({...formData, status: v ?? ""})}>
                <SelectTrigger>
                  <SelectValue placeholder="Select final status" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="completed">Completed (Mark as successful)</SelectItem>
                  <SelectItem value="no_show">No Show (Patient missed session)</SelectItem>
                  <SelectItem value="ended_early">Ended Early (Incomplete)</SelectItem>
                  <SelectItem value="cancelled">Cancelled</SelectItem>
                </SelectContent>
              </Select>
            </div>

            <div className="flex items-center space-x-2 pt-8">
              <Switch 
                id="commission" 
                checked={formData.generate_commission}
                onCheckedChange={(v) => setFormData({...formData, generate_commission: v})}
              />
              <Label htmlFor="commission">Generate Therapist Commission</Label>
            </div>
          </div>

          <div className="space-y-2">
            <Label htmlFor="notes">Admin Review Notes</Label>
            <Textarea 
              id="notes" 
              placeholder="Reason for decision..." 
              value={formData.admin_notes}
              onChange={(e) => setFormData({...formData, admin_notes: e.target.value})}
            />
            <p className="text-xs text-muted-foreground italic">These notes will be stored for audit purposes.</p>
          </div>
        </CardContent>
        <CardFooter className="flex justify-end gap-3">
          <Button variant="outline" onClick={() => router.back()}>Cancel</Button>
          <Button onClick={handleSubmit} disabled={submitting}>
            {submitting ? "Updating..." : "Save Final Decision"}
          </Button>
        </CardFooter>
      </Card>
    </main>
  );
}

"use client";

import { useEffect, useState } from "react";
import { Card, CardContent } from "@/components/ui/card";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import client from "@/lib/api/client";
import { format } from "date-fns";
import Link from "next/link";
import { Search, Calendar, RefreshCw } from "lucide-react";
import { PageHeader } from "@/components/shared/page-header";
import { TableBodyShimmer } from "@/components/shared/shimmer-skeleton";

const STATUS_STYLES: Record<string, string> = {
  completed:  "bg-emerald-50 text-emerald-700",
  ongoing:    "bg-blue-50 text-blue-600",
  cancelled:  "bg-red-50 text-red-700",
  scheduled:  "bg-gray-50 text-gray-600",
  no_show:    "bg-orange-50 text-orange-700",
};

function SessionStatusBadge({ status }: { status: string }) {
  const style = STATUS_STYLES[status] ?? "bg-gray-100 text-gray-600";
  return (
    <span className={`inline-flex items-center px-2 py-0.5 rounded-full text-xs font-medium capitalize ${style}`}>
      {status?.replace(/_/g, " ")}
    </span>
  );
}

export default function SessionsPage() {
  const [sessions, setSessions] = useState<unknown[]>([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState("");

  useEffect(() => {
    fetchSessions();
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  const fetchSessions = async () => {
    setLoading(true);
    try {
      const res = await client.get("/api/v1/admin/sessions");
      const raw = res.data?.data;
      setSessions(Array.isArray(raw) ? raw : Array.isArray(raw?.data) ? raw.data : []);
    } catch (error) {
      console.error("Failed to fetch sessions", error);
    } finally {
      setLoading(false);
    }
  };

  const filteredSessions = (sessions as Record<string, unknown>[]).filter((s) => {
    const patient = s.patient as Record<string, unknown> | undefined;
    const therapist = s.therapist as Record<string, unknown> | undefined;
    const therapistUser = therapist?.user as Record<string, unknown> | undefined;
    const q = search.toLowerCase();
    return (
      (patient?.full_name as string)?.toLowerCase().includes(q) ||
      (therapistUser?.full_name as string)?.toLowerCase().includes(q) ||
      (s.uuid as string)?.includes(search)
    );
  });

  return (
    <main className="p-6 space-y-6">
      <PageHeader
        title="Platform Sessions"
        subtitle="All therapy sessions across the platform"
      >
        <div className="flex items-center gap-2">
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
            <Input
              placeholder="Search sessions…"
              className="pl-9 w-64"
              value={search}
              onChange={(e) => setSearch(e.target.value)}
            />
          </div>
          <Button onClick={fetchSessions} variant="outline" size="sm" className="gap-2">
            <RefreshCw className={`w-4 h-4 ${loading ? "animate-spin" : ""}`} />
            Refresh
          </Button>
        </div>
      </PageHeader>

      <Card>
        <CardContent className="p-0">
          <div className="overflow-x-auto">
            <Table>
              <TableHeader>
                <TableRow className="bg-gray-50">
                  <TableHead className="px-4 py-3 text-xs font-medium text-gray-500 uppercase tracking-wide">Date &amp; Time</TableHead>
                  <TableHead className="px-4 py-3 text-xs font-medium text-gray-500 uppercase tracking-wide">Patient</TableHead>
                  <TableHead className="px-4 py-3 text-xs font-medium text-gray-500 uppercase tracking-wide">Therapist</TableHead>
                  <TableHead className="px-4 py-3 text-xs font-medium text-gray-500 uppercase tracking-wide">Type</TableHead>
                  <TableHead className="px-4 py-3 text-xs font-medium text-gray-500 uppercase tracking-wide">Status</TableHead>
                  <TableHead className="px-4 py-3 text-xs font-medium text-gray-500 uppercase tracking-wide">Duration</TableHead>
                  <TableHead className="px-4 py-3 text-xs font-medium text-gray-500 uppercase tracking-wide text-right">Actions</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {loading ? (
                  <TableBodyShimmer rows={6} cols={7} />
                ) : filteredSessions.length === 0 ? (
                  <TableRow>
                    <TableCell colSpan={7}>
                      <div className="flex flex-col items-center justify-center py-16">
                        <Calendar className="w-10 h-10 text-gray-300 mb-3" />
                        <p className="text-sm font-medium text-gray-600">No sessions found</p>
                        <p className="text-xs text-gray-400 mt-1">
                          {search ? "Try a different search term" : "Sessions will appear here once scheduled"}
                        </p>
                      </div>
                    </TableCell>
                  </TableRow>
                ) : (
                  filteredSessions.map((session, idx) => {
                    const s = session as Record<string, unknown>;
                    const patient = s.patient as Record<string, unknown> | undefined;
                    const therapist = s.therapist as Record<string, unknown> | undefined;
                    const therapistUser = therapist?.user as Record<string, unknown> | undefined;
                    return (
                      <TableRow
                        key={s.id as string}
                        className={idx % 2 === 0 ? "bg-white hover:bg-teal/5" : "bg-gray-50/50 hover:bg-teal/5"}
                      >
                        <TableCell className="px-4 py-3 font-medium text-sm">
                          {s.scheduled_at
                            ? format(new Date(s.scheduled_at as string), "MMM d, yyyy HH:mm")
                            : "—"}
                        </TableCell>
                        <TableCell className="px-4 py-3">
                          <p className="text-sm font-medium text-gray-900">
                            {(patient?.full_name as string) || "Unknown"}
                          </p>
                          <p className="text-xs text-gray-400">{patient?.email as string}</p>
                        </TableCell>
                        <TableCell className="px-4 py-3 text-sm text-gray-700">
                          {(therapistUser?.full_name as string) || "Unknown"}
                        </TableCell>
                        <TableCell className="px-4 py-3 text-sm capitalize text-gray-600">
                          {(s.session_type as string)?.replace(/_/g, " ")}
                        </TableCell>
                        <TableCell className="px-4 py-3">
                          <SessionStatusBadge status={s.status as string} />
                        </TableCell>
                        <TableCell className="px-4 py-3 text-sm text-gray-600">
                          {((s.actual_duration_minutes as number) || 0)} mins
                        </TableCell>
                        <TableCell className="px-4 py-3 text-right">
                          <Button asChild variant="ghost" size="sm" className="text-teal hover:text-teal hover:bg-teal/5">
                            <Link href={`/admin/sessions/${s.uuid as string}/review`}>Review</Link>
                          </Button>
                        </TableCell>
                      </TableRow>
                    );
                  })
                )}
              </TableBody>
            </Table>
          </div>
        </CardContent>
      </Card>
    </main>
  );
}

"use client";

import { useEffect, useState, Suspense } from "react";
import { useSearchParams, useRouter } from "next/navigation";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Card, CardContent, CardDescription, CardHeader, CardTitle, CardFooter } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Button } from "@/components/ui/button";
import { Switch } from "@/components/ui/switch";
import { useSettingsStore } from "@/store/settings-store";
import { Loader2, Save } from "lucide-react";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Badge } from "@/components/ui/badge";

import { SubscriptionSettings } from "@/components/admin-dashboard/settings/subscription-settings";
import { MailSettings } from "@/components/admin-dashboard/settings/mail-settings";
import { IPProtectionSettings } from "@/components/admin-dashboard/settings/ip-protection-settings";
import { IPProtectionLogs } from "@/components/admin-dashboard/ip-protection-logs";
import { BrandingSettings } from "@/components/admin-dashboard/settings/branding-settings";
import type { AppSettings } from "@/lib/api/settings";
import client from "@/lib/api/client";
import { toast } from "@/components/ui/use-toast";

interface PayoutSetting {
  id: number;
  role: string;
  payout_day: number;
  minimum_amount_kobo: number;
  currency: string;
  provider: string;
  auto_process: boolean;
}

function SettingsContent() {
  const { settings, isLoading, fetchSettings, updateSettings, fetchPlans, quotaDefaults, quotaOverview, fetchQuotaDefaults, updateQuotaDefaults, fetchQuotaOverview, deviceFingerprints, fetchDeviceFingerprints } = useSettingsStore();
  const [localSettings, setLocalSettings] = useState(settings);
  const [localQuotas, setLocalQuotas] = useState(quotaDefaults);
  const searchParams = useSearchParams();
  const router = useRouter();
  const tabParam = (searchParams.get("tab") ?? "").toLowerCase();
  const availableTabs = ["general", "financial", "subscriptions", "features", "ai", "security", "env", "quotas", "navigation", "commission", "documents", "mail", "sms", "protection", "branding", "payouts", "geo", "gateways"];
  const initialTab = availableTabs.includes(tabParam) ? tabParam : "general";

  const [userRole, setUserRole] = useState<'admin' | 'ceo' | 'coo'>('admin');

  // SMS + WhatsApp settings state
  const [smsSettings, setSmsSettings] = useState({
    sms_enabled: true,
    termii_api_key: '',
    termii_sender_id: 'ONWYND',
    otp_expiry_mins: 10,
    otp_length: 6,
    event_otp: true,
    event_session_reminder: true,
    event_appointment: true,
    event_group_reminder: false,
    event_payment_confirmation: false,
    whatsapp_enabled: false,
    whatsapp_provider: 'qr' as 'qr' | 'meta' | 'termii',
    whatsapp_phone_number_id: '',
    meta_wa_phone_number_id: '',
    meta_wa_access_token: '',
    wa_event_session_reminder: false,
    wa_event_appointment: false,
    wa_event_group_reminder: false,
    wa_event_payment_confirmation: false,
  });

  // WhatsApp QR/status state
  const [waStatus, setWaStatus] = useState<{
    status?: string; phone?: string; pushName?: string; hasQr?: boolean;
    qr_status?: string; qr_hint?: string;
    termii_configured?: boolean;
    connected?: boolean; display_name?: string; quality?: string;
    phone_number_id_set?: boolean; access_token_set?: boolean; reason?: string;
  } | null>(null);
  const [waQr, setWaQr] = useState<string | null>(null);
  const [waLoading, setWaLoading] = useState(false);

  const fetchWaStatus = async () => {
    setWaLoading(true);
    try {
      const res = await client.get('/api/v1/admin/whatsapp/status');
      setWaStatus(res.data?.data ?? null);
    } catch { /* silent */ } finally { setWaLoading(false); }
  };

  const fetchWaQr = async () => {
    try {
      const res = await client.get('/api/v1/admin/whatsapp/qr');
      setWaQr(res.data?.data?.qr ?? null);
    } catch { setWaQr(null); }
  };

  const handleWaDisconnect = async () => {
    try {
      await client.post('/api/v1/admin/whatsapp/disconnect');
      toast({ title: 'WhatsApp disconnected' });
      fetchWaStatus();
      setWaQr(null);
    } catch {
      toast({ title: 'Error', description: 'Failed to disconnect', variant: 'destructive' });
    }
  };
  const [smsTemplates, setSmsTemplates] = useState({
    otp:                  "Your {app_name} verification code is {code}. Valid for {expiry_mins} minutes. Do not share this code.",
    session_reminder:     "Hi {name}, reminder: therapy session with {therapist_name} at {session_time}. Log in via {app_name}.",
    appointment:          "Hi {name}, appointment with {therapist_name} confirmed for {date} at {time}. — {app_name}.",
    group_reminder:       "Hi {name}, group session \"{session_title}\" starts at {time}. Join via {app_name} dashboard.",
    payment_confirmation: "Hi {name}, payment of {amount} {currency} for {plan_name} was successful. — {app_name}.",
  });
  const [smsTemplatesSaving, setSmsTemplatesSaving] = useState(false);
  const [smsSaving, setSmsSaving] = useState(false);

  const handleSaveSms = async () => {
    setSmsSaving(true);
    try {
      await client.put('/api/v1/admin/settings/sms', smsSettings);
      toast({ title: 'SMS settings saved' });
    } catch {
      toast({ title: 'Error', description: 'Failed to save SMS settings', variant: 'destructive' });
    } finally {
      setSmsSaving(false);
    }
  };

  const handleSaveSmsTemplates = async () => {
    setSmsTemplatesSaving(true);
    try {
      await client.put('/api/v1/admin/settings/sms_templates', smsTemplates);
      toast({ title: 'SMS templates saved' });
    } catch {
      toast({ title: 'Error', description: 'Failed to save SMS templates', variant: 'destructive' });
    } finally {
      setSmsTemplatesSaving(false);
    }
  };

  // Gateway settings state — flat key/value map: {name}_enabled, {name}_mode, {name}_{mode}_key…
  type GatewaySettings = Record<string, boolean | string>;
  const buildDefaultGateways = (): GatewaySettings => {
    const out: GatewaySettings = {};
    const defaultsOn = ['paystack', 'dodopayments'];
    for (const gw of ['paystack', 'flutterwave', 'klump', 'stripe', 'dodopayments']) {
      out[`${gw}_enabled`]         = defaultsOn.includes(gw);
      out[`${gw}_mode`]            = 'test';
      out[`${gw}_test_public_key`] = '';
      out[`${gw}_test_secret_key`] = '';
      out[`${gw}_live_public_key`] = '';
      out[`${gw}_live_secret_key`] = '';
    }
    return out;
  };
  const [gatewaySettings, setGatewaySettings] = useState<GatewaySettings>(buildDefaultGateways());
  const [gatewayLoading, setGatewayLoading] = useState(false);
  const [gatewaySaving, setGatewaySaving] = useState(false);

  // Geo settings state
  const [geoSettings, setGeoSettings] = useState({
    auto_detect: true,
    regional_testimonials: true,
    regional_pricing: true,
    regional_phone: true,
    regional_payment_gateway: true,
    international_gateway: "dodopayments" as "dodopayments" | "stripe" | "flutterwave",
    stripe_paused: true,
  });
  const [geoLoading, setGeoLoading] = useState(false);
  const [geoSaving, setGeoSaving] = useState(false);

  // Payout settings state
  const [payoutSettings, setPayoutSettings] = useState<PayoutSetting[]>([]);
  const [payoutLoading, setPayoutLoading] = useState(false);
  const [savingPayout, setSavingPayout] = useState<string | null>(null);

  const fetchPayoutSettings = async () => {
    setPayoutLoading(true);
    try {
      const res = await client.get("/api/v1/admin/payout-settings");
      const d = res.data?.data ?? res.data;
      setPayoutSettings(Array.isArray(d) ? d : []);
    } catch {
      toast({ title: "Error", description: "Failed to load payout settings", variant: "destructive" });
    } finally {
      setPayoutLoading(false);
    }
  };

  const savePayoutSetting = async (setting: PayoutSetting) => {
    setSavingPayout(setting.role);
    try {
      await client.patch(`/api/v1/admin/payout-settings/${setting.role}`, setting);
      toast({ title: "Saved", description: `Payout settings for ${setting.role} updated.` });
    } catch {
      toast({ title: "Error", description: "Failed to save payout setting", variant: "destructive" });
    } finally {
      setSavingPayout(null);
    }
  };

  const updatePayoutField = (role: string, field: keyof PayoutSetting, value: unknown) => {
    setPayoutSettings((prev: PayoutSetting[]) => prev.map((s: PayoutSetting) => s.role === role ? { ...s, [field]: value } : s));
  };

  useEffect(() => {
    const userStr = localStorage.getItem("user");
    if (userStr) {
      try {
        const user = JSON.parse(userStr);
        const role = user.role?.slug || user.role || 'admin';
        setUserRole(role);
      } catch (e) {
        console.error("Failed to parse user from localStorage", e);
      }
    }
  }, []);

  useEffect(() => {
    fetchSettings();
    fetchPlans();
    fetchQuotaDefaults();
    fetchQuotaOverview();
    fetchDeviceFingerprints();
    fetchPayoutSettings();
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [fetchSettings, fetchPlans, fetchQuotaDefaults, fetchQuotaOverview, fetchDeviceFingerprints]);

  useEffect(() => {
    setLocalSettings(settings);
  }, [settings]);

  useEffect(() => {
    setLocalQuotas(quotaDefaults);
  }, [quotaDefaults]);

  // Gateway + SMS settings fetch
  useEffect(() => {
    setGatewayLoading(true);
    client.get("/api/v1/admin/settings")
      .then((res) => {
        const d = res.data?.data ?? res.data ?? {};
        const gw = d.gateways ?? {};
        if (Object.keys(gw).length) setGatewaySettings((prev) => ({ ...prev, ...gw }));
        const sms = d.sms ?? {};
        if (Object.keys(sms).length) setSmsSettings((prev) => ({ ...prev, ...sms }));
        const tmpl = d.sms_templates ?? {};
        if (Object.keys(tmpl).length) setSmsTemplates((prev) => ({ ...prev, ...tmpl }));
      })
      .catch(() => {})
      .finally(() => setGatewayLoading(false));
  }, []);

  const handleSaveGateways = async () => {
    setGatewaySaving(true);
    try {
      await client.put("/api/v1/admin/settings/gateways", gatewaySettings);
      toast({ title: "Gateway settings saved" });
    } catch {
      toast({ title: "Error", description: "Failed to save gateway settings", variant: "destructive" });
    } finally {
      setGatewaySaving(false);
    }
  };

  // Geo settings fetch + save
  useEffect(() => {
    setGeoLoading(true);
    client.get("/api/v1/public/config")
      .then((res) => {
        const geo = res.data?.data?.geo ?? res.data?.geo ?? {};
        if (Object.keys(geo).length) setGeoSettings((prev) => ({ ...prev, ...geo }));
      })
      .catch(() => {})
      .finally(() => setGeoLoading(false));
  }, []);

  const handleSaveGeo = async () => {
    setGeoSaving(true);
    try {
      await client.put("/api/v1/admin/settings/geo", geoSettings);
      toast({ title: "Geo settings saved" });
    } catch {
      toast({ title: "Error", description: "Failed to save geo settings", variant: "destructive" });
    } finally {
      setGeoSaving(false);
    }
  };

  const handleSaveQuotas = async () => {
    if (!localQuotas) return;
    await updateQuotaDefaults(localQuotas);
  };

  const updateLocalQuota = (key: string, value: number) => {
    setLocalQuotas((prev) => prev ? { ...prev, [key]: value } : prev);
  };

  const handleSave = async (section: keyof AppSettings) => {
    if (!localSettings) return;
    await updateSettings(section, localSettings[section]);
  };

  const updateLocal = (section: string, key: string, value: unknown) => {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    setLocalSettings((prev: any) => ({
      ...prev,
      [section]: {
        ...prev[section],
        [key]: value
      }
    }));
  };

  if (!localSettings) {
    return <div className="flex justify-center p-10"><Loader2 className="animate-spin" /></div>;
  }

  return (
    <div className="w-full p-6 space-y-6">
      <div className="flex items-center justify-between">
        <h1 className="text-3xl font-bold tracking-tight">Settings</h1>
        <p className="text-muted-foreground">Manage application configuration.</p>
      </div>

      <Tabs defaultValue={initialTab} className="w-full" onValueChange={(val) => router.replace(`/admin/settings?tab=${val}`)}>
        <TabsList className="flex flex-wrap h-auto gap-1 bg-transparent border-none">
          <TabsTrigger value="general" className="data-[state=active]:bg-muted">General</TabsTrigger>
          <TabsTrigger value="financial" className="data-[state=active]:bg-muted">Financial</TabsTrigger>
          <TabsTrigger value="subscriptions" className="data-[state=active]:bg-muted">Plans</TabsTrigger>
          <TabsTrigger value="features" className="data-[state=active]:bg-muted">Features</TabsTrigger>
          <TabsTrigger value="ai" className="data-[state=active]:bg-muted">AI</TabsTrigger>
          <TabsTrigger value="security" className="data-[state=active]:bg-muted">Security</TabsTrigger>
          <TabsTrigger value="env" className="data-[state=active]:bg-muted">Keys</TabsTrigger>
          <TabsTrigger value="quotas" className="data-[state=active]:bg-muted">Quotas</TabsTrigger>
          <TabsTrigger value="navigation" className="data-[state=active]:bg-muted">Navigation</TabsTrigger>
          <TabsTrigger value="commission" className="data-[state=active]:bg-muted">Commission</TabsTrigger>
          <TabsTrigger value="documents" className="data-[state=active]:bg-muted">Documents</TabsTrigger>
          <TabsTrigger value="mail" className="data-[state=active]:bg-muted">Mail</TabsTrigger>
          <TabsTrigger value="protection" className="data-[state=active]:bg-muted">IP Protection</TabsTrigger>
          <TabsTrigger value="branding" className="data-[state=active]:bg-muted">Branding</TabsTrigger>
          <TabsTrigger value="payouts" className="data-[state=active]:bg-muted">Payouts</TabsTrigger>
          <TabsTrigger value="sms" className="data-[state=active]:bg-muted">SMS</TabsTrigger>
          <TabsTrigger value="geo" className="data-[state=active]:bg-muted">Geo & Localization</TabsTrigger>
          <TabsTrigger value="gateways" className="data-[state=active]:bg-muted">Gateways</TabsTrigger>
        </TabsList>

        {/* General Settings */}
        <TabsContent value="general">
          <Card>
            <CardHeader>
              <CardTitle>General Settings</CardTitle>
              <CardDescription>Basic application information and defaults.</CardDescription>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="space-y-2">
                <Label htmlFor="siteName">Site Name</Label>
                <Input 
                  id="siteName" 
                  value={localSettings.general.siteName} 
                  onChange={(e) => updateLocal('general', 'siteName', e.target.value)} 
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="supportEmail">Support Email</Label>
                <Input 
                  id="supportEmail" 
                  type="email" 
                  value={localSettings.general.supportEmail} 
                  onChange={(e) => updateLocal('general', 'supportEmail', e.target.value)} 
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="baseCurrency">Base Currency</Label>
                <Select 
                  value={localSettings.general.baseCurrency} 
                  onValueChange={(val) => updateLocal('general', 'baseCurrency', val)}
                >
                  <SelectTrigger>
                    <SelectValue placeholder="Select currency" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="USD">USD ($)</SelectItem>
                    <SelectItem value="EUR">EUR (€)</SelectItem>
                    <SelectItem value="GBP">GBP (£)</SelectItem>
                    <SelectItem value="NGN">NGN (₦)</SelectItem>
                  </SelectContent>
                </Select>
              </div>
              <div className="flex items-center justify-between rounded-lg border p-4">
                <div className="space-y-0.5">
                  <Label className="text-base">Maintenance Mode</Label>
                  <div className="text-sm text-muted-foreground">Disable access for non-admins</div>
                </div>
                <Switch 
                  checked={localSettings.general.maintenanceMode} 
                  onCheckedChange={(checked) => updateLocal('general', 'maintenanceMode', checked)} 
                />
              </div>
            </CardContent>
            <CardFooter>
              <Button onClick={() => handleSave('general')} disabled={isLoading}>
                {isLoading && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                <Save className="mr-2 h-4 w-4" /> Save Changes
              </Button>
            </CardFooter>
          </Card>
        </TabsContent>

        {/* Financial Settings — DB3 */}
        <TabsContent value="financial">
          <Card>
            <CardHeader>
              <CardTitle>Financial Settings</CardTitle>
              <CardDescription>Commission rates, platform fees, and payout thresholds.</CardDescription>
            </CardHeader>
            <CardContent className="space-y-4">
