"use client";

import { useEffect, useState } from "react";
import { useForm, Controller } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import * as z from "zod";

import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { RadioGroup, RadioGroupItem } from "@/components/ui/radio-group";
import { useToast } from "@/components/ui/use-toast";
import { adminService } from "@/lib/api/admin";

const supportSettingsSchema = z.object({
  provider: z.enum(["ai_internal", "chatwoot", "intercom"]),
  chatwoot_url: z.string().optional(),
  chatwoot_website_token: z.string().optional(),
  intercom_app_id: z.string().optional(),
});

type SupportSettingsFormValues = z.infer<typeof supportSettingsSchema>;

export default function SupportSettingsPage() {
  const { toast } = useToast();
  const [loading, setLoading] = useState(true);

  const form = useForm<SupportSettingsFormValues>({
    resolver: zodResolver(supportSettingsSchema),
    defaultValues: {
      provider: "ai_internal",
    },
  });

  useEffect(() => {
    const fetchSettings = async () => {
      try {
        const settings = await adminService.getSettings();
        if (settings.support) {
          form.reset(settings.support);
        }
      } catch (error) {
        toast({
          variant: "destructive",
          title: "Failed to load settings",
          description: "Could not retrieve current support settings from the server.",
        });
      } finally {
        setLoading(false);
      }
    };
    fetchSettings();
  }, [form, toast]);

  const onSubmit = async (data: SupportSettingsFormValues) => {
    try {
      await adminService.updateSettings("support", data);
      toast({
        title: "Settings Saved",
        description: "Support settings have been updated successfully.",
      });
    } catch (error) {
      toast({
        variant: "destructive",
        title: "Save Failed",
        description: "Could not save support settings. Please try again.",
      });
    }
  };

  const provider = form.watch("provider");

  if (loading) {
    return <div>Loading...</div>; // Replace with a proper skeleton loader
  }

  return (
    <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-8">
      <Card>
        <CardHeader>
          <CardTitle>Live Support Configuration</CardTitle>
          <CardDescription>
            Choose the provider for the customer support chat widget.
          </CardDescription>
        </CardHeader>
        <CardContent className="space-y-6">
          <Controller
            name="provider"
            control={form.control}
            render={({ field }) => (
              <RadioGroup
                onValueChange={field.onChange}
                value={field.value}
                className="grid grid-cols-1 md:grid-cols-3 gap-4"
              >
                <Label className="flex flex-col items-start space-y-2 border rounded-md p-4 hover:bg-accent hover:text-accent-foreground [&:has([data-state=checked])]:border-primary">
                  <div className="flex items-center space-x-3">
                    <RadioGroupItem value="ai_internal" />
                    <span className="font-bold">Internal AI Support</span>
                  </div>
                  <p className="text-sm text-muted-foreground pl-6">
                    Use the built-in AI companion for initial support queries.
                  </p>
                </Label>
                <Label className="flex flex-col items-start space-y-2 border rounded-md p-4 hover:bg-accent hover:text-accent-foreground [&:has([data-state=checked])]:border-primary">
                  <div className="flex items-center space-x-3">
                    <RadioGroupItem value="chatwoot" />
                    <span className="font-bold">Chatwoot</span>
                  </div>
                  <p className="text-sm text-muted-foreground pl-6">
                    Integrate with a self-hosted or cloud Chatwoot instance.
                  </p>
                </Label>
                <Label className="flex flex-col items-start space-y-2 border rounded-md p-4 hover:bg-accent hover:text-accent-foreground [&:has([data-state=checked])]:border-primary">
                  <div className="flex items-center space-x-3">
                    <RadioGroupItem value="intercom" />
                    <span className="font-bold">Intercom</span>
                  </div>
                  <p className="text-sm text-muted-foreground pl-6">
                    Use the Intercom messenger widget for live support.
                  </p>
                </Label>
              </RadioGroup>
            )}
          />

          {provider === "chatwoot" && (
            <div className="space-y-4 pt-4 border-t">
              <h3 className="text-lg font-medium">Chatwoot Settings</h3>
              <div className="space-y-2">
                <Label htmlFor="chatwoot_url">Chatwoot URL</Label>
                <Input
                  id="chatwoot_url"
                  placeholder="https://chat.yourdomain.com"
                  {...form.register("chatwoot_url")}
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="chatwoot_website_token">Website Token</Label>
                <Input
                  id="chatwoot_website_token"
                  type="password"
                  placeholder="****************"
                  {...form.register("chatwoot_website_token")}
                />
              </div>
            </div>
          )}

          {provider === "intercom" && (
            <div className="space-y-4 pt-4 border-t">
              <h3 className="text-lg font-medium">Intercom Settings</h3>
              <div className="space-y-2">
                <Label htmlFor="intercom_app_id">App ID</Label>
                <Input
                  id="intercom_app_id"
                  placeholder="Your Intercom App ID"
                  {...form.register("intercom_app_id")}
                />
              </div>
            </div>
          )}
        </CardContent>
      </Card>

      <Button type="submit" disabled={form.formState.isSubmitting}>
        {form.formState.isSubmitting ? "Saving..." : "Save Changes"}
      </Button>
    </form>
  );
}

"use client";

import { useEffect, useState, useCallback } from "react";
import { adminService } from "@/lib/api/admin";
import { Card, CardContent } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import {
  Table, TableBody, TableCell, TableHead, TableHeader, TableRow,
} from "@/components/ui/table";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Loader2, Search, GraduationCap, ShieldCheck, ShieldAlert, CalendarClock } from "lucide-react";
import { toast } from "@/components/ui/use-toast";
import { addYears, format, parseISO } from "date-fns";

type UserSubscription = {
  id: number;
  user_id: number;
  plan_id: number;
  status: string;
  plan_type: string;
  current_period_start?: string;
  current_period_end?: string;
  auto_renew: boolean;
  cancelled_at?: string;
  subscribed_at: string;
  user_name: string;
  user_email: string;
  plan_name: string;
  plan_slug: string;
  billing_interval: string;
  price_ngn?: number;
  price_usd?: number;
  student_verification_status?: string | null;
  student_verified_at?: string | null;
  student_email?: string | null;
  student_id?: string | null;
  comped_flag?: number | string | boolean | null;
  approved_by_name?: string | null;
};

type Meta = {
  current_page: number;
  last_page: number;
  per_page: number;
  total: number;
};

function fmt(d?: string | null) {
  if (!d) return "—";
  try { return format(parseISO(d), "MMM d, yyyy"); } catch { return d; }
}

function computeMethod(s: UserSubscription): string {
  const email = (s.student_email ?? "").toLowerCase();
  const domain = email.includes("@") ? email.split("@").pop() ?? "" : email;
  if (domain.endsWith(".edu.ng") || domain.endsWith(".ac.ng")) return "Email Domain";
  if (s.student_id) return "Student ID";
  return "Manual";
}

function computeExpiry(verifiedAt?: string | null) {
  if (!verifiedAt) return "—";
  try {
    const dt = parseISO(verifiedAt);
    const exp = addYears(dt, 4);
    return format(exp, "MMM d, yyyy");
  } catch {
    return "—";
  }
}

export default function StudentSubscriptionsPage() {
  const [subs, setSubs] = useState<UserSubscription[]>([]);
  const [meta, setMeta] = useState<Meta | null>(null);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState("");
  const [status, setStatus] = useState<"all" | "active" | "cancelled" | "past_due" | "trial">("all");
  const [page, setPage] = useState(1);

  const load = useCallback(async (p = page, q = search, s = status) => {
    setLoading(true);
    try {
      const res = await adminService.getUserSubscriptions({
        page: p,
        search: q || undefined,
        status: s !== "all" ? s : undefined,
        plan_type: "d2c",
        per_page: 20,
      });
      const list: UserSubscription[] = (res.data ?? res ?? []).filter((r: UserSubscription) => r.plan_slug === "student");
      setSubs(list);
      setMeta(res.meta ?? null);
    } catch {
      toast({ description: "Failed to load student subscriptions.", variant: "destructive" });
    } finally {
      setLoading(false);
    }
  }, [page, search, status]);

  useEffect(() => { load(1, "", "active"); }, []); // eslint-disable-line react-hooks/exhaustive-deps

  return (
    <div className="p-4 md:p-8 space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold flex items-center gap-2">
            <GraduationCap className="h-6 w-6 text-primary" />
            Student Subscriptions
          </h1>
          <p className="text-sm text-muted-foreground">
            Active users on the Student plan with verification details.
          </p>
        </div>
      </div>

      <Card>
        <CardContent className="p-4 space-y-4">
          <div className="flex flex-col md:flex-row md:items-center gap-3">
            <div className="relative md:w-80">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
              <Input
                placeholder="Search by name or email"
                className="pl-9"
                value={search}
                onChange={(e) => setSearch(e.target.value)}
                onKeyDown={(e) => { if (e.key === "Enter") load(1, search, status); }}
              />
            </div>
            <Select value={status} onValueChange={(v: any) => setStatus(v)}>
              <SelectTrigger className="w-[180px]">
                <SelectValue placeholder="Status" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="all">All status</SelectItem>
                <SelectItem value="active">Active</SelectItem>
                <SelectItem value="trial">Trial</SelectItem>
                <SelectItem value="past_due">Past Due</SelectItem>
                <SelectItem value="cancelled">Cancelled</SelectItem>
              </SelectContent>
            </Select>
            <Button onClick={() => load(1, search, status)}>Apply</Button>
          </div>

          <div className="rounded-md border">
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>User</TableHead>
                  <TableHead>Email</TableHead>
                  <TableHead>Plan</TableHead>
                  <TableHead>Status</TableHead>
                  <TableHead>Verified</TableHead>
                  <TableHead>Method</TableHead>
                  <TableHead>Expiry</TableHead>
                  <TableHead>Started</TableHead>
                  <TableHead>Renews</TableHead>
                  <TableHead className="text-right">Actions</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {loading ? (
                  <TableRow>
                    <TableCell colSpan={8} className="py-10 text-center">
                      <Loader2 className="h-5 w-5 animate-spin inline-block text-muted-foreground" />
                    </TableCell>
                  </TableRow>
                ) : subs.length === 0 ? (
                  <TableRow>
                    <TableCell colSpan={8} className="py-10 text-center text-muted-foreground">
                      No student subscriptions found.
                    </TableCell>
                  </TableRow>
                ) : (
                  subs.map((s) => {
                    const verified = s.student_verification_status === "approved" || s.student_verification_status === "verified";
                    return (
                      <TableRow key={s.id}>
                        <TableCell className="font-medium">{s.user_name}</TableCell>
                        <TableCell className="text-muted-foreground">{s.user_email}</TableCell>
                        <TableCell>
                          <div className="flex items-center gap-2">
                            <Badge variant="outline">{s.plan_name}</Badge>
                            {String(s.comped_flag) === "1" || String(s.comped_flag).toLowerCase() === "true" ? (
                              <span
                                title={s.approved_by_name ? `Approved by ${s.approved_by_name}` : "Approved by Admin"}
                                className="inline-flex items-center gap-1 px-1.5 py-0.5 rounded-md text-[10px] font-semibold bg-sage/10 text-[#3d4a26] border border-sage/30"
                              >
                                Approved by Admin
                              </span>
                            ) : null}
                          </div>
                        </TableCell>
                        <TableCell>
                          <Badge className="capitalize">{s.status.replace("_", " ")}</Badge>
                        </TableCell>
                        <TableCell>
                          {verified ? (
                            <span className="inline-flex items-center gap-1 text-green-700 bg-green-50 px-2 py-0.5 rounded-full text-xs">
                              <ShieldCheck className="h-3 w-3" /> {fmt(s.student_verified_at)}
                            </span>
                          ) : (
                            <span className="inline-flex items-center gap-1 text-amber-700 bg-amber-50 px-2 py-0.5 rounded-full text-xs">
                              <ShieldAlert className="h-3 w-3" /> Pending
                            </span>
                          )}
                        </TableCell>
                        <TableCell className="text-xs">{computeMethod(s)}</TableCell>
                        <TableCell className="text-xs">{computeExpiry(s.student_verified_at)}</TableCell>
                        <TableCell className="text-xs">{fmt(s.current_period_start ?? s.subscribed_at)}</TableCell>
                        <TableCell className="text-xs">{fmt(s.current_period_end)}</TableCell>
                        <TableCell className="text-right">
                          <UpgradeButton userId={s.user_id} currentPlanSlug={s.plan_slug} />
                        </TableCell>
                      </TableRow>
                    );
                  })
                )}
              </TableBody>
            </Table>
          </div>

          <div className="flex items-center justify-between pt-2">
            <div className="text-xs text-muted-foreground">
              {meta ? `Page ${meta.current_page} of ${meta.last_page}` : ""}
            </div>
            <div className="flex gap-2">
              <Button
                variant="outline"
                size="sm"
                disabled={!meta || meta.current_page <= 1 || loading}
                onClick={() => { const p = Math.max(1, (meta?.current_page ?? 1) - 1); setPage(p); load(p, search, status); }}
              >
                Prev
              </Button>
              <Button
                variant="outline"
                size="sm"
                disabled={!meta || meta.current_page >= (meta?.last_page ?? 1) || loading}
                onClick={() => { const p = Math.min((meta?.last_page ?? 1), (meta?.current_page ?? 1) + 1); setPage(p); load(p, search, status); }}
              >
                Next
              </Button>
            </div>
          </div>
        </CardContent>
      </Card>

      <Card>
        <CardContent className="p-4 flex items-center gap-3 text-sm text-muted-foreground">
          <CalendarClock className="h-4 w-4" />
          Student verification expires 4 years after approval. Renew upon graduation.
        </CardContent>
      </Card>
    </div>
  );
}

function UpgradeButton({ userId, currentPlanSlug }: { userId: number; currentPlanSlug?: string }) {
  const [open, setOpen] = useState(false);
  const [plans, setPlans] = useState<Array<{ uuid: string; name: string; slug: string; plan_type?: string; billing_interval?: string }>>([]);
  const [selected, setSelected] = useState<string>("");
  const [saving, setSaving] = useState(false);
  const [includeRevenue, setIncludeRevenue] = useState(false);

  const loadPlans = useCallback(async () => {
    try {
      const res = await adminService.getAllPlans();
      const list = Array.isArray((res as any)?.data) ? (res as any).data : Array.isArray(res) ? res : [];
      setPlans(list);
    } catch {
      // ignore
    }
  }, []);

  useEffect(() => {
    if (open && plans.length === 0) loadPlans();
  }, [open, plans.length, loadPlans]);

  const submit = async () => {
    if (!selected) return;
    setSaving(true);
    try {
      await adminService.upgradeUserSubscription(userId, {
        plan_uuid: selected,
        comped: true,
        include_in_revenue: includeRevenue,
      });
      setOpen(false);
      toast({ description: "Subscription upgraded.", variant: "default" });
    } catch {
      toast({ description: "Failed to upgrade subscription.", variant: "destructive" });
    } finally {
      setSaving(false);
    }
  };

  return (
    <>
      <Button size="sm" variant="outline" onClick={() => setOpen(true)}>
        Upgrade
      </Button>
      {open && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40">
          <div className="w-[560px] max-w-[90vw] rounded-xl bg-white p-5 space-y-4">
            <div className="flex items-center justify-between">
              <div>
                <h3 className="text-base font-semibold">Upgrade Subscription</h3>
                <p className="text-xs text-muted-foreground">Current: {currentPlanSlug ?? "none"}</p>
              </div>
              <button className="text-sm text-muted-foreground" onClick={() => setOpen(false)}>Close</button>
            </div>
            <div className="space-y-2">
              <label className="text-sm font-medium">Select Plan</label>
              <Select value={selected} onValueChange={(v: string | null) => setSelected(v ?? "")}>
                <SelectTrigger>
                  <SelectValue placeholder="Choose a plan" />
                </SelectTrigger>
                <SelectContent>
                  {plans.map((p) => (
                    <SelectItem key={p.uuid} value={p.uuid}>
                      {p.name} {p.plan_type ? `· ${p.plan_type}` : ""} {p.billing_interval ? `· ${p.billing_interval}` : ""}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
            <div className="flex items-center justify-between rounded-lg border p-3">
              <div className="space-y-0.5">
                <p className="text-sm font-medium">Include in revenue reports</p>
                <p className="text-xs text-muted-foreground">Count this admin-applied upgrade towards revenue.</p>
              </div>
              <input
                type="checkbox"
                checked={includeRevenue}
                onChange={(e) => setIncludeRevenue(e.target.checked)}
                aria-label="Include in revenue"
                className="w-4 h-4"
              />
            </div>
            <div className="flex justify-end gap-2 pt-2">
              <Button variant="outline" onClick={() => setOpen(false)}>Cancel</Button>
              <Button onClick={submit} disabled={!selected || saving}>
                {saving && <Loader2 className="h-4 w-4 animate-spin mr-2" />}
                Apply
              </Button>
            </div>
          </div>
        </div>
      )}
    </>
  );
}

"use client";

import { useEffect, useState, useCallback, useRef } from "react";
import { adminService } from "@/lib/api/admin";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import { Input } from "@/components/ui/input";
import { ScrollArea } from "@/components/ui/scroll-area";
import { toast } from "@/components/ui/use-toast";
import {
  Loader2,
  RefreshCw,
  Trash2,
  FileText,
  Filter,
  Search,
  AlertCircle,
  AlertTriangle,
  Info,
  Bug,
} from "lucide-react";

interface LogLine {
  timestamp: string | null;
  level: string;
  message: string;
  raw: string;
}

interface LogData {
  lines: LogLine[];
  total: number;
  file_size: number;
}

const LEVEL_CONFIG: Record<string, { label: string; color: string; icon: React.ElementType }> = {
  error:     { label: "Error",     color: "bg-red-100 text-red-700 border-red-200",     icon: AlertCircle },
  critical:  { label: "Critical",  color: "bg-red-100 text-red-800 border-red-300",     icon: AlertCircle },
  alert:     { label: "Alert",     color: "bg-red-100 text-red-700 border-red-200",     icon: AlertCircle },
  emergency: { label: "Emergency", color: "bg-red-200 text-red-900 border-red-400",     icon: AlertCircle },
  warning:   { label: "Warning",   color: "bg-yellow-100 text-yellow-700 border-yellow-200", icon: AlertTriangle },
  notice:    { label: "Notice",    color: "bg-blue-100 text-blue-700 border-blue-200",  icon: Info },
  info:      { label: "Info",      color: "bg-blue-100 text-blue-600 border-blue-200",  icon: Info },
  debug:     { label: "Debug",     color: "bg-gray-100 text-gray-600 border-gray-200",  icon: Bug },
};

const ROW_COLORS: Record<string, string> = {
  error:     "border-l-4 border-l-red-500 bg-red-50/40",
  critical:  "border-l-4 border-l-red-600 bg-red-50/60",
  alert:     "border-l-4 border-l-red-500 bg-red-50/40",
  emergency: "border-l-4 border-l-red-700 bg-red-50/80",
  warning:   "border-l-4 border-l-yellow-400 bg-yellow-50/40",
  notice:    "border-l-4 border-l-blue-400 bg-blue-50/30",
  info:      "border-l-4 border-l-blue-400 bg-blue-50/20",
  debug:     "border-l-4 border-l-gray-300 bg-transparent",
};

function formatBytes(bytes: number): string {
  if (bytes < 1024) return `${bytes} B`;
  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
  return `${(bytes / 1024 / 1024).toFixed(2)} MB`;
}

export default function LogsPage() {
  const [data, setData] = useState<LogData | null>(null);
  const [loading, setLoading] = useState(true);
  const [clearing, setClearing] = useState(false);
  const [clearOpen, setClearOpen] = useState(false);
  const [lines, setLines] = useState("200");
  const [levelFilter, setLevelFilter] = useState("all");
  const [search, setSearch] = useState("");
  const bottomRef = useRef<HTMLDivElement>(null);

  const load = useCallback(async () => {
    setLoading(true);
    try {
      const res = await adminService.getLogs(Number(lines));
      setData(res as any);
    } catch {
      toast({ title: "Failed to load logs", variant: "destructive" });
    } finally {
      setLoading(false);
    }
  }, [lines]);

  useEffect(() => { load(); }, [load]);

  // Auto-scroll to bottom on new data
  useEffect(() => {
    if (data && bottomRef.current) {
      bottomRef.current.scrollIntoView({ behavior: "smooth" });
    }
  }, [data]);

  const handleClear = async () => {
    setClearing(true);
    try {
      await adminService.clearLogs();
      toast({ title: "Logs cleared successfully" });
      setData({ lines: [], total: 0, file_size: 0 });
    } catch {
      toast({ title: "Failed to clear logs", variant: "destructive" });
    } finally {
      setClearing(false);
      setClearOpen(false);
    }
  };

  const filtered = data?.lines.filter((l) => {
    if (levelFilter !== "all" && l.level !== levelFilter) return false;
    if (search && !l.message.toLowerCase().includes(search.toLowerCase()) && !l.raw.toLowerCase().includes(search.toLowerCase())) return false;
    return true;
  }) ?? [];

  const levelCounts = data?.lines.reduce<Record<string, number>>((acc, l) => {
    acc[l.level] = (acc[l.level] ?? 0) + 1;
    return acc;
  }, {}) ?? {};

  return (
    <div className="p-6 space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold flex items-center gap-2">
            <FileText className="h-6 w-6" />
            Laravel Logs
          </h1>
          {data && (
            <p className="text-sm text-muted-foreground mt-1">
              {data.total.toLocaleString()} total lines · {formatBytes(data.file_size)} on disk
            </p>
          )}
        </div>
        <div className="flex gap-2">
          <Button variant="outline" size="sm" onClick={load} disabled={loading}>
            <RefreshCw className={`h-4 w-4 mr-2 ${loading ? "animate-spin" : ""}`} />
            Refresh
          </Button>
          <Button
            variant="destructive"
            size="sm"
            onClick={() => setClearOpen(true)}
            disabled={clearing || loading}
          >
            <Trash2 className="h-4 w-4 mr-2" />
            Clear Logs
          </Button>
        </div>
      </div>

      {/* Level summary chips */}
      {data && data.lines.length > 0 && (
        <div className="flex flex-wrap gap-2">
          {Object.entries(levelCounts)
            .sort(([a], [b]) => {
              const order = ["emergency","critical","alert","error","warning","notice","info","debug"];
              return order.indexOf(a) - order.indexOf(b);
            })
            .map(([level, count]) => {
              const cfg = LEVEL_CONFIG[level] ?? LEVEL_CONFIG.debug;
              return (
                <button
                  key={level}
                  onClick={() => setLevelFilter(levelFilter === level ? "all" : level)}
                  className={`px-3 py-1 rounded-full text-xs font-semibold border transition-all ${cfg.color} ${levelFilter === level ? "ring-2 ring-offset-1 ring-current" : "opacity-80 hover:opacity-100"}`}
                >
                  {cfg.label}: {count}
                </button>
              );
            })}
          {levelFilter !== "all" && (
            <button
              onClick={() => setLevelFilter("all")}
              className="px-3 py-1 rounded-full text-xs font-semibold border bg-gray-100 text-gray-600 hover:bg-gray-200"
            >
              Show all
            </button>
          )}
        </div>
      )}

      {/* Filters bar */}
      <div className="flex flex-col sm:flex-row gap-3">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
          <Input
            placeholder="Search log messages…"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="pl-9"
          />
        </div>
        <div className="flex gap-2">
          <Select value={levelFilter} onValueChange={(v) => setLevelFilter(v ?? "all")}>
            <SelectTrigger className="w-36">
              <Filter className="h-4 w-4 mr-2" />
              <SelectValue placeholder="Level" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">All levels</SelectItem>
              <SelectItem value="emergency">Emergency</SelectItem>
              <SelectItem value="critical">Critical</SelectItem>
              <SelectItem value="alert">Alert</SelectItem>
              <SelectItem value="error">Error</SelectItem>
              <SelectItem value="warning">Warning</SelectItem>
              <SelectItem value="notice">Notice</SelectItem>
              <SelectItem value="info">Info</SelectItem>
              <SelectItem value="debug">Debug</SelectItem>
            </SelectContent>
          </Select>
          <Select value={lines} onValueChange={(v) => setLines(v ?? "200")}>
            <SelectTrigger className="w-32">
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="50">Last 50</SelectItem>
              <SelectItem value="200">Last 200</SelectItem>
              <SelectItem value="500">Last 500</SelectItem>
              <SelectItem value="1000">Last 1 000</SelectItem>
              <SelectItem value="2000">Last 2 000</SelectItem>
            </SelectContent>
          </Select>
        </div>
      </div>

      {/* Log output */}
      <Card>
        <CardHeader className="pb-2">
          <CardTitle className="text-sm font-medium text-muted-foreground">
            Showing {filtered.length} of {data?.lines.length ?? 0} loaded lines
            {search && ` · filtered by "${search}"`}
          </CardTitle>
        </CardHeader>
        <CardContent className="p-0">
          {loading ? (
            <div className="flex items-center justify-center py-20">
              <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
            </div>
          ) : filtered.length === 0 ? (
            <div className="flex flex-col items-center justify-center py-20 text-muted-foreground gap-2">
              <FileText className="h-10 w-10 opacity-30" />
              <p>{data?.lines.length === 0 ? "Log file is empty." : "No log entries match your filters."}</p>
            </div>
          ) : (
            <ScrollArea className="h-[560px] font-mono text-xs">
              <div className="divide-y divide-border">
                {filtered.map((line, idx) => {
                  const cfg = LEVEL_CONFIG[line.level] ?? LEVEL_CONFIG.debug;
                  const Icon = cfg.icon;
                  const rowColor = ROW_COLORS[line.level] ?? "";
                  return (
                    <div key={idx} className={`px-4 py-2 flex gap-3 items-start hover:bg-muted/30 transition-colors ${rowColor}`}>
                      <div className="flex-shrink-0 mt-0.5">
                        <Icon className="h-3.5 w-3.5" />
                      </div>
                      <div className="flex-1 min-w-0 space-y-0.5">
                        <div className="flex items-center gap-2 flex-wrap">
                          <Badge variant="outline" className={`text-[10px] py-0 px-1.5 ${cfg.color}`}>
                            {cfg.label}
                          </Badge>
                          {line.timestamp && (
                            <span className="text-muted-foreground text-[11px]">{line.timestamp}</span>
                          )}
                        </div>
                        <p className="break-all leading-relaxed text-foreground/90">{line.message}</p>
                      </div>
                    </div>
                  );
                })}
                <div ref={bottomRef} />
              </div>
            </ScrollArea>
          )}
        </CardContent>
      </Card>

      {/* Clear confirmation */}
      <AlertDialog open={clearOpen} onOpenChange={setClearOpen}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Clear all logs?</AlertDialogTitle>
            <AlertDialogDescription>
              This will permanently truncate <strong>storage/logs/laravel.log</strong>. This action cannot be undone.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancel</AlertDialogCancel>
            <AlertDialogAction
              className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
              onClick={handleClear}
              disabled={clearing}
            >
              {clearing ? <Loader2 className="h-4 w-4 animate-spin mr-2" /> : <Trash2 className="h-4 w-4 mr-2" />}
              Clear Logs
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
}

"use client";

import { useParams } from "next/navigation";
import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import { adminService } from "@/lib/api/admin";
import { Alert, AlertDescription, AlertTitle } from "@/components/ui/alert";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Switch } from "@/components/ui/switch";
import { Loader2, ShieldAlert } from "lucide-react";
import { useMemo, useState } from "react";

type FundingModel = "model_a" | "model_b";
type BillingCycle = "monthly" | "semester" | "annual";

type UniversityConfig = {
  id: number;
  name: string;
  type: "university";
  funding_model: FundingModel | null;
  billing_cycle: BillingCycle | null;
  semester_start_month: number | null;
  semester_2_start_month: number | null;
  session_credits_per_student: number;
  session_ceiling_ngn: number;
  domain_auto_join: boolean;
  university_domain: string | null;
  student_id_verification: boolean;
  crisis_notification_email: string | null;
  early_crisis_detection: boolean;
};

export default function UniversityConfigPage() {
  const params = useParams<{ id: string }>();
  const id = params.id;
  const queryClient = useQueryClient();
  const [local, setLocal] = useState<Partial<UniversityConfig>>({});

  const { data, isLoading, isError } = useQuery({
    queryKey: ["admin", "universities", id, "config"],
    queryFn: () => adminService.getUniversityConfig(id),
    select: (d: any) => (d?.data ?? d) as UniversityConfig,
  });

  const config = useMemo<UniversityConfig | undefined>(() => {
    if (!data) return undefined;
    return {
      ...data,
      billing_cycle:
        (data.billing_cycle as BillingCycle | null) ??
        (data.funding_model === "model_a" ? "annual" : data.funding_model === "model_b" ? "semester" : null),
    };
  }, [data]);

  const { mutate, isPending } = useMutation({
    mutationFn: (payload: Partial<UniversityConfig>) =>
      adminService.updateUniversityConfig(id, payload),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["admin", "universities", id, "config"] });
    },
  });

  const current = { ...config, ...local } as UniversityConfig | undefined;

  const showSemesterFields = current?.billing_cycle === "semester";
  const warnings: string[] = [];
  if (!current?.crisis_notification_email) {
    warnings.push("This university cannot go live until a crisis alert email is configured.");
  }
  if (current?.domain_auto_join && !current?.university_domain) {
    warnings.push("Add the university email domain to activate auto-join.");
  }

  const handleSave = () => {
    const payload: Partial<UniversityConfig> = {
      funding_model: current?.funding_model ?? null,
      billing_cycle: current?.billing_cycle ?? null,
      semester_start_month: current?.semester_start_month ?? null,
      semester_2_start_month: current?.semester_2_start_month ?? null,
      session_credits_per_student: current?.session_credits_per_student ?? 3,
      session_ceiling_ngn: current?.session_ceiling_ngn ?? 15000,
      domain_auto_join: !!current?.domain_auto_join,
      university_domain: current?.domain_auto_join ? (current?.university_domain ?? null) : null,
      student_id_verification: !!current?.student_id_verification,
      crisis_notification_email: current?.crisis_notification_email ?? null,
      early_crisis_detection: true,
    };
    mutate(payload);
  };

  if (isLoading) {
    return (
      <div className="flex h-64 items-center justify-center">
        <Loader2 className="h-8 w-8 animate-spin text-primary" />
      </div>
    );
  }

  if (isError || !current) {
    return (
      <div className="p-6">
        <Alert variant="destructive">
          <AlertTitle>Failed to load configuration</AlertTitle>
          <AlertDescription>Please try again later.</AlertDescription>
        </Alert>
      </div>
    );
  }

  return (
    <div className="flex-1 space-y-4 p-4 md:p-8 pt-6">
      <div className="flex items-center justify-between">
        <h2 className="text-2xl font-semibold tracking-tight">{current.name} — University Configuration</h2>
        <Button onClick={handleSave} disabled={isPending}>
          {isPending && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
          Save Changes
        </Button>
      </div>

      {warnings.length > 0 && (
        <div className="space-y-2">
          {warnings.map((w, i) => (
            <Alert key={i} variant="warning" className="items-start">
              <ShieldAlert className="mt-0.5 h-4 w-4" />
              <div>
                <AlertTitle>Action Required</AlertTitle>
                <AlertDescription>{w}</AlertDescription>
              </div>
            </Alert>
          ))}
        </div>
      )}

      <div className="grid gap-6 md:grid-cols-2">
        <div className="space-y-4">
          <div className="space-y-2">
            <Label>Funding Model</Label>
            <div className="rounded-lg border p-3 space-y-2">
              <label className="flex items-start gap-3">
                <input
                  type="radio"
                  name="funding_model"
                  value="model_a"
                  checked={current.funding_model === "model_a"}
                  onChange={() => setLocal((s) => ({ ...s, funding_model: "model_a", billing_cycle: s.billing_cycle ?? "annual" }))}
                />
                <div>
                  <div className="font-medium">Institution pays (contract billing)</div>
                  <div className="text-muted-foreground text-sm">Students pay nothing; institution is billed.</div>
                </div>
              </label>
              <label className="flex items-start gap-3">
                <input
                  type="radio"
                  name="funding_model"
                  value="model_b"
                  checked={current.funding_model === "model_b"}
                  onChange={() => setLocal((s) => ({ ...s, funding_model: "model_b", billing_cycle: s.billing_cycle ?? "semester" }))}
                />
                <div>
                  <div className="font-medium">School fees levy (institution collects, remits)</div>
                  <div className="text-muted-foreground text-sm">Identical student experience; semester invoice trigger.</div>
                </div>
              </label>
              <label className="flex items-start gap-3 opacity-60">
                <input type="radio" name="funding_model" disabled />
                <div>
                  <div className="font-medium">Student pays directly (D2C)</div>
                  <div className="text-muted-foreground text-sm">
                    Not configurable here — D2C has no organization record.
                  </div>
                </div>
              </label>
            </div>
          </div>

          <div className="space-y-2">
            <Label>Billing Cycle</Label>
            <Select
              value={current.billing_cycle ?? ""}
              onValueChange={(v: string | null) => setLocal((s) => ({ ...s, billing_cycle: (v as BillingCycle) || null }))}
            >
              <SelectTrigger>
                <SelectValue placeholder="Select billing cycle" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="monthly">Monthly</SelectItem>
                <SelectItem value="semester">Semester</SelectItem>
                <SelectItem value="annual">Annual</SelectItem>
              </SelectContent>
            </Select>
            <div className="text-xs text-muted-foreground">
              Default for Model A: Annual. Default for Model B: Semester.
            </div>
          </div>

          {showSemesterFields && (
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label>Semester 1 Start Month</Label>
                <Input
                  type="number"
                  min={1}
                  max={12}
                  value={current.semester_start_month ?? ""}
                  onChange={(e) => setLocal((s) => ({ ...s, semester_start_month: e.target.value ? Number(e.target.value) : null }))}
                  placeholder="1-12"
                />
              </div>
              <div className="space-y-2">
                <Label>Semester 2 Start Month</Label>
                <Input
                  type="number"
                  min={1}
                  max={12}
                  value={current.semester_2_start_month ?? ""}
                  onChange={(e) => setLocal((s) => ({ ...s, semester_2_start_month: e.target.value ? Number(e.target.value) : null }))}
                  placeholder="1-12"
                />
              </div>
            </div>
          )}

          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label>Monthly Session Credits Per Student</Label>
              <Input
                type="number"
                min={0}
                max={12}
                value={current.session_credits_per_student ?? 3}
                onChange={(e) => setLocal((s) => ({ ...s, session_credits_per_student: Number(e.target.value) }))}
              />
            </div>
            <div className="space-y-2">
              <Label>Per-Session Coverage Ceiling (₦)</Label>
              <Input
                type="number"
                min={0}
                value={current.session_ceiling_ngn ?? 15000}
                onChange={(e) => setLocal((s) => ({ ...s, session_ceiling_ngn: Number(e.target.value) }))}
              />
            </div>
          </div>
        </div>

        <div className="space-y-6">
          <div className="flex items-center justify-between rounded-lg border p-4">
            <div className="space-y-1">
              <div className="font-medium">Email Domain Auto-Join</div>
              <div className="text-sm text-muted-foreground">
                Automatically link signups from the university domain to this org.
              </div>
            </div>
            <Switch
              checked={!!current.domain_auto_join}
              onCheckedChange={(val) => setLocal((s) => ({ ...s, domain_auto_join: val }))}
            />
          </div>
          {current.domain_auto_join && (
            <div className="space-y-2">
              <Label>University Email Domain</Label>
              <Input
                placeholder="e.g., uniport.edu.ng"
                value={current.university_domain ?? ""}
                onChange={(e) => setLocal((s) => ({ ...s, university_domain: e.target.value || null }))}
              />
            </div>
          )}

          <div className="flex items-center justify-between rounded-lg border p-4">
            <div className="space-y-1">
              <div className="font-medium">Require Matriculation Number Verification</div>
              <div className="text-sm text-muted-foreground">
                Students must submit matric number; admin approves in Student Verifications.
              </div>
            </div>
            <Switch
              checked={!!current.student_id_verification}
              onCheckedChange={(val) => setLocal((s) => ({ ...s, student_id_verification: val }))}
            />
          </div>

          <div className="space-y-2">
            <Label>Crisis Alert Recipient (Student Affairs)</Label>
            <Input
              type="email"
              placeholder="name@university.edu.ng"
              value={current.crisis_notification_email ?? ""}
              onChange={(e) => setLocal((s) => ({ ...s, crisis_notification_email: e.target.value || null }))}
            />
          </div>

          <div className="flex items-center justify-between rounded-lg border p-4 opacity-70">
            <div className="space-y-1">
              <div className="font-medium">Crisis Detection</div>
              <div className="text-sm text-muted-foreground">
                Mandatory for all university accounts and cannot be disabled.
              </div>
            </div>
            <Switch checked={true} disabled />
          </div>
        </div>
      </div>
    </div>
  );
}

"use client";

import { useCallback, useEffect, useMemo, useState } from "react";
import { adminService } from "@/lib/api/admin";
import { Card, CardContent } from "@/components/ui/card";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Loader2, Search, Lock } from "lucide-react";
import { toast } from "@/components/ui/use-toast";
import Cookies from "js-cookie";
import { PageHeader } from "@/components/shared/page-header";
import { TableBodyShimmer } from "@/components/shared/shimmer-skeleton";

const STATUS_STYLES: Record<string, string> = {
  active:   "bg-emerald-50 text-emerald-700",
  inactive: "bg-gray-100 text-gray-500",
  free:     "bg-gray-50 text-gray-500",
  trial:    "bg-blue-50 text-blue-600",
  premium:  "bg-teal/10 text-teal",
  paused:   "bg-amber-50 text-amber-700",
  expired:  "bg-red-50 text-red-700",
};

function StatusPill({ label, style }: { label: string; style?: string }) {
  return (
    <span className={`inline-flex items-center px-2 py-0.5 rounded-full text-xs font-medium capitalize ${style ?? "bg-gray-100 text-gray-600"}`}>
      {label}
    </span>
  );
}

type AdminUserRow = {
  id: number;
  uuid: string;
  first_name: string | null;
  last_name: string | null;
  name: string;
  email: string;
  role?: string | null;
  profile_photo?: string | null;
  is_active: boolean;
  current_plan?: string | null;
  current_plan_slug?: string | null;
  subscription_status?: string | null;
  comped_upgrade_approved?: boolean;
  comped_approved_by?: string | null;
};

type RolesList = Array<{ id: number; name: string; slug: string }>;

export default function AdminUsersPage() {
  const [rows, setRows] = useState<AdminUserRow[]>([]);
  const [roles, setRoles] = useState<RolesList>([]);
  const [search, setSearch] = useState("");
  const [page, setPage] = useState(1);
  const [loading, setLoading] = useState(true);
  const [updatingRole, setUpdatingRole] = useState<number | null>(null);
  const [meta, setMeta] = useState<{ current_page: number; last_page: number } | null>(null);
  const [isReadOnly, setIsReadOnly] = useState(false);

  useEffect(() => {
    const role = Cookies.get("user_role");
    if (role === "coo" || role === "cgo") setIsReadOnly(true);
  }, []);

  const load = useCallback(async (p = page) => {
    setLoading(true);
    try {
      const res = await adminService.getUsers({ page: p, search: search || undefined });
      const data = ((res as { data?: AdminUserRow[] })?.data ?? res ?? []) as AdminUserRow[];
      setRows(Array.isArray(data) ? data : []);
      const m = (res as { meta?: { current_page: number; last_page: number } })?.meta ?? null;
      setMeta(m);
    } catch {
      toast({ description: "Failed to load users.", variant: "destructive" });
    } finally {
      setLoading(false);
    }
  }, [page, search]); // eslint-disable-line react-hooks/exhaustive-deps

  const loadRoles = useCallback(async () => {
    try {
      const res = await adminService.getRoles();
      const data = (res as { data?: RolesList })?.data ?? res ?? [];
      setRoles(Array.isArray(data) ? data : []);
    } catch { /* ignore */ }
  }, []);

  useEffect(() => { load(1); }, []); // eslint-disable-line react-hooks/exhaustive-deps
  useEffect(() => { loadRoles(); }, [loadRoles]);

  const roleOptions = useMemo(() => roles.map((r) => ({ slug: r.slug, name: r.name })), [roles]);

  const changeRole = async (userId: number, newRole: string) => {
    setUpdatingRole(userId);
    try {
      await adminService.updateUser(userId, { role: newRole });
      setRows((prev) => prev.map((r) => (r.id === userId ? { ...r, role: newRole } : r)));
      toast({ description: "Role updated.", variant: "default" });
    } catch {
      toast({ description: "Failed to update role.", variant: "destructive" });
    } finally {
      setUpdatingRole(null);
    }
  };

  return (
    <div className="p-6 space-y-6">
      <PageHeader
        title="Users"
        subtitle="Manage roles, plans, and subscriptions"
      >
        <div className="flex items-center gap-2">
          {isReadOnly && (
            <span className="inline-flex items-center gap-1 px-2.5 py-1 rounded-full text-xs font-medium bg-gray-100 text-gray-500">
              <Lock className="w-3 h-3" /> Read-Only
            </span>
          )}
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
            <Input
              placeholder="Search name or email"
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              onKeyDown={(e) => { if (e.key === "Enter") load(1); }}
              className="pl-9 w-72"
            />
          </div>
          <Button onClick={() => load(1)} className="bg-teal text-white hover:bg-teal-mid">Apply</Button>
        </div>
      </PageHeader>

      <Card>
        <CardContent className="p-0">
          <div className="overflow-x-auto">
            <Table>
              <TableHeader>
                <TableRow className="bg-gray-50">
                  <TableHead className="px-4 py-3 text-xs font-medium text-gray-500 uppercase tracking-wide">Name</TableHead>
                  <TableHead className="px-4 py-3 text-xs font-medium text-gray-500 uppercase tracking-wide">Email</TableHead>
                  <TableHead className="px-4 py-3 text-xs font-medium text-gray-500 uppercase tracking-wide">Role</TableHead>
                  <TableHead className="px-4 py-3 text-xs font-medium text-gray-500 uppercase tracking-wide">Plan</TableHead>
                  <TableHead className="px-4 py-3 text-xs font-medium text-gray-500 uppercase tracking-wide">Subscription</TableHead>
                  <TableHead className="px-4 py-3 text-xs font-medium text-gray-500 uppercase tracking-wide">Status</TableHead>
                  <TableHead className="px-4 py-3 text-xs font-medium text-gray-500 uppercase tracking-wide text-right">Actions</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {loading ? (
                  <TableBodyShimmer rows={8} cols={7} />
                ) : rows.length === 0 ? (
                  <TableRow>
                    <TableCell colSpan={7}>
                      <div className="flex flex-col items-center justify-center py-16">
                        <Search className="w-10 h-10 text-gray-200 mb-3" />
                        <p className="text-sm font-medium text-gray-600">No users found</p>
                        <p className="text-xs text-gray-400 mt-1">
                          {search ? "Try a different search term" : "Users will appear here once they register"}
                        </p>
                      </div>
                    </TableCell>
                  </TableRow>
                ) : rows.map((u, idx) => (
                  <TableRow
                    key={u.id}
                    className={idx % 2 === 0 ? "bg-white hover:bg-teal/5" : "bg-gray-50/50 hover:bg-teal/5"}
                  >
                    <TableCell className="px-4 py-3 font-medium text-gray-900">{u.name}</TableCell>
                    <TableCell className="px-4 py-3 text-sm text-gray-500">{u.email}</TableCell>
                    <TableCell className="px-4 py-3 w-56">
                      <Select
                        value={u.role ?? ""}
                        onValueChange={(val) => val && changeRole(u.id, val)}
                        disabled={updatingRole === u.id || isReadOnly}
                      >
                        <SelectTrigger className="h-8 text-xs">
                          <SelectValue placeholder="Select role" />
                        </SelectTrigger>
                        <SelectContent>
                          {roleOptions.map((r) => (
                            <SelectItem key={r.slug} value={r.slug}>{r.name}</SelectItem>
                          ))}
                        </SelectContent>
                      </Select>
                    </TableCell>
                    <TableCell className="px-4 py-3">
                      <div className="flex items-center gap-1.5">
                        {u.current_plan ? (
                          <span className="inline-flex items-center px-2 py-0.5 rounded-full text-xs font-medium bg-teal/10 text-teal">
                            {u.current_plan}
                          </span>
                        ) : (
                          <span className="text-xs text-gray-400">—</span>
                        )}
                        {u.comped_upgrade_approved && (
                          <span className="inline-flex items-center px-1.5 py-0.5 rounded text-[10px] font-semibold bg-amber-warm/10 text-amber-warm border border-amber-warm/20">
                            Admin Approved
                          </span>
                        )}
                      </div>
                    </TableCell>
                    <TableCell className="px-4 py-3">
                      {u.subscription_status ? (
                        <StatusPill
                          label={u.subscription_status.replace(/_/g, " ")}
                          style={STATUS_STYLES[u.subscription_status] ?? "bg-gray-100 text-gray-600"}
                        />
                      ) : (
                        <StatusPill label="Free" style={STATUS_STYLES.free} />
                      )}
                    </TableCell>
                    <TableCell className="px-4 py-3">
                      <StatusPill
                        label={u.is_active ? "Active" : "Inactive"}
                        style={u.is_active ? STATUS_STYLES.active : STATUS_STYLES.inactive}
                      />
                    </TableCell>
                    <TableCell className="px-4 py-3 text-right">
                      {!isReadOnly && (
                        <UpgradeButton userId={u.id} currentPlanSlug={u.current_plan_slug ?? undefined} />
                      )}
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </div>

          <div className="flex items-center justify-between px-4 py-3 border-t border-gray-50">
            <div className="text-xs text-gray-400">
              {meta ? `Page ${meta.current_page} of ${meta.last_page}` : ""}
            </div>
            <div className="flex gap-2">
              <Button
                variant="outline"
                size="sm"
                disabled={!meta || meta.current_page <= 1 || loading}
                onClick={() => { const p = Math.max(1, (meta?.current_page ?? 1) - 1); setPage(p); load(p); }}
              >
                Prev
              </Button>
              <Button
                variant="outline"
                size="sm"
                disabled={!meta || meta.current_page >= (meta?.last_page ?? 1) || loading}
                onClick={() => { const p = Math.min((meta?.last_page ?? 1), (meta?.current_page ?? 1) + 1); setPage(p); load(p); }}
              >
                Next
              </Button>
            </div>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

function UpgradeButton({ userId, currentPlanSlug }: { userId: number; currentPlanSlug?: string }) {
  const [open, setOpen] = useState(false);
  const [plans, setPlans] = useState<Array<{ uuid: string; name: string; slug: string; plan_type?: string; billing_interval?: string }>>([]);
  const [selected, setSelected] = useState<string>("");
  const [saving, setSaving] = useState(false);
  const [includeRevenue, setIncludeRevenue] = useState(false);

  const loadPlans = useCallback(async () => {
    try {
      const res = await adminService.getAllPlans();
      const list = Array.isArray((res as { data?: unknown[] })?.data)
        ? (res as { data: typeof plans }).data
        : Array.isArray(res) ? res : [];
      setPlans(list);
    } catch { /* ignore */ }
  }, []);

  useEffect(() => {
    if (open && plans.length === 0) loadPlans();
  }, [open, plans.length, loadPlans]);

  const submit = async () => {
    if (!selected) return;
    setSaving(true);
    try {
      await adminService.upgradeUserSubscription(userId, {
        plan_uuid: selected,
        comped: true,
        include_in_revenue: includeRevenue,
      });
      setOpen(false);
      toast({ description: "Subscription upgraded.", variant: "default" });
    } catch {
      toast({ description: "Failed to upgrade subscription.", variant: "destructive" });
    } finally {
      setSaving(false);
    }
  };

  return (
    <>
      <Button size="sm" variant="outline" onClick={() => setOpen(true)} className="text-xs">
        Upgrade
      </Button>
      {open && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40">
          <div className="w-[560px] max-w-[90vw] rounded-xl bg-white p-5 space-y-4 shadow-xl">
            <div className="flex items-center justify-between">
              <div>
                <h3 className="text-base font-semibold text-gray-900">Upgrade Subscription</h3>
                <p className="text-xs text-gray-400">Current: {currentPlanSlug ?? "none"}</p>
              </div>
              <button className="text-sm text-gray-400 hover:text-gray-600" onClick={() => setOpen(false)}>
                Close
              </button>
            </div>
            <div className="space-y-2">
              <label className="text-sm font-medium text-gray-700">Select Plan</label>
              <Select value={selected} onValueChange={(val) => val && setSelected(val)}>
                <SelectTrigger>
                  <SelectValue placeholder="Choose a plan" />
                </SelectTrigger>
                <SelectContent>
                  {plans.map((p) => (
                    <SelectItem key={p.uuid} value={p.uuid}>
                      {p.name} {p.plan_type ? `· ${p.plan_type}` : ""} {p.billing_interval ? `· ${p.billing_interval}` : ""}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
            <div className="flex items-center justify-between rounded-lg border border-gray-100 bg-gray-50 p-3">
              <div className="space-y-0.5">
                <p className="text-sm font-medium text-gray-700">Include in revenue reports</p>
                <p className="text-xs text-gray-400">Count this admin-applied upgrade towards revenue.</p>
              </div>
              <input
                type="checkbox"
                checked={includeRevenue}
                onChange={(e) => setIncludeRevenue(e.target.checked)}
                aria-label="Include in revenue"
                className="w-4 h-4 accent-teal"
              />
            </div>
            <div className="flex justify-end gap-2 pt-2">
              <Button variant="outline" onClick={() => setOpen(false)}>Cancel</Button>
              <Button
                onClick={submit}
                disabled={!selected || saving}
                className="bg-teal text-white hover:bg-teal-mid"
              >
                {saving && <Loader2 className="h-4 w-4 animate-spin mr-2" />}
                Apply
              </Button>
            </div>
          </div>
        </div>
      )}
    </>
  );
}

"use client";

import { useEffect, useState, useCallback, useMemo } from "react";
import {
  adminWaitlistService,
  type WaitlistEntry,
  type WaitlistStats,
  type WaitlistFilters,
} from "@/lib/api/admin-waitlist.service";
