  Select, SelectContent, SelectItem, SelectTrigger, SelectValue,
} from "@/components/ui/select";
import {
  DropdownMenu, DropdownMenuContent, DropdownMenuItem,
  DropdownMenuSeparator, DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import {
  Tooltip, TooltipContent, TooltipProvider, TooltipTrigger,
} from "@/components/ui/tooltip";
import {
  Loader2, Trash2, Filter, MoreHorizontal, RefreshCw, Search,
  Mail, Users, UserCheck, XCircle, TrendingUp, Clock, Download,
  Globe, Megaphone, Send, AlertCircle, ChevronDown,
} from "lucide-react";
import { toast } from "@/components/ui/use-toast";

type Status = WaitlistEntry["status"];
type Role = WaitlistEntry["role"];

// ── helpers ────────────────────────────────────────────────────────────────

function daysAgo(date: string) {
  return Math.floor((Date.now() - new Date(date).getTime()) / 86_400_000);
}

function statusBadge(status: Status) {
  const cfg: Record<Status, { cls: string; label: string }> = {
    pending:  { cls: "bg-yellow-100 text-yellow-700 hover:bg-yellow-100", label: "Pending" },
    invited:  { cls: "bg-green-100  text-green-700  hover:bg-green-100",  label: "Invited" },
    declined: { cls: "bg-red-100    text-red-700    hover:bg-red-100",    label: "Declined" },
  };
  const { cls, label } = cfg[status] ?? { cls: "", label: status };
  return <Badge className={cls}>{label}</Badge>;
}

function roleBadge(role: Role) {
  const cfg: Record<Role, { cls: string; label: string }> = {
    patient:     { cls: "bg-blue-100   text-blue-700   hover:bg-blue-100",   label: "Patient" },
    therapist:   { cls: "bg-purple-100 text-purple-700 hover:bg-purple-100", label: "Therapist" },
    institution: { cls: "bg-orange-100 text-orange-700 hover:bg-orange-100", label: "Institution" },
    other:       { cls: "bg-gray-100   text-gray-600   hover:bg-gray-100",   label: "Other" },
  };
  const { cls, label } = cfg[role] ?? { cls: "", label: role };
  return <Badge className={cls}>{label}</Badge>;
}

function urgencyPill(days: number) {
  if (days >= 14) return <span className="text-xs font-semibold text-red-600">🔥 {days}d</span>;
  if (days >= 7)  return <span className="text-xs font-semibold text-orange-500">⏳ {days}d</span>;
  return <span className="text-xs text-muted-foreground">{days}d</span>;
}

// Mini horizontal bar
function MiniBar({ value, max, color }: { value: number; max: number; color: string }) {
  const pct = max > 0 ? Math.round((value / max) * 100) : 0;
  return (
    <div className="flex items-center gap-2">
      <div className="flex-1 h-1.5 bg-muted rounded-full overflow-hidden">
        <div className={`h-full rounded-full ${color}`} style={{ width: `${pct}%` }} />
      </div>
      <span className="text-xs tabular-nums w-6 text-right text-muted-foreground">{value}</span>
    </div>
  );
}

// ── component ──────────────────────────────────────────────────────────────

export default function AdminWaitlistPage() {
  const [entries, setEntries] = useState<WaitlistEntry[]>([]);
  const [stats, setStats] = useState<WaitlistStats | null>(null);
  const [pagination, setPagination] = useState({ total: 0, last_page: 1, current_page: 1, per_page: 25 });
  const [isLoading, setIsLoading] = useState(true);

  // filters
  const [search, setSearch] = useState("");
  const [statusFilter, setStatusFilter] = useState<WaitlistFilters["status"]>("all");
  const [roleFilter, setRoleFilter] = useState<WaitlistFilters["role"]>("all");

  // selection
  const [selected, setSelected] = useState<Set<number>>(new Set());
  const [batchLoading, setBatchLoading] = useState(false);

  // detail dialog
  const [detail, setDetail] = useState<WaitlistEntry | null>(null);

  // ── data ────────────────────────────────────────────────────────────────

  const fetchData = useCallback(async (page = 1) => {
    setIsLoading(true);
    try {
      const data = await adminWaitlistService.getWaitlist({
        search: search || undefined,
        status: statusFilter,
        role: roleFilter,
        page,
        per_page: 25,
      });
      const rows: WaitlistEntry[] = data.submissions?.data ?? (data.submissions as unknown as WaitlistEntry[]) ?? [];
      setEntries(rows);
      setStats(data.stats ?? null);
      const p = data.submissions as { total?: number; per_page?: number; current_page?: number; last_page?: number };
      setPagination({
        total: p.total ?? rows.length,
        per_page: p.per_page ?? 25,
        current_page: p.current_page ?? 1,
        last_page: p.last_page ?? 1,
      });
      setSelected(new Set());
    } catch {
      toast({ title: "Error", description: "Failed to load waitlist", variant: "destructive" });
    } finally {
      setIsLoading(false);
    }
  }, [search, statusFilter, roleFilter]);

  useEffect(() => { fetchData(); }, [fetchData]);

  // ── derived ──────────────────────────────────────────────────────────────

  // pending entries sorted oldest-first (longest wait at top)
  const inviteQueue = useMemo(() =>
    entries
      .filter((e) => e.status === "pending")
      .sort((a, b) => new Date(a.created_at).getTime() - new Date(b.created_at).getTime()),
    [entries]);

  const pendingIds = useMemo(() => entries.filter((e) => e.status === "pending").map((e) => e.id), [entries]);
  const allPendingSelected = pendingIds.length > 0 && pendingIds.every((id) => selected.has(id));

  // ── actions ──────────────────────────────────────────────────────────────

  const handleInvite = async (id: number) => {
    try {
      await adminWaitlistService.invite(id);
      toast({ title: "Invite sent!" });
      fetchData(pagination.current_page);
    } catch {
      toast({ title: "Error", description: "Could not send invite.", variant: "destructive" });
    }
  };

  const handleBatchInvite = async () => {
    const ids = [...selected].filter((id) => entries.find((e) => e.id === id)?.status === "pending");
    if (!ids.length) return;
    if (!confirm(`Send invites to ${ids.length} selected people?`)) return;
    setBatchLoading(true);
    try {
      const res = await adminWaitlistService.batchInvite(ids);
      toast({ title: `${res.invited} invite(s) sent!` });
      fetchData(pagination.current_page);
    } catch {
      toast({ title: "Error", description: "Batch invite failed.", variant: "destructive" });
    } finally {
      setBatchLoading(false);
    }
  };

  const handleInviteAll = async () => {
    if (!inviteQueue.length) return;
    if (!confirm(`Send invites to ALL ${inviteQueue.length} pending people?`)) return;
    setBatchLoading(true);
    try {
      const res = await adminWaitlistService.batchInvite(inviteQueue.map((e) => e.id));
      toast({ title: `${res.invited} invite(s) sent!` });
      fetchData(pagination.current_page);
    } catch {
      toast({ title: "Error", description: "Invite all failed.", variant: "destructive" });
    } finally {
      setBatchLoading(false);
    }
  };

  const handleStatusChange = async (id: number, status: Status) => {
    try {
      await adminWaitlistService.updateStatus(id, status);
      toast({ title: `Marked as ${status}.` });
      fetchData(pagination.current_page);
    } catch {
      toast({ title: "Error", description: "Status update failed.", variant: "destructive" });
    }
  };

  const handleDelete = async (id: number) => {
    if (!confirm("Remove this person from the waitlist?")) return;
    try {
      await adminWaitlistService.destroy(id);
      toast({ title: "Removed." });
      if (detail?.id === id) setDetail(null);
      fetchData(pagination.current_page);
    } catch {
      toast({ title: "Error", description: "Delete failed.", variant: "destructive" });
    }
  };

  const toggleSelect = (id: number) => {
    setSelected((prev) => {
      const next = new Set(prev);
      next.has(id) ? next.delete(id) : next.add(id);
      return next;
    });
  };

  const toggleAllPending = () => {
    setSelected(allPendingSelected ? new Set() : new Set(pendingIds));
  };

  // ── render ────────────────────────────────────────────────────────────────

  const roleMax = stats ? Math.max(...Object.values(stats.by_role)) : 1;
  const countryMax = stats ? Math.max(...Object.values(stats.by_country)) : 1;
  const referralMax = stats ? Math.max(...Object.values(stats.by_referral)) : 1;

  const selectedPendingCount = [...selected].filter((id) =>
    entries.find((e) => e.id === id)?.status === "pending"
  ).length;

  return (
    <TooltipProvider>
    <div className="flex-1 space-y-5 p-4 md:p-8 pt-6">

      {/* ── Header ── */}
      <div className="flex items-center justify-between flex-wrap gap-3">
        <div>
          <h2 className="text-3xl font-bold tracking-tight">Waitlist</h2>
          <p className="text-muted-foreground">
            Manage signups and send invitations when ready to onboard.
          </p>
        </div>
        <div className="flex items-center gap-2">
          <Button variant="outline" size="sm" onClick={() => fetchData(pagination.current_page)}>
            <RefreshCw className="mr-2 h-4 w-4" />
            Refresh
          </Button>
          <Button variant="outline" size="sm" asChild>
            <a href={adminWaitlistService.exportUrl()} download>
              <Download className="mr-2 h-4 w-4" />
              Export CSV
            </a>
          </Button>
          {inviteQueue.length > 0 && (
            <Button size="sm" onClick={handleInviteAll} disabled={batchLoading}>
              {batchLoading
                ? <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                : <Send className="mr-2 h-4 w-4" />}
              Invite All Pending ({inviteQueue.length})
            </Button>
          )}
        </div>
      </div>

      {/* ── Stat Cards ── */}
      {stats && (
        <div className="grid grid-cols-2 sm:grid-cols-5 gap-3">
          {[
            { label: "Total",      value: stats.total,     icon: Users,      color: "text-foreground" },
            { label: "Pending",    value: stats.pending,   icon: Clock,      color: "text-yellow-600" },
            { label: "Invited",    value: stats.invited,   icon: UserCheck,  color: "text-green-600"  },
            { label: "Declined",   value: stats.declined,  icon: XCircle,    color: "text-red-500"    },
            { label: "Conversion", value: `${stats.conversion_rate}%`, icon: TrendingUp, color: "text-blue-600" },
          ].map(({ label, value, icon: Icon, color }) => (
            <Card key={label}>
              <CardContent className="pt-4 flex items-center justify-between">
                <div>
                  <p className="text-xs text-muted-foreground">{label}</p>
                  <p className="text-2xl font-bold">{value}</p>
                </div>
                <Icon className={`h-7 w-7 opacity-20 ${color}`} />
              </CardContent>
            </Card>
          ))}
        </div>
      )}

      {/* ── Insight Panel ── */}
      {stats && (stats.total > 0) && (
        <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">

          {/* By Role */}
          <Card>
            <CardHeader className="pb-2 pt-4 px-4">
              <CardTitle className="text-sm font-medium flex items-center gap-1.5">
                <Users className="h-4 w-4 text-muted-foreground" /> By Role
              </CardTitle>
            </CardHeader>
            <CardContent className="px-4 pb-4 space-y-2">
              {Object.entries(stats.by_role).sort((a,b) => b[1]-a[1]).map(([role, count]) => (
                <div key={role}>
                  <div className="flex justify-between text-xs mb-0.5">
                    <span className="capitalize">{role}</span>
                  </div>
                  <MiniBar value={count} max={roleMax} color="bg-primary" />
                </div>
              ))}
              {Object.keys(stats.by_role).length === 0 && (
                <p className="text-xs text-muted-foreground">No data yet.</p>
              )}
            </CardContent>
          </Card>

          {/* By Country */}
          <Card>
            <CardHeader className="pb-2 pt-4 px-4">
              <CardTitle className="text-sm font-medium flex items-center gap-1.5">
                <Globe className="h-4 w-4 text-muted-foreground" /> Top Countries
              </CardTitle>
            </CardHeader>
            <CardContent className="px-4 pb-4 space-y-2">
              {Object.entries(stats.by_country).map(([country, count]) => (
                <div key={country}>
                  <div className="flex justify-between text-xs mb-0.5">
                    <span>{country}</span>
                  </div>
                  <MiniBar value={count} max={countryMax} color="bg-blue-500" />
                </div>
              ))}
              {Object.keys(stats.by_country).length === 0 && (
                <p className="text-xs text-muted-foreground">No country data.</p>
              )}
            </CardContent>
          </Card>

          {/* By Referral */}
          <Card>
            <CardHeader className="pb-2 pt-4 px-4">
              <CardTitle className="text-sm font-medium flex items-center gap-1.5">
                <Megaphone className="h-4 w-4 text-muted-foreground" /> How They Found Us
              </CardTitle>
            </CardHeader>
            <CardContent className="px-4 pb-4 space-y-2">
              {Object.entries(stats.by_referral).map(([source, count]) => (
                <div key={source}>
                  <div className="flex justify-between text-xs mb-0.5">
                    <span className="capitalize">{source}</span>
                  </div>
                  <MiniBar value={count} max={referralMax} color="bg-purple-500" />
                </div>
              ))}
              {Object.keys(stats.by_referral).length === 0 && (
                <p className="text-xs text-muted-foreground">No referral data.</p>
              )}
            </CardContent>
          </Card>
        </div>
      )}

      {/* ── Invite Queue callout ── */}
      {inviteQueue.length > 0 && (
        <Card className="border-yellow-200 dark:border-yellow-900 bg-yellow-50/60 dark:bg-yellow-950/20">
          <CardContent className="pt-4 pb-3 px-4">
            <div className="flex items-center gap-2 mb-2">
              <AlertCircle className="h-4 w-4 text-yellow-600" />
              <p className="text-sm font-semibold text-yellow-700 dark:text-yellow-400">
                {inviteQueue.length} people waiting to be invited
                {stats?.oldest_pending && (
                  <span className="font-normal ml-1 text-yellow-600">
                    — oldest joined {daysAgo(stats.oldest_pending)} days ago
                  </span>
                )}
              </p>
            </div>
            <div className="flex flex-wrap gap-2">
              {inviteQueue.slice(0, 5).map((e) => (
                <Tooltip key={e.id}>
                  <TooltipTrigger asChild>
                    <button
                      onClick={() => setDetail(e)}
                      className="inline-flex items-center gap-1.5 text-xs bg-white dark:bg-yellow-950 border border-yellow-200 dark:border-yellow-800 rounded-full px-2.5 py-1 hover:bg-yellow-100 dark:hover:bg-yellow-900 transition-colors"
                    >
                      {urgencyPill(daysAgo(e.created_at))}
                      <span className="font-medium">{e.first_name} {e.last_name}</span>
                      <span className="text-muted-foreground">{e.role}</span>
                    </button>
                  </TooltipTrigger>
                  <TooltipContent>{e.email}</TooltipContent>
                </Tooltip>
              ))}
              {inviteQueue.length > 5 && (
                <span className="text-xs text-muted-foreground self-center">+{inviteQueue.length - 5} more</span>
              )}
            </div>
          </CardContent>
        </Card>
      )}

      {/* ── Filters + Bulk Actions ── */}
      <div className="flex items-center gap-3 flex-wrap">
        <div className="relative flex-1 min-w-[200px] max-w-sm">
          <Search className="absolute left-2.5 top-2.5 h-4 w-4 text-muted-foreground" />
          <Input
            className="pl-8"
            placeholder="Search name or email…"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />
        </div>
        <Filter className="h-4 w-4 text-muted-foreground" />
        <Select value={statusFilter} onValueChange={(v) => setStatusFilter(v as WaitlistFilters["status"])}>
          <SelectTrigger className="w-36">
            <SelectValue placeholder="Status" />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="all">All Status</SelectItem>
            <SelectItem value="pending">Pending</SelectItem>
            <SelectItem value="invited">Invited</SelectItem>
            <SelectItem value="declined">Declined</SelectItem>
          </SelectContent>
        </Select>
        <Select value={roleFilter} onValueChange={(v) => setRoleFilter(v as WaitlistFilters["role"])}>
          <SelectTrigger className="w-36">
            <SelectValue placeholder="Role" />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="all">All Roles</SelectItem>
            <SelectItem value="patient">Patient</SelectItem>
            <SelectItem value="therapist">Therapist</SelectItem>
            <SelectItem value="institution">Institution</SelectItem>
            <SelectItem value="other">Other</SelectItem>
          </SelectContent>
        </Select>

        {selectedPendingCount > 0 && (
          <Button size="sm" onClick={handleBatchInvite} disabled={batchLoading} className="ml-auto">
            {batchLoading
              ? <Loader2 className="mr-2 h-4 w-4 animate-spin" />
              : <Mail className="mr-2 h-4 w-4" />}
            Invite Selected ({selectedPendingCount})
          </Button>
        )}
      </div>

      {/* ── Table ── */}
      <Card>
        <CardHeader>
          <CardTitle>Signups ({pagination.total})</CardTitle>
        </CardHeader>
        <CardContent>
          {isLoading ? (
            <div className="flex h-48 items-center justify-center">
              <Loader2 className="h-8 w-8 animate-spin text-primary" />
            </div>
          ) : entries.length === 0 ? (
            <div className="text-center py-12 text-muted-foreground">
              <Users className="w-12 h-12 mx-auto mb-4 opacity-50" />
              <p>No signups found.</p>
            </div>
          ) : (
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead className="w-10">
                    <Tooltip>
                      <TooltipTrigger asChild>
                        <Checkbox
                          checked={allPendingSelected}
                          onCheckedChange={toggleAllPending}
                          aria-label="Select all pending"
                        />
                      </TooltipTrigger>
                      <TooltipContent>Select all pending</TooltipContent>
                    </Tooltip>
                  </TableHead>
                  <TableHead>Name</TableHead>
                  <TableHead>Role</TableHead>
                  <TableHead>Country</TableHead>
                  <TableHead>Source</TableHead>
                  <TableHead>Waiting</TableHead>
                  <TableHead>Status</TableHead>
                  <TableHead className="text-right">Actions</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {entries.map((entry) => {
                  const days = daysAgo(entry.created_at);
                  const isPending = entry.status === "pending";
                  return (
                    <TableRow
                      key={entry.id}
                      className={isPending && days >= 7 ? "bg-orange-50/40 dark:bg-orange-950/10" : ""}
                    >
                      <TableCell>
                        {isPending && (
                          <Checkbox
                            checked={selected.has(entry.id)}
                            onCheckedChange={() => toggleSelect(entry.id)}
                          />
                        )}
                      </TableCell>
                      <TableCell className="text-sm">
                        <button
                          className="font-medium hover:underline text-left"
                          onClick={() => setDetail(entry)}
                        >
                          {entry.first_name} {entry.last_name}
                        </button>
                        <div className="text-xs text-muted-foreground">{entry.email}</div>
                      </TableCell>
                      <TableCell>{roleBadge(entry.role)}</TableCell>
                      <TableCell className="text-sm text-muted-foreground">{entry.country ?? "—"}</TableCell>
                      <TableCell className="text-sm text-muted-foreground max-w-[120px] truncate">
                        {entry.referral_source ?? "—"}
                      </TableCell>
                      <TableCell>{urgencyPill(days)}</TableCell>
                      <TableCell>{statusBadge(entry.status)}</TableCell>
                      <TableCell className="text-right">
                        <DropdownMenu>
                          <DropdownMenuTrigger asChild>
                            <Button variant="ghost" size="icon">
                              <MoreHorizontal className="h-4 w-4" />
                            </Button>
                          </DropdownMenuTrigger>
                          <DropdownMenuContent align="end">
                            <DropdownMenuItem onClick={() => setDetail(entry)}>
                              View Details
                            </DropdownMenuItem>
                            {entry.status === "pending" && (
                              <DropdownMenuItem onClick={() => handleInvite(entry.id)}>
                                <Mail className="mr-2 h-4 w-4 text-green-600" />
                                Send Invite
                              </DropdownMenuItem>
                            )}
                            {entry.status !== "declined" && (
                              <DropdownMenuItem onClick={() => handleStatusChange(entry.id, "declined")}>
                                <XCircle className="mr-2 h-4 w-4 text-red-500" />
                                Decline
                              </DropdownMenuItem>
                            )}
                            {entry.status === "declined" && (
                              <DropdownMenuItem onClick={() => handleStatusChange(entry.id, "pending")}>
                                <Clock className="mr-2 h-4 w-4 text-yellow-600" />
                                Restore to Pending
                              </DropdownMenuItem>
                            )}
                            <DropdownMenuSeparator />
                            <DropdownMenuItem
                              className="text-destructive focus:text-destructive"
                              onClick={() => handleDelete(entry.id)}
                            >
                              <Trash2 className="mr-2 h-4 w-4" />
                              Remove
                            </DropdownMenuItem>
                          </DropdownMenuContent>
                        </DropdownMenu>
                      </TableCell>
                    </TableRow>
                  );
                })}
              </TableBody>
            </Table>
          )}
        </CardContent>
      </Card>

      {/* Pagination */}
      {pagination.last_page > 1 && (
        <div className="flex items-center justify-center gap-2">
          <Button variant="outline" size="sm" disabled={pagination.current_page <= 1}
            onClick={() => fetchData(pagination.current_page - 1)}>
            Previous
          </Button>
          <span className="text-sm text-muted-foreground">
            Page {pagination.current_page} of {pagination.last_page}
          </span>
          <Button variant="outline" size="sm" disabled={pagination.current_page >= pagination.last_page}
            onClick={() => fetchData(pagination.current_page + 1)}>
            Next
          </Button>
        </div>
      )}

      {/* ── Detail Dialog ── */}
      <Dialog open={!!detail} onOpenChange={(open) => !open && setDetail(null)}>
        <DialogContent className="max-w-lg">
          <DialogHeader>
            <DialogTitle>Waitlist Entry</DialogTitle>
          </DialogHeader>
          {detail && (
            <div className="space-y-4">
              <div className="flex items-start justify-between flex-wrap gap-2">
                <div>
                  <p className="font-semibold text-base">{detail.first_name} {detail.last_name}</p>
                  <p className="text-sm text-muted-foreground">{detail.email}</p>
                </div>
                <div className="flex items-center gap-2 flex-wrap">
                  {statusBadge(detail.status)}
                  {roleBadge(detail.role)}
                </div>
              </div>

              <div className="grid grid-cols-2 gap-x-4 gap-y-2 text-sm">
                <div>
                  <p className="text-xs text-muted-foreground">Country</p>
                  <p>{detail.country ?? "—"}</p>
                </div>
                <div>
                  <p className="text-xs text-muted-foreground">Referral Source</p>
                  <p className="capitalize">{detail.referral_source ?? "—"}</p>
                </div>
                <div>
                  <p className="text-xs text-muted-foreground">Joined</p>
                  <p>{new Date(detail.created_at).toLocaleDateString()} ({daysAgo(detail.created_at)} days ago)</p>
                </div>
                {detail.invited_at && (
                  <div>
                    <p className="text-xs text-muted-foreground">Invited</p>
                    <p>{new Date(detail.invited_at).toLocaleDateString()}</p>
                  </div>
                )}
              </div>

              {/* Role-specific fields */}
              {detail.role === "therapist" && (
                <div className="border-t pt-3 space-y-2">
                  <p className="font-semibold text-sm">Therapist Information</p>
                  <div className="grid grid-cols-2 gap-x-4 gap-y-2 text-sm">
                    <div>
                      <p className="text-xs text-muted-foreground">Years of Experience</p>
                      <p>{detail.years_of_experience ?? "—"}</p>
                    </div>
                    <div>
                      <p className="text-xs text-muted-foreground">Specialty</p>
                      <p>{detail.specialty ?? "—"}</p>
                    </div>
                  </div>
                </div>
              )}

              {detail.role === "institution" && (
                <div className="border-t pt-3 space-y-2">
                  <p className="font-semibold text-sm">Institution Information</p>
                  <div className="grid grid-cols-2 gap-x-4 gap-y-2 text-sm">
                    <div>
                      <p className="text-xs text-muted-foreground">Organization Name</p>
                      <p>{detail.organization_name ?? "—"}</p>
                    </div>
                    <div>
                      <p className="text-xs text-muted-foreground">Institution Type</p>
                      <p className="capitalize">{detail.institution_type ?? "—"}</p>
                    </div>
                    <div className="col-span-2">
                      <p className="text-xs text-muted-foreground">Company Size / Student Count</p>
                      <p>{detail.company_size ?? "—"}</p>
                    </div>
                  </div>
                </div>
              )}

              {detail.message && (
                <div>
                  <p className="text-xs text-muted-foreground mb-1">Message</p>
                  <p className="text-sm bg-muted/40 rounded-lg p-3 whitespace-pre-wrap">{detail.message}</p>
                </div>
              )}

              <div className="flex gap-2 flex-wrap pt-2 border-t">
                {detail.status === "pending" && (
                  <Button size="sm" onClick={() => { handleInvite(detail.id); setDetail(null); }}>
                    <Mail className="mr-2 h-3.5 w-3.5" />
                    Send Invite
                  </Button>
                )}
                {detail.status !== "declined" && (
                  <Button size="sm" variant="outline"
                    onClick={() => { handleStatusChange(detail.id, "declined"); setDetail(null); }}>
                    <XCircle className="mr-2 h-3.5 w-3.5" />
                    Decline
                  </Button>
                )}
                {detail.status === "declined" && (
                  <Button size="sm" variant="outline"
                    onClick={() => { handleStatusChange(detail.id, "pending"); setDetail(null); }}>
                    Restore to Pending
                  </Button>
                )}
                <Button size="sm" variant="ghost"
                  className="text-destructive hover:text-destructive ml-auto"
                  onClick={() => handleDelete(detail.id)}>
                  <Trash2 className="mr-2 h-3.5 w-3.5" />
                  Remove
                </Button>
              </div>
            </div>
          )}
        </DialogContent>
      </Dialog>

    </div>
    </TooltipProvider>
  );
}

"use client";

import React, { useEffect, useState } from "react";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Dialog, DialogContent, DialogFooter, DialogHeader, DialogTitle,
} from "@/components/ui/dialog";
import {
  Select, SelectContent, SelectItem, SelectTrigger, SelectValue,
} from "@/components/ui/select";
import { cooService } from "@/lib/api/coo";
import {
  Target,
  Plus,
  TrendingUp,
  RefreshCw,
  Pencil,
  Trash2,
  Loader2,
} from "lucide-react";
import { toast } from "@/components/ui/use-toast";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow
} from "@/components/ui/table";
import { Skeleton } from "@/components/ui/skeleton";
import { Progress } from "@/components/ui/progress";

const CAMPAIGN_TYPES = ["social", "email", "seo", "paid", "content", "partnership", "event", "other"];
const CAMPAIGN_STATUSES = ["draft", "active", "paused", "completed"];

const EMPTY_FORM = {
  name: "",
  type: "social",
  status: "draft",
  budget: "",
  start_date: "",
  end_date: "",
};

export default function MarketingPage() {
  const [funnel, setFunnel] = useState<any>(null);
  const [campaigns, setCampaigns] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [dialogOpen, setDialogOpen] = useState(false);
  const [saving, setSaving] = useState(false);
  const [editingId, setEditingId] = useState<number | null>(null);
  const [form, setForm] = useState({ ...EMPTY_FORM });

  const fetchData = async () => {
    setLoading(true);
    try {
      const [funnelRes, campaignsRes] = await Promise.all([
        cooService.getMarketingFunnel(),
        cooService.getMarketingCampaigns()
      ]);
      setFunnel(funnelRes.data.data);
      setCampaigns(campaignsRes.data.data.data || []);
    } catch {
      toast({ title: "Error", description: "Failed to load marketing data", variant: "destructive" });
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchData(); }, []);

  const openCreate = () => {
    setEditingId(null);
    setForm({ ...EMPTY_FORM });
    setDialogOpen(true);
  };

  const openEdit = (c: any) => {
    setEditingId(c.id);
    setForm({
      name: c.name ?? "",
      type: c.type ?? "social",
      status: c.status ?? "draft",
      budget: c.budget?.amount ?? c.budget ?? "",
      start_date: c.start_date ?? "",
      end_date: c.end_date ?? "",
    });
    setDialogOpen(true);
  };

  const handleSave = async () => {
    if (!form.name || !form.type || !form.status) {
      toast({ description: "Name, type, and status are required", variant: "destructive" });
      return;
    }
    setSaving(true);
    try {
      const payload = {
        name: form.name,
        type: form.type,
        status: form.status,
        budget: form.budget ? Number(form.budget) : null,
        start_date: form.start_date || null,
        end_date: form.end_date || null,
      };
      if (editingId) {
        await cooService.updateMarketingCampaign(editingId, payload);
        toast({ description: "Campaign updated" });
      } else {
        await cooService.createMarketingCampaign(payload);
        toast({ description: "Campaign created" });
      }
      setDialogOpen(false);
      fetchData();
    } catch {
      toast({ description: "Failed to save campaign", variant: "destructive" });
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async (id: number, name: string) => {
    if (!confirm(`Delete campaign "${name}"?`)) return;
    try {
      await cooService.deleteMarketingCampaign(id);
      toast({ description: "Campaign deleted" });
      fetchData();
    } catch {
      toast({ description: "Failed to delete campaign", variant: "destructive" });
    }
  };

  if (loading && !funnel) {
    return (
      <div className="space-y-6">
        <Skeleton className="h-10 w-64" />
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <Skeleton className="h-[400px] w-full" />
          <Skeleton className="h-[400px] w-full" />
        </div>
      </div>
    );
  }

  const { funnel: funnelData, growth } = funnel || {};

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-bold tracking-tight">Marketing & Growth</h1>
          <p className="text-muted-foreground">Acquisition funnel and campaign performance</p>
        </div>
        <Button onClick={fetchData} variant="outline" size="sm" className="gap-2">
          <RefreshCw className={`w-4 h-4 ${loading ? 'animate-spin' : ''}`} />
          Refresh
        </Button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <Card className="lg:col-span-2">
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <TrendingUp className="w-5 h-5 text-blue-500" />
              Acquisition Funnel
            </CardTitle>
            <CardDescription>Conversion steps from visit to first session</CardDescription>
          </CardHeader>
          <CardContent className="space-y-8 py-6">
            <div className="space-y-2">
              <div className="flex justify-between text-sm">
                <span className="font-medium">Homepage Visits</span>
                <span>{funnelData?.homepage_visits || 'Requires Analytics'}</span>
              </div>
              <Progress value={100} className="h-3" />
            </div>

            <div className="space-y-2">
              <div className="flex justify-between text-sm">
                <span className="font-medium">Signups Started</span>
                <div className="flex gap-2 items-center">
                  <span>{funnelData?.signups_started}</span>
                  <Badge variant="outline" className="text-[10px]">12.5% CR</Badge>
                </div>
              </div>
              <Progress value={85} className="h-3 bg-blue-50" />
            </div>

            <div className="space-y-2">
              <div className="flex justify-between text-sm">
                <span className="font-medium">Onboarding Completed</span>
                <div className="flex gap-2 items-center">
                  <span>{funnelData?.onboarding_completed}</span>
                  <Badge variant="outline" className="text-[10px]">68% CR</Badge>
                </div>
              </div>
              <Progress value={58} className="h-3 bg-blue-100" />
            </div>

            <div className="space-y-2">
              <div className="flex justify-between text-sm">
                <span className="font-medium">First AI Message</span>
                <div className="flex gap-2 items-center">
                  <span>{funnelData?.first_ai_message}</span>
                  <Badge variant="outline" className="text-[10px]">92% CR</Badge>
                </div>
              </div>
              <Progress value={53} className="h-3 bg-blue-200" />
            </div>

            <div className="space-y-2">
              <div className="flex justify-between text-sm">
                <span className="font-medium">First Session Booked</span>
                <div className="flex gap-2 items-center">
                  <span>{funnelData?.first_session_booked}</span>
                  <Badge variant="default" className="text-[10px]">24% CR</Badge>
                </div>
              </div>
              <Progress value={12} className="h-3 bg-blue-500" />
            </div>
          </CardContent>
        </Card>

        <div className="space-y-6">
          <Card>
            <CardHeader className="pb-2">
              <CardTitle className="text-sm font-medium">Total Users</CardTitle>
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">{growth?.total_users}</div>
              <p className="text-xs text-muted-foreground">+{growth?.new_this_week} this week</p>
            </CardContent>
          </Card>

          <Card>
            <CardHeader className="pb-2">
              <CardTitle className="text-sm font-medium">Users by Plan</CardTitle>
            </CardHeader>
            <CardContent className="space-y-2">
              {growth?.users_by_plan?.map((plan: any) => (
                <div key={plan.name} className="flex justify-between text-sm items-center py-1">
                  <span className="capitalize">{plan.name}</span>
                  <span className="font-semibold">{plan.total}</span>
                </div>
              ))}
            </CardContent>
          </Card>
        </div>
      </div>

      <Card>
        <CardHeader className="flex flex-row items-center justify-between">
          <div>
            <CardTitle>Marketing Campaigns</CardTitle>
            <CardDescription>Performance tracking for active marketing channels</CardDescription>
          </div>
          <Button size="sm" className="gap-2" onClick={openCreate}>
            <Plus className="w-4 h-4" />
            New Campaign
          </Button>
        </CardHeader>
        <CardContent className="p-0">
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead>Campaign Name</TableHead>
                <TableHead>Channel</TableHead>
                <TableHead>Budget</TableHead>
                <TableHead>Status</TableHead>
                <TableHead className="text-right">Actions</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {campaigns.length === 0 ? (
                <TableRow>
                  <TableCell colSpan={5} className="h-32 text-center text-muted-foreground">
                    No campaigns yet. Click "New Campaign" to add one.
                  </TableCell>
                </TableRow>
              ) : (
                campaigns.map((campaign) => (
                  <TableRow key={campaign.id}>
                    <TableCell className="font-medium">{campaign.name}</TableCell>
                    <TableCell>
                      <Badge variant="outline" className="capitalize">
                        {campaign.type || 'Social'}
                      </Badge>
                    </TableCell>
                    <TableCell>
                      {campaign.budget ? `$${Number(campaign.budget).toLocaleString()}` : "—"}
                    </TableCell>
                    <TableCell>
                      <Badge variant={campaign.status === 'active' ? 'default' : 'secondary'}>
                        {campaign.status}
                      </Badge>
                    </TableCell>
                    <TableCell className="text-right">
                      <div className="flex justify-end gap-2">
                        <Button variant="ghost" size="icon" onClick={() => openEdit(campaign)}>
                          <Pencil className="w-4 h-4" />
                        </Button>
                        <Button variant="ghost" size="icon" className="text-destructive" onClick={() => handleDelete(campaign.id, campaign.name)}>
                          <Trash2 className="w-4 h-4" />
                        </Button>
                      </div>
                    </TableCell>
                  </TableRow>
                ))
              )}
            </TableBody>
          </Table>
        </CardContent>
      </Card>

      {/* Create / Edit Dialog */}
      <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
        <DialogContent className="sm:max-w-[480px]">
          <DialogHeader>
            <DialogTitle>{editingId ? "Edit Campaign" : "New Campaign"}</DialogTitle>
          </DialogHeader>
          <div className="grid gap-3 py-2">
            <div className="grid gap-1.5">
              <Label>Campaign Name *</Label>
              <Input placeholder="e.g. Q2 LinkedIn Push" value={form.name} onChange={e => setForm(f => ({ ...f, name: e.target.value }))} />
            </div>
            <div className="grid grid-cols-2 gap-3">
              <div className="grid gap-1.5">
                <Label>Channel / Type *</Label>
                <Select value={form.type} onValueChange={v => setForm(f => ({ ...f, type: v ?? "" }))}>
                  <SelectTrigger><SelectValue /></SelectTrigger>
                  <SelectContent>
                    {CAMPAIGN_TYPES.map(t => <SelectItem key={t} value={t} className="capitalize">{t}</SelectItem>)}
                  </SelectContent>
                </Select>
              </div>
              <div className="grid gap-1.5">
                <Label>Status *</Label>
                <Select value={form.status} onValueChange={v => setForm(f => ({ ...f, status: v ?? "" }))}>
                  <SelectTrigger><SelectValue /></SelectTrigger>
                  <SelectContent>
                    {CAMPAIGN_STATUSES.map(s => <SelectItem key={s} value={s} className="capitalize">{s}</SelectItem>)}
                  </SelectContent>
                </Select>
              </div>
            </div>
            <div className="grid gap-1.5">
              <Label>Budget (USD) <span className="text-muted-foreground text-xs">optional</span></Label>
              <Input type="number" min={0} placeholder="e.g. 5000" value={form.budget} onChange={e => setForm(f => ({ ...f, budget: e.target.value }))} />
            </div>
            <div className="grid grid-cols-2 gap-3">
              <div className="grid gap-1.5">
                <Label>Start Date</Label>
                <Input type="date" value={form.start_date} onChange={e => setForm(f => ({ ...f, start_date: e.target.value }))} />
              </div>
              <div className="grid gap-1.5">
                <Label>End Date</Label>
                <Input type="date" value={form.end_date} onChange={e => setForm(f => ({ ...f, end_date: e.target.value }))} />
              </div>
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setDialogOpen(false)} disabled={saving}>Cancel</Button>
            <Button onClick={handleSave} disabled={saving || !form.name}>
              {saving ? <><Loader2 className="mr-2 h-4 w-4 animate-spin" />Saving…</> : editingId ? "Update" : "Create Campaign"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

"use client";

import React, { useEffect, useState } from "react";
import { Button } from "@/components/ui/button";
import { cooService } from "@/lib/api/coo";
import {
  Plus,
  Milestone,
  AlertCircle,
  Gavel,
  Settings,
  FileText,
  HelpCircle,
} from "lucide-react";
import { toast } from "@/components/ui/use-toast";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Skeleton } from "@/components/ui/skeleton";
import { PageHeader } from "@/components/shared/page-header";

const LOG_TYPE_ICONS: Record<string, React.ElementType> = {
  milestone:     Milestone,
  incident:      AlertCircle,
  decision:      Gavel,
  process:       Settings,
  investor_note: FileText,
  other:         HelpCircle,
};

const LOG_TYPE_COLORS: Record<string, string> = {
  milestone:     "bg-emerald-50 text-emerald-700",
  incident:      "bg-red-50 text-red-700",
  decision:      "bg-blue-50 text-blue-700",
  process:       "bg-amber-50 text-amber-700",
  investor_note: "bg-purple-50 text-purple-700",
  other:         "bg-gray-100 text-gray-700",
};

const DOT_COLORS: Record<string, string> = {
  milestone:     "bg-emerald-500",
  incident:      "bg-red-500",
  decision:      "bg-blue-500",
  process:       "bg-amber-warm",
  investor_note: "bg-purple-500",
  other:         "bg-gray-400",
};

function formatDate(dateStr: string): string {
  return new Date(dateStr).toLocaleDateString("en-GB", {
    day: "2-digit",
    month: "short",
    year: "numeric",
  });
}

interface LogEntry {
  id: number;
  title: string;
  type: string;
  body: string;
  log_date: string;
  visibility: string;
  creator?: { first_name?: string; last_name?: string };
}

interface FormState {
  title: string;
  type: string;
  body: string;
  log_date: string;
  visibility: string;
}

const EMPTY_FORM: FormState = {
  title: "",
  type: "milestone",
  body: "",
  log_date: new Date().toISOString().split("T")[0],
  visibility: "coo_ceo",
};

export default function OperationalLogPage() {
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [loading, setLoading] = useState(true);
  const [isDialogOpen, setIsDialogOpen] = useState(false);
  const [editingLog, setEditingLog] = useState<LogEntry | null>(null);
  const [formData, setFormData] = useState<FormState>(EMPTY_FORM);

  const fetchLogs = async () => {
    setLoading(true);
    try {
      const res = await cooService.getOperationalLogs();
      setLogs((res as { data: { data: { data: LogEntry[] } } }).data.data.data || []);
    } catch {
      toast({ title: "Error", description: "Failed to load operational logs", variant: "destructive" });
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchLogs();
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  const handleCreateOrUpdate = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      if (editingLog) {
        await cooService.updateOperationalLog(editingLog.id, formData);
        toast({ title: "Success", description: "Log entry updated" });
      } else {
        await cooService.createOperationalLog(formData);
        toast({ title: "Success", description: "Log entry created" });
      }
      setIsDialogOpen(false);
      setEditingLog(null);
      setFormData(EMPTY_FORM);
      fetchLogs();
    } catch {
      toast({ title: "Error", description: "Failed to save log entry", variant: "destructive" });
    }
  };

  const handleDelete = async (id: number) => {
    if (!confirm("Are you sure you want to delete this log entry?")) return;
    try {
      await cooService.deleteOperationalLog(id);
      toast({ title: "Success", description: "Log entry deleted" });
      fetchLogs();
    } catch {
      toast({ title: "Error", description: "Failed to delete log entry", variant: "destructive" });
    }
  };

  const openEditDialog = (log: LogEntry) => {
    setEditingLog(log);
    setFormData({
      title: log.title,
      type: log.type,
      body: log.body,
      log_date: new Date(log.log_date).toISOString().split("T")[0],
      visibility: log.visibility,
    });
    setIsDialogOpen(true);
  };

  return (
    <div className="p-6 space-y-6">
      <PageHeader
        title="Operational Log"
        subtitle="Internal operational history and milestone log"
      >
        <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
          <DialogTrigger asChild>
            <Button
              className="gap-2 bg-teal text-white hover:bg-teal-mid"
              onClick={() => {
                setEditingLog(null);
                setFormData(EMPTY_FORM);
              }}
            >
              <Plus className="w-4 h-4" />
              Add Entry
            </Button>
          </DialogTrigger>
          <DialogContent className="sm:max-w-[525px]">
            <form onSubmit={handleCreateOrUpdate}>
              <DialogHeader>
                <DialogTitle>{editingLog ? "Edit Log Entry" : "Add New Log Entry"}</DialogTitle>
                <DialogDescription>
                  Document important operational events for future reference.
                </DialogDescription>
              </DialogHeader>
              <div className="grid gap-4 py-4">
                <div className="grid gap-2">
                  <Label htmlFor="log-title">Title</Label>
                  <Input
                    id="log-title"
                    value={formData.title}
                    onChange={(e) => setFormData({ ...formData, title: e.target.value })}
                    placeholder="e.g. Series A Funding Completed"
                    required
                  />
                </div>
                <div className="grid grid-cols-2 gap-4">
                  <div className="grid gap-2">
                    <Label htmlFor="log-type">Type</Label>
                    <Select
                      value={formData.type}
                      onValueChange={(value: string | null) => setFormData({ ...formData, type: value ?? "" })}
                    >
                      <SelectTrigger id="log-type">
                        <SelectValue placeholder="Select type" />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="milestone">Milestone</SelectItem>
                        <SelectItem value="incident">Incident</SelectItem>
                        <SelectItem value="decision">Decision</SelectItem>
                        <SelectItem value="process">Process Change</SelectItem>
                        <SelectItem value="investor_note">Investor Note</SelectItem>
                        <SelectItem value="other">Other</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>
                  <div className="grid gap-2">
                    <Label htmlFor="log-date">Date</Label>
                    <Input
                      id="log-date"
                      type="date"
                      value={formData.log_date}
                      onChange={(e) => setFormData({ ...formData, log_date: e.target.value })}
                      required
                    />
                  </div>
                </div>
                <div className="grid gap-2">
                  <Label htmlFor="log-body">Content</Label>
                  <Textarea
                    id="log-body"
                    value={formData.body}
                    onChange={(e) => setFormData({ ...formData, body: e.target.value })}
                    placeholder="Detailed description…"
                    className="h-32"
                    required
                  />
                </div>
                <div className="grid gap-2">
                  <Label htmlFor="log-visibility">Visibility</Label>
                  <Select
                    value={formData.visibility}
                    onValueChange={(value: string | null) => setFormData({ ...formData, visibility: value ?? "" })}
                  >
                    <SelectTrigger id="log-visibility">
                      <SelectValue placeholder="Select visibility" />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="coo_ceo">COO &amp; CEO Only</SelectItem>
                      <SelectItem value="all_admin">All Admin Staff</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
              </div>
              <DialogFooter>
                <Button type="submit" className="bg-teal text-white hover:bg-teal-mid">
                  {editingLog ? "Save Changes" : "Create Entry"}
                </Button>
              </DialogFooter>
            </form>
          </DialogContent>
        </Dialog>
      </PageHeader>

      {/* Timeline */}
      <div className="bg-white rounded-xl border border-gray-100 shadow-sm p-6">
        {loading ? (
          <div className="space-y-8">
            {[1, 2, 3, 4].map((i) => (
              <div key={i} className="flex gap-4">
                <div className="flex flex-col items-center">
                  <Skeleton className="w-3 h-3 rounded-full mt-1 shrink-0" />
                  <Skeleton className="w-px flex-1 mt-1" />
                </div>
                <div className="pb-6 flex-1 space-y-2">
                  <Skeleton className="h-4 w-1/3" />
                  <Skeleton className="h-3 w-1/5" />
                  <Skeleton className="h-3 w-2/3 mt-2" />
                </div>
              </div>
            ))}
          </div>
        ) : logs.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-16">
            <FileText className="w-12 h-12 text-gray-200 mb-4" />
            <p className="text-sm font-medium text-gray-600">No log entries yet</p>
            <p className="text-xs text-gray-400 mt-1">Add your first operational milestone or incident</p>
          </div>
        ) : (
          <div>
            {logs.map((log, idx) => {
              const Icon = LOG_TYPE_ICONS[log.type] ?? HelpCircle;
              const dotColor = DOT_COLORS[log.type] ?? "bg-gray-400";
              const badgeColor = LOG_TYPE_COLORS[log.type] ?? "bg-gray-100 text-gray-700";
              const isLast = idx === logs.length - 1;

              return (
                <div key={log.id} className="flex gap-4">
                  {/* Timeline spine */}
                  <div className="flex flex-col items-center shrink-0">
                    <div className={`w-2.5 h-2.5 rounded-full mt-1.5 shrink-0 ${dotColor}`} />
                    {!isLast && <div className="w-px flex-1 bg-gray-100 mt-1" />}
                  </div>

                  {/* Entry content */}
                  <div className="pb-8 flex-1 min-w-0">
                    <div className="flex items-start justify-between gap-3">
                      <div className="flex items-start gap-2 min-w-0">
                        <p className="text-sm font-semibold text-gray-900 truncate">{log.title}</p>
                      </div>
                      <div className="flex items-center gap-2 shrink-0">
                        <span className="text-xs text-gray-400">{formatDate(log.log_date)}</span>
                        {/* Edit / Delete actions */}
                        <button
                          onClick={() => openEditDialog(log)}
                          className="text-xs text-gray-400 hover:text-teal transition-colors px-1"
                          title="Edit"
                        >
                          Edit
                        </button>
                        <button
                          onClick={() => handleDelete(log.id)}
                          className="text-xs text-gray-400 hover:text-red-500 transition-colors px-1"
                          title="Delete"
                        >
                          Delete
                        </button>
                      </div>
                    </div>

                    <div className="flex items-center gap-2 mt-1.5 flex-wrap">
                      <span className={`inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-xs font-medium ${badgeColor}`}>
                        <Icon className="w-3 h-3" />
                        {log.type.replace(/_/g, " ")}
                      </span>
                      <span className="text-xs text-gray-400">
                        by {log.creator?.first_name ?? "—"} {log.creator?.last_name ?? ""}
                      </span>
                      <span className={`inline-flex items-center px-1.5 py-0.5 rounded text-[10px] font-medium uppercase ${
                        log.visibility === "coo_ceo" ? "bg-gray-100 text-gray-500" : "bg-teal/5 text-teal"
                      }`}>
                        {log.visibility === "coo_ceo" ? "Private" : "Shared"}
                      </span>
                    </div>

                    <p className="text-sm text-gray-600 mt-2 leading-relaxed">{log.body}</p>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
}

"use client";

import { useEffect, useMemo, useState } from "react";
import { adminService } from "@/lib/api/admin";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuLabel, DropdownMenuTrigger } from "@/components/ui/dropdown-menu";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { MoreHorizontal, Download, Search, Filter, CheckCircle, XCircle, Wrench } from "lucide-react";
import { downloadCSV } from "@/lib/export-utils";

type WorkflowItem = {
  id: number | string;
  title?: string;
  type?: string;
  status?: "pending" | "approved" | "rejected" | "completed" | string;
  requester?: string;
  created_at?: string;
  updated_at?: string;
};

export default function AdminWorkflowsPage() {
  const [items, setItems] = useState<WorkflowItem[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [search, setSearch] = useState("");
  const [status, setStatus] = useState("all");

  async function load() {
    setIsLoading(true);
    try {
      const res = await adminService.getMaintenance();
      const rows = Array.isArray((res as any)?.data) ? (res as any).data : Array.isArray(res) ? res : [];
      setItems(rows as WorkflowItem[]);
    } finally {
      setIsLoading(false);
    }
  }

  useEffect(() => {
    load();
  }, []);

  const filtered = useMemo(() => {
    const s = search.toLowerCase();
    return items.filter((r) => {
      const txt = `${r.title ?? ""} ${r.type ?? ""} ${r.status ?? ""} ${r.requester ?? ""}`.toLowerCase();
      const matchSearch = txt.includes(s);
      const matchStatus = status === "all" ? true : (r.status ?? "").toLowerCase() === status;
      return matchSearch && matchStatus;
    });
  }, [items, search, status]);

  async function approve(id: number | string) {
    await adminService.approveMaintenance(id);
    await load();
  }
  async function reject(id: number | string) {
    await adminService.rejectMaintenance(id);
    await load();
  }
  async function complete(id: number | string) {
    await adminService.completeMaintenance(id);
    await load();
  }

  function handleExport() {
    const rows = filtered.map((r) => ({
      id: r.id,
      title: r.title ?? "",
      type: r.type ?? "",
      status: r.status ?? "",
      requester: r.requester ?? "",
      created_at: r.created_at ?? "",
    }));
    downloadCSV("admin-workflows.csv", ["id", "title", "type", "status", "requester", "created_at"], rows);
  }

  return (
    <div className="flex-1 p-6 space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-3xl font-bold tracking-tight">Workflows</h2>
          <p className="text-sm text-muted-foreground">Approve or complete maintenance and requests</p>
        </div>
        <Button variant="outline" onClick={handleExport}>
          <Download className="h-4 w-4 mr-2" /> Export
        </Button>
      </div>

      <Card>
        <CardHeader className="flex flex-row items-center justify-between">
          <div>
            <CardTitle>Pending & Active Items</CardTitle>
            <CardDescription>Track approval and completion flow</CardDescription>
          </div>
          <div className="flex items-center gap-3 w-full md:w-auto">
            <div className="relative w-full md:w-72">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
              <Input
                placeholder="Search workflows..."
                className="pl-9"
                value={search}
                onChange={(e) => setSearch(e.target.value)}
              />
            </div>
            <div className="flex items-center gap-2">
              <Filter className="h-4 w-4 text-muted-foreground" />
              <Select value={status} onValueChange={(v: string | null) => setStatus(v ?? "all")}>
                <SelectTrigger className="w-[160px]">
                  <SelectValue placeholder="Filter by status" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">All</SelectItem>
                  <SelectItem value="pending">Pending</SelectItem>
                  <SelectItem value="approved">Approved</SelectItem>
                  <SelectItem value="rejected">Rejected</SelectItem>
                  <SelectItem value="completed">Completed</SelectItem>
                </SelectContent>
              </Select>
            </div>
          </div>
        </CardHeader>
        <CardContent className="overflow-auto">
          <div className="border rounded-md">
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>Title</TableHead>
                  <TableHead>Type</TableHead>
                  <TableHead>Status</TableHead>
                  <TableHead>Requester</TableHead>
                  <TableHead>Created</TableHead>
                  <TableHead className="w-[160px]">Actions</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {isLoading ? (
                  <TableRow>
                    <TableCell colSpan={6} className="text-center py-6">Loading...</TableCell>
                  </TableRow>
                ) : filtered.length ? (
                  filtered.map((r) => (
                    <TableRow key={String(r.id)}>
                      <TableCell className="font-medium">{r.title ?? "—"}</TableCell>
                      <TableCell>{r.type ?? "—"}</TableCell>
                      <TableCell>
                        <span className="inline-flex items-center gap-1">
                          {String(r.status).toLowerCase() === "approved" && <CheckCircle className="h-4 w-4 text-green-500" />}
                          {String(r.status).toLowerCase() === "rejected" && <XCircle className="h-4 w-4 text-red-500" />}
                          {String(r.status).toLowerCase() === "completed" && <Wrench className="h-4 w-4 text-blue-500" />}
                          <Badge variant="secondary" className="capitalize">{r.status ?? "pending"}</Badge>
                        </span>
                      </TableCell>
                      <TableCell>{r.requester ?? "—"}</TableCell>
                      <TableCell>{r.created_at ? new Date(r.created_at).toLocaleString() : "—"}</TableCell>
                      <TableCell>
                        <DropdownMenu>
                          <DropdownMenuTrigger asChild>
                            <Button variant="ghost" className="h-8 w-8 p-0">
                              <span className="sr-only">Open menu</span>
                              <MoreHorizontal className="h-4 w-4" />
                            </Button>
                          </DropdownMenuTrigger>
                          <DropdownMenuContent align="end">
                            <DropdownMenuLabel>Actions</DropdownMenuLabel>
                            <DropdownMenuItem onClick={() => approve(r.id)}>Approve</DropdownMenuItem>
                            <DropdownMenuItem onClick={() => reject(r.id)} className="text-red-600">Reject</DropdownMenuItem>
                            <DropdownMenuItem onClick={() => complete(r.id)}>Mark Complete</DropdownMenuItem>
                          </DropdownMenuContent>
                        </DropdownMenu>
                      </TableCell>
                    </TableRow>
                  ))
                ) : (
                  <TableRow>
                    <TableCell colSpan={6} className="text-center py-6">No workflows found.</TableCell>
                  </TableRow>
                )}
              </TableBody>
            </Table>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Skeleton } from "@/components/ui/skeleton";
import { Alert, AlertDescription } from "@/components/ui/alert";
import client from "@/lib/api/client";
import { RefreshCw, ShieldCheck, AlertTriangle, CheckCircle2, XCircle, AlertCircle } from "lucide-react";

interface ComplianceCheck {
  label: string;
  status: "pass" | "fail" | "warn";
  description?: string;
  last_checked?: string;
  owner?: string;
}

interface ComplianceData {
  compliance_score?: number;
  open_issues?: number;
  resolved_issues?: number;
  checks?: ComplianceCheck[];
  last_audit_date?: string;
}

const STATUS_CONFIG = {
  pass: { icon: CheckCircle2, color: "text-emerald-600", badge: "bg-emerald-50 text-emerald-700 hover:bg-emerald-50", label: "Pass" },
  warn: { icon: AlertCircle,  color: "text-yellow-600",  badge: "bg-yellow-50 text-yellow-700 hover:bg-yellow-50",   label: "Warning" },
  fail: { icon: XCircle,      color: "text-red-600",     badge: "bg-red-50 text-red-700 hover:bg-red-50",           label: "Fail" },
};

export default function AuditCompliancePage() {
  const [data, setData]       = useState<ComplianceData | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError]     = useState<string | null>(null);

  const fetchData = async () => {
    setLoading(true);
    setError(null);
    try {
      const [statsRes, overviewRes] = await Promise.all([
        client.get("/api/v1/compliance/stats").catch(() => ({ data: {} })),
        client.get("/api/v1/audit/overview").catch(() => ({ data: {} })),
      ]);
      const stats    = statsRes.data?.data   ?? statsRes.data   ?? {};
      const overview = overviewRes.data?.data ?? overviewRes.data ?? {};
      setData({
        compliance_score:  stats.compliance_score  ?? overview.compliance_score ?? 100,
        open_issues:       stats.open_issues        ?? overview.active_violations ?? 0,
        resolved_issues:   stats.resolved_issues    ?? 0,
        checks:            overview.compliance_checks ?? [],
        last_audit_date:   stats.last_audit_date    ?? null,
      });
    } catch {
      setError("Unable to load compliance data.");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchData(); }, []); // eslint-disable-line react-hooks/exhaustive-deps

  const score       = data?.compliance_score ?? 100;
  const scoreColor  = score >= 90 ? "text-emerald-600" : score >= 70 ? "text-yellow-600" : "text-red-600";
  const checks      = data?.checks ?? [];
  const passCount   = checks.filter((c) => c.status === "pass").length;
  const warnCount   = checks.filter((c) => c.status === "warn").length;
  const failCount   = checks.filter((c) => c.status === "fail").length;

  return (
    <div className="p-6 space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold tracking-tight">Compliance Status</h1>
          <p className="text-sm text-muted-foreground mt-0.5">Platform-wide compliance posture and control checks</p>
        </div>
        <Button variant="outline" size="sm" className="gap-2" onClick={fetchData} disabled={loading}>
          <RefreshCw className={`size-4 ${loading ? "animate-spin" : ""}`} />
          Refresh
        </Button>
      </div>

      {error && (
        <Alert variant="destructive">
          <AlertTriangle className="size-4" />
          <AlertDescription>{error}</AlertDescription>
        </Alert>
      )}

      {/* Score + summary cards */}
      <div className="grid grid-cols-1 sm:grid-cols-4 gap-4">
        {loading ? (
          Array.from({ length: 4 }).map((_, i) => <Skeleton key={i} className="h-24" />)
        ) : (
          <>
            <Card className="sm:col-span-1 flex flex-col items-center justify-center py-6">
              <ShieldCheck className={`size-8 mb-2 ${scoreColor}`} />
              <p className={`text-4xl font-bold ${scoreColor}`}>{score}%</p>
              <p className="text-xs text-muted-foreground mt-1">Compliance Score</p>
            </Card>
            {[
              { label: "Passing", value: passCount, color: "text-emerald-600" },
              { label: "Warnings", value: warnCount, color: "text-yellow-600" },
              { label: "Failing", value: failCount, color: "text-red-600" },
            ].map(({ label, value, color }) => (
              <Card key={label} className="flex flex-col items-center justify-center py-6">
                <p className={`text-3xl font-bold ${color}`}>{value}</p>
                <p className="text-xs text-muted-foreground mt-1">{label} Checks</p>
              </Card>
            ))}
          </>
        )}
      </div>

      {/* Checks list */}
      <Card>
        <CardHeader className="pb-2">
          <CardTitle className="text-base">Control Checks</CardTitle>
        </CardHeader>
        <CardContent className="space-y-2">
          {loading ? (
            Array.from({ length: 6 }).map((_, i) => <Skeleton key={i} className="h-12" />)
          ) : checks.length === 0 ? (
            <p className="text-sm text-muted-foreground py-6 text-center">No compliance checks configured.</p>
          ) : (
            checks.map((check, i) => {
              const cfg = STATUS_CONFIG[check.status] ?? STATUS_CONFIG.warn;
              return (
                <div key={i} className="flex items-center justify-between p-3 rounded-lg border bg-card">
                  <div className="flex items-center gap-3">
                    <cfg.icon className={`size-4 shrink-0 ${cfg.color}`} />
                    <div>
                      <p className="text-sm font-medium">{check.label}</p>
                      {check.description && <p className="text-xs text-muted-foreground">{check.description}</p>}
                    </div>
                  </div>
                  <div className="flex items-center gap-2 shrink-0">
                    {check.owner && <span className="text-xs text-muted-foreground hidden sm:block">{check.owner}</span>}
                    <Badge className={`text-xs ${cfg.badge}`}>{cfg.label}</Badge>
                  </div>
                </div>
              );
            })
          )}
        </CardContent>
      </Card>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Alert, AlertDescription } from "@/components/ui/alert";
import { Skeleton } from "@/components/ui/skeleton";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { StatCard } from "@/components/shared/stat-card";
import { StatCardsShimmer } from "@/components/shared/shimmer-skeleton";
import client from "@/lib/api/client";
import { RefreshCw, ShieldCheck, AlertTriangle, Users, Lock, FileText, Activity } from "lucide-react";

interface AuditOverview {
  events_today?: number;
  flagged_events?: number;
  compliance_score?: number;
  active_violations?: number;
  users_audited?: number;
  security_events?: number;
  recent_events?: {
    id: number | string;
    timestamp: string;
    user_name?: string;
    action: string;
    ip_address?: string;
    severity: "low" | "medium" | "high" | "critical";
    resource?: string;
  }[];
  compliance_checks?: { label: string; status: "pass" | "fail" | "warn"; description?: string }[];
  risk_level?: "low" | "medium" | "high";
}

const SEVERITY_COLORS: Record<string, string> = {
  low:      "bg-gray-100 text-gray-700",
  medium:   "bg-yellow-50 text-yellow-700",
  high:     "bg-orange-50 text-orange-700",
  critical: "bg-red-50 text-red-700",
};

const RISK_COLORS: Record<string, string> = {
  low:    "text-emerald-600 bg-emerald-50",
  medium: "text-yellow-700 bg-yellow-50",
  high:   "text-red-600 bg-red-50",
};

export default function AuditDashboardPage() {
  const [data, setData] = useState<AuditOverview | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const fetchData = async () => {
    setLoading(true);
    setError(null);
    try {
      const res = await client.get("/api/v1/audit/overview");
      setData(res.data?.data ?? res.data ?? {});
    } catch {
      setError("Unable to load audit data. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchData(); }, []); // eslint-disable-line react-hooks/exhaustive-deps

  const events = data?.recent_events ?? [];
  const checks = data?.compliance_checks ?? [];
  const riskLevel = data?.risk_level ?? "low";

  return (
    <div className="p-6 space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-bold tracking-tight">Audit & Compliance Center</h1>
          <p className="text-muted-foreground text-sm mt-1">Read-only view — all changes require authorization</p>
        </div>
        <Button onClick={fetchData} variant="outline" size="sm" className="gap-2">
          <RefreshCw className={`w-4 h-4 ${loading ? "animate-spin" : ""}`} />
          Refresh
        </Button>
      </div>

      {error && (
        <Alert variant="destructive">
          <AlertTriangle className="h-4 w-4" />
          <AlertDescription>{error}</AlertDescription>
        </Alert>
      )}

      {loading && !data ? (
        <StatCardsShimmer count={6} />
      ) : (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-6 gap-4">
          <StatCard label="Events Today"       value={data?.events_today}      icon={Activity}    colour="blue"   isLoading={loading} />
          <StatCard label="Flagged Events"      value={data?.flagged_events}    icon={AlertTriangle} colour={(data?.flagged_events ?? 0) > 0 ? "red" : "emerald"} isLoading={loading} />
          <StatCard label="Compliance Score"    value={data?.compliance_score !== undefined ? `${data.compliance_score}%` : "—"} icon={ShieldCheck} colour={((data?.compliance_score ?? 0) >= 90) ? "emerald" : ((data?.compliance_score ?? 0) >= 70) ? "amber" : "red"} isLoading={loading} />
          <StatCard label="Active Violations"   value={data?.active_violations} icon={AlertTriangle} colour={(data?.active_violations ?? 0) > 0 ? "red" : "emerald"} isLoading={loading} />
          <StatCard label="Users Audited"       value={data?.users_audited}     icon={Users}       colour="blue"   isLoading={loading} />
          <StatCard label="Security Events"     value={data?.security_events}   icon={Lock}        colour={(data?.security_events ?? 0) > 5 ? "red" : "amber"} isLoading={loading} />
        </div>
      )}

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <Card className="lg:col-span-2">
          <CardHeader>
            <CardTitle>Recent Audit Events</CardTitle>
          </CardHeader>
          <CardContent>
            {loading ? (
              <Skeleton className="h-64 w-full" />
            ) : events.length === 0 ? (
              <p className="text-sm text-muted-foreground">No events recorded today.</p>
            ) : (
              <Table>
                <TableHeader>
                  <TableRow>
                    <TableHead>Time</TableHead>
                    <TableHead>User</TableHead>
                    <TableHead>Action</TableHead>
                    <TableHead>Resource</TableHead>
                    <TableHead>IP</TableHead>
                    <TableHead>Severity</TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {events.slice(0, 12).map((ev) => (
                    <TableRow key={ev.id}>
                      <TableCell className="text-xs text-muted-foreground whitespace-nowrap">
                        {new Date(ev.timestamp).toLocaleTimeString()}
                      </TableCell>
                      <TableCell className="text-sm">{ev.user_name ?? "—"}</TableCell>
                      <TableCell className="text-sm font-medium">{ev.action}</TableCell>
                      <TableCell className="text-xs text-muted-foreground">{ev.resource ?? "—"}</TableCell>
                      <TableCell className="text-xs text-muted-foreground">{ev.ip_address ?? "—"}</TableCell>
                      <TableCell>
                        <span className={`inline-flex items-center px-2 py-0.5 rounded-full text-xs font-medium ${SEVERITY_COLORS[ev.severity] ?? "bg-gray-100 text-gray-700"}`}>
                          {ev.severity}
                        </span>
                      </TableCell>
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            )}
          </CardContent>
        </Card>

        <div className="space-y-4">
          <Card>
            <CardHeader>
              <CardTitle className="text-base">Overall Risk Level</CardTitle>
            </CardHeader>
            <CardContent>
              {loading ? (
                <Skeleton className="h-16 w-full" />
              ) : (
                <div className={`text-center py-4 rounded-lg font-bold text-xl capitalize ${RISK_COLORS[riskLevel]}`}>
                  {riskLevel} Risk
                </div>
              )}
            </CardContent>
          </Card>

          <Card>
            <CardHeader>
              <CardTitle className="text-base">Compliance Checks</CardTitle>
            </CardHeader>
            <CardContent className="space-y-2">
              {loading ? (
                Array.from({ length: 5 }).map((_, i) => <Skeleton key={i} className="h-8 w-full" />)
              ) : checks.length === 0 ? (
                <p className="text-sm text-muted-foreground">No checks configured.</p>
              ) : (
                checks.map((check, i) => (
                  <div key={i} className="flex items-center justify-between py-1.5 border-b last:border-0">
                    <div className="flex items-center gap-2">
                      <FileText className="w-3 h-3 text-muted-foreground" />
                      <span className="text-sm">{check.label}</span>
                    </div>
                    <Badge className={check.status === "pass" ? "bg-emerald-50 text-emerald-700 hover:bg-emerald-50" : check.status === "warn" ? "bg-yellow-50 text-yellow-700 hover:bg-yellow-50" : "bg-red-50 text-red-700 hover:bg-red-50"}>
                      {check.status}
                    </Badge>
                  </div>
                ))
              )}
            </CardContent>
          </Card>
        </div>
      </div>
    </div>
  );
}

