                                {ev.user_agent && (
                                  <div>
                                    <p className="font-semibold text-muted-foreground uppercase tracking-wide mb-0.5">User Agent</p>
                                    <p className="font-mono break-all">{ev.user_agent}</p>
                                  </div>
