                                {ev.details && (
                                  <div className="sm:col-span-2">
                                    <p className="font-semibold text-muted-foreground uppercase tracking-wide mb-0.5">Details</p>
                                    <p className="whitespace-pre-wrap">{ev.details}</p>
                                  </div>
