"use client";

import { useEffect, useState } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Skeleton } from "@/components/ui/skeleton";
import { Shield, CheckCircle, RefreshCw, Phone, Clock } from "lucide-react";
import { toast } from "@/components/ui/use-toast";
import { format } from "date-fns";
import client from "@/lib/api/client";
import { cn } from "@/lib/utils";

interface CrisisAlert {
  id: string;
  user_id: string;
  user_name?: string;
  severity: "medium" | "high" | "critical";
  trigger: string;
  created_at: string;
  resolved_at?: string;
  status: "open" | "in_progress" | "resolved";
}

const SEVERITY_COLOR: Record<string, string> = {
  critical: "bg-red-100 text-red-800",
  high:     "bg-orange-100 text-orange-800",
  medium:   "bg-amber-100 text-amber-800",
};

export default function CrisisAlertsPage() {
  const [alerts, setAlerts] = useState<CrisisAlert[]>([]);
  const [loading, setLoading] = useState(true);

  const load = async () => {
    setLoading(true);
    try {
      const res = await client.get("/api/v1/clinical-advisor/crisis-alerts");
      setAlerts(res.data?.data ?? []);
    } catch {
      // Endpoint may not exist yet — show empty state gracefully
      setAlerts([]);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { load(); }, []); // eslint-disable-line react-hooks/exhaustive-deps

  const resolve = async (id: string) => {
    try {
      await client.patch(`/api/v1/clinical-advisor/crisis-alerts/${id}/resolve`);
      setAlerts(prev => prev.map(a => a.id === id ? { ...a, status: "resolved" as const, resolved_at: new Date().toISOString() } : a));
      toast({ title: "Alert resolved", description: "Crisis alert marked as resolved." });
    } catch {
      toast({ title: "Error", description: "Could not resolve alert.", variant: "destructive" });
    }
  };

  const open = alerts.filter(a => a.status !== "resolved");
  const resolved = alerts.filter(a => a.status === "resolved");

  return (
    <div className="p-6 space-y-6 max-w-4xl mx-auto">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold flex items-center gap-2">
            <Shield className="h-6 w-6 text-red-500" />
            Crisis Alerts
          </h1>
          <p className="text-sm text-muted-foreground mt-0.5">
            Active crisis interventions requiring immediate clinical attention.
          </p>
        </div>
        <Button variant="outline" size="sm" onClick={load} disabled={loading} className="gap-2">
          <RefreshCw className={cn("h-4 w-4", loading && "animate-spin")} />
          Refresh
        </Button>
      </div>

      {loading ? (
        <div className="space-y-3">
          {[1, 2].map(i => <Skeleton key={i} className="h-24 w-full rounded-xl" />)}
        </div>
      ) : open.length === 0 && resolved.length === 0 ? (
        <Card>
          <CardContent className="flex flex-col items-center gap-3 py-16 text-center">
            <CheckCircle className="h-12 w-12 text-green-500" />
            <p className="font-semibold">No crisis alerts</p>
            <p className="text-sm text-muted-foreground">All members are currently safe.</p>
          </CardContent>
        </Card>
      ) : (
        <div className="space-y-4">
          {open.length > 0 && (
            <Card>
              <CardHeader>
                <CardTitle className="text-base text-red-600">{open.length} Active Alert{open.length !== 1 ? "s" : ""}</CardTitle>
              </CardHeader>
              <CardContent className="p-0">
                {open.map(alert => (
                  <div key={alert.id} className="flex items-start gap-4 p-4 border-b last:border-b-0">
                    <Badge className={cn("shrink-0 text-xs capitalize", SEVERITY_COLOR[alert.severity])}>
                      {alert.severity}
                    </Badge>
                    <div className="flex-1 min-w-0">
                      <p className="font-medium text-sm">{alert.user_name ?? `User #${alert.user_id}`}</p>
                      <p className="text-sm text-muted-foreground mt-0.5">{alert.trigger}</p>
                      <div className="flex items-center gap-1 mt-1 text-xs text-muted-foreground">
                        <Clock className="h-3 w-3" />
                        {format(new Date(alert.created_at), "MMM d, yyyy HH:mm")}
                      </div>
                    </div>
                    <div className="flex gap-2 shrink-0">
                      <Button size="sm" variant="outline" className="gap-1.5">
                        <Phone className="h-3.5 w-3.5" />
                        Contact
                      </Button>
                      <Button size="sm" variant="default" onClick={() => resolve(alert.id)}>
                        Resolve
                      </Button>
                    </div>
                  </div>
                ))}
              </CardContent>
            </Card>
          )}
          {resolved.length > 0 && (
            <Card>
              <CardHeader>
                <CardTitle className="text-base text-muted-foreground">Resolved ({resolved.length})</CardTitle>
              </CardHeader>
              <CardContent className="p-0">
                {resolved.map(alert => (
                  <div key={alert.id} className="flex items-start gap-4 p-4 border-b last:border-b-0 opacity-60">
                    <Badge variant="secondary" className="shrink-0 text-xs capitalize">{alert.severity}</Badge>
                    <div className="flex-1 min-w-0">
                      <p className="font-medium text-sm line-through">{alert.user_name ?? `User #${alert.user_id}`}</p>
                      <p className="text-xs text-muted-foreground">{alert.trigger}</p>
                    </div>
                    <Badge variant="outline" className="text-xs shrink-0">Resolved</Badge>
                  </div>
                ))}
              </CardContent>
            </Card>
          )}
        </div>
      )}
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Skeleton } from "@/components/ui/skeleton";
import { AlertTriangle, CheckCircle, Clock, User, RefreshCw } from "lucide-react";
import { toast } from "@/components/ui/use-toast";
import client from "@/lib/api/client";
import { cn } from "@/lib/utils";

interface DistressItem {
  id: string;
  session_id: string;
  member_id: string;
  organization_id: number | null;
  risk_level: "low" | "medium" | "high" | "severe" | "critical";
  flagged_at: string;
  message_preview: string;
  resources_shown: boolean;
}

const RISK_COLOR: Record<string, string> = {
  critical: "bg-red-100 text-red-800 border-red-200",
  severe:   "bg-red-100 text-red-800 border-red-200",
  high:     "bg-orange-100 text-orange-800 border-orange-200",
  medium:   "bg-amber-100 text-amber-800 border-amber-200",
  low:      "bg-green-100 text-green-800 border-green-200",
};

function timeAgo(dateStr: string) {
  const diff = Math.floor((Date.now() - new Date(dateStr).getTime()) / 60000);
  if (diff < 1) return "Just now";
  if (diff < 60) return `${diff}m ago`;
  if (diff < 1440) return `${Math.floor(diff / 60)}h ago`;
  return `${Math.floor(diff / 1440)}d ago`;
}

export default function DistressQueuePage() {
  const [items, setItems] = useState<DistressItem[]>([]);
  const [loading, setLoading] = useState(true);

  const load = async () => {
    setLoading(true);
    try {
      const res = await client.get("/api/v1/clinical-advisor/distress-queue");
      setItems(res.data?.data ?? []);
    } catch {
      toast({ title: "Error", description: "Failed to load distress queue.", variant: "destructive" });
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { load(); }, []); // eslint-disable-line react-hooks/exhaustive-deps

  const resolve = async (id: string) => {
    try {
      await client.patch(`/api/v1/clinical-advisor/distress-queue/${id}/resolve`, {
        resolution_type: "resolved",
        notes: "Reviewed and resolved by clinical advisor",
      });
      setItems(prev => prev.filter(i => i.id !== id));
      toast({ title: "Resolved", description: "Distress flag marked as resolved." });
    } catch {
      toast({ title: "Error", description: "Could not resolve item.", variant: "destructive" });
    }
  };

  return (
    <div className="p-6 space-y-6 max-w-4xl mx-auto">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold flex items-center gap-2">
            <AlertTriangle className="h-6 w-6 text-amber-500" />
            Distress Queue
          </h1>
          <p className="text-sm text-muted-foreground mt-0.5">
            High-risk AI conversations flagged for clinical review.
          </p>
        </div>
        <Button variant="outline" size="sm" onClick={load} disabled={loading} className="gap-2">
          <RefreshCw className={cn("h-4 w-4", loading && "animate-spin")} />
          Refresh
        </Button>
      </div>

      {loading ? (
        <Card>
          <CardContent className="space-y-4 pt-6">
            {[1, 2, 3].map(i => (
              <div key={i} className="flex items-center gap-3 p-4 border rounded-lg">
                <Skeleton className="w-16 h-6 rounded-full" />
                <div className="flex-1 space-y-2">
                  <Skeleton className="h-4 w-40" />
                  <Skeleton className="h-3 w-full" />
                </div>
                <Skeleton className="h-8 w-20" />
              </div>
            ))}
          </CardContent>
        </Card>
      ) : items.length === 0 ? (
        <Card>
          <CardContent className="flex flex-col items-center gap-3 py-16 text-center">
            <CheckCircle className="h-12 w-12 text-green-500" />
            <p className="font-semibold">Queue is clear</p>
            <p className="text-sm text-muted-foreground">No active distress flags at this time.</p>
          </CardContent>
        </Card>
      ) : (
        <Card>
          <CardHeader>
            <CardTitle>{items.length} active flag{items.length !== 1 ? "s" : ""}</CardTitle>
          </CardHeader>
          <CardContent className="p-0">
            {items.map(item => (
              <div key={item.id} className="flex items-start gap-4 p-4 border-b last:border-b-0 hover:bg-muted/30 transition-colors">
                <Badge className={cn("shrink-0 text-xs capitalize", RISK_COLOR[item.risk_level])}>
                  {item.risk_level}
                </Badge>
                <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-2 mb-1">
                    <User className="h-3.5 w-3.5 text-muted-foreground" />
                    <span className="font-medium text-sm">{item.member_id}</span>
                    <Clock className="h-3 w-3 text-muted-foreground ml-2" />
                    <span className="text-xs text-muted-foreground">{timeAgo(item.flagged_at)}</span>
                  </div>
                  <p className="text-sm text-muted-foreground line-clamp-2">{item.message_preview}</p>
                  <div className="flex gap-2 mt-1.5">
                    {item.resources_shown && (
                      <Badge variant="outline" className="text-xs">Resources shown</Badge>
                    )}
                    {item.organization_id && (
                      <Badge variant="outline" className="text-xs">Org #{item.organization_id}</Badge>
                    )}
                  </div>
                </div>
                <Button size="sm" variant="outline" onClick={() => resolve(item.id)}>
                  Resolve
                </Button>
              </div>
            ))}
          </CardContent>
        </Card>
      )}
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Skeleton } from "@/components/ui/skeleton";
import { Bell, RefreshCw, CheckCheck } from "lucide-react";
import { toast } from "@/components/ui/use-toast";
import { format } from "date-fns";
import client from "@/lib/api/client";
import { cn } from "@/lib/utils";

interface Notification {
  id: number;
  title: string;
  message: string;
  type: string;
  read_at: string | null;
  created_at: string;
}

export default function ClinicalNotificationsPage() {
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [loading, setLoading] = useState(true);

  const load = async () => {
    setLoading(true);
    try {
      const res = await client.get("/api/v1/notifications");
      const data = res.data?.data ?? res.data;
      setNotifications(Array.isArray(data?.data) ? data.data : Array.isArray(data) ? data : []);
    } catch {
      toast({ title: "Error", description: "Failed to load notifications.", variant: "destructive" });
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { load(); }, []); // eslint-disable-line react-hooks/exhaustive-deps

  const markAllRead = async () => {
    try {
      await client.post("/api/v1/notifications/mark-all-read");
      setNotifications(prev => prev.map(n => ({ ...n, read_at: new Date().toISOString() })));
      toast({ title: "All marked as read" });
    } catch {
      toast({ title: "Error", description: "Could not mark as read.", variant: "destructive" });
    }
  };

  const unread = notifications.filter(n => !n.read_at).length;

  return (
    <div className="p-6 space-y-6 max-w-3xl mx-auto">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold flex items-center gap-2">
            <Bell className="h-6 w-6" />
            Notifications
            {unread > 0 && (
              <Badge className="bg-red-500 text-white text-xs">{unread}</Badge>
            )}
          </h1>
          <p className="text-sm text-muted-foreground mt-0.5">
            Clinical alerts, system messages, and updates.
          </p>
        </div>
        <div className="flex gap-2">
          {unread > 0 && (
            <Button variant="outline" size="sm" onClick={markAllRead} className="gap-2">
              <CheckCheck className="h-4 w-4" />
              Mark all read
            </Button>
          )}
          <Button variant="outline" size="sm" onClick={load} disabled={loading} className="gap-2">
            <RefreshCw className={cn("h-4 w-4", loading && "animate-spin")} />
            Refresh
          </Button>
        </div>
      </div>

      {loading ? (
        <div className="space-y-2">
          {[1, 2, 3, 4].map(i => <Skeleton key={i} className="h-16 w-full rounded-lg" />)}
        </div>
      ) : notifications.length === 0 ? (
        <Card>
          <CardContent className="flex flex-col items-center gap-3 py-16 text-center">
            <Bell className="h-10 w-10 text-muted-foreground/40" />
            <p className="text-muted-foreground text-sm">No notifications yet.</p>
          </CardContent>
        </Card>
      ) : (
        <Card>
          <CardHeader>
            <CardTitle className="text-base">{notifications.length} notifications</CardTitle>
          </CardHeader>
          <CardContent className="p-0">
            {notifications.map(n => (
              <div
                key={n.id}
                className={cn(
                  "flex items-start gap-4 p-4 border-b last:border-b-0 transition-colors",
                  !n.read_at ? "bg-blue-50/40" : "hover:bg-muted/20"
                )}
              >
                <Bell className={cn("h-4 w-4 mt-0.5 shrink-0", !n.read_at ? "text-blue-500" : "text-muted-foreground")} />
                <div className="flex-1 min-w-0">
                  <p className={cn("text-sm", !n.read_at ? "font-semibold" : "font-medium")}>{n.title}</p>
                  <p className="text-sm text-muted-foreground mt-0.5">{n.message}</p>
                  <p className="text-xs text-muted-foreground mt-1">
                    {format(new Date(n.created_at), "MMM d, yyyy HH:mm")}
                  </p>
                </div>
                {!n.read_at && (
                  <span className="w-2 h-2 rounded-full bg-blue-500 shrink-0 mt-1.5" />
                )}
              </div>
            ))}
          </CardContent>
        </Card>
      )}
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Skeleton } from "@/components/ui/skeleton";
import { Button } from "@/components/ui/button";
import { BarChart2, RefreshCw, TrendingUp, TrendingDown, Minus } from "lucide-react";
import client from "@/lib/api/client";
import { cn } from "@/lib/utils";

interface ClinicalStats {
  total_sessions: number;
  sessions_change: number;
  active_members: number;
  members_change: number;
  distress_flags: number;
  flags_change: number;
  avg_session_rating: number;
  resolved_crises: number;
  open_crises: number;
  therapist_utilization: number;
}

function Trend({ value }: { value: number }) {
  if (value > 0) return <span className="flex items-center gap-0.5 text-green-600 text-xs"><TrendingUp className="h-3 w-3" />+{value}%</span>;
  if (value < 0) return <span className="flex items-center gap-0.5 text-red-500 text-xs"><TrendingDown className="h-3 w-3" />{value}%</span>;
  return <span className="flex items-center gap-0.5 text-muted-foreground text-xs"><Minus className="h-3 w-3" />0%</span>;
}

export default function ClinicalReportsPage() {
  const [stats, setStats] = useState<ClinicalStats | null>(null);
  const [loading, setLoading] = useState(true);

  const load = async () => {
    setLoading(true);
    try {
      const res = await client.get("/api/v1/clinical-advisor/stats");
      setStats(res.data?.data ?? res.data);
    } catch {
      // Fall back to empty state
      setStats(null);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { load(); }, []); // eslint-disable-line react-hooks/exhaustive-deps

  const metrics = stats ? [
    { label: "Total Sessions (30d)", value: stats.total_sessions, change: stats.sessions_change },
    { label: "Active Members", value: stats.active_members, change: stats.members_change },
    { label: "Distress Flags (30d)", value: stats.distress_flags, change: stats.flags_change },
    { label: "Avg Session Rating", value: stats.avg_session_rating?.toFixed(1) ?? "—", change: 0 },
    { label: "Open Crises", value: stats.open_crises, change: 0 },
    { label: "Resolved Crises (30d)", value: stats.resolved_crises, change: 0 },
    { label: "Therapist Utilization", value: `${stats.therapist_utilization ?? 0}%`, change: 0 },
  ] : [];

  return (
    <div className="p-6 space-y-6 max-w-5xl mx-auto">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold flex items-center gap-2">
            <BarChart2 className="h-6 w-6 text-teal" />
            Clinical Reports
          </h1>
          <p className="text-sm text-muted-foreground mt-0.5">
            Platform-wide mental health and clinical outcome metrics.
          </p>
        </div>
        <Button variant="outline" size="sm" onClick={load} disabled={loading} className="gap-2">
          <RefreshCw className={cn("h-4 w-4", loading && "animate-spin")} />
          Refresh
        </Button>
      </div>

      {loading ? (
        <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-3">
          {[1, 2, 3, 4, 5, 6].map(i => <Skeleton key={i} className="h-28 w-full rounded-xl" />)}
        </div>
      ) : metrics.length === 0 ? (
        <Card>
          <CardContent className="flex flex-col items-center gap-3 py-16 text-center">
            <BarChart2 className="h-10 w-10 text-muted-foreground/40" />
            <p className="font-semibold">No report data available</p>
            <p className="text-sm text-muted-foreground">Reports will appear once the clinical stats endpoint is active.</p>
          </CardContent>
        </Card>
      ) : (
        <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-3">
          {metrics.map(m => (
            <Card key={m.label}>
              <CardHeader className="pb-1">
                <CardTitle className="text-sm font-medium text-muted-foreground">{m.label}</CardTitle>
              </CardHeader>
              <CardContent>
                <p className="text-3xl font-bold">{m.value}</p>
                {typeof m.change === "number" && m.change !== 0 && (
                  <div className="mt-1">
                    <Trend value={m.change} />
                  </div>
                )}
              </CardContent>
            </Card>
          ))}
        </div>
      )}
    </div>
  );
}

