        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2 text-base">
              <Zap className="w-4 h-4 text-purple-500" />
              Platform Health
            </CardTitle>
          </CardHeader>
          <CardContent className="space-y-3">
            <div className="flex justify-between items-center py-2 border-b border-gray-50">
              <span className="text-sm text-gray-600">API Error Rate</span>
              {platform_health?.api_error_rate !== undefined ? (
                <Badge className={platform_health.api_error_rate < 0.1 ? "bg-emerald-50 text-emerald-700 hover:bg-emerald-50" : "bg-red-50 text-red-700 hover:bg-red-50"}>
                  {platform_health.api_error_rate}%
                </Badge>
              ) : <span className="text-sm text-gray-400">—</span>}
            </div>
            <div className="flex justify-between items-center py-2 border-b border-gray-50">
              <span className="text-sm text-gray-600">Last Payment Processed</span>
              <span className="text-xs text-gray-600">
                {platform_health?.last_payment_webhook
                  ? new Date(platform_health.last_payment_webhook).toLocaleString()
                  : "—"}
              </span>
            </div>
            <div className="flex justify-between items-center py-2">
              <span className="text-sm text-gray-600">AI Companion Uptime</span>
              <span className="text-xs text-gray-600">
                {platform_health?.ai_companion_uptime
                  ? new Date(platform_health.ai_companion_uptime).toLocaleTimeString()
                  : "—"}
              </span>
            </div>
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

"use client";

import { useCallback, useEffect, useState } from "react";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Label } from "@/components/ui/label";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
} from "@/components/ui/dialog";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { toast } from "@/components/ui/use-toast";
import {
  Heart, Shield, DollarSign, Plane, BookOpen, Plus,
  Pencil, Trash2, Loader2, RefreshCw,
  Users, Briefcase, Star, Gift, Coffee, Zap, Globe, Music,
} from "lucide-react";
import { hrService } from "@/lib/api/hr";

// Map icon name strings (stored in DB) → lucide components
const ICON_MAP: Record<string, React.ElementType> = {
  Heart, Shield, DollarSign, Plane, BookOpen,
  Users, Briefcase, Star, Gift, Coffee, Zap, Globe, Music,
};

const ICON_OPTIONS = Object.keys(ICON_MAP);

interface Benefit {
  id: number;
  title: string;
  description: string | null;
  icon: string;
  status: "active" | "inactive";
  enrolled_count: number;
}

const emptyForm = { title: "", description: "", icon: "Heart", status: "active" as "active" | "inactive", enrolled_count: 0 };

export default function HRBenefitsPage() {
  const [benefits, setBenefits] = useState<Benefit[]>([]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);

  // Dialog state
  const [dialogOpen, setDialogOpen] = useState(false);
  const [editTarget, setEditTarget] = useState<Benefit | null>(null);
  const [form, setForm] = useState(emptyForm);

  const load = useCallback(async () => {
    setLoading(true);
    try {
      const data = await hrService.getBenefits() as any;
      setBenefits(Array.isArray(data) ? data : (data?.data ?? []));
    } catch {
      toast({ description: "Failed to load benefits.", variant: "destructive" });
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { load(); }, [load]);

  function openAdd() {
    setEditTarget(null);
    setForm(emptyForm);
    setDialogOpen(true);
  }

  function openEdit(b: Benefit) {
    setEditTarget(b);
    setForm({ title: b.title, description: b.description ?? "", icon: b.icon, status: b.status, enrolled_count: b.enrolled_count });
    setDialogOpen(true);
  }

  async function handleSave() {
    if (!form.title.trim()) {
      toast({ description: "Title is required.", variant: "destructive" });
      return;
    }
    setSaving(true);
    try {
      if (editTarget) {
        await hrService.updateBenefit(editTarget.id, form);
        toast({ description: "Benefit updated." });
      } else {
        await hrService.createBenefit(form);
        toast({ description: "Benefit added." });
      }
      setDialogOpen(false);
      load();
    } catch {
      toast({ description: "Failed to save benefit.", variant: "destructive" });
    } finally {
      setSaving(false);
    }
  }

  async function handleDelete(b: Benefit) {
    if (!confirm(`Delete "${b.title}"?`)) return;
    try {
      await hrService.deleteBenefit(b.id);
      toast({ description: `"${b.title}" removed.` });
      load();
    } catch {
      toast({ description: "Failed to delete benefit.", variant: "destructive" });
    }
  }

  async function toggleStatus(b: Benefit) {
    const next = b.status === "active" ? "inactive" : "active";
    try {
      await hrService.updateBenefit(b.id, { status: next });
      toast({ description: `${b.title} marked ${next}.` });
      load();
    } catch {
      toast({ description: "Failed to update status.", variant: "destructive" });
    }
  }

  const totalEnrolled = benefits.reduce((s, b) => s + b.enrolled_count, 0);
  const activeBenefits = benefits.filter((b) => b.status === "active").length;

  return (
    <div className="p-6 space-y-6">
      <div className="flex items-center justify-between flex-wrap gap-3">
        <div>
          <h1 className="text-3xl font-bold tracking-tight">Employee Benefits</h1>
          <p className="text-muted-foreground">Manage and configure benefit plans for employees.</p>
        </div>
        <div className="flex gap-2">
          <Button variant="outline" size="icon" onClick={load}>
            <RefreshCw className="h-4 w-4" />
          </Button>
          <Button className="gap-2" onClick={openAdd}>
            <Plus className="h-4 w-4" /> Add Benefit
          </Button>
        </div>
      </div>

      {/* Summary cards */}
      <div className="grid gap-4 sm:grid-cols-3">
        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium text-muted-foreground">Total Plans</CardTitle>
          </CardHeader>
          <CardContent>
            <p className="text-3xl font-bold">{benefits.length}</p>
          </CardContent>
        </Card>
        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium text-muted-foreground">Active Plans</CardTitle>
          </CardHeader>
          <CardContent>
            <p className="text-3xl font-bold text-green-600">{activeBenefits}</p>
          </CardContent>
        </Card>
        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium text-muted-foreground">Total Enrolled</CardTitle>
          </CardHeader>
          <CardContent>
            <p className="text-3xl font-bold">{totalEnrolled.toLocaleString()}</p>
          </CardContent>
        </Card>
      </div>

      {/* Benefit cards */}
      {loading ? (
        <div className="flex justify-center py-16">
          <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
        </div>
      ) : benefits.length === 0 ? (
        <Card>
          <CardContent className="py-12 text-center text-muted-foreground">
            No benefits configured yet. Click <strong>Add Benefit</strong> to get started.
          </CardContent>
        </Card>
      ) : (
        <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
          {benefits.map((benefit) => {
            const Icon = ICON_MAP[benefit.icon] ?? Heart;
            return (
              <Card key={benefit.id}>
                <CardHeader className="pb-3">
                  <div className="flex items-center justify-between">
                    <div className="flex items-center gap-2">
                      <div className="size-9 rounded-lg bg-primary/10 flex items-center justify-center">
                        <Icon className="size-4 text-primary" />
                      </div>
                      <CardTitle className="text-base">{benefit.title}</CardTitle>
                    </div>
                    <Badge
                      variant={benefit.status === "active" ? "default" : "secondary"}
                      className="cursor-pointer"
                      onClick={() => toggleStatus(benefit)}
                    >
                      {benefit.status === "active" ? "Active" : "Inactive"}
                    </Badge>
                  </div>
                </CardHeader>
                <CardContent>
                  <CardDescription>{benefit.description}</CardDescription>
                  <div className="mt-3 flex items-center justify-between text-sm">
                    <span className="text-muted-foreground">{benefit.enrolled_count.toLocaleString()} enrolled</span>
                    <div className="flex gap-1">
                      <Button variant="ghost" size="icon" className="h-7 w-7" onClick={() => openEdit(benefit)}>
                        <Pencil className="h-3.5 w-3.5" />
                      </Button>
                      <Button variant="ghost" size="icon" className="h-7 w-7 text-destructive hover:text-destructive" onClick={() => handleDelete(benefit)}>
                        <Trash2 className="h-3.5 w-3.5" />
                      </Button>
                    </div>
                  </div>
                </CardContent>
              </Card>
            );
          })}
        </div>
      )}

      {/* Add / Edit Dialog */}
      <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>{editTarget ? "Edit Benefit" : "Add Benefit"}</DialogTitle>
          </DialogHeader>
          <div className="space-y-4 py-2">
            <div className="space-y-1">
              <Label>Title</Label>
              <Input
                placeholder="e.g. Health Insurance"
                value={form.title}
                onChange={(e) => setForm((p) => ({ ...p, title: e.target.value }))}
              />
            </div>
            <div className="space-y-1">
              <Label>Description</Label>
              <Textarea
                placeholder="Brief description of the benefit"
                value={form.description}
                onChange={(e) => setForm((p) => ({ ...p, description: e.target.value }))}
              />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1">
                <Label>Icon</Label>
                <Select value={form.icon} onValueChange={(v) => setForm((p) => ({ ...p, icon: v ?? "" }))}>
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    {ICON_OPTIONS.map((name) => {
                      const Ic = ICON_MAP[name];
                      return (
                        <SelectItem key={name} value={name}>
                          <span className="flex items-center gap-2">
                            <Ic className="h-4 w-4" /> {name}
                          </span>
                        </SelectItem>
                      );
                    })}
                  </SelectContent>
                </Select>
              </div>
              <div className="space-y-1">
                <Label>Status</Label>
                <Select value={form.status} onValueChange={(v) => v !== null && setForm((p) => ({ ...p, status: v as "active" | "inactive" }))}>
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="active">Active</SelectItem>
                    <SelectItem value="inactive">Inactive</SelectItem>
                  </SelectContent>
                </Select>
              </div>
            </div>
            <div className="space-y-1">
              <Label>Enrolled Count</Label>
              <Input
                type="number"
                min={0}
                value={form.enrolled_count}
                onChange={(e) => setForm((p) => ({ ...p, enrolled_count: parseInt(e.target.value) || 0 }))}
              />
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setDialogOpen(false)} disabled={saving}>Cancel</Button>
            <Button onClick={handleSave} disabled={saving}>
              {saving && <Loader2 className="h-4 w-4 animate-spin mr-2" />}
              {editTarget ? "Save Changes" : "Add Benefit"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { PlusCircle, Building2, Users, Pencil, Trash2, UserCheck } from "lucide-react";
import client from "@/lib/api/client";
import { PermissionGate } from "@/components/shared/PermissionGate";
import { usePageView } from "@/hooks/usePageView";

interface StaffUser {
  id: number;
  first_name: string;
  last_name: string;
  email: string;
}

interface Department {
  id: number;
  name: string;
  code: string;
  description?: string;
  headcount?: number;
  employees_count?: number;
  is_active: boolean;
  head?: { id: number; first_name: string; last_name: string } | null;
  parent?: { id: number; name: string; code: string } | null;
  children?: Department[];
}

const EMPTY_FORM = {
  name: "", code: "", description: "", head_user_id: "", parent_department_id: "",
};

export default function DepartmentsPage() {
  usePageView("hr.departments");

  const [depts, setDepts]         = useState<Department[]>([]);
  const [staff, setStaff]         = useState<StaffUser[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [showForm, setShowForm]   = useState(false);
  const [editing, setEditing]     = useState<Department | null>(null);
  const [form, setForm]           = useState(EMPTY_FORM);
  const [saving, setSaving]       = useState(false);

  const loadDepts = async () => {
    setIsLoading(true);
    try {
      const res = await client.get("/api/v1/hr/departments");
      setDepts(res.data ?? []);
    } finally {
      setIsLoading(false);
    }
  };

  const loadStaff = async () => {
    try {
      // Pull active employees to use as department head candidates
      const res = await client.get("/api/v1/hr/employee-records", {
        params: { employment_status: "active", per_page: 200 },
      });
      const items = res.data?.data ?? res.data ?? [];
      setStaff(
        (Array.isArray(items) ? items : []).map(
          (e: { user: { id: number; first_name: string; last_name: string; email: string } }) => ({
            id: e.user.id,
            first_name: e.user.first_name,
            last_name: e.user.last_name,
            email: e.user.email,
          })
        )
      );
    } catch {
      // Non-blocking — head selector degrades gracefully
    }
  };

  useEffect(() => {
    loadDepts();
    loadStaff();
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  const openCreate = () => { setEditing(null); setForm(EMPTY_FORM); setShowForm(true); };
  const openEdit = (d: Department) => {
    setEditing(d);
    setForm({
      name: d.name,
      code: d.code,
      description: d.description ?? "",
      head_user_id: d.head?.id?.toString() ?? "",
      parent_department_id: d.parent?.id?.toString() ?? "",
    });
    setShowForm(true);
  };

  const handleSave = async () => {
    if (!form.name || !form.code) return;
    setSaving(true);
    try {
      const payload = {
        name: form.name,
        code: form.code.toUpperCase(),
        description: form.description || undefined,
        head_user_id: form.head_user_id ? parseInt(form.head_user_id) : null,
        parent_department_id: form.parent_department_id
          ? parseInt(form.parent_department_id) : null,
      };
      if (editing) {
        await client.put(`/api/v1/hr/departments/${editing.id}`, payload);
      } else {
        await client.post("/api/v1/hr/departments", payload);
      }
      setShowForm(false);
      setEditing(null);
      setForm(EMPTY_FORM);
      await loadDepts();
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async (id: number) => {
    if (!confirm("Delete this department? It must have no employees.")) return;
    await client.delete(`/api/v1/hr/departments/${id}`);
    await loadDepts();
  };

  const parentOptions = depts.filter((d) => !editing || d.id !== editing.id);

  return (
    <div className="p-6 space-y-6 max-w-5xl mx-auto">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold">Departments</h1>
          <p className="text-sm text-muted-foreground">
            Manage organizational departments and their structure.
          </p>
        </div>
        <PermissionGate resource="hr" permission="write">
          <button
            onClick={openCreate}
            className="flex items-center gap-2 px-4 py-2 rounded-xl bg-primary text-primary-foreground text-sm font-semibold hover:opacity-90 transition-opacity"
          >
            <PlusCircle size={16} /> New Department
          </button>
        </PermissionGate>
      </div>

      {/* Form */}
      {showForm && (
        <div className="rounded-2xl border border-border bg-card p-6 space-y-4">
          <h2 className="font-semibold text-base">
            {editing ? "Edit Department" : "New Department"}
          </h2>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            {/* Name */}
            <div>
              <label className="block text-xs font-semibold mb-1">
                Name <span className="text-red-500">*</span>
              </label>
              <input
                type="text"
                value={form.name}
                onChange={(e) => setForm({ ...form, name: e.target.value })}
                className="w-full rounded-xl border border-border bg-background px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-primary"
                placeholder="e.g. Marketing"
              />
            </div>

            {/* Code */}
            <div>
              <label className="block text-xs font-semibold mb-1">
                Code <span className="text-red-500">*</span>
              </label>
              <input
                type="text"
                value={form.code}
                onChange={(e) => setForm({ ...form, code: e.target.value.toUpperCase() })}
                className="w-full rounded-xl border border-border bg-background px-3 py-2 text-sm font-mono focus:outline-none focus:ring-2 focus:ring-primary"
                placeholder="MKT"
                maxLength={20}
              />
            </div>

            {/* Department Head */}
            <div>
              <label className="block text-xs font-semibold mb-1">
                Department Head
              </label>
              <select
                value={form.head_user_id}
                onChange={(e) => setForm({ ...form, head_user_id: e.target.value })}
                className="w-full rounded-xl border border-border bg-background px-3 py-2 text-sm focus:outline-none"
              >
                <option value="">— None —</option>
                {staff.map((u) => (
                  <option key={u.id} value={u.id}>
                    {u.first_name} {u.last_name}
                    {u.email ? ` (${u.email})` : ""}
                  </option>
                ))}
              </select>
            </div>

            {/* Parent Department */}
            <div>
              <label className="block text-xs font-semibold mb-1">
                Parent Department
              </label>
              <select
                value={form.parent_department_id}
                onChange={(e) => setForm({ ...form, parent_department_id: e.target.value })}
                className="w-full rounded-xl border border-border bg-background px-3 py-2 text-sm focus:outline-none"
              >
                <option value="">— None (top-level) —</option>
                {parentOptions.map((d) => (
                  <option key={d.id} value={d.id}>{d.name}</option>
                ))}
              </select>
            </div>

            {/* Description — full width */}
            <div className="sm:col-span-2">
              <label className="block text-xs font-semibold mb-1">Description</label>
              <input
                type="text"
                value={form.description}
                onChange={(e) => setForm({ ...form, description: e.target.value })}
                className="w-full rounded-xl border border-border bg-background px-3 py-2 text-sm focus:outline-none"
                placeholder="Brief description"
              />
            </div>
          </div>

          <div className="flex gap-3 pt-2">
            <button
              onClick={() => { setShowForm(false); setEditing(null); }}
              className="flex-1 px-4 py-2 rounded-xl border border-border text-sm font-semibold hover:bg-muted transition-colors"
            >
              Cancel
            </button>
            <button
              disabled={saving || !form.name || !form.code}
              onClick={handleSave}
              className="flex-1 px-4 py-2 rounded-xl bg-primary text-primary-foreground text-sm font-semibold hover:opacity-90 disabled:opacity-50 transition-opacity"
            >
              {saving ? "Saving…" : editing ? "Update" : "Create"}
            </button>
          </div>
        </div>
      )}

      {/* Department list */}
      {isLoading ? (
        <div className="py-12 flex justify-center">
          <div className="w-8 h-8 border-4 border-primary border-t-transparent rounded-full animate-spin" />
        </div>
      ) : depts.length === 0 ? (
        <div className="py-16 text-center text-sm text-muted-foreground">
          No departments yet. Create one to get started.
        </div>
      ) : (
        <div className="divide-y divide-border rounded-2xl border overflow-hidden">
          {depts.map((dept) => (
            <div
              key={dept.id}
              className="flex items-center gap-4 p-4 bg-card hover:bg-muted/20 transition-colors"
            >
              <div className="w-10 h-10 rounded-xl bg-primary/10 flex items-center justify-center shrink-0">
                <Building2 size={18} className="text-primary" />
              </div>
              <div className="flex-1 min-w-0">
                <div className="flex items-center gap-2 flex-wrap">
                  <span className="font-semibold text-sm">{dept.name}</span>
                  <span className="text-[10px] font-mono px-1.5 py-0.5 rounded bg-muted text-muted-foreground">
                    {dept.code}
                  </span>
                  {dept.parent && (
                    <span className="text-[10px] text-muted-foreground">
                      under {dept.parent.name}
                    </span>
                  )}
                  {!dept.is_active && (
                    <span className="text-[10px] px-1.5 py-0.5 rounded bg-red-100 text-red-600">
                      Inactive
                    </span>
                  )}
                </div>
                <div className="flex items-center gap-3 mt-0.5 text-xs text-muted-foreground flex-wrap">
                  <span className="flex items-center gap-1">
                    <Users size={11} />
                    {dept.employees_count ?? dept.headcount ?? 0} employees
                  </span>
                  {dept.head && (
                    <span className="flex items-center gap-1">
                      <UserCheck size={11} />
                      Head: {dept.head.first_name} {dept.head.last_name}
                    </span>
                  )}
                  {dept.description && <span>{dept.description}</span>}
                </div>
              </div>
              <div className="flex gap-1 shrink-0">
                <PermissionGate resource="hr" permission="update">
                  <button
                    onClick={() => openEdit(dept)}
                    className="p-2 rounded-lg hover:bg-muted transition-colors text-muted-foreground hover:text-foreground"
                  >
                    <Pencil size={14} />
                  </button>
                </PermissionGate>
                <PermissionGate resource="hr" permission="delete">
                  <button
                    onClick={() => handleDelete(dept.id)}
                    className="p-2 rounded-lg hover:bg-red-50 transition-colors text-muted-foreground hover:text-red-600"
                  >
                    <Trash2 size={14} />
                  </button>
                </PermissionGate>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { PlusCircle, Briefcase, ChevronUp, Pencil, Trash2 } from "lucide-react";
import client from "@/lib/api/client";
import { PermissionGate } from "@/components/shared/PermissionGate";
import { usePageView } from "@/hooks/usePageView";

interface Department { id: number; name: string; code: string; }
interface Designation {
  id: number;
  title: string;
  code: string;
  level: number;
  department?: Department | null;
  reports_to?: { id: number; title: string } | null;
  salary_band_min?: number | null;
  salary_band_max?: number | null;
  is_active: boolean;
  employees_count?: number;
  employee_count?: number; // legacy alias
}

const LEVEL_LABELS: Record<number, string> = {
  1: "C-Suite / Executive",
  2: "President / EVP",
  3: "VP / Director",
  4: "Senior Manager",
  5: "Manager",
  6: "Senior Associate",
  7: "Associate",
  8: "Junior",
  9: "Entry Level",
  10: "Intern",
};

const EMPTY_FORM = {
  title: "", code: "", level: "5", department_id: "",
  reports_to_designation_id: "", salary_band_min: "", salary_band_max: "",
};

const fmt = (n?: number | null) =>
  n != null ? `₦${n.toLocaleString()}` : "—";

export default function DesignationsPage() {
  usePageView("hr.designations");

  const [designations, setDesignations] = useState<Designation[]>([]);
  const [departments, setDepartments]   = useState<Department[]>([]);
  const [isLoading, setIsLoading]       = useState(false);
  const [showForm, setShowForm]         = useState(false);
  const [editing, setEditing]           = useState<Designation | null>(null);
  const [form, setForm]                 = useState(EMPTY_FORM);
  const [saving, setSaving]             = useState(false);

  const load = async () => {
    setIsLoading(true);
    try {
      const [dRes, depRes] = await Promise.all([
        client.get("/api/v1/hr/designations"),
        client.get("/api/v1/hr/departments"),
      ]);
      setDesignations(dRes.data ?? []);
      setDepartments(depRes.data ?? []);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => { load(); }, []); // eslint-disable-line react-hooks/exhaustive-deps

  const openCreate = () => {
    setEditing(null);
    setForm(EMPTY_FORM);
    setShowForm(true);
  };

  const openEdit = (d: Designation) => {
    setEditing(d);
    setForm({
      title: d.title,
      code: d.code,
      level: d.level.toString(),
      department_id: d.department?.id?.toString() ?? "",
      reports_to_designation_id: d.reports_to?.id?.toString() ?? "",
      salary_band_min: d.salary_band_min?.toString() ?? "",
      salary_band_max: d.salary_band_max?.toString() ?? "",
    });
    setShowForm(true);
  };

  const handleSave = async () => {
    if (!form.title || !form.code || !form.level) return;
    setSaving(true);
    try {
      const payload = {
        title: form.title,
        code: form.code.toUpperCase(),
        level: parseInt(form.level),
        department_id: form.department_id ? parseInt(form.department_id) : null,
        reports_to_designation_id: form.reports_to_designation_id
          ? parseInt(form.reports_to_designation_id) : null,
        salary_band_min: form.salary_band_min ? parseFloat(form.salary_band_min) : null,
        salary_band_max: form.salary_band_max ? parseFloat(form.salary_band_max) : null,
      };
      if (editing) {
        await client.put(`/api/v1/hr/designations/${editing.id}`, payload);
      } else {
        await client.post("/api/v1/hr/designations", payload);
      }
      setShowForm(false);
      setEditing(null);
      setForm(EMPTY_FORM);
      await load();
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async (id: number) => {
    if (!confirm("Delete this designation? It must have no assigned employees.")) return;
    await client.delete(`/api/v1/hr/designations/${id}`);
    await load();
  };

  // Group by level for display
  const byLevel = designations.reduce<Record<number, Designation[]>>((acc, d) => {
    (acc[d.level] ??= []).push(d);
    return acc;
  }, {});
  const levels = Object.keys(byLevel).map(Number).sort((a, b) => a - b);

  const reportsToOptions = designations.filter(
    (d) => !editing || d.id !== editing.id
  );

  return (
    <div className="p-6 space-y-6 max-w-5xl mx-auto">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold">Designations</h1>
          <p className="text-sm text-muted-foreground">
            Job titles, levels, and salary bands across departments.
          </p>
        </div>
        <PermissionGate resource="hr" permission="write">
          <button
            onClick={openCreate}
            className="flex items-center gap-2 px-4 py-2 rounded-xl bg-primary text-primary-foreground text-sm font-semibold hover:opacity-90 transition-opacity"
          >
            <PlusCircle size={16} /> New Designation
          </button>
        </PermissionGate>
      </div>

      {/* Form */}
      {showForm && (
        <div className="rounded-2xl border border-border bg-card p-6 space-y-4">
          <h2 className="font-semibold text-base">
            {editing ? "Edit Designation" : "New Designation"}
          </h2>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <div>
              <label className="block text-xs font-semibold mb-1">
                Title <span className="text-red-500">*</span>
              </label>
              <input
                type="text"
                value={form.title}
                onChange={(e) => setForm({ ...form, title: e.target.value })}
                className="w-full rounded-xl border border-border bg-background px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-primary"
                placeholder="e.g. Senior Software Engineer"
              />
            </div>
            <div>
              <label className="block text-xs font-semibold mb-1">
                Code <span className="text-red-500">*</span>
              </label>
              <input
                type="text"
                value={form.code}
                onChange={(e) => setForm({ ...form, code: e.target.value.toUpperCase() })}
                className="w-full rounded-xl border border-border bg-background px-3 py-2 text-sm font-mono focus:outline-none focus:ring-2 focus:ring-primary"
                placeholder="SSE"
                maxLength={20}
              />
            </div>
            <div>
              <label className="block text-xs font-semibold mb-1">
                Level <span className="text-red-500">*</span>
              </label>
              <select
                value={form.level}
                onChange={(e) => setForm({ ...form, level: e.target.value })}
                className="w-full rounded-xl border border-border bg-background px-3 py-2 text-sm focus:outline-none"
              >
                {Array.from({ length: 10 }, (_, i) => i + 1).map((l) => (
                  <option key={l} value={l}>{l} — {LEVEL_LABELS[l]}</option>
                ))}
              </select>
            </div>
            <div>
              <label className="block text-xs font-semibold mb-1">Department</label>
              <select
                value={form.department_id}
                onChange={(e) => setForm({ ...form, department_id: e.target.value })}
                className="w-full rounded-xl border border-border bg-background px-3 py-2 text-sm focus:outline-none"
              >
                <option value="">— All Departments —</option>
                {departments.map((d) => (
                  <option key={d.id} value={d.id}>{d.name}</option>
                ))}
              </select>
            </div>
            <div>
              <label className="block text-xs font-semibold mb-1">Reports To</label>
              <select
                value={form.reports_to_designation_id}
                onChange={(e) => setForm({ ...form, reports_to_designation_id: e.target.value })}
                className="w-full rounded-xl border border-border bg-background px-3 py-2 text-sm focus:outline-none"
              >
                <option value="">— None —</option>
                {reportsToOptions.map((d) => (
                  <option key={d.id} value={d.id}>
                    L{d.level} · {d.title}
                  </option>
                ))}
              </select>
            </div>
            <div className="grid grid-cols-2 gap-2">
              <div>
                <label className="block text-xs font-semibold mb-1">Min Salary (₦)</label>
                <input
                  type="number"
                  value={form.salary_band_min}
                  onChange={(e) => setForm({ ...form, salary_band_min: e.target.value })}
                  className="w-full rounded-xl border border-border bg-background px-3 py-2 text-sm focus:outline-none"
                  placeholder="0"
                  min={0}
                />
              </div>
              <div>
                <label className="block text-xs font-semibold mb-1">Max Salary (₦)</label>
                <input
                  type="number"
                  value={form.salary_band_max}
                  onChange={(e) => setForm({ ...form, salary_band_max: e.target.value })}
                  className="w-full rounded-xl border border-border bg-background px-3 py-2 text-sm focus:outline-none"
                  placeholder="0"
                  min={0}
                />
              </div>
            </div>
          </div>
          <div className="flex gap-3 pt-2">
            <button
              onClick={() => { setShowForm(false); setEditing(null); }}
              className="flex-1 px-4 py-2 rounded-xl border border-border text-sm font-semibold hover:bg-muted transition-colors"
            >
              Cancel
            </button>
            <button
              disabled={saving || !form.title || !form.code}
              onClick={handleSave}
              className="flex-1 px-4 py-2 rounded-xl bg-primary text-primary-foreground text-sm font-semibold hover:opacity-90 disabled:opacity-50 transition-opacity"
            >
              {saving ? "Saving…" : editing ? "Update" : "Create"}
            </button>
          </div>
        </div>
      )}

      {/* Designation list grouped by level */}
      {isLoading ? (
        <div className="py-12 flex justify-center">
          <div className="w-8 h-8 border-4 border-primary border-t-transparent rounded-full animate-spin" />
        </div>
      ) : designations.length === 0 ? (
        <div className="py-16 text-center text-sm text-muted-foreground">
          No designations yet. Create one to get started.
        </div>
      ) : (
        <div className="space-y-4">
          {levels.map((level) => (
            <div key={level}>
              <div className="flex items-center gap-2 mb-2">
                <ChevronUp size={14} className="text-muted-foreground" />
                <span className="text-xs font-bold text-muted-foreground uppercase tracking-wide">
                  Level {level} — {LEVEL_LABELS[level]}
                </span>
              </div>
              <div className="divide-y divide-border rounded-2xl border overflow-hidden">
                {byLevel[level].map((d) => (
                  <div key={d.id} className="flex items-center gap-4 p-4 bg-card hover:bg-muted/20 transition-colors">
                    <div className="w-10 h-10 rounded-xl bg-primary/10 flex items-center justify-center shrink-0">
                      <Briefcase size={18} className="text-primary" />
                    </div>
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-2 flex-wrap">
                        <span className="font-semibold text-sm">{d.title}</span>
                        <span className="text-[10px] font-mono px-1.5 py-0.5 rounded bg-muted text-muted-foreground">
                          {d.code}
                        </span>
                        {d.department && (
                          <span className="text-[10px] px-1.5 py-0.5 rounded bg-blue-50 dark:bg-blue-900/20 text-blue-700 dark:text-blue-300">
                            {d.department.name}
                          </span>
                        )}
                        {!d.is_active && (
                          <span className="text-[10px] px-1.5 py-0.5 rounded bg-red-100 text-red-600">
                            Inactive
                          </span>
                        )}
                      </div>
                      <div className="flex items-center gap-3 mt-0.5 text-xs text-muted-foreground flex-wrap">
                        {d.reports_to && (
                          <span>Reports to: {d.reports_to.title}</span>
                        )}
                        <span>
                          Band: {fmt(d.salary_band_min)} – {fmt(d.salary_band_max)}
                        </span>
                        {(d.employees_count ?? d.employee_count) != null && (
                          <span>{d.employees_count ?? d.employee_count} employee{(d.employees_count ?? d.employee_count) !== 1 ? "s" : ""}</span>
                        )}
                      </div>
                    </div>
                    <div className="flex gap-1 shrink-0">
                      <PermissionGate resource="hr" permission="update">
                        <button
                          onClick={() => openEdit(d)}
                          className="p-2 rounded-lg hover:bg-muted transition-colors text-muted-foreground hover:text-foreground"
                        >
                          <Pencil size={14} />
                        </button>
                      </PermissionGate>
                      <PermissionGate resource="hr" permission="delete">
                        <button
                          onClick={() => handleDelete(d.id)}
                          className="p-2 rounded-lg hover:bg-red-50 transition-colors text-muted-foreground hover:text-red-600"
                        >
                          <Trash2 size={14} />
                        </button>
                      </PermissionGate>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

"use client";

import { useEffect, useState, useCallback } from "react";
import {
  PlusCircle, Users, Pencil, Archive, RotateCcw,
  Search, ChevronLeft, ChevronRight,
} from "lucide-react";
import client from "@/lib/api/client";
import { PermissionGate } from "@/components/shared/PermissionGate";
import { usePageView } from "@/hooks/usePageView";
import { format } from "date-fns";

// ── Types ──────────────────────────────────────────────────────────────────────

interface Department  { id: number; name: string; code: string }
interface Designation { id: number; title: string; level: number }
interface Manager     { id: number; first_name: string; last_name: string }

interface EmployeeRecord {
  id: number;
  employee_number: string;
  employment_status: "active" | "probation" | "on_leave" | "suspended" | "resigned" | "terminated";
  contract_type: string;
  work_mode: "onsite" | "remote" | "hybrid";
  join_date: string | null;
  deleted_at?: string | null;
  current_salary?: number | null;
  user: { id: number; first_name: string; last_name: string; email: string; is_active: boolean };
  department: Department | null;
  designation: Designation | null;
  manager: Manager | null;
}

interface Meta { current_page: number; last_page: number; total: number; per_page: number }

// ── Helpers ────────────────────────────────────────────────────────────────────

const STATUS_BADGE: Record<string, string> = {
  active:      "bg-green-100 text-green-700",
  probation:   "bg-yellow-100 text-yellow-700",
  on_leave:    "bg-blue-100 text-blue-700",
  suspended:   "bg-orange-100 text-orange-700",
  resigned:    "bg-gray-100 text-gray-500",
  terminated:  "bg-red-100 text-red-600",
};
const STATUS_LABEL: Record<string, string> = {
  active: "Active", probation: "Probation", on_leave: "On Leave",
  suspended: "Suspended", resigned: "Resigned", terminated: "Terminated",
};
const CONTRACT_LABEL: Record<string, string> = {
  permanent: "Full-time", part_time: "Part-time", contract: "Contractor",
  internship: "Intern", consultant: "Consultant",
  full_time: "Full-time", contractor: "Contractor", intern: "Intern",
};

const EMPTY_FORM = {
  first_name: "", last_name: "", email: "", department_id: "", designation_id: "",
  manager_id: "", contract_type: "full_time", work_mode: "onsite",
  employment_status: "active", join_date: "", current_salary: "",
};

// ── Page ───────────────────────────────────────────────────────────────────────

export default function EmployeesPage() {
  usePageView("hr.employees");

  // View mode: "active" = live records, "archived" = soft-deleted
  const [viewMode, setViewMode]           = useState<"active" | "archived">("active");

  const [records, setRecords]             = useState<EmployeeRecord[]>([]);
  const [meta, setMeta]                   = useState<Meta | null>(null);
  const [departments, setDepartments]     = useState<Department[]>([]);
  const [designations, setDesignations]   = useState<Designation[]>([]);
  const [managers, setManagers]           = useState<{ id: number; first_name: string; last_name: string }[]>([]);
  const [isLoading, setIsLoading]         = useState(false);

  const [search, setSearch]               = useState("");
  const [deptFilter, setDeptFilter]       = useState("");
  const [statusFilter, setStatusFilter]   = useState("");
  const [page, setPage]                   = useState(1);

  const [showForm, setShowForm]           = useState(false);
  const [editing, setEditing]             = useState<EmployeeRecord | null>(null);
  const [form, setForm]                   = useState(EMPTY_FORM);
  const [saving, setSaving]               = useState(false);

  // ── Data loading ─────────────────────────────────────────────────────────────

  const loadRecords = useCallback(async () => {
    setIsLoading(true);
    try {
      if (viewMode === "archived") {
        const params: Record<string, unknown> = { page };
        if (search) params.search = search;
        const res = await client.get("/api/v1/hr/employee-records/archived", { params });
        const data = res.data;
        if (data?.data) {
          setRecords(data.data);
          setMeta({ current_page: data.current_page, last_page: data.last_page, total: data.total, per_page: data.per_page });
        } else {
          setRecords(Array.isArray(data) ? data : []);
          setMeta(null);
        }
      } else {
        const params: Record<string, unknown> = { page };
        if (search) params.search = search;
        if (deptFilter) params.department_id = deptFilter;
        if (statusFilter) params.employment_status = statusFilter;
        const res = await client.get("/api/v1/hr/employee-records", { params });
        const data = res.data;
        if (data?.data) {
          setRecords(data.data);
          setMeta({ current_page: data.current_page, last_page: data.last_page, total: data.total, per_page: data.per_page });
        } else {
          setRecords(Array.isArray(data) ? data : []);
          setMeta(null);
        }
      }
    } finally {
      setIsLoading(false);
    }
  }, [page, search, deptFilter, statusFilter, viewMode]);

  const loadOptions = async () => {
    try {
      const [dRes, desRes] = await Promise.all([
        client.get("/api/v1/hr/departments"),
        client.get("/api/v1/hr/designations"),
      ]);
      setDepartments(dRes.data ?? []);
      setDesignations(desRes.data ?? []);
    } catch { /* non-blocking */ }
  };

  const loadManagers = async (deptId?: string) => {
    try {
      const params: Record<string, unknown> = { per_page: 200 };
      if (deptId) params.department_id = deptId;
      const res = await client.get("/api/v1/hr/employee-records", { params });
      const items = res.data?.data ?? res.data ?? [];
      setManagers(
        (Array.isArray(items) ? items : []).map((e: EmployeeRecord) => ({
          id: e.user.id, first_name: e.user.first_name, last_name: e.user.last_name,
        }))
      );
    } catch { /* non-blocking */ }
  };

  useEffect(() => { loadOptions(); }, []); // eslint-disable-line react-hooks/exhaustive-deps
  useEffect(() => { loadRecords(); }, [loadRecords]);

  // Reset page when switching modes
  const switchMode = (mode: "active" | "archived") => {
    setViewMode(mode);
    setPage(1);
    setSearch("");
  };

  // ── Form helpers ─────────────────────────────────────────────────────────────

  const openCreate = () => {
    setEditing(null);
    setForm(EMPTY_FORM);
    loadManagers();
    setShowForm(true);
  };

  const openEdit = (r: EmployeeRecord) => {
    setEditing(r);
    setForm({
      first_name: r.user.first_name,
      last_name: r.user.last_name,
      email: r.user.email,
      department_id: r.department?.id?.toString() ?? "",
      designation_id: r.designation?.id?.toString() ?? "",
      manager_id: r.manager?.id?.toString() ?? "",
      contract_type: r.contract_type,
      work_mode: r.work_mode,
      employment_status: r.employment_status,
      join_date: r.join_date ?? "",
      current_salary: r.current_salary?.toString() ?? "",
    });
    loadManagers(r.department?.id?.toString());
    setShowForm(true);
  };

  const handleSave = async () => {
    if (!form.first_name || !form.last_name || !form.email) return;
    setSaving(true);
    try {
      const payload: Record<string, unknown> = {
        first_name: form.first_name,
        last_name: form.last_name,
        email: form.email,
        contract_type: form.contract_type,
        work_mode: form.work_mode,
        employment_status: form.employment_status,
        department_id: form.department_id ? parseInt(form.department_id) : null,
        designation_id: form.designation_id ? parseInt(form.designation_id) : null,
        manager_id: form.manager_id ? parseInt(form.manager_id) : null,
        join_date: form.join_date || null,
        current_salary: form.current_salary ? parseFloat(form.current_salary) : null,
      };
      if (editing) {
        await client.put(`/api/v1/hr/employee-records/${editing.id}`, payload);
      } else {
        await client.post("/api/v1/hr/employee-records", payload);
      }
      setShowForm(false);
      setEditing(null);
      setForm(EMPTY_FORM);
      loadRecords();
    } finally {
      setSaving(false);
    }
  };

  const handleArchive = async (id: number, name: string) => {
    if (!confirm(`Archive ${name}'s record? It can be restored later by an admin or CEO.`)) return;
    await client.delete(`/api/v1/hr/employee-records/${id}`);
    loadRecords();
  };

  const handleRestore = async (id: number, name: string) => {
    if (!confirm(`Restore ${name}'s record?`)) return;
    await client.post(`/api/v1/hr/employee-records/${id}/restore`);
    loadRecords();
  };

  return (
    <div className="p-6 space-y-5 max-w-7xl mx-auto">
      {/* Header */}
      <div className="flex items-center justify-between flex-wrap gap-3">
        <div>
          <h1 className="text-2xl font-bold">Employees</h1>
          <p className="text-sm text-muted-foreground">
            {meta ? `${meta.total} ${viewMode === "archived" ? "archived" : "employee"} records` : "Staff directory and records."}
          </p>
        </div>
        <div className="flex items-center gap-2">
          {/* Active / Archived toggle */}
          <div className="flex items-center gap-1 p-1 bg-muted rounded-xl text-sm">
            <button
              onClick={() => switchMode("active")}
              className={`px-3 py-1.5 rounded-lg font-semibold transition-colors ${
                viewMode === "active" ? "bg-card shadow-sm" : "text-muted-foreground hover:text-foreground"
              }`}
            >
              Active
            </button>
            <button
              onClick={() => switchMode("archived")}
              className={`px-3 py-1.5 rounded-lg font-semibold transition-colors flex items-center gap-1.5 ${
                viewMode === "archived" ? "bg-card shadow-sm" : "text-muted-foreground hover:text-foreground"
              }`}
            >
              <Archive size={13} />
              Archived
            </button>
          </div>

          {viewMode === "active" && (
            <PermissionGate resource="hr" permission="write">
              <button
                onClick={openCreate}
                className="flex items-center gap-2 px-4 py-2 rounded-xl bg-primary text-primary-foreground text-sm font-semibold hover:opacity-90 transition-opacity"
              >
                <PlusCircle size={16} /> Add Employee
              </button>
            </PermissionGate>
          )}
        </div>
      </div>

      {/* Filters */}
      <div className="flex flex-wrap gap-3">
        <div className="relative flex-1 min-w-48">
          <Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" />
          <input
            type="text"
            value={search}
            onChange={(e) => { setSearch(e.target.value); setPage(1); }}
            placeholder="Search name or email…"
            className="w-full pl-8 pr-3 py-2 rounded-xl border border-border bg-background text-sm focus:outline-none focus:ring-2 focus:ring-primary"
          />
        </div>
        {viewMode === "active" && (
          <>
            <select
              value={deptFilter}
              onChange={(e) => { setDeptFilter(e.target.value); setPage(1); }}
              className="rounded-xl border border-border bg-background px-3 py-2 text-sm focus:outline-none"
            >
              <option value="">All Departments</option>
              {departments.map((d) => <option key={d.id} value={d.id}>{d.name}</option>)}
            </select>
            <select
              value={statusFilter}
              onChange={(e) => { setStatusFilter(e.target.value); setPage(1); }}
              className="rounded-xl border border-border bg-background px-3 py-2 text-sm focus:outline-none"
            >
              <option value="">All Statuses</option>
