interface PayrollEntry {
  id: number;
  uuid: string;
  user_id: number;
  employee_name: string;
  employee_email: string;
  department: string;
  amount: number | string;
  period: string;
  period_start: string | null;
  period_end: string | null;
  status: string;
  reference_number: string;
  paid_at: string | null;
}

interface Employee {
  id: number;
  first_name: string;
  last_name: string;
  email: string;
  department: string;
}

function statusVariant(status: string) {
  switch (status) {
    case "paid":       return "default" as const;
    case "processing": return "secondary" as const;
    case "pending":    return "outline" as const;
    case "failed":     return "destructive" as const;
    default:           return "outline" as const;
  }
}

const emptyForm = {
  user_id: "",
  amount: "",
  period_start: "",
  period_end: "",
  pay_date: "",
  status: "pending",
};

export default function PayrollPage() {
  const [payroll, setPayroll]       = useState<PayrollEntry[]>([]);
  const [employees, setEmployees]   = useState<Employee[]>([]);
  const [isLoading, setIsLoading]   = useState(true);
  const [createOpen, setCreateOpen] = useState(false);
  const [creating, setCreating]     = useState(false);
  const [form, setForm]             = useState(emptyForm);

  const [markingUuid, setMarkingUuid]   = useState<string | null>(null);
  const [confirmEntry, setConfirmEntry] = useState<PayrollEntry | null>(null);

  const fetchPayroll = useCallback(async () => {
    setIsLoading(true);
    try {
      const data = await hrService.getPayroll();
      const rows = (data as any)?.data ?? data;
      setPayroll(Array.isArray(rows) ? rows : []);
    } catch {
      toast({ description: "Failed to load payroll data", variant: "destructive" });
    } finally {
      setIsLoading(false);
    }
  }, []);

  const fetchEmployees = useCallback(async () => {
    try {
      const data = await hrService.getEmployees({ per_page: 200 });
      const rows = (data as any)?.data ?? data;
      setEmployees(Array.isArray(rows) ? rows : []);
    } catch {
      // silently — employees list is best-effort for the picker
    }
  }, []);

  useEffect(() => {
    fetchPayroll();
    fetchEmployees();
  }, [fetchPayroll, fetchEmployees]);

  const handleCreate = async () => {
    if (!form.user_id || !form.amount || !form.period_start || !form.period_end) {
      toast({ description: "Please fill in all required fields.", variant: "destructive" });
      return;
    }
    setCreating(true);
    try {
      await hrService.createPayroll({
        user_id:      Number(form.user_id),
        amount:       Number(form.amount),
        period_start: form.period_start,
        period_end:   form.period_end,
        pay_date:     form.pay_date || undefined,
        status:       form.status,
      });
      toast({ description: "Payroll entry created." });
      setCreateOpen(false);
      setForm(emptyForm);
      fetchPayroll();
    } catch {
      toast({ description: "Failed to create payroll entry.", variant: "destructive" });
    } finally {
      setCreating(false);
    }
  };

  const handleMarkPaid = async () => {
    if (!confirmEntry) return;
    setMarkingUuid(confirmEntry.uuid);
    try {
      await hrService.markPayrollPaid(confirmEntry.uuid);
      toast({ description: `${confirmEntry.employee_name}'s payroll marked as paid. Email sent.` });
      fetchPayroll();
    } catch {
      toast({ description: "Failed to mark as paid.", variant: "destructive" });
    } finally {
      setMarkingUuid(null);
      setConfirmEntry(null);
    }
  };

  const totalPending = payroll.filter((p) => p.status === "pending").length;
  const totalPaid    = payroll.filter((p) => p.status === "paid").length;
  const totalAmount  = payroll
    .filter((p) => p.status === "paid")
    .reduce((sum, p) => sum + (typeof p.amount === "number" ? p.amount : parseFloat(String(p.amount)) || 0), 0);

  return (
    <div className="p-6 space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-bold tracking-tight">Payroll</h1>
          <p className="text-muted-foreground">Manage Onwynd internal employee paychecks.</p>
        </div>
        <div className="flex gap-2">
          <Button variant="outline" size="sm" onClick={fetchPayroll} disabled={isLoading}>
            <RefreshCw className={`h-4 w-4 mr-2 ${isLoading ? "animate-spin" : ""}`} />
            Refresh
          </Button>
          <Button onClick={() => setCreateOpen(true)}>
            <Plus className="mr-2 h-4 w-4" />
            New Entry
          </Button>
        </div>
      </div>

      {/* Summary cards */}
      <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium text-muted-foreground">Pending</CardTitle>
          </CardHeader>
          <CardContent>
            <p className="text-2xl font-bold">{totalPending}</p>
          </CardContent>
        </Card>
        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium text-muted-foreground">Paid this batch</CardTitle>
          </CardHeader>
          <CardContent>
            <p className="text-2xl font-bold">{totalPaid}</p>
          </CardContent>
        </Card>
        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium text-muted-foreground">Total disbursed</CardTitle>
          </CardHeader>
          <CardContent>
            <p className="text-2xl font-bold">₦{totalAmount.toLocaleString()}</p>
          </CardContent>
        </Card>
      </div>

      {/* Table */}
      <Card>
        <CardHeader>
          <CardTitle>Payroll Records</CardTitle>
          <CardDescription>
            Onwynd employee payroll entries. Use &quot;Mark as Paid&quot; to disburse and automatically notify the employee by email.
          </CardDescription>
        </CardHeader>
        <CardContent>
          {isLoading ? (
            <div className="flex items-center justify-center py-8">
              <Loader2 className="h-6 w-6 animate-spin text-muted-foreground" />
            </div>
          ) : payroll.length === 0 ? (
            <div className="text-center py-8 text-muted-foreground">
              No payroll records found. Create the first entry above.
            </div>
          ) : (
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>Employee</TableHead>
                  <TableHead>Department</TableHead>
                  <TableHead>Period</TableHead>
                  <TableHead>Amount</TableHead>
                  <TableHead>Ref #</TableHead>
                  <TableHead>Status</TableHead>
                  <TableHead>Paid</TableHead>
                  <TableHead></TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {payroll.map((entry) => (
                  <TableRow key={entry.id}>
                    <TableCell>
                      <div>
                        <div className="font-medium">{entry.employee_name}</div>
                        <div className="text-xs text-muted-foreground">{entry.employee_email}</div>
                      </div>
                    </TableCell>
                    <TableCell>{entry.department}</TableCell>
                    <TableCell className="whitespace-nowrap">{entry.period}</TableCell>
                    <TableCell className="font-medium">
                      ₦{typeof entry.amount === "number"
                        ? entry.amount.toLocaleString()
                        : parseFloat(String(entry.amount)).toLocaleString()}
                    </TableCell>
                    <TableCell className="text-xs text-muted-foreground font-mono">
                      {entry.reference_number}
                    </TableCell>
                    <TableCell>
                      <Badge variant={statusVariant(entry.status)}>{entry.status}</Badge>
                    </TableCell>
                    <TableCell>
                      {entry.paid_at ? new Date(entry.paid_at).toLocaleDateString() : "—"}
                    </TableCell>
                    <TableCell>
                      {entry.status !== "paid" && (
                        <Button
                          size="sm"
                          variant="outline"
                          className="whitespace-nowrap"
                          onClick={() => setConfirmEntry(entry)}
                          disabled={markingUuid === entry.uuid}
                        >
                          {markingUuid === entry.uuid ? (
                            <Loader2 className="h-4 w-4 animate-spin" />
                          ) : (
                            <>
                              <CheckCircle2 className="h-4 w-4 mr-1" />
                              Mark as Paid
                            </>
                          )}
                        </Button>
                      )}
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          )}
        </CardContent>
      </Card>

      {/* Create Entry Dialog */}
      <Dialog open={createOpen} onOpenChange={setCreateOpen}>
        <DialogContent className="sm:max-w-md">
          <DialogHeader>
            <DialogTitle>New Payroll Entry</DialogTitle>
            <DialogDescription>
              Create a paycheck record for an Onwynd internal employee.
            </DialogDescription>
          </DialogHeader>
          <div className="space-y-4 py-2">
            <div className="space-y-1">
              <Label>
                Employee <span className="text-destructive">*</span>
              </Label>
              <Select
                value={form.user_id}
                onValueChange={(v) => setForm((f) => ({ ...f, user_id: v ?? "" }))}
              >
                <SelectTrigger>
                  <SelectValue placeholder="Select employee…" />
                </SelectTrigger>
                <SelectContent>
                  {employees.map((e) => (
                    <SelectItem key={e.id} value={String(e.id)}>
                      {e.first_name} {e.last_name}
                      {e.department ? ` (${e.department})` : ""}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            <div className="space-y-1">
              <Label>
                Amount (₦) <span className="text-destructive">*</span>
              </Label>
              <Input
                type="number"
                min="0"
                placeholder="e.g. 350000"
                value={form.amount}
                onChange={(e) => setForm((f) => ({ ...f, amount: e.target.value }))}
              />
            </div>

            <div className="grid grid-cols-2 gap-3">
              <div className="space-y-1">
                <Label>
                  Period Start <span className="text-destructive">*</span>
                </Label>
                <Input
                  type="date"
                  value={form.period_start}
                  onChange={(e) => setForm((f) => ({ ...f, period_start: e.target.value }))}
                />
              </div>
              <div className="space-y-1">
                <Label>
                  Period End <span className="text-destructive">*</span>
                </Label>
                <Input
                  type="date"
                  value={form.period_end}
                  onChange={(e) => setForm((f) => ({ ...f, period_end: e.target.value }))}
                />
              </div>
            </div>

            <div className="space-y-1">
              <Label>Pay Date (optional)</Label>
              <Input
                type="date"
                value={form.pay_date}
                onChange={(e) => setForm((f) => ({ ...f, pay_date: e.target.value }))}
              />
            </div>

            <div className="space-y-1">
              <Label>Initial Status</Label>
              <Select
                value={form.status}
                onValueChange={(v) => setForm((f) => ({ ...f, status: v ?? "pending" }))}
              >
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="pending">Pending</SelectItem>
                  <SelectItem value="processing">Processing</SelectItem>
                  <SelectItem value="paid">Paid</SelectItem>
                </SelectContent>
              </Select>
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setCreateOpen(false)}>
              Cancel
            </Button>
            <Button onClick={handleCreate} disabled={creating}>
              {creating && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              Create Entry
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Mark as Paid confirmation */}
      <AlertDialog
        open={!!confirmEntry}
        onOpenChange={(o) => { if (!o) setConfirmEntry(null); }}
      >
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Mark as Paid?</AlertDialogTitle>
            <AlertDialogDescription>
              This will mark <strong>{confirmEntry?.employee_name}</strong>&apos;s payroll entry (
              <strong>
                ₦{typeof confirmEntry?.amount === "number"
                  ? confirmEntry.amount.toLocaleString()
                  : parseFloat(String(confirmEntry?.amount ?? "0")).toLocaleString()}
              </strong>
              ) as paid and send them a payslip notification email.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancel</AlertDialogCancel>
            <AlertDialogAction onClick={handleMarkPaid} disabled={!!markingUuid}>
              {markingUuid ? (
                <Loader2 className="h-4 w-4 animate-spin mr-2" />
              ) : (
                <DollarSign className="h-4 w-4 mr-2" />
              )}
              Confirm &amp; Notify
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { hrService } from "@/lib/api/hr";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Loader2, Users, DollarSign, Calendar, UserPlus } from "lucide-react";
import { useToast } from "@/components/ui/use-toast";
import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
} from "recharts";

interface HRStats {
  total_employees: number;
  active_employees: number;
  pending_leave: number;
  approved_leave_month: number;
  new_hires_this_month: number;
  total_payroll_month: number;
}

interface ChartPoint { month: string; amount: number; }

export default function HRReportsPage() {
  const { toast } = useToast();
  const [stats, setStats] = useState<HRStats | null>(null);
  const [chartData, setChartData] = useState<ChartPoint[]>([]);
  const [period, setPeriod] = useState("6");
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetch = async () => {
      setLoading(true);
      try {
        const [s, c] = await Promise.all([
          hrService.getStats(),
          hrService.getChartData(period),
        ]);
        setStats(typeof s === 'object' && s !== null ? s as HRStats : null);
        const raw = Array.isArray(c) ? c : [];
        setChartData(raw);
      } catch (error) {
        console.error('Failed to fetch HR data:', error);
        toast({
          title: "Error",
          description: "Failed to load HR statistics. Please try again.",
          variant: "destructive",
        });
        setStats(null);
        setChartData([]);
      } finally {
        setLoading(false);
      }
    };
    fetch();
  }, [period]);

  if (loading) {
    return (
      <div className="flex items-center justify-center h-full p-12">
        <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
      </div>
    );
  }

  if (stats === null) {
    return (
      <div className="p-6">
        <div className="mb-6">
          <h1 className="text-3xl font-bold tracking-tight">HR Reports</h1>
          <p className="text-muted-foreground">Workforce analytics and payroll overview.</p>
        </div>
        <Card>
          <CardContent className="text-center py-12">
            <div className="text-muted-foreground mb-2">Failed to load HR statistics</div>
            <div className="text-sm text-muted-foreground">Please try refreshing the page or contact support if the issue persists.</div>
          </CardContent>
        </Card>
      </div>
    );
  }

  return (
    <div className="p-6 space-y-6">
      <div>
        <h1 className="text-3xl font-bold tracking-tight">HR Reports</h1>
        <p className="text-muted-foreground">Workforce analytics and payroll overview.</p>
      </div>

      <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
        <Card>
          <CardHeader className="flex flex-row items-center justify-between pb-2 space-y-0">
            <CardTitle className="text-sm font-medium">Total Employees</CardTitle>
            <Users className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{stats?.total_employees ?? 0}</div>
            <p className="text-xs text-muted-foreground">{stats?.active_employees ?? 0} active</p>
          </CardContent>
        </Card>
        <Card>
          <CardHeader className="flex flex-row items-center justify-between pb-2 space-y-0">
            <CardTitle className="text-sm font-medium">Monthly Payroll</CardTitle>
            <DollarSign className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">₦{(stats?.total_payroll_month ?? 0).toLocaleString()}</div>
            <p className="text-xs text-muted-foreground">This month&apos;s total</p>
          </CardContent>
        </Card>
        <Card>
          <CardHeader className="flex flex-row items-center justify-between pb-2 space-y-0">
            <CardTitle className="text-sm font-medium">Leave Requests</CardTitle>
            <Calendar className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold text-yellow-600">{stats?.pending_leave ?? 0}</div>
            <p className="text-xs text-muted-foreground">{stats?.approved_leave_month ?? 0} approved this month</p>
          </CardContent>
        </Card>
        <Card>
          <CardHeader className="flex flex-row items-center justify-between pb-2 space-y-0">
            <CardTitle className="text-sm font-medium">New Hires</CardTitle>
            <UserPlus className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold text-green-600">{stats?.new_hires_this_month ?? 0}</div>
            <p className="text-xs text-muted-foreground">This month</p>
          </CardContent>
        </Card>
      </div>

      <Card>
        <CardHeader>
          <div className="flex items-center justify-between">
            <div>
              <CardTitle>Payroll Trend</CardTitle>
              <CardDescription>Monthly payroll expenditure over time.</CardDescription>
            </div>
            <Select value={period} onValueChange={(v: string | null) => v && setPeriod(v)}>
              <SelectTrigger className="w-[120px]">
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="3">3 months</SelectItem>
                <SelectItem value="6">6 months</SelectItem>
                <SelectItem value="12">12 months</SelectItem>
              </SelectContent>
            </Select>
          </div>
        </CardHeader>
        <CardContent>
          {chartData.length === 0 ? (
            <div className="flex items-center justify-center py-12 text-muted-foreground text-sm">
              No payroll data available yet.
            </div>
          ) : (
            <ResponsiveContainer width="100%" height={300}>
              <BarChart data={chartData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} />
                <XAxis dataKey="month" tick={{ fontSize: 12 }} />
                <YAxis tick={{ fontSize: 12 }} tickFormatter={(v) => `₦${(v / 1000).toFixed(0)}k`} />
                <Tooltip formatter={(v) => [`₦${Number(v ?? 0).toLocaleString()}`, "Payroll"]} />
                <Bar dataKey="amount" fill="hsl(var(--primary))" radius={[4, 4, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

﻿"use client";

// F3  B2B Per-Seat Quota Usage Dashboard for HR / Institution Admins.

import { useEffect, useState } from "react";
import { institutionalService } from "@/lib/api/institutional";
import {
  Card, CardContent, CardHeader, CardTitle,
} from "@/components/ui/card";
import {
  Table, TableBody, TableCell, TableHead, TableHeader, TableRow,
} from "@/components/ui/table";
import { Badge } from "@/components/ui/badge";
import { Loader2, Users, Activity, AlertTriangle, TrendingUp } from "lucide-react";

interface SeatActivity {
  seat_number: number;
  last_active_at: string | null;
  sessions_count: number;
  ai_conversations_count: number;
  is_at_risk: boolean;
  risk_reason?: string;
}

interface QuotaUsageData {
  total_seats: number;
  used_seats: number;
  active_seats: number;
  at_risk_seats: number;
  utilization_rate: number;
  plan_name: string;
  renewal_date?: string;
  seat_activity: SeatActivity[];
}

function formatDate(iso: string | null) {
  if (!iso) return "Never";
  return new Date(iso).toLocaleDateString("en-GB", { day: "2-digit", month: "short", year: "numeric" });
}

export default function QuotaUsagePage() {
  const [data, setData] = useState<QuotaUsageData | null>(null);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState<"all" | "at_risk" | "active">("all");

  useEffect(() => {
    institutionalService.getQuotaUsage()
      .then((res: any) => setData(res as QuotaUsageData))
      .catch(() => {})
      .finally(() => setLoading(false));
  }, []);

  const seats = data?.seat_activity ?? [];
  const filtered = seats.filter((s) => {
    if (filter === "at_risk") return s.is_at_risk;
    if (filter === "active") return !s.is_at_risk && s.sessions_count > 0;
    return true;
  });

  const utilizationPct = data ? Math.round(data.utilization_rate * 100) : 0;
  const utilizationColor = utilizationPct >= 80 ? "text-emerald-600" : utilizationPct >= 50 ? "text-amber-600" : "text-red-600";

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-[60vh]">
        <Loader2 className="w-10 h-10 animate-spin text-muted-foreground" />
      </div>
    );
  }

  return (
    <div className="flex-1 space-y-6 p-6 pt-6">
      <div>
        <h2 className="text-2xl font-bold tracking-tight">Seat Quota Usage</h2>
        <p className="text-muted-foreground text-sm mt-1">
          Monitor employee engagement and identify at-risk members. All data is anonymized.
        </p>
      </div>

      {/* Stat cards */}
      <div className="grid gap-4 grid-cols-2 md:grid-cols-4">
        <Card>
          <CardContent className="p-5 flex items-start gap-3">
            <div className="size-9 rounded-lg bg-blue-100 dark:bg-blue-900/30 flex items-center justify-center shrink-0">
              <Users className="w-5 h-5 text-blue-600 dark:text-blue-400" />
            </div>
            <div>
              <p className="text-xs text-muted-foreground">Total Seats</p>
              <p className="text-2xl font-bold">{data?.total_seats ?? ""}</p>
              <p className="text-xs text-muted-foreground mt-0.5">{data?.plan_name}</p>
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardContent className="p-5 flex items-start gap-3">
            <div className="size-9 rounded-lg bg-emerald-100 dark:bg-emerald-900/30 flex items-center justify-center shrink-0">
              <Activity className="w-5 h-5 text-emerald-600 dark:text-emerald-400" />
            </div>
            <div>
              <p className="text-xs text-muted-foreground">Active Seats</p>
              <p className="text-2xl font-bold">{data?.active_seats ?? ""}</p>
              <p className={`text-xs font-semibold mt-0.5 ${utilizationColor}`}>{utilizationPct}% utilization</p>
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardContent className="p-5 flex items-start gap-3">
            <div className="size-9 rounded-lg bg-amber-100 dark:bg-amber-900/30 flex items-center justify-center shrink-0">
              <AlertTriangle className="w-5 h-5 text-amber-600 dark:text-amber-400" />
            </div>
            <div>
              <p className="text-xs text-muted-foreground">At-Risk Seats</p>
              <p className="text-2xl font-bold">{data?.at_risk_seats ?? ""}</p>
              <p className="text-xs text-muted-foreground mt-0.5">No activity &gt;14d</p>
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardContent className="p-5 flex items-start gap-3">
            <div className="size-9 rounded-lg bg-purple-100 dark:bg-purple-900/30 flex items-center justify-center shrink-0">
              <TrendingUp className="w-5 h-5 text-purple-600 dark:text-purple-400" />
            </div>
            <div>
              <p className="text-xs text-muted-foreground">Used Seats</p>
              <p className="text-2xl font-bold">{data?.used_seats ?? ""}</p>
              {data?.renewal_date && (
                <p className="text-xs text-muted-foreground mt-0.5">Renews {formatDate(data.renewal_date)}</p>
              )}
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Utilization bar */}
      {data && (
        <div className="bg-muted rounded-xl p-4">
          <div className="flex items-center justify-between mb-2">
            <span className="text-sm font-semibold">Seat Utilization</span>
            <span className={`text-sm font-bold ${utilizationColor}`}>{data.active_seats} / {data.total_seats} active</span>
          </div>
          <div className="h-3 rounded-full bg-border overflow-hidden">
            <div
              className={`h-full rounded-full transition-all ${utilizationPct >= 80 ? "bg-emerald-500" : utilizationPct >= 50 ? "bg-amber-500" : "bg-red-500"}`}
              style={{ width: `${utilizationPct}%` }}
            />
          </div>
          <p className="text-xs text-muted-foreground mt-2">
            {data.at_risk_seats > 0
              ? `${data.at_risk_seats} seat(s) are at risk of churn  consider sending a wellness nudge.`
              : "All active seats show healthy engagement."}
          </p>
        </div>
      )}

      {/* Seat activity table */}
      <Card>
        <CardHeader className="flex flex-row items-center justify-between pb-2">
          <CardTitle className="text-base">Anonymized Seat Activity</CardTitle>
          <div className="flex gap-2">
            {(["all", "at_risk", "active"] as const).map((f) => (
              <button
                key={f}
                type="button"
                onClick={() => setFilter(f)}
                className={`px-3 py-1 rounded-lg text-xs font-semibold transition-colors ${
                  filter === f ? "bg-primary text-primary-foreground" : "bg-muted text-muted-foreground hover:bg-muted/80"
                }`}
              >
                {f === "all" ? "All" : f === "at_risk" ? "At Risk" : "Active"}
              </button>
            ))}
          </div>
        </CardHeader>
        <CardContent>
          {filtered.length === 0 ? (
            <p className="text-sm text-muted-foreground py-8 text-center">No seats match this filter.</p>
          ) : (
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>Seat #</TableHead>
                  <TableHead>Last Active</TableHead>
                  <TableHead className="text-right">Sessions</TableHead>
                  <TableHead className="text-right">AI Conversations</TableHead>
                  <TableHead>Status</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {filtered.map((seat) => (
                  <TableRow key={seat.seat_number}>
                    <TableCell className="font-mono text-sm">#{String(seat.seat_number).padStart(3, "0")}</TableCell>
                    <TableCell className="text-muted-foreground">{formatDate(seat.last_active_at)}</TableCell>
                    <TableCell className="text-right">{seat.sessions_count}</TableCell>
                    <TableCell className="text-right">{seat.ai_conversations_count}</TableCell>
                    <TableCell>
                      {seat.is_at_risk ? (
                        <Badge variant="destructive" className="text-xs">
                          At Risk{seat.risk_reason ? `  ${seat.risk_reason}` : ""}
                        </Badge>
                      ) : seat.sessions_count > 0 ? (
                        <Badge variant="default" className="text-xs">Active</Badge>
                      ) : (
                        <Badge variant="secondary" className="text-xs">Unused</Badge>
                      )}
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          )}
        </CardContent>
      </Card>

      <p className="text-xs text-muted-foreground text-center">
        All seat data is fully anonymized. No personally identifiable information is displayed.
      </p>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Button } from "@/components/ui/button";
import { Skeleton } from "@/components/ui/skeleton";
import { Badge } from "@/components/ui/badge";
import { institutionalService } from "@/lib/api/institutional";

// API returns { count: number; events: CrisisEvent[] }
type CrisisEvent = {
  id: number;
  uuid: string;
  risk_level: "low" | "medium" | "high" | "severe";
  flagged_at: string;
  member_identifier: string;
  status: "pending" | "reviewed" | "resolved";
  reason: string;
  resources_shown: boolean;
};

export default function AtRiskPage() {
  const [isLoading, setIsLoading] = useState(true);
  const [count, setCount] = useState(0);
  const [events, setEvents] = useState<CrisisEvent[]>([]);

  useEffect(() => {
    async function load() {
      setIsLoading(true);
      try {
        const data = await institutionalService.getAtRisk() as { count?: number; events?: CrisisEvent[] } | null;
        if (data && "events" in data && Array.isArray(data.events)) {
          setCount(data.count ?? 0);
          setEvents(data.events);
        }
      } finally {
        setIsLoading(false);
      }
    }
    load();
  }, []);

  function exportCSV() {
    const headers = ["Member ID", "Risk Level", "Time", "Reason", "Status"];
    const lines = events.map((e) =>
      [
        JSON.stringify(e.member_identifier),
        JSON.stringify(e.risk_level),
        JSON.stringify(new Date(e.flagged_at).toLocaleString()),
        JSON.stringify(e.reason),
        JSON.stringify(e.status),
      ].join(","),
    );
    const csv = [headers.join(","), ...lines].join("\n");
    const blob = new Blob([csv], { type: "text/csv;charset=utf-8;" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = "crisis-events-anonymized.csv";
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  }

  function getRiskBadgeColor(level: string) {
    switch (level) {
      case "severe": return "bg-red-600 hover:bg-red-700";
      case "high": return "bg-red-500 hover:bg-red-600";
      case "medium": return "bg-orange-500 hover:bg-orange-600";
      default: return "bg-yellow-500 hover:bg-yellow-600";
    }
  }

  return (
    <div className="p-6 space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-bold tracking-tight">Crisis Alerts</h1>
          <p className="text-muted-foreground text-sm mt-1">
            Anonymized log of crisis flags triggered by members.
            Review these events to understand community wellness trends.
          </p>
        </div>
        <Button variant="secondary" onClick={exportCSV} disabled={isLoading || events.length === 0}>
          Export CSV
        </Button>
      </div>

      <div className="rounded-xl border bg-amber-50 border-amber-200 px-4 py-3 flex items-start gap-3">
        <span className="text-amber-600 text-lg flex-shrink-0 mt-0.5">🔒</span>
        <p className="text-sm text-amber-800">
          <strong>Privacy protected.</strong> You can see that a crisis event occurred and its severity,
          but member identities are masked (e.g., "Member #a1b"). This protects employee confidentiality.
        </p>
      </div>

      <Card>
        <CardHeader>
          <CardTitle>
            Crisis Events
            {!isLoading && (
              <span className="ml-2 text-sm font-normal text-muted-foreground">
                ({count} total)
              </span>
            )}
          </CardTitle>
        </CardHeader>
        <CardContent>
          {isLoading ? (
            <Skeleton className="h-64 w-full" />
          ) : events.length === 0 ? (
            <p className="text-sm text-muted-foreground py-10 text-center">
              No crisis events detected in the reporting period.
            </p>
          ) : (
            <div className="rounded-md border">
              <Table>
                <TableHeader>
                  <TableRow>
                    <TableHead>Risk Level</TableHead>
                    <TableHead>Timestamp</TableHead>
                    <TableHead>Member Identifier</TableHead>
                    <TableHead>Reason</TableHead>
                    <TableHead>Status</TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {events.map((e) => (
                    <TableRow key={e.id}>
                      <TableCell>
                        <Badge className={getRiskBadgeColor(e.risk_level)}>
                          {e.risk_level.toUpperCase()}
                        </Badge>
                      </TableCell>
                      <TableCell className="text-sm">
                        {new Date(e.flagged_at).toLocaleString()}
                      </TableCell>
                      <TableCell className="font-mono text-sm">
                        {e.member_identifier}
                      </TableCell>
                      <TableCell className="text-muted-foreground text-sm">
                        {e.reason}
                      </TableCell>
                      <TableCell>
                        <Badge variant={e.status === "pending" ? "outline" : "secondary"}>
                          {e.status}
                        </Badge>
                      </TableCell>
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

