import { Button } from "@/components/ui/button";
import { Skeleton } from "@/components/ui/skeleton";
import { Badge } from "@/components/ui/badge";
import { Alert, AlertDescription } from "@/components/ui/alert";
import client from "@/lib/api/client";
import { cn } from "@/lib/utils";
import {
  Send, Search, MessageSquare, MoreHorizontal, AlertTriangle, Plus,
} from "lucide-react";

/* ─── Types ──────────────────────────────────────────────────────────────── */

interface StaffUser {
  id: number;
  first_name: string;
  last_name: string;
  email: string;
  profile_photo?: string;
  is_online?: boolean;
  role?: { name: string; slug: string };
}

interface ChatMessage {
  id: number;
  from_user_id: number;
  to_user_id: number;
  message: string;
  message_type: string;
  is_read: boolean;
  created_at: string;
  sender?: { id: number; first_name: string; last_name: string };
}

/* ─── Helpers ─────────────────────────────────────────────────────────────── */

function initials(u: StaffUser) {
  return `${u.first_name[0] ?? ""}${u.last_name[0] ?? ""}`.toUpperCase();
}

function timeLabel(ts: string) {
  const d = new Date(ts);
  const now = new Date();
  const sameDay = d.toDateString() === now.toDateString();
  return sameDay
    ? d.toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" })
    : d.toLocaleDateString([], { month: "short", day: "numeric" });
}

/* ─── Component ──────────────────────────────────────────────────────────── */

export default function MessagesPage() {
  // ── Staff / conversations list ───────────────────────────────────────────
  const [staff,          setStaff]          = useState<StaffUser[]>([]);
  const [staffSearch,    setStaffSearch]     = useState("");
  const [staffLoading,   setStaffLoading]    = useState(true);
  const [conversations,  setConversations]   = useState<StaffUser[]>([]);

  // ── Active conversation ──────────────────────────────────────────────────
  const [activeUser,     setActiveUser]      = useState<StaffUser | null>(null);
  const [messages,       setMessages]        = useState<ChatMessage[]>([]);
  const [msgLoading,     setMsgLoading]      = useState(false);
  const [msgError,       setMsgError]        = useState<string | null>(null);
  const [draft,          setDraft]           = useState("");
  const [sending,        setSending]         = useState(false);
  const [myId,           setMyId]            = useState<number | null>(null);

  // ── Tab (conversations | new) ────────────────────────────────────────────
  const [tab, setTab] = useState<"conversations" | "new">("conversations");

  const bottomRef = useRef<HTMLDivElement>(null);

  /* ── Load current user id ─────────────────────────────────────────────── */
  useEffect(() => {
    try {
      const u = JSON.parse(localStorage.getItem("user") || "{}");
      if (u?.id) setMyId(Number(u.id));
    } catch { /* ignore */ }
  }, []);

  /* ── Load recent conversations ───────────────────────────────────────────*/
  useEffect(() => {
    (async () => {
      try {
        const res = await client.get("/api/v1/chat/conversations");
        const items: StaffUser[] = (res.data?.data?.conversations ?? []) as StaffUser[];
        setConversations(items);
      } catch { /* ignore */ }
    })();
  }, []);

  /* ── Load staff directory (for new conversations) ────────────────────── */
  useEffect(() => {
    setStaffLoading(true);
    const t = setTimeout(async () => {
      try {
        const res = await client.get("/api/v1/chat/staff", {
          params: staffSearch ? { search: staffSearch } : {},
        });
        setStaff((res.data?.data ?? []) as StaffUser[]);
      } catch { /* ignore */ }
      finally { setStaffLoading(false); }
    }, 300);
    return () => clearTimeout(t);
  }, [staffSearch]);

  /* ── Load messages for active conversation ────────────────────────────── */
  const loadMessages = useCallback(async (userId: number) => {
    setMsgLoading(true);
    setMsgError(null);
    try {
      const res = await client.get(`/api/v1/chat/conversations/${userId}`);
      const msgs: ChatMessage[] = (res.data?.data?.messages ?? []).reverse();
      setMessages(msgs);
    } catch {
      setMsgError("Could not load messages. Please try again.");
    } finally {
      setMsgLoading(false);
    }
  }, []);

  useEffect(() => {
    if (activeUser) loadMessages(activeUser.id);
  }, [activeUser, loadMessages]);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  /* ── Send message ─────────────────────────────────────────────────────── */
  const sendMessage = async () => {
    if (!draft.trim() || !activeUser || sending) return;
    const text = draft.trim();
    setDraft("");
    setSending(true);
    // Optimistic append
    const optimistic: ChatMessage = {
      id: Date.now(),
      from_user_id: myId ?? 0,
      to_user_id: activeUser.id,
      message: text,
      message_type: "text",
      is_read: false,
      created_at: new Date().toISOString(),
    };
    setMessages((prev) => [...prev, optimistic]);
    try {
      await client.post("/api/v1/chat/messages", {
        to_user_id: activeUser.id,
        message: text,
        message_type: "text",
      });
    } catch {
      // Roll back optimistic message
      setMessages((prev) => prev.filter((m) => m.id !== optimistic.id));
      setDraft(text);
    } finally {
      setSending(false);
    }
  };

  const displayList = tab === "conversations" ? conversations : staff;

  return (
    <div className="flex h-[calc(100vh-4rem)] overflow-hidden">
      {/* ── Left pane: contact list ──────────────────────────────────────── */}
      <div className="w-72 border-r flex flex-col bg-background shrink-0">
        {/* Header */}
        <div className="px-4 pt-4 pb-2 border-b">
          <div className="flex items-center justify-between mb-3">
            <h2 className="text-base font-semibold">Messages</h2>
            <Button
              variant="ghost"
              size="icon"
              className="size-8"
              onClick={() => setTab(tab === "new" ? "conversations" : "new")}
              title="New conversation"
            >
              <Plus className="size-4" />
            </Button>
          </div>
          {/* Tabs */}
          <div className="flex gap-1 mb-2">
            {(["conversations", "new"] as const).map((t) => (
              <button
                key={t}
                onClick={() => setTab(t)}
                className={cn(
                  "flex-1 text-xs py-1 rounded-md font-medium transition-colors",
                  tab === t
                    ? "bg-primary text-primary-foreground"
                    : "text-muted-foreground hover:bg-muted"
                )}
              >
                {t === "conversations" ? "Recent" : "New Chat"}
              </button>
            ))}
          </div>
          {tab === "new" && (
            <div className="relative">
              <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 size-3.5 text-muted-foreground" />
              <Input
                value={staffSearch}
                onChange={(e) => setStaffSearch(e.target.value)}
                placeholder="Search staff…"
                className="pl-8 h-8 text-xs"
              />
            </div>
          )}
        </div>

        {/* Contact list */}
        <div className="flex-1 overflow-y-auto">
          {staffLoading && tab === "new" ? (
            <div className="p-3 space-y-2">
              {Array.from({ length: 5 }).map((_, i) => (
                <div key={i} className="flex items-center gap-2">
                  <Skeleton className="size-9 rounded-full" />
                  <div className="flex-1 space-y-1">
                    <Skeleton className="h-3 w-24" />
                    <Skeleton className="h-2.5 w-16" />
                  </div>
                </div>
              ))}
            </div>
          ) : displayList.length === 0 ? (
            <p className="text-xs text-muted-foreground text-center py-8 px-4">
              {tab === "conversations"
                ? "No conversations yet. Start one below."
                : "No staff members found."}
            </p>
          ) : (
            displayList.map((user) => (
              <button
                key={user.id}
                onClick={() => { setActiveUser(user); setTab("conversations"); }}
                className={cn(
                  "w-full flex items-center gap-3 px-4 py-3 hover:bg-muted/50 transition-colors text-left",
                  activeUser?.id === user.id && "bg-muted"
                )}
              >
                {/* Avatar */}
                <div className="relative shrink-0">
                  {user.profile_photo ? (
                    <img src={user.profile_photo} alt="" className="size-9 rounded-full object-cover" />
                  ) : (
                    <div className="size-9 rounded-full bg-primary/10 text-primary flex items-center justify-center text-xs font-bold">
                      {initials(user)}
                    </div>
                  )}
                  {user.is_online && (
                    <span className="absolute bottom-0 right-0 size-2.5 rounded-full bg-emerald-500 border-2 border-background" />
                  )}
                </div>
                {/* Info */}
                <div className="flex-1 min-w-0">
                  <p className="text-sm font-medium truncate">
                    {user.first_name} {user.last_name}
                  </p>
                  {user.role && (
                    <p className="text-xs text-muted-foreground capitalize">{user.role.name}</p>
                  )}
                </div>
              </button>
            ))
          )}
        </div>
      </div>

      {/* ── Right pane: active conversation ──────────────────────────────── */}
      <div className="flex-1 flex flex-col min-w-0">
        {activeUser ? (
          <>
            {/* Chat header */}
            <div className="flex items-center gap-3 px-4 py-3 border-b bg-background">
              <div className="relative">
                {activeUser.profile_photo ? (
                  <img src={activeUser.profile_photo} alt="" className="size-9 rounded-full object-cover" />
                ) : (
                  <div className="size-9 rounded-full bg-primary/10 text-primary flex items-center justify-center text-xs font-bold">
                    {initials(activeUser)}
                  </div>
                )}
                {activeUser.is_online && (
                  <span className="absolute bottom-0 right-0 size-2.5 rounded-full bg-emerald-500 border-2 border-background" />
                )}
              </div>
              <div className="flex-1">
                <p className="text-sm font-semibold">
                  {activeUser.first_name} {activeUser.last_name}
                </p>
                <p className="text-xs text-muted-foreground">
                  {activeUser.is_online ? (
                    <span className="text-emerald-600">Online</span>
                  ) : "Offline"}
                  {activeUser.role && ` · ${activeUser.role.name}`}
                </p>
              </div>
              <Button variant="ghost" size="icon" className="size-8">
                <MoreHorizontal className="size-4" />
              </Button>
            </div>

            {/* Messages area */}
            <div className="flex-1 overflow-y-auto px-4 py-4 space-y-3">
              {msgError && (
                <Alert variant="destructive">
                  <AlertTriangle className="size-4" />
                  <AlertDescription>{msgError}</AlertDescription>
                </Alert>
              )}
              {msgLoading ? (
                <div className="space-y-3">
                  {Array.from({ length: 4 }).map((_, i) => (
                    <div key={i} className={cn("flex", i % 2 === 0 ? "justify-start" : "justify-end")}>
                      <Skeleton className="h-10 w-48 rounded-2xl" />
                    </div>
                  ))}
                </div>
              ) : messages.length === 0 ? (
                <div className="flex flex-col items-center justify-center h-full py-16">
                  <MessageSquare className="size-8 text-muted-foreground mb-2" />
                  <p className="text-sm text-muted-foreground">
                    No messages yet. Say hello!
                  </p>
                </div>
              ) : (
                messages.map((msg) => {
                  const isMe = msg.from_user_id === myId;
                  return (
                    <div key={msg.id} className={cn("flex", isMe ? "justify-end" : "justify-start")}>
                      <div
                        className={cn(
                          "max-w-xs lg:max-w-md px-3.5 py-2 rounded-2xl text-sm break-words",
                          isMe
                            ? "bg-primary text-primary-foreground rounded-br-sm"
                            : "bg-muted text-foreground rounded-bl-sm"
                        )}
                      >
                        <p>{msg.message}</p>
                        <p className={cn("text-[10px] mt-0.5 text-right", isMe ? "text-primary-foreground/70" : "text-muted-foreground")}>
                          {timeLabel(msg.created_at)}
                        </p>
                      </div>
                    </div>
                  );
                })
              )}
              <div ref={bottomRef} />
            </div>

            {/* Input */}
            <div className="px-4 py-3 border-t bg-background">
              <form
                onSubmit={(e) => { e.preventDefault(); sendMessage(); }}
                className="flex items-center gap-2"
              >
                <Input
                  value={draft}
                  onChange={(e) => setDraft(e.target.value)}
                  placeholder={`Message ${activeUser.first_name}…`}
                  className="flex-1"
                  autoFocus
                />
                <Button type="submit" size="icon" disabled={!draft.trim() || sending}>
                  <Send className="size-4" />
                </Button>
              </form>
            </div>
          </>
        ) : (
          <div className="flex-1 flex flex-col items-center justify-center text-center px-6">
            <MessageSquare className="size-12 text-muted-foreground mb-3" />
            <h3 className="text-base font-semibold mb-1">Staff Messaging</h3>
            <p className="text-sm text-muted-foreground max-w-xs">
              Select a conversation on the left or start a new one. Messages are private between staff members.
            </p>
          </div>
        )}
      </div>
    </div>
  );
}

"use client";

import { useEffect, useRef, useState } from "react";
import { therapistService } from "@/lib/api/therapist";
import { toast } from "@/components/ui/use-toast";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Separator } from "@/components/ui/separator";
import {
  ShieldCheck,
  ShieldAlert,
  Clock,
  Upload,
  FileText,
  Loader2,
  Star,
  Users,
  Calendar,
  AlertTriangle,
  RefreshCw,
} from "lucide-react";

interface Verification {
  status: "pending" | "approved" | "rejected" | null;
  is_verified: boolean;
  rejection_reason: string | null;
  rejected_at: string | null;
  verified_at: string | null;
  has_certificate: boolean;
}

interface Profile {
  id: number;
  full_name: string;
  email: string;
  phone: string | null;
  bio: string | null;
  specialization: string | null;
  qualification: string | null;
  years_of_experience: number | null;
  license_number: string | null;
  hourly_rate: number | null;
  currency: string;
  status: string | null;
  avatar_url: string | null;
  certificate_url: string | null;
  languages: string[];
  areas_of_focus: string[];
  verification: Verification | null;
  stats: {
    total_sessions: number;
    completed_sessions: number;
    average_rating: number;
    total_reviews: number;
  };
  created_at: string;
}

function VerificationStatusCard({ verification, onUpload, uploading }: {
  verification: Verification | null;
  onUpload: (file: File) => void;
  uploading: boolean;
}) {
  const fileRef = useRef<HTMLInputElement>(null);

  if (!verification || !verification.status) {
    return (
      <Card className="border-yellow-200 bg-yellow-50 dark:bg-yellow-950/20">
        <CardContent className="pt-6 flex flex-col gap-3">
          <div className="flex items-center gap-3">
            <AlertTriangle className="size-5 text-yellow-600 shrink-0" />
            <div>
              <p className="font-semibold text-yellow-900 dark:text-yellow-200">Profile Not Submitted</p>
              <p className="text-sm text-yellow-700 dark:text-yellow-300 mt-0.5">
                Your therapist profile has not been submitted for verification. Upload your certificate to begin.
              </p>
            </div>
          </div>
          <Button
            variant="outline"
            size="sm"
            className="w-fit border-yellow-400 text-yellow-800"
            disabled={uploading}
            onClick={() => fileRef.current?.click()}
          >
            {uploading ? <Loader2 className="size-4 mr-2 animate-spin" /> : <Upload className="size-4 mr-2" />}
            Upload Certificate
          </Button>
          <input ref={fileRef} type="file" accept=".pdf,.jpg,.jpeg,.png" className="hidden"
            onChange={(e) => { const f = e.target.files?.[0]; if (f) onUpload(f); }} />
        </CardContent>
      </Card>
    );
  }

  if (verification.status === "approved") {
    return (
      <Card className="border-green-200 bg-green-50 dark:bg-green-950/20">
        <CardContent className="pt-6 flex items-center gap-4">
          <div className="rounded-full bg-green-100 p-3">
            <ShieldCheck className="size-6 text-green-600" />
          </div>
          <div>
            <p className="font-semibold text-green-900 dark:text-green-200">Verified Therapist</p>
            <p className="text-sm text-green-700 dark:text-green-300 mt-0.5">
              Your profile and credentials have been verified by the Onwynd team.
              {verification.verified_at && (
                <> Approved on {new Date(verification.verified_at).toLocaleDateString("en-GB", { day: "2-digit", month: "short", year: "numeric" })}.</>
              )}
            </p>
          </div>
        </CardContent>
      </Card>
    );
  }

  if (verification.status === "rejected") {
    return (
      <Card className="border-red-200 bg-red-50 dark:bg-red-950/20">
        <CardContent className="pt-6 flex flex-col gap-4">
          <div className="flex items-start gap-4">
            <div className="rounded-full bg-red-100 p-3 shrink-0">
              <ShieldAlert className="size-6 text-red-600" />
            </div>
            <div>
              <p className="font-semibold text-red-900 dark:text-red-200">Documents Rejected</p>
              {verification.rejected_at && (
                <p className="text-xs text-red-500 mt-0.5">
                  Rejected on {new Date(verification.rejected_at).toLocaleDateString("en-GB", { day: "2-digit", month: "short", year: "numeric" })}
                </p>
              )}
              {verification.rejection_reason && (
                <div className="mt-2 rounded-md border border-red-200 bg-white/60 px-3 py-2 text-sm text-red-800 leading-relaxed">
                  <span className="font-medium">Reason: </span>{verification.rejection_reason}
                </div>
              )}
            </div>
          </div>
          <div className="flex flex-col gap-2">
            <p className="text-sm text-red-700">Please address the issue above and re-upload your certificate.</p>
            <Button
              variant="destructive"
              size="sm"
              className="w-fit"
              disabled={uploading}
              onClick={() => fileRef.current?.click()}
            >
              {uploading ? <Loader2 className="size-4 mr-2 animate-spin" /> : <RefreshCw className="size-4 mr-2" />}
              Re-upload Certificate
            </Button>
          </div>
          <input ref={fileRef} type="file" accept=".pdf,.jpg,.jpeg,.png" className="hidden"
            onChange={(e) => { const f = e.target.files?.[0]; if (f) onUpload(f); }} />
        </CardContent>
      </Card>
    );
  }

  // pending
  return (
    <Card className="border-yellow-200 bg-yellow-50 dark:bg-yellow-950/20">
      <CardContent className="pt-6 flex items-center gap-4">
        <div className="rounded-full bg-yellow-100 p-3 shrink-0">
          <Clock className="size-6 text-yellow-600 animate-pulse" />
        </div>
        <div>
          <p className="font-semibold text-yellow-900 dark:text-yellow-200">Verification Pending</p>
          <p className="text-sm text-yellow-700 dark:text-yellow-300 mt-0.5">
            Your documents have been submitted and are currently under review by the Onwynd team.
            This typically takes 1–3 business days.
          </p>
          {verification.has_certificate && (
            <p className="text-xs text-yellow-600 mt-1 flex items-center gap-1">
              <FileText className="size-3" /> Certificate uploaded ✓
            </p>
          )}
        </div>
      </CardContent>
    </Card>
  );
}

export default function TherapistProfilePage() {
  const [profile, setProfile] = useState<Profile | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [uploading, setUploading] = useState(false);

  const load = async () => {
    try {
      const data = await therapistService.getProfile();
      setProfile(data as Profile | null);
    } catch (error: any) {
      console.error("Profile load failed:", error);

      // More specific error messages based on error type
      if (error?.response?.status === 401) {
        toast({ title: "Authentication Error", description: "Please log in again", variant: "destructive" });
      } else if (error?.response?.status === 403) {
        toast({ title: "Permission Error", description: "You don't have permission to view this profile", variant: "destructive" });
      } else if (error?.response?.status === 404) {
        toast({ title: "Profile Not Found", description: "Profile could not be found", variant: "destructive" });
      } else if (error?.response?.status >= 500) {
        toast({ title: "Server Error", description: "Server error occurred. Please try again later", variant: "destructive" });
      } else if (error?.message?.includes("Network")) {
        toast({ title: "Network Error", description: "Network connection failed. Please check your internet", variant: "destructive" });
      } else {
        toast({ title: "Error", description: "Failed to load profile. Please try again", variant: "destructive" });
      }
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => { load(); }, []);

  const handleCertificateUpload = async (file: File) => {
    // File validation
    const maxSize = 10 * 1024 * 1024; // 10MB
    const allowedTypes = ["application/pdf", "image/jpeg", "image/jpg", "image/png"];

    if (!allowedTypes.includes(file.type)) {
      toast({ title: "Invalid File", description: "Only PDF, JPG, JPEG, and PNG files are allowed", variant: "destructive" });
      return;
    }

    if (file.size > maxSize) {
      toast({ title: "File Too Large", description: "File size must be less than 10MB", variant: "destructive" });
      return;
    }

    setUploading(true);
    try {
      await therapistService.uploadCertificate(file);
      toast({ title: "Certificate Uploaded", description: "Your certificate has been submitted for review." });
      load();
    } catch (error: any) {
      console.error("Certificate upload failed:", error);

      // More specific error messages based on error type
      if (error?.response?.status === 400) {
        const message = error?.response?.data?.message || "Invalid file format or size";
        toast({ title: "Upload Failed", description: message, variant: "destructive" });
      } else if (error?.response?.status === 413) {
        toast({ title: "File Too Large", description: "File size exceeds server limit", variant: "destructive" });
      } else if (error?.response?.status === 401) {
        toast({ title: "Authentication Error", description: "Please log in again", variant: "destructive" });
      } else if (error?.response?.status >= 500) {
        toast({ title: "Server Error", description: "Server error occurred. Please try again later", variant: "destructive" });
      } else if (error?.message?.includes("Network")) {
        toast({ title: "Network Error", description: "Network connection failed. Please check your internet", variant: "destructive" });
      } else {
        toast({ title: "Upload Failed", description: "Could not upload certificate. Please try again", variant: "destructive" });
      }
    } finally {
      setUploading(false);
    }
  };

  if (isLoading) {
    return (
      <div className="flex h-96 items-center justify-center">
        <Loader2 className="h-8 w-8 animate-spin text-primary" />
      </div>
    );
  }

  if (!profile) return null;

  const v = profile.verification;
  const verificationBadge = () => {
    if (!v || !v.status) return <Badge variant="outline" className="text-xs bg-zinc-100 text-zinc-500">Not Submitted</Badge>;
    if (v.status === "approved") return <Badge variant="outline" className="text-xs bg-green-50 text-green-700 border-green-200">Verified</Badge>;
    if (v.status === "rejected") return <Badge variant="outline" className="text-xs bg-red-50 text-red-700 border-red-200">Rejected</Badge>;
    return <Badge variant="outline" className="text-xs bg-yellow-50 text-yellow-700 border-yellow-200">Pending Review</Badge>;
  };

  return (
    <div className="flex-1 space-y-6 p-4 md:p-8 pt-6 max-w-4xl">
      <div className="flex items-center gap-3">
        <div>
          <h2 className="text-3xl font-bold tracking-tight">My Profile</h2>
          <p className="text-muted-foreground text-sm">View your professional profile and verification status.</p>
        </div>
      </div>

      {/* Verification Status — always at top */}
      <VerificationStatusCard
        verification={v}
        onUpload={handleCertificateUpload}
        uploading={uploading}
      />

      {/* Stats row */}
      <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
        {[
          { label: "Total Sessions",  value: profile.stats.total_sessions,    icon: Calendar },
          { label: "Completed",       value: profile.stats.completed_sessions, icon: Users    },
          { label: "Avg Rating",      value: profile.stats.average_rating.toFixed(1) + " ★", icon: Star },
          { label: "Reviews",         value: profile.stats.total_reviews,      icon: FileText },
        ].map(({ label, value, icon: Icon }) => (
          <Card key={label}>
            <CardContent className="pt-4 pb-4 flex flex-col gap-1">
              <div className="flex items-center gap-1.5 text-xs text-muted-foreground">
                <Icon className="size-3.5" />{label}
              </div>
              <p className="text-2xl font-semibold">{value}</p>
            </CardContent>
          </Card>
        ))}
      </div>

      {/* Profile details */}
      <Card>
        <CardHeader>
          <div className="flex items-center justify-between">
            <CardTitle>Professional Details</CardTitle>
            {verificationBadge()}
          </div>
          <CardDescription>Your information as visible to patients and the platform.</CardDescription>
        </CardHeader>
        <CardContent className="space-y-5">
          <div className="grid sm:grid-cols-2 gap-x-8 gap-y-4 text-sm">
            <InfoRow label="Full Name"   value={profile.full_name} />
            <InfoRow label="Email"       value={profile.email} />
            <InfoRow label="Phone"       value={profile.phone} />
            <InfoRow label="Specialization" value={profile.specialization} />
            <InfoRow label="Qualification"  value={profile.qualification} />
            <InfoRow label="Experience"  value={profile.years_of_experience ? `${profile.years_of_experience} years` : null} />
            <InfoRow label="License No." value={profile.license_number} />
            <InfoRow label="Hourly Rate" value={profile.hourly_rate ? `${profile.currency} ${Number(profile.hourly_rate).toLocaleString()}` : null} />
          </div>

          {profile.bio && (
            <>
              <Separator />
              <div className="space-y-1">
                <p className="text-xs font-medium text-muted-foreground uppercase tracking-wide">Bio</p>
                <p className="text-sm leading-relaxed">{profile.bio}</p>
              </div>
            </>
          )}

          {profile.languages?.length > 0 && (
            <>
              <Separator />
              <div className="space-y-2">
                <p className="text-xs font-medium text-muted-foreground uppercase tracking-wide">Languages</p>
                <div className="flex flex-wrap gap-1.5">
                  {profile.languages.map((l) => (
                    <Badge key={l} variant="secondary" className="text-xs">{l}</Badge>
                  ))}
                </div>
              </div>
            </>
          )}

          {profile.areas_of_focus?.length > 0 && (
            <>
              <Separator />
              <div className="space-y-2">
                <p className="text-xs font-medium text-muted-foreground uppercase tracking-wide">Areas of Focus</p>
                <div className="flex flex-wrap gap-1.5">
                  {profile.areas_of_focus.map((a) => (
                    <Badge key={a} variant="outline" className="text-xs">{a}</Badge>
                  ))}
                </div>
              </div>
            </>
          )}
        </CardContent>
      </Card>

      {/* Document section */}
      <Card>
        <CardHeader>
          <CardTitle>Documents</CardTitle>
          <CardDescription>Your uploaded professional documents and their verification status.</CardDescription>
        </CardHeader>
        <CardContent>
          <div className="flex items-center justify-between py-3 border rounded-lg px-4">
            <div className="flex items-center gap-3">
              <FileText className="size-5 text-muted-foreground" />
              <div>
                <p className="text-sm font-medium">Professional Certificate</p>
                <p className="text-xs text-muted-foreground">
                  {v?.has_certificate ? "Certificate on file" : "No certificate uploaded"}
                </p>
              </div>
            </div>
            {verificationBadge()}
          </div>
          <p className="text-xs text-muted-foreground mt-3">
            Accepted formats: PDF, JPG, PNG. To update your certificate, go to{" "}
            <a href="/therapist/settings" className="underline text-primary">Settings</a>.
          </p>
        </CardContent>
      </Card>
    </div>
  );
}

function InfoRow({ label, value }: { label: string; value: string | number | null | undefined }) {
  return (
    <div className="space-y-0.5">
      <p className="text-xs text-muted-foreground font-medium">{label}</p>
      <p className="font-medium">{value ?? <span className="text-muted-foreground font-normal">—</span>}</p>
    </div>
  );
}

"use client";

import Link from "next/link";

import { useEffect, useState } from "react";
import { therapistService } from "@/lib/api/therapist";
import { toast } from "@/components/ui/use-toast";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Loader2, Video, Search, ChevronLeft, ChevronRight } from "lucide-react";

interface Session {
  id: number;
  patient_name: string;
  patient_email: string;
  is_anonymous: boolean;
  anonymous_username?: string;
  date: string;
  time: string;
  duration: number;
  status: string;
  session_fee: number;
  formatted_fee: string;
  notes: string | null;
}

const STATUS_STYLES: Record<string, string> = {
  scheduled:  "bg-blue-50   text-blue-700   border-blue-200",
  completed:  "bg-green-50  text-green-700  border-green-200",
  cancelled:  "bg-red-50    text-red-700    border-red-200",
  in_progress:"bg-purple-50 text-purple-700 border-purple-200",
  no_show:    "bg-zinc-100  text-zinc-500   border-zinc-200",
};

const ITEMS_PER_PAGE = 15;

export default function SessionsPage() {
  const [sessions, setSessions] = useState<Session[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [search, setSearch] = useState("");
  const [searchInput, setSearchInput] = useState("");
  const [statusFilter, setStatusFilter] = useState("all");
  const [view, setView] = useState("week");
  const [page, setPage] = useState(1);
  const [total, setTotal] = useState(0);

  const load = async () => {
    setIsLoading(true);
    try {
      const params: Record<string, unknown> = { page, per_page: ITEMS_PER_PAGE };
      if (search) params.search = search;
      if (statusFilter !== "all") params.status = statusFilter;
      if (view === "week") params.type = "upcoming";
      const raw = await therapistService.getSessions(params) as any;
      // Backend returns a Laravel paginator object — unwrap
      const rows: any[] = Array.isArray(raw) ? raw : (raw?.data ?? []);
      const totalCount: number = raw?.total ?? rows.length;

      // Normalise backend fields → frontend Session interface
      const items: Session[] = rows.map((s) => {
        const scheduledAt = s.scheduled_at ? new Date(s.scheduled_at) : null;
        const patientUser = s.patient ?? {};
        const firstName = patientUser.first_name ?? "";
        const lastName  = patientUser.last_name  ?? "";
        const fullName  = [firstName, lastName].filter(Boolean).join(" ") || "Patient";
        return {
          id: s.id,
          patient_name:    s.patient_name    ?? fullName,
          patient_email:   s.patient_email   ?? (patientUser.email ?? ""),
          is_anonymous:    s.is_anonymous    ?? false,
          anonymous_username: s.anonymous_nickname ?? s.anonymous_username,
          date: s.date ?? (scheduledAt ? scheduledAt.toISOString().split("T")[0] : ""),
          time: s.time ?? (scheduledAt ? scheduledAt.toTimeString().substring(0, 5) : ""),
          duration:      s.duration      ?? s.duration_minutes ?? 60,
          status:        s.status,
          session_fee:   s.session_fee   ?? s.session_rate ?? 0,
          formatted_fee: s.formatted_fee ?? (s.session_rate ? `₦${Number(s.session_rate).toLocaleString()}` : "—"),
          notes:         s.notes         ?? s.booking_notes ?? null,
        };
      });

      setSessions(items);
      setTotal(totalCount);
    } catch {
      toast({ title: "Error", description: "Failed to load sessions", variant: "destructive" });
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => { load(); }, [view, page, statusFilter, search]);

  const lastPage = Math.max(1, Math.ceil(total / ITEMS_PER_PAGE));

  return (
    <div className="flex-1 space-y-6 p-4 md:p-8 pt-6">
      <div className="flex items-center gap-2">
        <Video className="h-6 w-6 text-primary" />
        <h2 className="text-3xl font-bold tracking-tight">Sessions</h2>
      </div>

      {/* Filters */}
      <div className="flex flex-wrap items-center gap-3">
        <div className="flex gap-2">
          <Input
            placeholder="Search patient…"
            value={searchInput}
            onChange={(e) => setSearchInput(e.target.value)}
            onKeyDown={(e) => { if (e.key === "Enter") { setSearch(searchInput); setPage(1); } }}
            className="h-9 w-56 text-sm"
          />
          <Button size="sm" variant="outline" className="h-9"
            onClick={() => { setSearch(searchInput); setPage(1); }}>
            <Search className="size-4" />
          </Button>
        </div>
        <Select value={statusFilter} onValueChange={(v: string | null) => { setStatusFilter(v || "all"); setPage(1); }}>
          <SelectTrigger className="h-9 w-40 text-sm">
            <SelectValue placeholder="Status" />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="all">All Statuses</SelectItem>
            <SelectItem value="scheduled">Scheduled</SelectItem>
            <SelectItem value="completed">Completed</SelectItem>
            <SelectItem value="cancelled">Cancelled</SelectItem>
            <SelectItem value="no_show">No Show</SelectItem>
          </SelectContent>
        </Select>
        <Select value={view} onValueChange={(v: string | null) => { if (v) { setView(v); setPage(1); } }}>
          <SelectTrigger className="h-9 w-36 text-sm">
            <SelectValue placeholder="View" />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="week">This Week</SelectItem>
            <SelectItem value="month">This Month</SelectItem>
          </SelectContent>
        </Select>
      </div>

      {isLoading ? (
        <div className="flex h-64 items-center justify-center">
          <Loader2 className="h-8 w-8 animate-spin text-primary" />
        </div>
      ) : (
        <div className="rounded-xl border bg-card overflow-hidden">
          <Table>
            <TableHeader>
              <TableRow className="bg-muted/40">
                <TableHead>Patient</TableHead>
                <TableHead>Date</TableHead>
                <TableHead>Time</TableHead>
                <TableHead>Duration</TableHead>
                <TableHead>Status</TableHead>
                <TableHead>Fee</TableHead>
                <TableHead>Notes</TableHead>
              <TableHead className="w-[110px]">Actions</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {sessions.length === 0 ? (
                <TableRow>
                  <TableCell colSpan={7} className="h-40 text-center text-muted-foreground">
                    No sessions found for this period.
                  </TableCell>
                </TableRow>
              ) : (
                sessions.map((s) => (
                  <TableRow key={s.id}>
                    <TableCell>
                      <div>
                        <p className="font-medium text-sm">
                          {s.is_anonymous ? (
                            <span className="flex items-center gap-1">
                              <span className="text-muted-foreground">🕵️</span>
                              {s.anonymous_username || "Anonymous User"}
                            </span>
                          ) : (
                            s.patient_name
                          )}
                        </p>
                        <p className="text-xs text-muted-foreground">
                          {s.is_anonymous ? "Anonymous Email" : s.patient_email}
                        </p>
                        {s.is_anonymous && (
                          <p className="text-xs text-orange-600 dark:text-orange-400 font-medium">
                            🔒 Patient has chosen to remain anonymous
                          </p>
                        )}
                      </div>
                    </TableCell>
                    <TableCell className="text-sm">
                      {new Date(s.date).toLocaleDateString("en-GB", { day: "2-digit", month: "short", year: "numeric" })}
                    </TableCell>
                    <TableCell className="text-sm">{s.time}</TableCell>
                    <TableCell className="text-sm">{s.duration} min</TableCell>
                    <TableCell>
                      <Badge variant="outline" className={`text-xs capitalize ${STATUS_STYLES[s.status] ?? ""}`}>
                        {s.status.replace("_", " ")}
                      </Badge>
                    </TableCell>
                    <TableCell className="text-sm font-medium">{s.formatted_fee}</TableCell>
                    <TableCell className="text-sm text-muted-foreground max-w-[200px] truncate">
                      {s.notes ?? "—"}
                    </TableCell>
                    <TableCell>
                      {(s.status === "scheduled" || s.status === "in_progress") && (
                        <Button asChild size="sm" className="h-7 gap-1.5 text-xs">
                          <Link href={`/therapist/sessions/${s.id}/room`}>
                            <Video className="size-3" />
                            Join
                          </Link>
                        </Button>
                      )}
                    </TableCell>
                  </TableRow>
                ))
              )}
            </TableBody>
          </Table>

          {lastPage > 1 && (
            <div className="flex items-center justify-between px-4 py-3 border-t">
              <span className="text-sm text-muted-foreground">
                Page {page} of {lastPage} · {total} sessions
              </span>
              <div className="flex gap-2">
                <Button variant="outline" size="icon" className="h-8 w-8" disabled={page <= 1} onClick={() => setPage(p => p - 1)}>
                  <ChevronLeft className="size-4" />
                </Button>
                <Button variant="outline" size="icon" className="h-8 w-8" disabled={page >= lastPage} onClick={() => setPage(p => p + 1)}>
                  <ChevronRight className="size-4" />
                </Button>
              </div>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

"use client";

import { useEffect, useRef, useState } from "react";
import { therapistService } from "@/lib/api/therapist";
import { toast } from "@/components/ui/use-toast";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Label } from "@/components/ui/label";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Button } from "@/components/ui/button";
import { Switch } from "@/components/ui/switch";
import { Separator } from "@/components/ui/separator";
import { Badge } from "@/components/ui/badge";
import { Save, Loader2, Upload, FileText, Bell, ChevronRight } from "lucide-react";
import Link from "next/link";

interface ProfileForm {
  full_name: string;
  phone: string;
  bio: string;
  specialization: string;
  qualification: string;
  years_of_experience: string;
  hourly_rate: string;
  is_accepting_clients: boolean;
  has_35min_slot: boolean;
  rate_35min: string;
}

export default function TherapistSettingsPage() {
  const [form, setForm] = useState<ProfileForm>({
    full_name: "",
    phone: "",
    bio: "",
    specialization: "",
    qualification: "",
    years_of_experience: "",
    hourly_rate: "",
    is_accepting_clients: true,
    has_35min_slot: false,
    rate_35min: "",
  });
  const [email, setEmail] = useState("");
  const [isLoading, setIsLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);
  const [isUploading, setIsUploading] = useState(false);
  const [hasCertificate, setHasCertificate] = useState(false);
  const [verificationStatus, setVerificationStatus] = useState<string | null>(null);
  const certRef = useRef<HTMLInputElement>(null);

  const load = async () => {
    try {
      const data = await therapistService.getProfile();
      const profile = data as any;
      setEmail(profile?.email ?? "");
      setHasCertificate(profile?.verification?.has_certificate ?? false);
      setVerificationStatus(profile?.verification?.status ?? null);
      setForm({
        full_name: profile?.full_name ?? "",
        phone: profile?.phone ?? "",
        bio: profile?.bio ?? "",
        specialization: profile?.specialization ?? "",
        qualification: profile?.qualification ?? "",
        years_of_experience: String(profile?.years_of_experience ?? ""),
        hourly_rate: String(profile?.hourly_rate ?? ""),
        is_accepting_clients: profile?.is_accepting_clients ?? true,
        has_35min_slot: profile?.has_35min_slot ?? false,
        rate_35min: profile?.rate_35min ? String(profile.rate_35min) : "",
      });
    } catch (error: any) {
      console.error("Profile load failed:", error);

      // More specific error messages based on error type
      if (error?.response?.status === 401) {
        toast({ title: "Authentication Error", description: "Please log in again", variant: "destructive" });
      } else if (error?.response?.status === 403) {
        toast({ title: "Permission Error", description: "You don't have permission to view this profile", variant: "destructive" });
      } else if (error?.response?.status === 404) {
        toast({ title: "Profile Not Found", description: "Profile could not be found", variant: "destructive" });
      } else if (error?.response?.status >= 500) {
        toast({ title: "Server Error", description: "Server error occurred. Please try again later", variant: "destructive" });
      } else if (error?.message?.includes("Network")) {
        toast({ title: "Network Error", description: "Network connection failed. Please check your internet", variant: "destructive" });
      } else {
        toast({ title: "Error", description: "Failed to load profile. Please try again", variant: "destructive" });
      }
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => { load(); }, []);

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();

    // Client-side validation
    if (!form.full_name.trim()) {
      toast({ title: "Validation Error", description: "Full name is required", variant: "destructive" });
      return;
    }

    if (form.phone && !/^\+?[\d\s\-\(\)]{10,}$/.test(form.phone)) {
      toast({ title: "Validation Error", description: "Please enter a valid phone number", variant: "destructive" });
      return;
    }

    if (form.years_of_experience && (isNaN(Number(form.years_of_experience)) || Number(form.years_of_experience) < 0)) {
      toast({ title: "Validation Error", description: "Years of experience must be a positive number", variant: "destructive" });
      return;
    }

    if (form.hourly_rate && (isNaN(Number(form.hourly_rate)) || Number(form.hourly_rate) <= 0)) {
      toast({ title: "Validation Error", description: "Hourly rate must be a positive number", variant: "destructive" });
      return;
    }

    setIsSaving(true);
    try {
      await therapistService.updateProfile({
        full_name: form.full_name.trim(),
        phone: form.phone.trim(),
        bio: form.bio.trim(),
        specialization: form.specialization.trim(),
        qualification: form.qualification.trim(),
        years_of_experience: form.years_of_experience,
        hourly_rate: form.hourly_rate,
        has_35min_slot: form.has_35min_slot,
        rate_35min: form.has_35min_slot && form.rate_35min ? Number(form.rate_35min) : null,
      });
      toast({ title: "Saved", description: "Your profile has been updated." });
    } catch (error: any) {
      console.error("Profile update failed:", error);

      // More specific error messages based on error type
      if (error?.response?.status === 400) {
        const message = error?.response?.data?.message || "Invalid data provided";
        toast({ title: "Validation Error", description: message, variant: "destructive" });
      } else if (error?.response?.status === 401) {
        toast({ title: "Authentication Error", description: "Please log in again", variant: "destructive" });
      } else if (error?.response?.status === 403) {
        toast({ title: "Permission Error", description: "You don't have permission to update this profile", variant: "destructive" });
      } else if (error?.response?.status >= 500) {
        toast({ title: "Server Error", description: "Server error occurred. Please try again later", variant: "destructive" });
      } else if (error?.message?.includes("Network")) {
        toast({ title: "Network Error", description: "Network connection failed. Please check your internet", variant: "destructive" });
      } else {
        toast({ title: "Error", description: "Failed to save profile. Please try again", variant: "destructive" });
      }
    } finally {
      setIsSaving(false);
    }
  };

  const handleCertificateUpload = async (file: File) => {
    // File validation
    const maxSize = 10 * 1024 * 1024; // 10MB
    const allowedTypes = ["application/pdf", "image/jpeg", "image/jpg", "image/png"];

    if (!allowedTypes.includes(file.type)) {
      toast({ title: "Invalid File", description: "Only PDF, JPG, JPEG, and PNG files are allowed", variant: "destructive" });
      return;
    }

    if (file.size > maxSize) {
      toast({ title: "File Too Large", description: "File size must be less than 10MB", variant: "destructive" });
      return;
    }

    setIsUploading(true);
    try {
      await therapistService.uploadCertificate(file);
      toast({ title: "Certificate Uploaded", description: "Your certificate has been submitted for re-review." });
      setHasCertificate(true);
      setVerificationStatus("pending");
    } catch (error: any) {
      console.error("Certificate upload failed:", error);

      // More specific error messages based on error type
      if (error?.response?.status === 400) {
        const message = error?.response?.data?.message || "Invalid file format or size";
        toast({ title: "Upload Failed", description: message, variant: "destructive" });
      } else if (error?.response?.status === 413) {
        toast({ title: "File Too Large", description: "File size exceeds server limit", variant: "destructive" });
      } else if (error?.response?.status === 401) {
        toast({ title: "Authentication Error", description: "Please log in again", variant: "destructive" });
      } else if (error?.response?.status >= 500) {
        toast({ title: "Server Error", description: "Server error occurred. Please try again later", variant: "destructive" });
      } else if (error?.message?.includes("Network")) {
        toast({ title: "Network Error", description: "Network connection failed. Please check your internet", variant: "destructive" });
      } else {
        toast({ title: "Upload Failed", description: "Could not upload certificate. Please try again", variant: "destructive" });
      }
    } finally {
      setIsUploading(false);
    }
  };

  const setField = (field: keyof ProfileForm, value: string | boolean) =>
    setForm((prev) => ({ ...prev, [field]: value }));

  if (isLoading) {
    return (
      <div className="flex h-96 items-center justify-center">
        <Loader2 className="h-8 w-8 animate-spin text-primary" />
      </div>
    );
  }

  const verificationBadge = () => {
    if (!verificationStatus) return null;
    const styles: Record<string, string> = {
      approved: "bg-green-50 text-green-700 border-green-200",
      pending:  "bg-yellow-50 text-yellow-700 border-yellow-200",
      rejected: "bg-red-50 text-red-700 border-red-200",
    };
    const labels: Record<string, string> = { approved: "Verified", pending: "Pending Review", rejected: "Rejected" };
    return (
      <Badge variant="outline" className={`text-xs ${styles[verificationStatus] ?? ""}`}>
        {labels[verificationStatus] ?? verificationStatus}
      </Badge>
    );
  };

  return (
    <div className="flex-1 space-y-6 p-4 md:p-8 pt-6 max-w-4xl">
      <div>
        <h2 className="text-3xl font-bold tracking-tight">Settings</h2>
        <p className="text-muted-foreground text-sm">Manage your profile, documents and availability preferences.</p>
      </div>

      <form onSubmit={handleSave} className="space-y-6">
        {/* Profile Info */}
        <Card>
          <CardHeader>
            <CardTitle>Profile Information</CardTitle>
            <CardDescription>Update your professional details visible to patients.</CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="grid sm:grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label htmlFor="full_name">Full Name</Label>
                <Input id="full_name" value={form.full_name} onChange={(e) => setField("full_name", e.target.value)} placeholder="Dr. Jane Doe" />
              </div>
              <div className="space-y-2">
                <Label htmlFor="email">Email</Label>
                <Input id="email" type="email" disabled value={email} className="opacity-60" />
              </div>
              <div className="space-y-2">
                <Label htmlFor="phone">Phone</Label>
                <Input id="phone" value={form.phone} onChange={(e) => setField("phone", e.target.value)} placeholder="+234 800 000 0000" />
              </div>
              <div className="space-y-2">
