"use client";

import { useEffect, useState } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Badge } from "@/components/ui/badge";
import { Skeleton } from "@/components/ui/skeleton";
import { Button } from "@/components/ui/button";
import { institutionalService } from "@/lib/api/institutional";

type CrisisEvent = {
  id: number;
  uuid: string;
  risk_level: "low" | "medium" | "high" | "severe";
  flagged_at: string;
  member_identifier: string;
  status: "pending" | "reviewed" | "resolved";
  reason: string;
  resources_shown: boolean;
};

export default function CrisisAlertsPage() {
  const [isLoading, setIsLoading] = useState(true);
  const [events, setEvents] = useState<CrisisEvent[]>([]);

  useEffect(() => {
    async function load() {
      setIsLoading(true);
      try {
        const data = await institutionalService.getAtRisk() as { events?: CrisisEvent[] } | null;
        if (data?.events) {
          // Show only high/severe for crisis alerts view
          setEvents(data.events.filter((e) => ["high", "severe"].includes(e.risk_level)));
        }
      } finally {
        setIsLoading(false);
      }
    }
    load();
  }, []);

  function getRiskBadgeColor(level: string) {
    return level === "severe" ? "bg-red-600 hover:bg-red-700" : "bg-red-500 hover:bg-red-600";
  }

  return (
    <div className="p-6 space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-bold tracking-tight">Crisis Alerts</h1>
          <p className="text-muted-foreground text-sm mt-1">
            High and severe risk flags requiring immediate attention from student affairs or counselling.
          </p>
        </div>
        <Badge variant="destructive" className="text-sm px-3 py-1">
          {isLoading ? "..." : `${events.filter((e) => e.status === "pending").length} pending`}
        </Badge>
      </div>

      <div className="rounded-xl border bg-red-50 border-red-200 px-4 py-3 flex items-start gap-3">
        <span className="text-red-600 text-lg flex-shrink-0 mt-0.5">⚠️</span>
        <p className="text-sm text-red-800">
          <strong>Immediate action may be required.</strong> These are anonymised high/severe flags.
          Contact your campus counselling centre or safeguarding team for follow-up protocols.
        </p>
      </div>

      <Card>
        <CardHeader>
          <CardTitle>Active Crisis Flags</CardTitle>
        </CardHeader>
        <CardContent>
          {isLoading ? (
            <Skeleton className="h-64 w-full" />
          ) : events.length === 0 ? (
            <p className="text-sm text-muted-foreground py-10 text-center">
              No active crisis alerts. All clear.
            </p>
          ) : (
            <div className="rounded-md border">
              <Table>
                <TableHeader>
                  <TableRow>
                    <TableHead>Severity</TableHead>
                    <TableHead>Flagged At</TableHead>
                    <TableHead>Student ID</TableHead>
                    <TableHead>Reason</TableHead>
                    <TableHead>Status</TableHead>
                    <TableHead>Resources Shown</TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {events.map((e) => (
                    <TableRow key={e.id}>
                      <TableCell>
                        <Badge className={getRiskBadgeColor(e.risk_level)}>
                          {e.risk_level.toUpperCase()}
                        </Badge>
                      </TableCell>
                      <TableCell className="text-sm">
                        {new Date(e.flagged_at).toLocaleString()}
                      </TableCell>
                      <TableCell className="font-mono text-sm">{e.member_identifier}</TableCell>
                      <TableCell className="text-muted-foreground text-sm">{e.reason}</TableCell>
                      <TableCell>
                        <Badge variant={e.status === "pending" ? "outline" : "secondary"}>
                          {e.status}
                        </Badge>
                      </TableCell>
                      <TableCell>
                        <Badge variant={e.resources_shown ? "default" : "outline"}>
                          {e.resources_shown ? "Yes" : "No"}
                        </Badge>
                      </TableCell>
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Skeleton } from "@/components/ui/skeleton";
import { Input } from "@/components/ui/input";
import { institutionalService } from "@/lib/api/institutional";
import { CheckCircle, XCircle, Clock } from "lucide-react";

type Verification = {
  id: number;
  student_email: string;
  student_id?: string;
  faculty?: string;
  year_of_study?: number;
  status: "pending" | "approved" | "rejected";
  submitted_at: string;
  reviewed_at?: string;
};

export default function StudentVerificationsPage() {
  const [isLoading, setIsLoading] = useState(true);
  const [verifications, setVerifications] = useState<Verification[]>([]);
  const [search, setSearch] = useState("");

  useEffect(() => {
    async function load() {
      setIsLoading(true);
      try {
        const data = await institutionalService.getStudentVerifications() as { data?: Verification[] } | null;
        if (data?.data) setVerifications(data.data);
      } finally {
        setIsLoading(false);
      }
    }
    load();
  }, []);

  const filtered = verifications.filter((v) =>
    v.student_email.toLowerCase().includes(search.toLowerCase()) ||
    (v.faculty ?? "").toLowerCase().includes(search.toLowerCase()) ||
    (v.student_id ?? "").toLowerCase().includes(search.toLowerCase()),
  );

  const pending = verifications.filter((v) => v.status === "pending").length;
  const approved = verifications.filter((v) => v.status === "approved").length;
  const rejected = verifications.filter((v) => v.status === "rejected").length;

  function statusIcon(status: string) {
    if (status === "approved") return <CheckCircle className="h-4 w-4 text-green-600" />;
    if (status === "rejected") return <XCircle className="h-4 w-4 text-red-500" />;
    return <Clock className="h-4 w-4 text-orange-500" />;
  }

  function statusVariant(status: string): "default" | "secondary" | "destructive" | "outline" {
    if (status === "approved") return "default";
    if (status === "rejected") return "destructive";
    return "outline";
  }

  return (
    <div className="p-6 space-y-6">
      <div>
        <h1 className="text-3xl font-bold tracking-tight">Student Verifications</h1>
        <p className="text-muted-foreground text-sm mt-1">
          Review and approve student enrolment verification requests for subsidised access.
        </p>
      </div>

      {/* Summary cards */}
      <div className="grid grid-cols-3 gap-4">
        <Card>
          <CardContent className="p-5 flex items-center gap-3">
            <Clock className="h-8 w-8 text-orange-500" />
            <div>
              <p className="text-xs text-muted-foreground">Pending</p>
              <p className="text-2xl font-bold">{isLoading ? "—" : pending}</p>
            </div>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-5 flex items-center gap-3">
            <CheckCircle className="h-8 w-8 text-green-600" />
            <div>
              <p className="text-xs text-muted-foreground">Approved</p>
              <p className="text-2xl font-bold">{isLoading ? "—" : approved}</p>
            </div>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-5 flex items-center gap-3">
            <XCircle className="h-8 w-8 text-red-500" />
            <div>
              <p className="text-xs text-muted-foreground">Rejected</p>
              <p className="text-2xl font-bold">{isLoading ? "—" : rejected}</p>
            </div>
          </CardContent>
        </Card>
      </div>

      <Card>
        <CardHeader>
          <div className="flex items-center justify-between">
            <CardTitle>Verification Requests</CardTitle>
            <Input
              placeholder="Search by email, faculty, ID..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="w-64"
            />
          </div>
        </CardHeader>
        <CardContent>
          {isLoading ? (
            <Skeleton className="h-64 w-full" />
          ) : filtered.length === 0 ? (
            <p className="text-sm text-muted-foreground py-10 text-center">
              No verification requests found.
            </p>
          ) : (
            <div className="rounded-md border">
              <Table>
                <TableHeader>
                  <TableRow>
                    <TableHead>Student Email</TableHead>
                    <TableHead>Student ID</TableHead>
                    <TableHead>Faculty</TableHead>
                    <TableHead>Year</TableHead>
                    <TableHead>Submitted</TableHead>
                    <TableHead>Status</TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {filtered.map((v) => (
                    <TableRow key={v.id}>
                      <TableCell className="text-sm">{v.student_email}</TableCell>
                      <TableCell className="font-mono text-sm">{v.student_id ?? "—"}</TableCell>
                      <TableCell className="text-sm">{v.faculty ?? "—"}</TableCell>
                      <TableCell className="text-sm">{v.year_of_study ? `Year ${v.year_of_study}` : "—"}</TableCell>
                      <TableCell className="text-sm">
                        {new Date(v.submitted_at).toLocaleDateString()}
                      </TableCell>
                      <TableCell>
                        <div className="flex items-center gap-1.5">
                          {statusIcon(v.status)}
                          <Badge variant={statusVariant(v.status)}>
                            {v.status}
                          </Badge>
                        </div>
                      </TableCell>
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Alert, AlertDescription } from "@/components/ui/alert";
import { Skeleton } from "@/components/ui/skeleton";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { StatCard } from "@/components/shared/stat-card";
import { StatCardsShimmer } from "@/components/shared/shimmer-skeleton";
import client from "@/lib/api/client";
import {
  BarChart, Bar, ResponsiveContainer, XAxis, YAxis, Tooltip, CartesianGrid, Legend,
  FunnelChart, Funnel, LabelList,
} from "recharts";
import { RefreshCw, Radio, Users, TrendingUp, Mail, FileImage, DollarSign, AlertTriangle } from "lucide-react";

interface MarketingDashboard {
  active_campaigns?: number;
  new_leads_mtd?: number;
  email_open_rate?: number;
  subscriber_growth?: number;
  cac?: number;
  content_published?: number;
  campaign_performance?: { name: string; sent: number; opened: number; clicked: number }[];
  email_funnel?: { name: string; value: number; fill: string }[];
  top_channels?: { channel: string; leads: number; conversion_rate: number }[];
}

export default function VpMarketingDashboardPage() {
  const [data, setData] = useState<MarketingDashboard | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const fetchData = async () => {
    setLoading(true);
    setError(null);
    try {
      const res = await client.get("/api/v1/marketing/dashboard");
      setData(res.data?.data ?? res.data ?? {});
    } catch {
      setError("Unable to load marketing data. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchData(); }, []); // eslint-disable-line react-hooks/exhaustive-deps

  const campaigns = data?.campaign_performance ?? [];
  const channels = data?.top_channels ?? [];
  const funnel = data?.email_funnel ?? [
    { name: "Sent", value: 100, fill: "#3b82f6" },
    { name: "Opened", value: data?.email_open_rate ?? 0, fill: "#10b981" },
    { name: "Clicked", value: 0, fill: "#f59e0b" },
    { name: "Converted", value: 0, fill: "#8b5cf6" },
  ];

  return (
    <div className="p-6 space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-bold tracking-tight">Marketing Leadership Dashboard</h1>
          <p className="text-muted-foreground text-sm mt-1">Growth, acquisition &amp; brand performance</p>
        </div>
        <Button onClick={fetchData} variant="outline" size="sm" className="gap-2">
          <RefreshCw className={`w-4 h-4 ${loading ? "animate-spin" : ""}`} />
          Refresh
        </Button>
      </div>

      {error && (
        <Alert variant="destructive">
          <AlertTriangle className="h-4 w-4" />
          <AlertDescription>{error}</AlertDescription>
        </Alert>
      )}

      {loading && !data ? (
        <StatCardsShimmer count={6} />
      ) : (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-6 gap-4">
          <StatCard label="Active Campaigns"    value={data?.active_campaigns}    icon={Radio}      colour="blue"   isLoading={loading} />
          <StatCard label="New Leads (MTD)"     value={data?.new_leads_mtd}       icon={TrendingUp} colour="emerald" isLoading={loading} />
          <StatCard label="Email Open Rate"     value={data?.email_open_rate !== undefined ? `${data.email_open_rate}%` : "—"} icon={Mail} colour="blue" isLoading={loading} />
          <StatCard label="Subscriber Growth"   value={data?.subscriber_growth !== undefined ? `+${data.subscriber_growth}` : "—"} icon={Users} colour="emerald" isLoading={loading} />
          <StatCard label="CAC"                 value={data?.cac !== undefined ? `₦${data.cac}` : "—"} icon={DollarSign} colour="amber" isLoading={loading} />
          <StatCard label="Content Published"   value={data?.content_published}   icon={FileImage}  colour="blue"   isLoading={loading} />
        </div>
      )}

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <Card>
          <CardHeader>
            <CardTitle>Campaign Performance</CardTitle>
          </CardHeader>
          <CardContent className="h-64">
            {loading ? (
              <Skeleton className="h-full w-full" />
            ) : campaigns.length === 0 ? (
              <p className="text-sm text-muted-foreground">No campaign data.</p>
            ) : (
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={campaigns}>
                  <CartesianGrid strokeDasharray="3 3" />
                  <XAxis dataKey="name" className="text-xs" />
                  <YAxis />
                  <Tooltip />
                  <Legend />
                  <Bar dataKey="sent" name="Sent" fill="#3b82f6" />
                  <Bar dataKey="opened" name="Opened" fill="#10b981" />
                  <Bar dataKey="clicked" name="Clicked" fill="#f59e0b" />
                </BarChart>
              </ResponsiveContainer>
            )}
          </CardContent>
        </Card>

        <Card>
          <CardHeader>
            <CardTitle>Email Conversion Funnel</CardTitle>
          </CardHeader>
          <CardContent className="h-64">
            {loading ? (
              <Skeleton className="h-full w-full" />
            ) : (
              <ResponsiveContainer width="100%" height="100%">
                <FunnelChart>
                  <Tooltip />
                  <Funnel dataKey="value" data={funnel} isAnimationActive>
                    <LabelList position="right" fill="#374151" stroke="none" dataKey="name" />
                  </Funnel>
                </FunnelChart>
              </ResponsiveContainer>
            )}
          </CardContent>
        </Card>
      </div>

      <Card>
        <CardHeader>
          <CardTitle>Top Performing Channels</CardTitle>
        </CardHeader>
        <CardContent>
          {loading ? (
            <Skeleton className="h-40 w-full" />
          ) : channels.length === 0 ? (
            <p className="text-sm text-muted-foreground">No channel data available.</p>
          ) : (
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>Channel</TableHead>
                  <TableHead>Leads Generated</TableHead>
                  <TableHead>Conversion Rate</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {channels.map((ch) => (
                  <TableRow key={ch.channel}>
                    <TableCell className="text-sm font-medium capitalize">{ch.channel}</TableCell>
                    <TableCell className="text-sm font-semibold">{ch.leads}</TableCell>
                    <TableCell>
                      <Badge className={ch.conversion_rate >= 5 ? "bg-emerald-50 text-emerald-700 hover:bg-emerald-50" : ch.conversion_rate >= 2 ? "bg-yellow-50 text-yellow-700 hover:bg-yellow-50" : "bg-red-50 text-red-700 hover:bg-red-50"}>
                        {ch.conversion_rate}%
                      </Badge>
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
