const getStatus = (employee: Employee): "Active" | "Inactive" => {
  return employee.is_active ? "Active" : "Inactive";
};

const statusColors: Record<
  "Active" | "Inactive",
  { bg: string; text: string; border: string }
> = {
  Active: {
    bg: "bg-emerald-50 dark:bg-emerald-950/30",
