              <DropdownMenuLabel className="text-muted-foreground text-xs font-medium">
                Status
              </DropdownMenuLabel>
              {["all", "Active", "Inactive"].map(
                (status) => (
                  <DropdownMenuCheckboxItem
                    key={status}
                    checked={statusFilter === status}
                    onCheckedChange={() => setStatusFilter(status)}
                  >
