const BASE_MENU = [
  { title: "Dashboard", href: "/manager/dashboard",       icon: LayoutDashboard },
  { title: "Team",      href: "/manager/team",            icon: Users           },
  { title: "Approvals", href: "/manager/approvals",       icon: CheckSquare     },
