  "3months": "Last 3 Months",
  "6months": "Last 6 Months",
  year: "Full Year",
  q1: "Q1 (Jan-Mar)",
  q2: "Q2 (Apr-Jun)",
  q3: "Q3 (Jul-Sep)",
  q4: "Q4 (Oct-Dec)",
};

type CustomTooltipProps = {
  active?: boolean;
  payload?: Array<{
    value?: number;
    dataKey?: string;
    payload?: unknown;
  }>;
  label?: string;
};

function CustomTooltip({ active, payload, label }: CustomTooltipProps) {
  if (!active || !payload?.length) return null;

  const moneyInData = payload.find((p) => p.dataKey === "moneyIn");
  const moneyOutData = payload.find((p) => p.dataKey === "moneyOut");
  const moneyIn = moneyInData?.value || 0;
  const moneyOut = moneyOutData?.value || 0;

  return (
    <div className="rounded-lg border bg-background p-3 shadow-lg ring-1 ring-black/5">
      <div className="mb-2 border-b pb-2">
        <p className="font-medium">{label}</p>
      </div>
      <div className="grid gap-2">
        <div className="flex items-center gap-2">
          <div className="h-2 w-2 rounded-full bg-emerald-500" />
          <span className="text-sm text-muted-foreground">Money In:</span>
          <span className="ml-auto font-medium tabular-nums">
            ${moneyIn.toLocaleString()}
          </span>
        </div>
        <div className="flex items-center gap-2">
          <div className="h-2 w-2 rounded-full bg-blue-500" />
          <span className="text-sm text-muted-foreground">Money Out:</span>
          <span className="ml-auto font-medium tabular-nums">
            ${moneyOut.toLocaleString()}
          </span>
        </div>
      </div>
    </div>
  );
}

export function FinancialFlowChart() {
  const { theme } = useTheme();
  const [chartType, setChartType] = useState<ChartType>("bar");
  const [selectedPeriod, setSelectedPeriod] = useState<TimePeriod>("year");

  const financialFlow = usePartnerStore((state) => state.financialFlow);
  const fetchFinancialFlow = usePartnerStore((state) => state.fetchFinancialFlow);

  useEffect(() => {
    fetchFinancialFlow(selectedPeriod);
  }, [selectedPeriod]); // fetchFinancialFlow is a stable Zustand action, no need to include it

  // Use financialFlow from store
  const data = financialFlow;

  if (!data || data.length === 0) {
    return (
      <div className="rounded-xl border bg-card text-card-foreground shadow-xs">
        <div className="p-6 flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4 border-b">
          <div>
            <h3 className="font-semibold leading-none tracking-tight">
              Financial Flow
            </h3>
            <p className="text-sm text-muted-foreground mt-1">
              Overview of incoming and outgoing funds
            </p>
          </div>
          <Button variant="outline" size="sm" onClick={() => fetchFinancialFlow(selectedPeriod)}>
            <RefreshCw className="size-4 mr-2" />
            Retry
          </Button>
        </div>
        <div className="h-[300px] flex items-center justify-center">
          <div className="text-center space-y-2">
            <AlertTriangle className="size-8 text-muted-foreground mx-auto" />
            <div className="text-sm text-muted-foreground">No financial data available</div>
            <div className="text-xs text-muted-foreground">Try refreshing or select a different time period</div>
          </div>
        </div>
      </div>
    );
  }

  const renderChart = () => {
    const commonProps = {
      data: data,
      margin: { top: 10, right: 10, left: 0, bottom: 0 },
    };

    const commonAxisProps = {
      fontSize: 12,
      tickLine: false,
      axisLine: false,
      stroke: theme === "dark" ? "#525252" : "#a3a3a3",
    };

    switch (chartType) {
      case "line":
        return (
          <LineChart {...commonProps}>
            <CartesianGrid
              strokeDasharray="3 3"
              vertical={false}
              stroke={theme === "dark" ? "#262626" : "#e5e5e5"}
            />
            <XAxis {...commonAxisProps} dataKey="month" dy={10} />
            <YAxis
              {...commonAxisProps}
              tickFormatter={(value) => `$${value / 1000}k`}
              dx={-10}
            />
            <Tooltip content={<CustomTooltip />} cursor={false} />
            <Line
              type="monotone"
              dataKey="moneyIn"
              stroke="#10b981"
              strokeWidth={2}
              dot={false}
              activeDot={{ r: 4, strokeWidth: 0 }}
            />
            <Line
              type="monotone"
              dataKey="moneyOut"
              stroke="#3b82f6"
              strokeWidth={2}
              dot={false}
              activeDot={{ r: 4, strokeWidth: 0 }}
            />
          </LineChart>
        );
      case "area":
        return (
          <AreaChart {...commonProps}>
            <defs>
              <linearGradient id="colorMoneyIn" x1="0" y1="0" x2="0" y2="1">
                <stop offset="5%" stopColor="#10b981" stopOpacity={0.3} />
                <stop offset="95%" stopColor="#10b981" stopOpacity={0} />
              </linearGradient>
              <linearGradient id="colorMoneyOut" x1="0" y1="0" x2="0" y2="1">
                <stop offset="5%" stopColor="#3b82f6" stopOpacity={0.3} />
                <stop offset="95%" stopColor="#3b82f6" stopOpacity={0} />
              </linearGradient>
            </defs>
            <CartesianGrid
              strokeDasharray="3 3"
              vertical={false}
              stroke={theme === "dark" ? "#262626" : "#e5e5e5"}
            />
            <XAxis {...commonAxisProps} dataKey="month" dy={10} />
            <YAxis
              {...commonAxisProps}
              tickFormatter={(value) => `$${value / 1000}k`}
              dx={-10}
            />
            <Tooltip content={<CustomTooltip />} cursor={false} />
            <Area
              type="monotone"
              dataKey="moneyIn"
              stroke="#10b981"
              fillOpacity={1}
              fill="url(#colorMoneyIn)"
            />
            <Area
              type="monotone"
              dataKey="moneyOut"
              stroke="#3b82f6"
              fillOpacity={1}
              fill="url(#colorMoneyOut)"
            />
          </AreaChart>
        );
      default:
        return (
          <BarChart {...commonProps} barGap={4}>
            <CartesianGrid
              strokeDasharray="3 3"
              vertical={false}
              stroke={theme === "dark" ? "#262626" : "#e5e5e5"}
            />
            <XAxis {...commonAxisProps} dataKey="month" dy={10} />
            <YAxis
              {...commonAxisProps}
              tickFormatter={(value) => `$${value / 1000}k`}
              dx={-10}
            />
            <Tooltip
              content={<CustomTooltip />}
              cursor={{ fill: theme === "dark" ? "#262626" : "#f5f5f5" }}
            />
            <Bar
              dataKey="moneyIn"
              fill="#10b981"
              radius={[4, 4, 0, 0]}
              maxBarSize={40}
            />
            <Bar
              dataKey="moneyOut"
              fill="#3b82f6"
              radius={[4, 4, 0, 0]}
              maxBarSize={40}
            />
          </BarChart>
        );
    }
  };

  return (
    <div className="rounded-xl border bg-card text-card-foreground shadow-xs">
      <div className="p-6 flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4 border-b">
        <div>
          <h3 className="font-semibold leading-none tracking-tight">
            Financial Flow
          </h3>
          <p className="text-sm text-muted-foreground mt-1">
            Overview of incoming and outgoing funds
          </p>
        </div>
        <div className="flex items-center gap-2">
          <DropdownMenu>
            <DropdownMenuTrigger asChild>
              <Button variant="outline" size="sm" className="h-8 gap-2">
                <Grid3X3 className="h-3.5 w-3.5" />
                <span className="hidden sm:inline">View: {chartType}</span>
              </Button>
            </DropdownMenuTrigger>
            <DropdownMenuContent align="end">
              <DropdownMenuLabel>Chart Type</DropdownMenuLabel>
              <DropdownMenuSeparator />
              <DropdownMenuCheckboxItem
                checked={chartType === "bar"}
                onCheckedChange={() => setChartType("bar")}
              >
                <BarChart3 className="mr-2 h-4 w-4" />
                Bar Chart
              </DropdownMenuCheckboxItem>
              <DropdownMenuCheckboxItem
                checked={chartType === "line"}
                onCheckedChange={() => setChartType("line")}
              >
                <LineChartIcon className="mr-2 h-4 w-4" />
                Line Chart
              </DropdownMenuCheckboxItem>
              <DropdownMenuCheckboxItem
                checked={chartType === "area"}
                onCheckedChange={() => setChartType("area")}
              >
                <AreaChartIcon className="mr-2 h-4 w-4" />
                Area Chart
              </DropdownMenuCheckboxItem>
            </DropdownMenuContent>
          </DropdownMenu>

          <DropdownMenu>
            <DropdownMenuTrigger asChild>
              <Button variant="outline" size="sm" className="h-8 gap-2">
                <Calendar className="h-3.5 w-3.5" />
                <span className="hidden sm:inline">
                  {periodLabels[selectedPeriod]}
                </span>
              </Button>
            </DropdownMenuTrigger>
            <DropdownMenuContent align="end" className="w-48">
              <DropdownMenuLabel>Time Period</DropdownMenuLabel>
              <DropdownMenuSeparator />
              <DropdownMenuSub>
                <DropdownMenuSubTrigger>Relative</DropdownMenuSubTrigger>
                <DropdownMenuSubContent>
                  <DropdownMenuItem onClick={() => setSelectedPeriod("3months")}>
                    Last 3 Months
                    {selectedPeriod === "3months" && (
                      <Check className="ml-auto h-4 w-4" />
                    )}
                  </DropdownMenuItem>
                  <DropdownMenuItem onClick={() => setSelectedPeriod("6months")}>
                    Last 6 Months
                    {selectedPeriod === "6months" && (
                      <Check className="ml-auto h-4 w-4" />
                    )}
                  </DropdownMenuItem>
                  <DropdownMenuItem onClick={() => setSelectedPeriod("year")}>
                    Full Year
                    {selectedPeriod === "year" && (
                      <Check className="ml-auto h-4 w-4" />
                    )}
                  </DropdownMenuItem>
                </DropdownMenuSubContent>
              </DropdownMenuSub>
              <DropdownMenuSub>
                <DropdownMenuSubTrigger>Quarters</DropdownMenuSubTrigger>
                <DropdownMenuSubContent>
                  <DropdownMenuItem onClick={() => setSelectedPeriod("q1")}>
                    Q1 (Jan-Mar)
                    {selectedPeriod === "q1" && (
                      <Check className="ml-auto h-4 w-4" />
                    )}
                  </DropdownMenuItem>
                  <DropdownMenuItem onClick={() => setSelectedPeriod("q2")}>
                    Q2 (Apr-Jun)
                    {selectedPeriod === "q2" && (
                      <Check className="ml-auto h-4 w-4" />
                    )}
                  </DropdownMenuItem>
                  <DropdownMenuItem onClick={() => setSelectedPeriod("q3")}>
                    Q3 (Jul-Sep)
                    {selectedPeriod === "q3" && (
                      <Check className="ml-auto h-4 w-4" />
                    )}
                  </DropdownMenuItem>
                  <DropdownMenuItem onClick={() => setSelectedPeriod("q4")}>
                    Q4 (Oct-Dec)
                    {selectedPeriod === "q4" && (
                      <Check className="ml-auto h-4 w-4" />
                    )}
                  </DropdownMenuItem>
                </DropdownMenuSubContent>
              </DropdownMenuSub>
            </DropdownMenuContent>
          </DropdownMenu>

          <Button 
            variant="outline" 
            size="icon" 
            className="h-8 w-8"
            onClick={() => fetchFinancialFlow(selectedPeriod)}
          >
            <RefreshCw className="h-3.5 w-3.5" />
          </Button>
        </div>
      </div>
      <div className="p-6 pl-2">
        <ResponsiveContainer width="100%" height={350} minWidth={0} minHeight={0}>
          {renderChart()}
        </ResponsiveContainer>
      </div>
    </div>
  );
}

import { Button } from "@/components/ui/button";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import {
  Form,
  FormControl,
  FormDescription,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from "@/components/ui/form";
import { Input } from "@/components/ui/input";
import { Switch } from "@/components/ui/switch";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Textarea } from "@/components/ui/textarea";
import { zodResolver } from "@hookform/resolvers/zod";
import { useForm } from "react-hook-form";
import * as z from "zod";
import { useEffect } from "react";
import { SubscriptionPlan } from "@/lib/api/settings";
import { useToast } from "@/components/ui/use-toast";

const planSchema = z.object({
  name: z.string().min(2, "Name must be at least 2 characters"),
  slug: z.string().min(2, "Slug must be at least 2 characters"),
  description: z.string().optional(),
  plan_type: z.enum(["individual", "corporate", "institutional", "therapist"]).default("individual"),
  price: z.coerce.number().min(0),
  price_ngn: z.coerce.number().min(0).optional(),
  price_usd: z.coerce.number().min(0).optional(),
  currency: z.string().default("NGN"),
  billing_interval: z.enum(["monthly", "quarterly", "yearly", "one_time"]),
  features: z.string(),
  is_active: z.boolean().default(true),
  max_sessions: z.coerce.number().optional(),
  trial_days: z.coerce.number().optional(),
});

type PlanFormValues = z.input<typeof planSchema>;

interface PlanFormProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  plan?: SubscriptionPlan | null;
  onSubmit: (data: unknown) => Promise<void>;
}

export function PlanForm({ open, onOpenChange, plan, onSubmit }: PlanFormProps) {
  const { toast } = useToast();
  const form = useForm<PlanFormValues>({
    resolver: zodResolver(planSchema),
    defaultValues: {
      name: "",
      slug: "",
      description: "",
      plan_type: "individual" as const,
      price: 0,
      price_ngn: 0,
      price_usd: 0,
      currency: "NGN",
      billing_interval: "monthly",
      features: "",
      is_active: true,
      max_sessions: 0,
      trial_days: 0,
    },
  });

  useEffect(() => {
    if (plan) {
      form.reset({
        name: plan.name,
        slug: plan.slug || "",
        description: plan.description || "",
        plan_type: (plan as any).plan_type || "individual",
        price: plan.price,
        price_ngn: (plan as any).price_ngn ?? 0,
        price_usd: (plan as any).price_usd ?? 0,
        currency: plan.currency || "NGN",
        billing_interval: plan.billing_interval,
        features: Array.isArray(plan.features) ? plan.features.join('\n') : (typeof plan.features === 'string' ? plan.features : ""),
        is_active: plan.is_active,
        max_sessions: plan.max_sessions || 0,
        trial_days: plan.trial_days || 0,
      });
    } else {
      form.reset({
        name: "",
        slug: "",
        description: "",
        plan_type: "individual" as const,
        price: 0,
        price_ngn: 0,
        price_usd: 0,
        currency: "NGN",
        billing_interval: "monthly",
        features: "",
        is_active: true,
        max_sessions: 0,
        trial_days: 0,
      });
    }
  }, [plan, form]);

  const handleSubmit = async (data: PlanFormValues) => {
    try {
      // Convert features string back to array
      const formattedData = {
        ...data,
        price: Number(data.price ?? 0),
        price_ngn: data.price_ngn != null ? Number(data.price_ngn) : undefined,
        price_usd: data.price_usd != null ? Number(data.price_usd) : undefined,
        max_sessions: data.max_sessions != null ? Number(data.max_sessions) : undefined,
        trial_days: data.trial_days != null ? Number(data.trial_days) : undefined,
        features: String(data.features || '').split('\n').filter((f) => f.trim() !== ''),
      };
      await onSubmit(formattedData);
      onOpenChange(false);
      form.reset();
      toast({
        title: "Success",
        description: plan ? "Plan updated successfully." : "Plan created successfully.",
      });
    } catch (error) {
      console.error(error);
      toast({
        title: "Error",
        description: "Failed to save plan. Please try again.",
        variant: "destructive",
      });
    }
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-[600px]">
        <DialogHeader>
          <DialogTitle>{plan ? "Edit Plan" : "Create Plan"}</DialogTitle>
          <DialogDescription>
            {plan ? "Update subscription plan details." : "Add a new subscription plan."}
          </DialogDescription>
        </DialogHeader>

        <Form {...form}>
          <form onSubmit={form.handleSubmit(handleSubmit)} className="space-y-4">
            <div className="grid grid-cols-2 gap-4">
              <FormField
                control={form.control}
                name="name"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>Name</FormLabel>
                    <FormControl>
                      <Input placeholder="Pro Plan" {...field} />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />
              <FormField
                control={form.control}
                name="slug"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>Slug</FormLabel>
                    <FormControl>
                      <Input placeholder="pro-plan" {...field} />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />
            </div>

            <FormField
              control={form.control}
              name="description"
              render={({ field }) => (
                <FormItem>
                  <FormLabel>Description</FormLabel>
                  <FormControl>
                    <Input placeholder="Plan description" {...field} />
                  </FormControl>
                  <FormMessage />
                </FormItem>
              )}
            />

            <FormField
              control={form.control}
              name="plan_type"
              render={({ field }) => (
                <FormItem>
                  <FormLabel>Plan Type</FormLabel>
                  <Select onValueChange={field.onChange} value={field.value}>
                    <FormControl>
                      <SelectTrigger>
                        <SelectValue placeholder="Select type" />
                      </SelectTrigger>
                    </FormControl>
                    <SelectContent>
                      <SelectItem value="individual">Individual</SelectItem>
                      <SelectItem value="corporate">Corporate</SelectItem>
                      <SelectItem value="institutional">Institutional</SelectItem>
                      <SelectItem value="therapist">Therapist</SelectItem>
                    </SelectContent>
                  </Select>
                  <FormMessage />
                </FormItem>
              )}
            />

            <div className="grid grid-cols-2 gap-4">
              <FormField
                control={form.control}
                name="price"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>Price</FormLabel>
                    <FormControl>
                      <Input
