"use client";

import { useEffect, useRef, useState } from "react";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import {
  Mic,
  MicOff,
  Video,
  VideoOff,
  Play,
  Square,
  Circle,
  Download,
  AlertCircle,
} from "lucide-react";
import { cn } from "@/lib/utils";

export function LivePreview() {
  const videoRef = useRef<HTMLVideoElement | null>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const recorderRef = useRef<MediaRecorder | null>(null);
  const chunksRef = useRef<Blob[]>([]);

  const [active, setActive] = useState(false);
  const [micEnabled, setMicEnabled] = useState(true);
  const [camEnabled, setCamEnabled] = useState(true);
  const [recording, setRecording] = useState(false);
  const [recordUrl, setRecordUrl] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    return () => {
      streamRef.current?.getTracks().forEach((t) => t.stop());
      if (videoRef.current) videoRef.current.srcObject = null;
    };
  }, []);

  const start = async () => {
    setError(null);
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true, video: true });
      streamRef.current = stream;
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        await videoRef.current.play();
      }
      setActive(true);
      setMicEnabled(true);
      setCamEnabled(true);
    } catch {
      setError("Could not access camera/microphone. Please check permissions.");
    }
  };

  const stop = () => {
    streamRef.current?.getTracks().forEach((t) => t.stop());
    streamRef.current = null;
    if (videoRef.current) videoRef.current.srcObject = null;
    setActive(false);
    setRecording(false);
  };

  const toggleMic = () => {
    const tracks = streamRef.current?.getAudioTracks() ?? [];
    const next = !micEnabled;
    tracks.forEach((t) => (t.enabled = next));
    setMicEnabled(next);
  };

  const toggleCam = () => {
    const tracks = streamRef.current?.getVideoTracks() ?? [];
    const next = !camEnabled;
    tracks.forEach((t) => (t.enabled = next));
    setCamEnabled(next);
  };

  const startRecording = () => {
    if (!streamRef.current) return;
    chunksRef.current = [];
    const rec = new MediaRecorder(streamRef.current);
    recorderRef.current = rec;
    rec.ondataavailable = (e) => {
      if (e.data.size > 0) chunksRef.current.push(e.data);
    };
    rec.onstop = () => {
      const blob = new Blob(chunksRef.current, { type: "video/webm" });
      setRecordUrl(URL.createObjectURL(blob));
      setRecording(false);
    };
    rec.start();
    setRecording(true);
  };

  const stopRecording = () => recorderRef.current?.stop();

  return (
    <div className="space-y-4">
      {error && (
        <div className="flex items-center gap-2 rounded-lg bg-destructive/10 border border-destructive/20 text-destructive px-4 py-3 text-sm">
          <AlertCircle className="size-4 shrink-0" />
          {error}
        </div>
      )}

      {/* Video preview */}
      <div className="relative rounded-xl overflow-hidden bg-zinc-900 aspect-video">
        <video ref={videoRef} className="w-full h-full object-cover" muted playsInline />

        {!active && (
          <div className="absolute inset-0 flex flex-col items-center justify-center gap-3 bg-zinc-900 text-zinc-400">
            <VideoOff className="size-10 opacity-40" />
            <p className="text-sm">Preview not started</p>
          </div>
        )}

        {active && !camEnabled && (
          <div className="absolute inset-0 flex items-center justify-center bg-zinc-900">
            <VideoOff className="size-10 text-zinc-600" />
          </div>
        )}

        {/* Status badges */}
        <div className="absolute top-3 right-3 flex gap-2">
          {active && recording && (
            <Badge className="bg-red-600 text-white gap-1.5 animate-pulse">
              <Circle className="size-2 fill-white" />
              REC
            </Badge>
          )}
          {active && !micEnabled && (
            <Badge variant="destructive" className="gap-1">
              <MicOff className="size-3" />
              Muted
            </Badge>
          )}
        </div>

        {/* Bottom label */}
        {active && (
          <div className="absolute bottom-2 left-2">
            <span className="bg-black/60 text-white text-xs font-medium px-2 py-0.5 rounded-md backdrop-blur-sm">
              Local Preview
            </span>
          </div>
        )}
      </div>

      {/* Controls */}
      <div className="flex flex-wrap items-center gap-2">
        {!active ? (
          <Button onClick={start} className="gap-2 bg-green-600 hover:bg-green-700 text-white">
            <Play className="size-4" />
            Start Preview
          </Button>
        ) : (
          <Button variant="destructive" onClick={stop} className="gap-2">
            <Square className="size-4" />
            Stop
          </Button>
        )}

        <Button
          variant={micEnabled ? "secondary" : "destructive"}
          size="icon"
          onClick={toggleMic}
          disabled={!active}
          title={micEnabled ? "Mute" : "Unmute"}
          className="rounded-full size-9"
        >
          {micEnabled ? <Mic className="size-4" /> : <MicOff className="size-4" />}
        </Button>

        <Button
          variant={camEnabled ? "secondary" : "destructive"}
          size="icon"
          onClick={toggleCam}
          disabled={!active}
          title={camEnabled ? "Camera off" : "Camera on"}
          className="rounded-full size-9"
        >
          {camEnabled ? <Video className="size-4" /> : <VideoOff className="size-4" />}
        </Button>

        <div className="ml-auto">
          {active && !recording ? (
            <Button
              variant="outline"
              size="sm"
              onClick={startRecording}
              className="gap-2 border-red-300 text-red-600 hover:bg-red-50"
            >
              <Circle className="size-3 fill-red-500 text-red-500" />
              Record
            </Button>
          ) : active && recording ? (
            <Button
              variant="outline"
              size="sm"
              onClick={stopRecording}
              className="gap-2 animate-pulse"
            >
              <Square className="size-3" />
              Stop Recording
            </Button>
          ) : null}
        </div>
      </div>

      {/* Recorded video */}
      {recordUrl && (
        <div className="space-y-3 rounded-xl border bg-muted/30 p-4">
          <div className="flex items-center justify-between">
            <p className="text-sm font-medium">Recording Complete</p>
            <a
              href={recordUrl}
              download="session-recording.webm"
              className={cn(
                "inline-flex items-center gap-1.5 text-sm font-medium px-3 py-1.5 rounded-lg",
                "bg-primary text-primary-foreground hover:opacity-90 transition-opacity"
              )}
            >
              <Download className="size-3.5" />
              Download
            </a>
          </div>
          <video src={recordUrl} controls className="w-full rounded-lg bg-black" />
        </div>
      )}
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import {
  CheckCircle, XCircle, MessageSquare, Clock, ChevronRight,
  AlertTriangle, CheckCircle2, Circle,
} from "lucide-react";
import { useApprovalStore, type ApprovalRequest, type ApprovalStatus } from "@/store/approval-store";
import { formatDistanceToNow } from "date-fns";

// ── Visual maps ────────────────────────────────────────────────────────────────

const STATUS_COLOR: Record<ApprovalStatus, string> = {
  pending:      "bg-amber-100 text-amber-700",
  under_review: "bg-blue-100 text-blue-700",
  approved:     "bg-green-100 text-green-700",
  rejected:     "bg-red-100 text-red-700",
  cancelled:    "bg-gray-100 text-gray-500",
  escalated:    "bg-orange-100 text-orange-700",
};

const STATUS_LABEL: Record<ApprovalStatus, string> = {
  pending:      "Pending",
  under_review: "Needs Info",
  approved:     "Approved",
  rejected:     "Rejected",
  cancelled:    "Cancelled",
  escalated:    "Escalated",
};

const TYPE_LABEL: Record<string, string> = {
  leave:       "Leave Request",
  budget:      "Budget Request",
  promotion:   "Promotion",
  transfer:    "Transfer",
  termination: "Termination",
  expense:     "Expense Claim",
  custom:      "Custom",
};

// ── Step progress bar ──────────────────────────────────────────────────────────

function StepProgress({ request }: { request: ApprovalRequest }) {
  return (
    <div className="flex items-center gap-1 mt-2">
      {request.steps.map((step, i) => {
        const done    = step.status === "approved";
        const current = step.step_number === request.current_step && request.status === "pending";
        const rejected = step.status === "rejected";
        return (
          <div key={i} className="flex items-center gap-1">
            <div
              title={step.step_label}
              className={`w-5 h-5 rounded-full flex items-center justify-center text-[10px] font-bold transition-colors ${
                done    ? "bg-green-500 text-white" :
                rejected ? "bg-red-500 text-white" :
                current  ? "bg-amber-400 text-white" :
                           "bg-muted text-muted-foreground"
              }`}
            >
              {done ? "✓" : rejected ? "✗" : step.step_number}
            </div>
            {i < request.steps.length - 1 && (
              <div className={`h-0.5 w-4 ${done ? "bg-green-400" : "bg-muted"}`} />
            )}
          </div>
        );
      })}
      <span className="ml-1 text-[10px] text-muted-foreground">
        Step {request.current_step}/{request.total_steps}
      </span>
    </div>
  );
}

// ── Action modal ───────────────────────────────────────────────────────────────

type ActionType = "approve" | "reject" | "review" | "respond";

interface ActionModalProps {
  request: ApprovalRequest;
  action: ActionType;
  onClose: () => void;
  onDone: () => void;
}

function ActionModal({ request, action, onClose, onDone }: ActionModalProps) {
  const { approve, reject, requestReview, respond } = useApprovalStore();
  const [text, setText]         = useState("");
  const [processing, setProcessing] = useState(false);

  const currentStep = request.steps.find((s) => s.step_number === request.current_step);

  const handleSubmit = async () => {
    if (!text.trim() && action !== "approve") return;
    setProcessing(true);
    try {
      if (action === "approve")  await approve(request.uuid, text || undefined);
      if (action === "reject")   await reject(request.uuid, text);
      if (action === "review")   await requestReview(request.uuid, text);
      if (action === "respond")  await respond(request.uuid, text);
      onDone();
    } finally {
      setProcessing(false);
    }
  };

  const config = {
    approve: {
      title: "Approve Request",
      placeholder: "Optional notes for the next reviewer…",
      required: false,
      color: "bg-green-600 hover:bg-green-700",
      label: "Confirm Approval",
    },
    reject: {
      title: "Reject Request",
      placeholder: "Explain why this is being rejected (required)…",
      required: true,
      color: "bg-red-600 hover:bg-red-700",
      label: "Confirm Rejection",
    },
    review: {
      title: "Request More Information",
      placeholder: "What additional information do you need from the submitter?",
      required: true,
      color: "bg-blue-600 hover:bg-blue-700",
      label: "Send Back for Info",
    },
    respond: {
      title: "Respond to Reviewer",
      placeholder: "Provide the requested information…",
      required: true,
      color: "bg-primary hover:opacity-90",
      label: "Submit Response",
    },
  }[action];

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40 p-4">
      <div className="bg-card rounded-2xl shadow-2xl w-full max-w-lg p-6 space-y-4">
        <h2 className="font-bold text-lg">{config.title}</h2>

        {/* Request summary */}
        <div className="rounded-xl bg-muted p-3 text-sm space-y-1">
          <p className="font-semibold">{request.title}</p>
          <p className="text-muted-foreground text-xs">
            {TYPE_LABEL[request.type]} · by {request.requester?.first_name} {request.requester?.last_name}
          </p>
          {currentStep && action !== "respond" && (
            <p className="text-xs text-muted-foreground">Current step: {currentStep.step_label}</p>
          )}
          {action === "respond" && currentStep?.action_notes && (
            <div className="mt-2 p-2 bg-blue-50 dark:bg-blue-900/20 rounded-lg text-xs">
              <p className="font-semibold text-blue-700 dark:text-blue-300">Reviewer asked:</p>
              <p className="text-blue-600 dark:text-blue-400 mt-0.5">{currentStep.action_notes}</p>
            </div>
          )}
        </div>

        {request.description && (
          <p className="text-xs text-muted-foreground">{request.description}</p>
        )}

        <div>
          <textarea
            value={text}
            onChange={(e) => setText(e.target.value)}
            rows={4}
            placeholder={config.placeholder}
            className="w-full rounded-xl border border-border bg-background px-3 py-2 text-sm resize-none focus:outline-none focus:ring-2 focus:ring-primary"
          />
        </div>

        <div className="flex gap-3 pt-1">
          <button
            onClick={onClose}
            className="flex-1 px-4 py-2 rounded-xl border border-border text-sm font-semibold hover:bg-muted transition-colors"
          >
            Cancel
          </button>
          <button
            disabled={processing || (config.required && !text.trim())}
            onClick={handleSubmit}
            className={`flex-1 px-4 py-2 rounded-xl text-white text-sm font-semibold transition-colors disabled:opacity-50 ${config.color}`}
          >
            {processing ? "Processing…" : config.label}
          </button>
        </div>
      </div>
    </div>
  );
}

// ── Request card ───────────────────────────────────────────────────────────────

interface RequestCardProps {
  request: ApprovalRequest;
  /** Whether the viewing user is an approver for the current step */
  isApproverForCurrentStep: boolean;
  /** Whether the viewing user is the requester AND request is under_review */
  canRespond: boolean;
  onAction: (req: ApprovalRequest, action: ActionType) => void;
}

function RequestCard({ request, isApproverForCurrentStep, canRespond, onAction }: RequestCardProps) {
  return (
    <div className="p-4 bg-card rounded-2xl border border-border space-y-3 hover:shadow-sm transition-shadow">
      {/* Header row */}
      <div className="flex items-start justify-between gap-3">
        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-2 flex-wrap">
            <span className="font-semibold text-sm truncate">{request.title}</span>
            <span className={`text-[10px] px-2 py-0.5 rounded-full font-semibold ${STATUS_COLOR[request.status]}`}>
              {STATUS_LABEL[request.status]}
            </span>
            <span className="text-[10px] px-2 py-0.5 rounded-full bg-muted text-muted-foreground font-medium">
              {TYPE_LABEL[request.type]}
            </span>
          </div>
          <p className="text-xs text-muted-foreground mt-0.5">
            {request.requester
              ? `${request.requester.first_name} ${request.requester.last_name}`
              : "Unknown"
            }
            {" · "}
            {formatDistanceToNow(new Date(request.created_at), { addSuffix: true })}
          </p>
        </div>
      </div>

      {/* Step progress */}
      <StepProgress request={request} />

      {/* Under review — reviewer's question */}
      {request.status === "under_review" && (() => {
        const step = request.steps.find((s) => s.step_number === request.current_step);
        return step?.action_notes ? (
          <div className="rounded-xl bg-blue-50 dark:bg-blue-900/20 p-2 text-xs text-blue-700 dark:text-blue-300">
            <span className="font-semibold">More info needed: </span>{step.action_notes}
          </div>
        ) : null;
      })()}

      {/* Rejection reason */}
      {request.status === "rejected" && (() => {
        const step = request.steps.find((s) => s.status === "rejected");
        return step?.action_notes ? (
          <div className="rounded-xl bg-red-50 dark:bg-red-900/20 p-2 text-xs text-red-700 dark:text-red-300">
            <span className="font-semibold">Rejected: </span>{step.action_notes}
          </div>
        ) : null;
      })()}

      {/* Action buttons */}
      <div className="flex gap-2 flex-wrap pt-1">
        {isApproverForCurrentStep && request.status === "pending" && (
          <>
            <button
              onClick={() => onAction(request, "approve")}
              className="flex items-center gap-1 px-3 py-1.5 rounded-lg bg-green-600 text-white text-xs font-semibold hover:bg-green-700 transition-colors"
            >
              <CheckCircle size={12} /> Approve
            </button>
            <button
              onClick={() => onAction(request, "reject")}
              className="flex items-center gap-1 px-3 py-1.5 rounded-lg bg-red-600 text-white text-xs font-semibold hover:bg-red-700 transition-colors"
            >
              <XCircle size={12} /> Reject
            </button>
            <button
              onClick={() => onAction(request, "review")}
              className="flex items-center gap-1 px-3 py-1.5 rounded-lg border border-border text-xs font-semibold hover:bg-muted transition-colors"
            >
              <MessageSquare size={12} /> Ask for Info
            </button>
          </>
        )}
        {canRespond && (
          <button
            onClick={() => onAction(request, "respond")}
            className="flex items-center gap-1 px-3 py-1.5 rounded-lg bg-blue-600 text-white text-xs font-semibold hover:bg-blue-700 transition-colors"
          >
            <MessageSquare size={12} /> Respond
          </button>
        )}
      </div>
    </div>
  );
}

// ── Main component ─────────────────────────────────────────────────────────────

interface Props {
  /** Filter by approval type */
  filterType?: string;
  /** Show "My Requests" tab or only "Inbox" */
  showTabs?: boolean;
}

export function ApprovalInbox({ filterType, showTabs = true }: Props) {
  const { requests, isLoading, fetchRequests, fetchInbox } = useApprovalStore();
  const [tab, setTab]       = useState<"inbox" | "mine">("inbox");
  const [active, setActive] = useState<{ req: ApprovalRequest; action: ActionType } | null>(null);

  // Grab current user id from cookie/localStorage
  const currentUserId = (() => {
    try {
      const raw = typeof window !== "undefined" ? localStorage.getItem("user") : null;
      return raw ? JSON.parse(raw)?.id : null;
    } catch { return null; }
  })();
  const currentRoles: string[] = (() => {
    try {
      const raw = typeof window !== "undefined" ? localStorage.getItem("user") : null;
      const user = raw ? JSON.parse(raw) : null;
      return user?.roles ?? [user?.role].filter(Boolean);
    } catch { return []; }
  })();

  useEffect(() => {
    fetchRequests(filterType ? { type: filterType as never } : {});
    fetchInbox();
  }, [filterType]); // eslint-disable-line react-hooks/exhaustive-deps

  const onAction = (req: ApprovalRequest, action: ActionType) => setActive({ req, action });
  const closeModal = () => setActive(null);
  const onDone = () => {
    setActive(null);
    fetchRequests(filterType ? { type: filterType as never } : {});
    fetchInbox();
  };

  // Filter: inbox = requests where I'm the current step approver
  const inbox = requests.filter((r) => {
    if (r.status !== "pending") return false;
    const step = r.steps.find((s) => s.step_number === r.current_step);
    return (
      step?.approver_id === currentUserId ||
      (step?.approver_role && currentRoles.includes(step.approver_role))
    );
  });

  // Filter: my requests
  const mine = requests.filter((r) => r.requested_by === currentUserId);

  const displayed = tab === "inbox" ? inbox : mine;

  return (
    <div className="space-y-4">
      {showTabs && (
        <div className="flex gap-1 p-1 bg-muted rounded-xl w-fit">
          <button
            onClick={() => setTab("inbox")}
            className={`px-4 py-1.5 rounded-lg text-sm font-semibold transition-colors ${
              tab === "inbox" ? "bg-card shadow-sm" : "text-muted-foreground hover:text-foreground"
            }`}
          >
            Inbox
            {inbox.length > 0 && (
              <span className="ml-1.5 inline-flex items-center justify-center rounded-full bg-primary text-primary-foreground text-[10px] font-bold min-w-[18px] h-[18px] px-1">
                {inbox.length}
              </span>
            )}
          </button>
          <button
            onClick={() => setTab("mine")}
            className={`px-4 py-1.5 rounded-lg text-sm font-semibold transition-colors ${
              tab === "mine" ? "bg-card shadow-sm" : "text-muted-foreground hover:text-foreground"
            }`}
          >
            My Requests
          </button>
        </div>
      )}

      {isLoading ? (
        <div className="py-12 flex justify-center">
          <div className="w-8 h-8 border-4 border-primary border-t-transparent rounded-full animate-spin" />
        </div>
      ) : displayed.length === 0 ? (
        <div className="py-16 text-center">
          <CheckCircle2 size={36} className="mx-auto mb-3 text-muted-foreground/40" />
          <p className="text-sm text-muted-foreground">
            {tab === "inbox" ? "No pending approvals in your inbox." : "No requests submitted yet."}
          </p>
        </div>
      ) : (
        <div className="space-y-3">
          {displayed.map((req) => {
            const currentStep = req.steps.find((s) => s.step_number === req.current_step);
            const isApprover  = Boolean(
              currentStep?.approver_id === currentUserId ||
              (currentStep?.approver_role && currentRoles.includes(currentStep.approver_role))
            );
            const canRespond = req.status === "under_review" && req.requested_by === currentUserId;

            return (
              <RequestCard
                key={req.uuid}
                request={req}
                isApproverForCurrentStep={isApprover}
                canRespond={canRespond}
                onAction={onAction}
              />
            );
          })}
        </div>
      )}

      {active && (
        <ActionModal
          request={active.req}
          action={active.action}
          onClose={closeModal}
          onDone={onDone}
        />
      )}
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { CheckCircle, XCircle, Clock, ChevronRight, MessageSquare, AlertCircle } from "lucide-react";
import { useBudgetStore, type BudgetRequest, type BudgetStatus } from "@/store/budget-store";

// Which status to show for each approver role
const ROLE_PENDING_STATUS: Record<string, BudgetStatus> = {
  coo:       "pending_coo",
  ceo:       "pending_ceo",
  president: "pending_ceo",
  finance:   "pending_finance",
  cfo:       "pending_finance",
};

const STATUS_LABEL: Record<BudgetStatus, string> = {
  draft:           "Draft",
  pending_coo:     "Awaiting COO",
  pending_ceo:     "Awaiting CEO",
  queried:         "Queried — Awaiting Creator",
  pending_finance: "Awaiting Finance",
  approved:        "Approved",
  rejected:        "Rejected",
};

const STATUS_COLOR: Record<BudgetStatus, string> = {
  draft:           "bg-gray-100 text-gray-600",
  pending_coo:     "bg-amber-100 text-amber-700",
  pending_ceo:     "bg-amber-100 text-amber-700",
  queried:         "bg-purple-100 text-purple-700",
  pending_finance: "bg-blue-100 text-blue-700",
  approved:        "bg-green-100 text-green-700",
  rejected:        "bg-red-100 text-red-700",
};

type ActionType = "approve" | "reject" | "query" | "respond";

interface Props {
  /** The approver role — determines which queue to show and which action to invoke */
  role: "coo" | "ceo" | "president" | "finance" | "cfo" | "admin" | "super_admin";
  /** Show all budgets (admin view) — overrides role filtering */
  showAll?: boolean;
  /** Current user ID — used to gate the "respond" action to the original submitter */
  currentUserId?: number;
}

export function BudgetApprovalQueue({ role, showAll = false, currentUserId }: Props) {
  const {
    budgets, isLoading, fetchBudgets,
    approveCoo, approveCeo, approveFinance, rejectBudget, queryCeo, respondToQuery,
  } = useBudgetStore();

  const [selectedBudget, setSelectedBudget]     = useState<BudgetRequest | null>(null);
  const [notes, setNotes]                       = useState("");
  const [rejectReason, setRejectReason]         = useState("");
  const [queryNotes, setQueryNotes]             = useState("");
  const [suggestedAmount, setSuggestedAmount]   = useState("");
  const [creatorResponse, setCreatorResponse]   = useState("");
  const [action, setAction]                     = useState<ActionType | null>(null);
  const [processing, setProcessing]             = useState(false);

  const pendingStatus = ROLE_PENDING_STATUS[role];
  const isCeo = role === "ceo" || role === "president";

  useEffect(() => {
    if (showAll) {
      fetchBudgets({});
    } else if (isCeo) {
      // CEO sees both pending_ceo and queried (creator has responded) budgets
      fetchBudgets({ status: "pending_ceo" });
    } else if (pendingStatus) {
      fetchBudgets({ status: pendingStatus });
    }
  }, [role]); // eslint-disable-line react-hooks/exhaustive-deps

  const handleApprove = async () => {
    if (!selectedBudget) return;
    setProcessing(true);
    try {
      if (role === "coo") await approveCoo(selectedBudget.id, notes || undefined);
      else if (isCeo)     await approveCeo(selectedBudget.id, notes || undefined);
      else                await approveFinance(selectedBudget.id, notes || undefined);
      closeModal();
    } finally {
      setProcessing(false);
    }
  };

  const handleReject = async () => {
    if (!selectedBudget || !rejectReason.trim()) return;
    setProcessing(true);
    try {
      await rejectBudget(selectedBudget.id, rejectReason);
      closeModal();
    } finally {
      setProcessing(false);
    }
  };

  const handleQuery = async () => {
    if (!selectedBudget || !queryNotes.trim()) return;
    setProcessing(true);
    try {
      const amount = suggestedAmount ? parseFloat(suggestedAmount) : undefined;
      await queryCeo(selectedBudget.id, queryNotes, amount);
      closeModal();
    } finally {
      setProcessing(false);
    }
  };

  const handleRespond = async () => {
    if (!selectedBudget || !creatorResponse.trim()) return;
    setProcessing(true);
    try {
      await respondToQuery(selectedBudget.id, creatorResponse);
      closeModal();
    } finally {
      setProcessing(false);
    }
  };

  const closeModal = () => {
    setSelectedBudget(null);
    setAction(null);
    setNotes("");
    setRejectReason("");
    setQueryNotes("");
    setSuggestedAmount("");
    setCreatorResponse("");
  };

  const isApprover = ["coo", "ceo", "president", "finance", "cfo"].includes(role);

  // Budgets where the creator can respond (queried and user is the submitter)
  const canRespond = (b: BudgetRequest) =>
    b.status === "queried" && currentUserId && b.submitted_by === currentUserId;

  return (
    <div className="space-y-4">
      {/* Budget list */}
      {isLoading ? (
        <div className="py-12 flex justify-center">
          <div className="w-8 h-8 border-4 border-primary border-t-transparent rounded-full animate-spin" />
        </div>
      ) : budgets.length === 0 ? (
        <div className="py-12 text-center text-sm text-muted-foreground">
          No budget requests to review.
        </div>
      ) : (
        <div className="divide-y divide-border rounded-xl border overflow-hidden">
          {budgets.map((budget) => (
            <div key={budget.id} className="flex items-center gap-4 p-4 bg-card hover:bg-muted/30 transition-colors">
              <div className="flex-1 min-w-0">
                <div className="flex items-center gap-2 mb-1">
                  <span className="font-semibold text-sm truncate">{budget.title}</span>
                  <span className={`text-xs px-2 py-0.5 rounded-full font-medium ${STATUS_COLOR[budget.status]}`}>
                    {STATUS_LABEL[budget.status]}
                  </span>
                </div>
                <div className="text-xs text-muted-foreground space-x-3">
                  <span>{budget.department} · {budget.category}</span>
                  <span>{budget.period}</span>
                  <span className="font-medium text-foreground">
                    {budget.currency} {Number(budget.amount_requested).toLocaleString()}
                  </span>
                </div>
                {budget.submittedBy && (
                  <div className="text-xs text-muted-foreground mt-0.5">
                    Submitted by {budget.submittedBy.first_name} {budget.submittedBy.last_name}
                  </div>
                )}
                {/* Show CEO query note when queried */}
                {budget.status === "queried" && budget.ceo_query_notes && (
                  <div className="mt-1.5 text-xs bg-purple-50 border border-purple-200 rounded-lg px-2.5 py-1.5 text-purple-800">
                    <span className="font-semibold">CEO query:</span> {budget.ceo_query_notes}
                    {budget.ceo_suggested_amount && (
                      <span className="ml-2 font-semibold">
                        · Suggested: {budget.currency} {Number(budget.ceo_suggested_amount).toLocaleString()}
                      </span>
                    )}
                  </div>
                )}
              </div>

              <div className="flex gap-2 shrink-0">
                {/* Standard approve / reject for current approver's queue */}
                {isApprover && budget.status === pendingStatus && (
                  <>
                    <button
                      onClick={() => { setSelectedBudget(budget); setAction("approve"); }}
                      className="flex items-center gap-1 px-3 py-1.5 rounded-lg bg-green-600 text-white text-xs font-semibold hover:bg-green-700 transition-colors"
                    >
                      <CheckCircle size={13} /> Approve
                    </button>
                    {/* CEO can query before approving */}
                    {isCeo && (
                      <button
                        onClick={() => { setSelectedBudget(budget); setAction("query"); }}
                        className="flex items-center gap-1 px-3 py-1.5 rounded-lg bg-purple-600 text-white text-xs font-semibold hover:bg-purple-700 transition-colors"
                      >
                        <MessageSquare size={13} /> Query
                      </button>
                    )}
                    <button
                      onClick={() => { setSelectedBudget(budget); setAction("reject"); }}
                      className="flex items-center gap-1 px-3 py-1.5 rounded-lg bg-red-600 text-white text-xs font-semibold hover:bg-red-700 transition-colors"
                    >
                      <XCircle size={13} /> Reject
                    </button>
                  </>
                )}

                {/* CEO reviewing a queried budget that has a creator response */}
                {isCeo && budget.status === "queried" && budget.creator_response && (
                  <>
                    <button
                      onClick={() => { setSelectedBudget(budget); setAction("approve"); }}
                      className="flex items-center gap-1 px-3 py-1.5 rounded-lg bg-green-600 text-white text-xs font-semibold hover:bg-green-700 transition-colors"
                    >
                      <CheckCircle size={13} /> Approve
                    </button>
                    <button
                      onClick={() => { setSelectedBudget(budget); setAction("reject"); }}
                      className="flex items-center gap-1 px-3 py-1.5 rounded-lg bg-red-600 text-white text-xs font-semibold hover:bg-red-700 transition-colors"
                    >
                      <XCircle size={13} /> Reject
                    </button>
                  </>
                )}

                {/* Creator responds to CEO query */}
                {canRespond(budget) && (
                  <button
                    onClick={() => { setSelectedBudget(budget); setAction("respond"); }}
                    className="flex items-center gap-1 px-3 py-1.5 rounded-lg bg-amber-600 text-white text-xs font-semibold hover:bg-amber-700 transition-colors"
                  >
                    <AlertCircle size={13} /> Respond
                  </button>
                )}
              </div>

              <ChevronRight size={16} className="text-muted-foreground shrink-0" />
            </div>
          ))}
        </div>
      )}

      {/* Action modal */}
      {selectedBudget && action && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40 p-4">
          <div className="bg-card rounded-2xl shadow-2xl w-full max-w-md p-6 space-y-4">
            <h2 className="font-bold text-lg">
              {action === "approve" && "Approve Budget"}
              {action === "reject"  && "Reject Budget"}
              {action === "query"   && "Query Budget — Request Clarification"}
              {action === "respond" && "Respond to CEO Query"}
            </h2>

            <div className="text-sm space-y-1 p-3 bg-muted rounded-xl">
              <p className="font-semibold">{selectedBudget.title}</p>
              <p className="text-muted-foreground">
                {selectedBudget.currency} {Number(selectedBudget.amount_requested).toLocaleString()} · {selectedBudget.period}
              </p>
              {selectedBudget.description && (
                <p className="text-muted-foreground text-xs mt-1">{selectedBudget.description}</p>
              )}
            </div>

            {action === "approve" && (
              <div>
                <label className="block text-xs font-semibold mb-1">Notes (optional)</label>
                <textarea
                  value={notes}
                  onChange={(e) => setNotes(e.target.value)}
                  rows={3}
                  className="w-full rounded-xl border border-border bg-background px-3 py-2 text-sm resize-none focus:outline-none focus:ring-2 focus:ring-primary"
                  placeholder="Any comments for the next reviewer…"
                />
              </div>
            )}

            {action === "reject" && (
              <div>
                <label className="block text-xs font-semibold mb-1">Rejection reason <span className="text-red-500">*</span></label>
                <textarea
                  value={rejectReason}
                  onChange={(e) => setRejectReason(e.target.value)}
                  rows={3}
                  className="w-full rounded-xl border border-border bg-background px-3 py-2 text-sm resize-none focus:outline-none focus:ring-2 focus:ring-destructive"
                  placeholder="Explain why this budget is being rejected…"
                />
              </div>
            )}

            {action === "query" && (
              <div className="space-y-3">
                <div>
                  <label className="block text-xs font-semibold mb-1">Query / clarification needed <span className="text-red-500">*</span></label>
                  <textarea
                    value={queryNotes}
                    onChange={(e) => setQueryNotes(e.target.value)}
                    rows={3}
                    className="w-full rounded-xl border border-border bg-background px-3 py-2 text-sm resize-none focus:outline-none focus:ring-2 focus:ring-purple-500"
                    placeholder="What information or justification do you need from the submitter?"
                  />
                </div>
                <div>
                  <label className="block text-xs font-semibold mb-1">
                    Suggested amount ({selectedBudget.currency}) <span className="text-muted-foreground font-normal">optional</span>
                  </label>
                  <input
                    type="number"
                    min={0}
                    value={suggestedAmount}
                    onChange={(e) => setSuggestedAmount(e.target.value)}
                    className="w-full rounded-xl border border-border bg-background px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-purple-500"
                    placeholder={`e.g. ${Number(selectedBudget.amount_requested * 0.8).toLocaleString()}`}
                  />
                  <p className="text-xs text-muted-foreground mt-1">
                    If the amount seems too high, propose a counter-figure here.
                  </p>
                </div>
              </div>
            )}

            {action === "respond" && (
              <div className="space-y-3">
                {selectedBudget.ceo_query_notes && (
                  <div className="p-3 bg-purple-50 border border-purple-200 rounded-xl text-xs text-purple-800 space-y-1">
                    <p className="font-semibold">CEO query:</p>
                    <p>{selectedBudget.ceo_query_notes}</p>
                    {selectedBudget.ceo_suggested_amount && (
                      <p className="font-semibold mt-1">
                        Suggested amount: {selectedBudget.currency} {Number(selectedBudget.ceo_suggested_amount).toLocaleString()}
                      </p>
                    )}
                  </div>
                )}
                <div>
                  <label className="block text-xs font-semibold mb-1">Your response <span className="text-red-500">*</span></label>
                  <textarea
                    value={creatorResponse}
                    onChange={(e) => setCreatorResponse(e.target.value)}
                    rows={4}
                    className="w-full rounded-xl border border-border bg-background px-3 py-2 text-sm resize-none focus:outline-none focus:ring-2 focus:ring-amber-500"
                    placeholder="Explain why this amount is needed or address the CEO's concerns…"
                  />
                </div>
              </div>
            )}

            <div className="flex gap-3 pt-2">
              <button
                onClick={closeModal}
                className="flex-1 px-4 py-2 rounded-xl border border-border text-sm font-semibold hover:bg-muted transition-colors"
              >
                Cancel
              </button>
              <button
                disabled={
                  processing ||
                  (action === "reject"  && !rejectReason.trim()) ||
                  (action === "query"   && !queryNotes.trim()) ||
                  (action === "respond" && !creatorResponse.trim())
                }
                onClick={
                  action === "approve" ? handleApprove :
                  action === "reject"  ? handleReject  :
                  action === "query"   ? handleQuery   :
                                        handleRespond
                }
                className={`flex-1 px-4 py-2 rounded-xl text-white text-sm font-semibold transition-colors disabled:opacity-50 ${
                  action === "approve" ? "bg-green-600 hover:bg-green-700" :
                  action === "reject"  ? "bg-red-600 hover:bg-red-700"    :
                  action === "query"   ? "bg-purple-600 hover:bg-purple-700" :
                                        "bg-amber-600 hover:bg-amber-700"
                }`}
              >
                {processing ? "Processing…" :
                  action === "approve" ? "Confirm Approval"   :
                  action === "reject"  ? "Confirm Rejection"  :
                  action === "query"   ? "Send Query"         :
                                        "Submit Response"
                }
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

"use client";

/**
 * FinancialStatements
 * Three Pillars of Finance — Balance Sheet / Income Statement / Cash Flow
 * Shared component used by Finance, Admin, CEO, and COO dashboards.
 */

import { useEffect, useState } from "react";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Skeleton } from "@/components/ui/skeleton";
import { Badge } from "@/components/ui/badge";
import {
  Select, SelectContent, SelectItem, SelectTrigger, SelectValue,
} from "@/components/ui/select";
import {
  Landmark, FileText, TrendingUp, TrendingDown, RefreshCw,
  ArrowUpRight, ArrowDownRight, Minus, Download,
} from "lucide-react";
import client from "@/lib/api/client";
import { cn } from "@/lib/utils";

// ── Types ──────────────────────────────────────────────────────────────────

interface BalanceSheet {
  as_of: string;
  currency: string;
  assets: {
    current: { cash_and_equivalents: number; accounts_receivable: number; prepaid_assets: number; total_current: number };
    non_current: { platform_infrastructure: number; total_non_current: number };
    total: number;
  };
  liabilities: {
    current: { accounts_payable: number; deferred_revenue: number; total_current: number };
    non_current: { long_term_debt: number; total_non_current: number };
    total: number;
  };
  equity: { paid_in_capital: number; retained_earnings: number; total: number };
}

interface IncomeStatement {
  period: string;
  start_date: string;
  end_date: string;
  currency: string;
  revenue: { gross_revenue: number; refunds: number; net_revenue: number };
  cost_of_revenue: number;
  gross_profit: number;
  gross_margin: number;
  operating_expenses: number;
  ebitda: number;
  depreciation_amortisation: number;
  ebit: number;
  interest: number;
  ebt: number;
  tax: number;
  net_income: number;
  monthly: { month: string; revenue: number; expenses: number; net_income: number }[];
}

interface CashFlow {
  period: string;
  currency: string;
  operating: { net_income: number; change_in_receivables: number; change_in_payables: number; total_cfo: number };
  investing: { capital_expenditure: number; investments: number; total_cfi: number };
  financing: { equity_raised: number; debt_repaid: number; total_cff: number };
  summary: { net_change: number; opening_cash: number; closing_cash: number };
}

// ── Helpers ────────────────────────────────────────────────────────────────

function fmt(n: number) {
  const abs = Math.abs(n);
  let s: string;
  if (abs >= 1_000_000) s = `₦${(abs / 1_000_000).toFixed(2)}M`;
  else if (abs >= 1_000) s = `₦${(abs / 1_000).toFixed(1)}K`;
  else s = `₦${abs.toFixed(2)}`;
  return n < 0 ? `-${s}` : s;
}

function TrendIcon({ value }: { value: number }) {
  if (value > 0) return <ArrowUpRight className="h-4 w-4 text-green-500" />;
  if (value < 0) return <ArrowDownRight className="h-4 w-4 text-red-500" />;
  return <Minus className="h-4 w-4 text-muted-foreground" />;
}

function Row({ label, value, indent = 0, bold = false, highlight }: {
  label: string; value: number; indent?: number; bold?: boolean;
  highlight?: "positive" | "negative" | "neutral";
}) {
  const color = highlight === "positive" ? "text-green-700" : highlight === "negative" ? "text-red-600" : "";
  return (
    <div className={cn("flex items-center justify-between py-1.5 border-b border-border/40 last:border-b-0", bold && "font-semibold")}>
      <span className={cn("text-sm", color)} style={{ paddingLeft: `${indent * 16}px` }}>{label}</span>
      <span className={cn("text-sm tabular-nums", color, bold && "font-bold")}>{fmt(value)}</span>
    </div>
  );
}

function SectionHeader({ label }: { label: string }) {
  return <p className="text-xs font-semibold uppercase tracking-widest text-muted-foreground mt-4 mb-1">{label}</p>;
}

// ── Balance Sheet ──────────────────────────────────────────────────────────

function BalanceSheetPanel() {
  const [data, setData] = useState<BalanceSheet | null>(null);
  const [loading, setLoading] = useState(true);

  const load = async () => {
    setLoading(true);
    try {
      const res = await client.get("/api/v1/finance/balance-sheet");
      setData(res.data?.data ?? null);
    } catch { setData(null); }
    finally { setLoading(false); }
  };

  useEffect(() => { load(); }, []); // eslint-disable-line react-hooks/exhaustive-deps

  if (loading) return <div className="space-y-3 p-4">{[1,2,3].map(i => <Skeleton key={i} className="h-32 rounded-xl" />)}</div>;
  if (!data) return <p className="p-6 text-sm text-muted-foreground">No balance sheet data available.</p>;

  const balanced = Math.abs(data.assets.total - (data.liabilities.total + data.equity.total)) < 1;

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between">
        <p className="text-xs text-muted-foreground">As of {data.as_of}</p>
        <div className="flex items-center gap-2">
          {balanced
            ? <Badge className="bg-green-100 text-green-700 border-0">Balanced ✓</Badge>
            : <Badge variant="destructive">Unbalanced</Badge>}
          <Button variant="ghost" size="icon" onClick={load}><RefreshCw className="h-4 w-4" /></Button>
        </div>
      </div>

      <div className="grid gap-4 md:grid-cols-3">
        {/* Assets */}
        <Card>
          <CardHeader className="pb-2"><CardTitle className="text-sm flex items-center gap-2"><TrendingUp className="h-4 w-4 text-green-600" />Assets</CardTitle></CardHeader>
          <CardContent>
            <SectionHeader label="Current Assets" />
            <Row label="Cash & Equivalents"  value={data.assets.current.cash_and_equivalents}  indent={1} />
            <Row label="Accounts Receivable" value={data.assets.current.accounts_receivable}   indent={1} />
            <Row label="Prepaid Assets"      value={data.assets.current.prepaid_assets}        indent={1} />
            <Row label="Total Current"       value={data.assets.current.total_current}         bold />
            <SectionHeader label="Non-Current Assets" />
            <Row label="Platform Infrastructure" value={data.assets.non_current.platform_infrastructure} indent={1} />
            <Row label="Total Non-Current"   value={data.assets.non_current.total_non_current} bold />
            <div className="mt-3 pt-2 border-t">
              <Row label="TOTAL ASSETS" value={data.assets.total} bold highlight="positive" />
            </div>
          </CardContent>
        </Card>

        {/* Liabilities */}
        <Card>
          <CardHeader className="pb-2"><CardTitle className="text-sm flex items-center gap-2"><TrendingDown className="h-4 w-4 text-red-500" />Liabilities</CardTitle></CardHeader>
          <CardContent>
            <SectionHeader label="Current Liabilities" />
            <Row label="Accounts Payable"  value={data.liabilities.current.accounts_payable} indent={1} />
            <Row label="Deferred Revenue"  value={data.liabilities.current.deferred_revenue}  indent={1} />
            <Row label="Total Current"     value={data.liabilities.current.total_current}     bold />
            <SectionHeader label="Non-Current Liabilities" />
            <Row label="Long-Term Debt"    value={data.liabilities.non_current.long_term_debt} indent={1} />
            <Row label="Total Non-Current" value={data.liabilities.non_current.total_non_current} bold />
            <div className="mt-3 pt-2 border-t">
              <Row label="TOTAL LIABILITIES" value={data.liabilities.total} bold highlight="negative" />
            </div>
          </CardContent>
        </Card>

        {/* Equity */}
        <Card>
          <CardHeader className="pb-2"><CardTitle className="text-sm flex items-center gap-2"><Landmark className="h-4 w-4 text-blue-600" />Shareholders' Equity</CardTitle></CardHeader>
          <CardContent>
            <SectionHeader label="Equity Components" />
            <Row label="Paid-In Capital"    value={data.equity.paid_in_capital}   indent={1} />
            <Row label="Retained Earnings"  value={data.equity.retained_earnings}  indent={1} />
            <div className="mt-3 pt-2 border-t">
              <Row label="TOTAL EQUITY" value={data.equity.total} bold highlight="positive" />
            </div>
            <div className="mt-4 p-3 rounded-lg bg-muted/50 text-xs text-muted-foreground space-y-1">
              <p className="font-semibold text-foreground">Accounting Identity</p>
              <p>Assets = Liabilities + Equity</p>
              <p className="font-mono">{fmt(data.assets.total)} = {fmt(data.liabilities.total)} + {fmt(data.equity.total)}</p>
            </div>
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

// ── Income Statement ───────────────────────────────────────────────────────

function IncomeStatementPanel() {
  const [data, setData] = useState<IncomeStatement | null>(null);
  const [loading, setLoading] = useState(true);
  const [period, setPeriod] = useState("month");

  const load = async (p = period) => {
    setLoading(true);
    try {
      const res = await client.get("/api/v1/finance/income-statement", { params: { period: p } });
      setData(res.data?.data ?? null);
    } catch { setData(null); }
    finally { setLoading(false); }
  };

  useEffect(() => { load(); }, []); // eslint-disable-line react-hooks/exhaustive-deps

  const handlePeriod = (p: string) => { setPeriod(p); load(p); };

  if (loading) return <div className="space-y-3 p-4">{[1,2].map(i => <Skeleton key={i} className="h-40 rounded-xl" />)}</div>;
  if (!data) return <p className="p-6 text-sm text-muted-foreground">No income statement data available.</p>;

  const profitable = data.net_income >= 0;

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between">
