} from "@/components/ui/dropdown-menu";
import { Button } from "@/components/ui/button";
import { ChevronDown, SwitchCamera } from "lucide-react";

const ROLE_LABELS: Record<string, string> = {
  super_admin:          'Super Admin',
  admin:                'Administrator',
  founder:              'Founder',
  ceo:                  'CEO',
  coo:                  'COO',
