'use client';

import { createContext, useEffect, useState } from 'react';
import { useDashboardIPProtection } from '@/hooks/useIPProtection';

interface DashboardIPConfig {
  ip_protection_dashboard_enabled: boolean;
  ip_protect_dash_devtools: boolean;
  ip_protect_dash_rightclick: boolean;
  ip_protect_dash_textselection: boolean;
  ip_protect_dash_keyboard: boolean;
  ip_protect_dash_clipboard: boolean;
  ip_protect_dash_log_attempts: boolean;
}

export function DashboardIPProtectionProvider({ children }: { children: React.ReactNode }) {
  const [config, setConfig] = useState<DashboardIPConfig | null>(null);

  useEffect(() => {
    const cached = sessionStorage.getItem('onwynd_dash_ip_config');
    const cacheTs = sessionStorage.getItem('onwynd_dash_ip_config_ts');
    const isStale = !cacheTs || Date.now() - parseInt(cacheTs) > 5 * 60 * 1000;

    if (cached && !isStale) {
      setConfig(JSON.parse(cached));
      return;
    }

    const token = localStorage.getItem('onwynd_token');
    const apiUrl = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:8000/api';

    fetch(`${apiUrl}/v1/config/ip-protection`, {
      headers: token ? { Authorization: `Bearer ${token}` } : {},
    })
      .then(r => r.json())
      .then(res => {
        const data = res.data;
        setConfig(data);
        sessionStorage.setItem('onwynd_dash_ip_config', JSON.stringify(data));
        sessionStorage.setItem('onwynd_dash_ip_config_ts', Date.now().toString());
      })
      .catch(() => setConfig(null));
  }, []);

  useDashboardIPProtection(config);

  return <>{children}</>;
}

import { create } from "zustand";
import client from "@/lib/api/client";

export type ApprovalStatus =
  | "pending" | "under_review" | "approved" | "rejected" | "cancelled" | "escalated";

export type ApprovalType =
  | "leave" | "budget" | "promotion" | "transfer" | "termination" | "expense" | "custom";

export interface ApprovalStep {
  id: number;
  step_number: number;
  step_label: string;
  approver_role: string | null;
  approver_id: number | null;
  approver?: { id: number; first_name: string; last_name: string } | null;
  status: "pending" | "approved" | "rejected" | "under_review" | "skipped" | "escalated";
  action_notes?: string | null;
  submitter_response?: string | null;
  actioned_at?: string | null;
  actioned_by?: number | null;
  due_at?: string | null;
}

export interface ApprovalRequest {
  id: number;
  uuid: string;
  type: ApprovalType;
  title: string;
  description?: string;
  status: ApprovalStatus;
  current_step: number;
  total_steps: number;
  metadata?: Record<string, unknown>;
  requested_by: number;
  requester?: { id: number; first_name: string; last_name: string; email: string };
  steps: ApprovalStep[];
  resolved_at?: string | null;
  created_at: string;
}

interface ApprovalState {
  requests: ApprovalRequest[];
  inbox: ApprovalStep[];
  isLoading: boolean;
  inboxLoading: boolean;
  error: string | null;
  total: number;

  fetchRequests: (params?: { type?: ApprovalType; status?: ApprovalStatus }) => Promise<void>;
  fetchInbox: () => Promise<void>;
  initiate: (payload: {
    type: ApprovalType;
    title: string;
    description?: string;
    metadata?: Record<string, unknown>;
    subject_type?: string;
    subject_id?: number;
    custom_steps?: { label: string; approver_id: number }[];
  }) => Promise<ApprovalRequest>;
  approve: (uuid: string, notes?: string) => Promise<ApprovalRequest>;
  reject: (uuid: string, reason: string) => Promise<ApprovalRequest>;
  requestReview: (uuid: string, questions: string) => Promise<ApprovalRequest>;
  respond: (uuid: string, response: string) => Promise<ApprovalRequest>;
  cancel: (uuid: string) => Promise<void>;
}

export const useApprovalStore = create<ApprovalState>((set, get) => ({
  requests: [],
  inbox: [],
  isLoading: false,
  inboxLoading: false,
  error: null,
  total: 0,

  fetchRequests: async (params = {}) => {
    set({ isLoading: true, error: null });
    try {
      const res = await client.get("/api/v1/approvals", { params });
      const d = res.data;
      set({ requests: d.data ?? d, total: d.total ?? (d.data ?? d).length });
    } catch (e: unknown) {
      set({ error: e instanceof Error ? e.message : "Failed to load approval requests" });
    } finally {
      set({ isLoading: false });
    }
  },

  fetchInbox: async () => {
    set({ inboxLoading: true });
    try {
      const res = await client.get("/api/v1/approvals/inbox");
      set({ inbox: res.data ?? [] });
    } finally {
      set({ inboxLoading: false });
    }
  },

  initiate: async (payload) => {
    const res = await client.post("/api/v1/approvals", payload);
    const req: ApprovalRequest = res.data;
    set((s) => ({ requests: [req, ...s.requests] }));
    return req;
  },

  approve: async (uuid, notes) => {
    const res = await client.post(`/api/v1/approvals/${uuid}/approve`, { notes });
    const updated: ApprovalRequest = res.data;
    set((s) => ({ requests: s.requests.map((r) => (r.uuid === uuid ? updated : r)) }));
    return updated;
  },

  reject: async (uuid, reason) => {
    const res = await client.post(`/api/v1/approvals/${uuid}/reject`, { reason });
    const updated: ApprovalRequest = res.data;
    set((s) => ({ requests: s.requests.map((r) => (r.uuid === uuid ? updated : r)) }));
    return updated;
  },

  requestReview: async (uuid, questions) => {
    const res = await client.post(`/api/v1/approvals/${uuid}/review`, { questions });
    const updated: ApprovalRequest = res.data;
    set((s) => ({ requests: s.requests.map((r) => (r.uuid === uuid ? updated : r)) }));
    return updated;
  },

  respond: async (uuid, response) => {
    const res = await client.post(`/api/v1/approvals/${uuid}/respond`, { response });
    const updated: ApprovalRequest = res.data;
    set((s) => ({ requests: s.requests.map((r) => (r.uuid === uuid ? updated : r)) }));
    return updated;
  },

  cancel: async (uuid) => {
    await client.post(`/api/v1/approvals/${uuid}/cancel`);
    set((s) => ({
      requests: s.requests.map((r) =>
        r.uuid === uuid ? { ...r, status: "cancelled" } : r
      ),
    }));
  },
}));

import { create } from "zustand";
import client from "@/lib/api/client";

export type BudgetStatus =
  | "draft"
  | "pending_coo"
  | "pending_ceo"
  | "queried"
  | "pending_finance"
  | "approved"
  | "rejected";

export interface BudgetRequest {
  id: number;
  department: string;
  category: string;
  title: string;
  description?: string;
  amount_requested: number;
  currency: string;
  period: string;
  status: BudgetStatus;
  submitted_by: number;
  submitted_at?: string;
  coo_notes?: string;
  ceo_notes?: string;
  finance_notes?: string;
  rejection_reason?: string;
  rejected_at?: string;
  ceo_query_notes?: string;
  ceo_suggested_amount?: number | null;
  creator_response?: string | null;
  creator_responded_at?: string | null;
  submittedBy?: { id: number; first_name: string; last_name: string };
  approvedByCoo?: { id: number; first_name: string; last_name: string } | null;
  approvedByCeo?: { id: number; first_name: string; last_name: string } | null;
  approvedByFinance?: { id: number; first_name: string; last_name: string } | null;
  rejectedBy?: { id: number; first_name: string; last_name: string } | null;
  created_at: string;
  updated_at: string;
}

interface BudgetState {
  budgets: BudgetRequest[];
  isLoading: boolean;
  error: string | null;
  total: number;
  page: number;

  fetchBudgets: (params?: { status?: BudgetStatus; page?: number }) => Promise<void>;
  createBudget: (payload: Omit<BudgetRequest, "id" | "status" | "submitted_by" | "created_at" | "updated_at">) => Promise<BudgetRequest>;
  updateBudget: (id: number, payload: Partial<BudgetRequest>) => Promise<BudgetRequest>;
  deleteBudget: (id: number) => Promise<void>;
  submitBudget: (id: number) => Promise<void>;
  approveCoo: (id: number, notes?: string) => Promise<void>;
  approveCeo: (id: number, notes?: string) => Promise<void>;
  approveFinance: (id: number, notes?: string) => Promise<void>;
  rejectBudget: (id: number, reason: string) => Promise<void>;
  queryCeo: (id: number, queryNotes: string, suggestedAmount?: number) => Promise<void>;
  respondToQuery: (id: number, response: string) => Promise<void>;
}

export const useBudgetStore = create<BudgetState>((set, get) => ({
  budgets: [],
  isLoading: false,
  error: null,
  total: 0,
  page: 1,

  fetchBudgets: async (params = {}) => {
    set({ isLoading: true, error: null });
    try {
      const res = await client.get("/api/v1/budgets", { params });
      const d = res.data;
      set({
        budgets: d.data ?? d,
        total: d.total ?? (d.data ?? d).length,
        page: d.current_page ?? 1,
      });
    } catch (e: unknown) {
      const msg = e instanceof Error ? e.message : "Failed to load budgets";
      set({ error: msg });
    } finally {
      set({ isLoading: false });
    }
  },

  createBudget: async (payload) => {
    const res = await client.post("/api/v1/budgets", payload);
    const budget: BudgetRequest = res.data;
    set((s) => ({ budgets: [budget, ...s.budgets] }));
    return budget;
  },

  updateBudget: async (id, payload) => {
    const res = await client.put(`/api/v1/budgets/${id}`, payload);
    const updated: BudgetRequest = res.data;
    set((s) => ({ budgets: s.budgets.map((b) => (b.id === id ? updated : b)) }));
    return updated;
  },

  deleteBudget: async (id) => {
    await client.delete(`/api/v1/budgets/${id}`);
    set((s) => ({ budgets: s.budgets.filter((b) => b.id !== id) }));
  },

  submitBudget: async (id) => {
    const res = await client.post(`/api/v1/budgets/${id}/submit`);
    const updated: BudgetRequest = res.data.budget;
    set((s) => ({ budgets: s.budgets.map((b) => (b.id === id ? updated : b)) }));
  },

  approveCoo: async (id, notes) => {
    const res = await client.post(`/api/v1/budgets/${id}/approve/coo`, { notes });
    const updated: BudgetRequest = res.data.budget;
    set((s) => ({ budgets: s.budgets.map((b) => (b.id === id ? updated : b)) }));
  },

  approveCeo: async (id, notes) => {
    const res = await client.post(`/api/v1/budgets/${id}/approve/ceo`, { notes });
    const updated: BudgetRequest = res.data.budget;
    set((s) => ({ budgets: s.budgets.map((b) => (b.id === id ? updated : b)) }));
  },

  approveFinance: async (id, notes) => {
    const res = await client.post(`/api/v1/budgets/${id}/approve/finance`, { notes });
    const updated: BudgetRequest = res.data.budget;
    set((s) => ({ budgets: s.budgets.map((b) => (b.id === id ? updated : b)) }));
  },

  rejectBudget: async (id, reason) => {
    const res = await client.post(`/api/v1/budgets/${id}/reject`, { reason });
    const updated: BudgetRequest = res.data.budget;
    set((s) => ({ budgets: s.budgets.map((b) => (b.id === id ? updated : b)) }));
  },

  queryCeo: async (id, queryNotes, suggestedAmount) => {
    const res = await client.post(`/api/v1/budgets/${id}/query/ceo`, {
      query_notes: queryNotes,
      ...(suggestedAmount !== undefined && { suggested_amount: suggestedAmount }),
    });
    const updated: BudgetRequest = res.data.budget;
    set((s) => ({ budgets: s.budgets.map((b) => (b.id === id ? updated : b)) }));
  },

  respondToQuery: async (id, response) => {
    const res = await client.post(`/api/v1/budgets/${id}/respond`, { response });
    const updated: BudgetRequest = res.data.budget;
    set((s) => ({ budgets: s.budgets.map((b) => (b.id === id ? updated : b)) }));
  },
}));

import { create } from "zustand";
import { financeService } from "@/lib/api/finance";
import { adminService } from "@/lib/api/admin";
import { marketingService } from "@/lib/api/marketing";
import { salesService } from "@/lib/api/sales";

type KPI = {
  id: string;
  title: string;
  value: string;
  change?: string;
  changeType?: "increase" | "decrease" | "neutral";
};

type SeriesPoint = {
  name: string;
  value: number;
  value2?: number;
};

type Period = "7days" | "30days" | "3months" | "6months" | "12months";

interface CEOState {
  isLoading: boolean;
  period: Period;
  error?: string;
  kpis: KPI[];
  revenueSeries: SeriesPoint[];
  userGrowthSeries: SeriesPoint[];
  leadSources: { name: string; value: number }[];
  alerts: { id: string; message: string; level: string }[];
  setPeriod: (p: Period) => void;
  fetchAll: () => Promise<void>;
}

export const useCEOStore = create<CEOState>((set, get) => ({
  isLoading: false,
  period: "6months",
  error: undefined,
  kpis: [],
  revenueSeries: [],
  userGrowthSeries: [],
  leadSources: [],
  alerts: [],
  setPeriod: (p) => {
    set({ period: p });
    get().fetchAll();
  },
  fetchAll: async () => {
    set({ isLoading: true });
    try {
      const selected = get().period;
      const revenuePeriod = (() => {
        switch (selected) {
          case "7days":
          case "30days":
            return "daily";
          case "3months":
          case "6months":
            return "monthly";
          case "12months":
            return "monthly";
          default:
            return "monthly";
        }
      })();
      const [finStatsRes, finRevenueRes, adminStatsRes, userGrowthRes, leadSrcRes, salesStatsRes] = await Promise.all([
        financeService.getStats(),
        financeService.getRevenueData(revenuePeriod),
        adminService.getStats(),
        adminService.getUserGrowthReport({ period: selected }),
        marketingService.getLeadSources(selected === "7days" ? "7days" : selected === "3months" ? "90days" : selected),
        salesService.getStats(),
      ]);

      const kpis: KPI[] = [];
      const finStats = finStatsRes?.data || finStatsRes;
      if (finStats) {
        if (finStats.mrr) kpis.push({ id: "mrr", title: "MRR", value: String(finStats.mrr) });
        if (finStats.arr) kpis.push({ id: "arr", title: "ARR", value: String(finStats.arr) });
        if (finStats.burn_rate) kpis.push({ id: "burn", title: "Burn Rate", value: String(finStats.burn_rate) });
        if (finStats.runway_months) kpis.push({ id: "runway", title: "Runway", value: String(finStats.runway_months) + " mo" });
      }
      const aStats = (adminStatsRes as any)?.data || adminStatsRes;
      if (aStats) {
        if (aStats.total_users) kpis.push({ id: "users", title: "Active Users", value: String(aStats.total_users) });
        if (aStats.new_signups) kpis.push({ id: "new", title: "New Signups", value: String(aStats.new_signups) });
        if (aStats.churn_rate) kpis.push({ id: "churn", title: "Churn Rate", value: String(aStats.churn_rate) + "%" });
      }
      const sStats = (salesStatsRes as any)?.data || salesStatsRes;
      if (sStats) {
        if (sStats.cac) kpis.push({ id: "cac", title: "CAC", value: String(sStats.cac) });
        if (sStats.ltv) kpis.push({ id: "ltv", title: "LTV", value: String(sStats.ltv) });
        if (sStats.ltv_cac_ratio) kpis.push({ id: "ltv_cac", title: "LTV:CAC", value: String(sStats.ltv_cac_ratio) });
      }

      type RevenueRow = { name?: string; month?: string; period?: string; revenue?: number; value?: number; expenses?: number };
      const revenueSeries: SeriesPoint[] = Array.isArray(finRevenueRes?.data)
        ? (finRevenueRes.data as RevenueRow[]).map((d) => ({
            name: String(d.name ?? d.month ?? d.period ?? ""),
            value: Number(d.revenue ?? d.value ?? 0),
            value2: Number(d.expenses ?? 0),
          }))
        : [];

      type GrowthRow = { name?: string; month?: string; period?: string; users?: number; value?: number; count?: number };
      const userGrowthSeries: SeriesPoint[] = Array.isArray((userGrowthRes as any)?.data)
        ? ((userGrowthRes as any).data as GrowthRow[]).map((d) => ({
            name: String(d.name ?? d.month ?? d.period ?? ""),
            value: Number(d.users ?? d.value ?? d.count ?? 0),
          }))
        : [];

      type LeadRow = { name?: string; source?: string; value?: number; count?: number };
      const leadSources = Array.isArray(leadSrcRes?.data)
        ? (leadSrcRes.data as LeadRow[]).map((d) => ({
            name: String(d.name ?? d.source ?? ""),
            value: Number(d.value ?? d.count ?? 0),
          }))
        : [];

      type AlertRow = { id?: string | number; uuid?: string; message?: string; level?: string };
      const alerts =
        Array.isArray(aStats?.alerts) ? (aStats.alerts as AlertRow[]).map((x) => ({ id: String(x.id ?? x.uuid ?? x.message), message: String(x.message ?? ""), level: String(x.level ?? "info") })) : [];

      const computedAlerts: { id: string; message: string; level: string }[] = [];
      const lastRev = revenueSeries.at(-1);
      const prevRev = revenueSeries.length > 1 ? revenueSeries[revenueSeries.length - 2] : undefined;
      if (lastRev && typeof lastRev.value2 === "number" && lastRev.value2 > lastRev.value) {
        computedAlerts.push({ id: "neg-margin", message: "Expenses exceeded revenue in the latest period", level: "destructive" });
      }
      if (lastRev && prevRev && prevRev.value > 0) {
        const drop = (prevRev.value - lastRev.value) / prevRev.value;
        if (drop > 0.15) {
          computedAlerts.push({ id: "rev-drop", message: "Revenue dropped over 15% vs previous period", level: "warning" });
        }
      }
      const lastUsers = userGrowthSeries.at(-1)?.value ?? 0;
      const prevUsers = userGrowthSeries.length > 1 ? userGrowthSeries[userGrowthSeries.length - 2].value : undefined;
      if (prevUsers && prevUsers > 0) {
        const userDrop = (prevUsers - lastUsers) / prevUsers;
        if (userDrop > 0.1) {
          computedAlerts.push({ id: "user-drop", message: "User growth declined over 10% from previous period", level: "warning" });
        }
      }
      const churn = aStats?.churn_rate;
      if (typeof churn === "number" && churn > 5) {
        computedAlerts.push({ id: "high-churn", message: "Churn rate is above 5%", level: "warning" });
      }
      const ltvRatio = sStats?.ltv_cac_ratio;
      if (typeof ltvRatio === "number" && ltvRatio < 2) {
        computedAlerts.push({ id: "ltv-cac", message: "LTV:CAC ratio below 2", level: "warning" });
      }

      set({ kpis, revenueSeries, userGrowthSeries, leadSources, alerts: [...computedAlerts, ...alerts], error: undefined });
    } catch {
      set({ kpis: [], revenueSeries: [], userGrowthSeries: [], leadSources: [], alerts: [], error: "Failed to load CEO dashboard data" });
    } finally {
      set({ isLoading: false });
    }
  },
}));

import { create } from "zustand";
import { supportService } from "@/lib/api/support";
import { techService } from "@/lib/api/tech";
import { marketingService } from "@/lib/api/marketing";
import { salesService } from "@/lib/api/sales";
import { institutionalService } from "@/lib/api/institutional";

type KPI = {
  id: string;
  title: string;
  value: string;
};

type SeriesPoint = {
  name: string;
  value: number;
};

type Period = "7days" | "30days" | "3months" | "6months" | "12months";

interface COOState {
  isLoading: boolean;
  period: Period;
  error?: string;
  kpis: KPI[];
  funnelSeries: SeriesPoint[];
  channelCac: { name: string; value: number }[];
  customerHealth: { name: string; value: number }[];
  teamProductivity: { name: string; value: number }[];
  setPeriod: (p: Period) => void;
  fetchAll: () => Promise<void>;
}

export const useCOOStore = create<COOState>((set, get) => ({
  isLoading: false,
  period: "30days",
  error: undefined,
  kpis: [],
  funnelSeries: [],
  channelCac: [],
  customerHealth: [],
  teamProductivity: [],
  setPeriod: (p) => {
    set({ period: p });
    get().fetchAll();
  },
  fetchAll: async () => {
    set({ isLoading: true });
    try {
      const selected = get().period;
      const leadPeriod = selected === "3months" ? "90days" : selected;
      const [supportStatsRes, techStatsRes, marketingLeadSourcesRes, salesStatsRes, instMetrics] = await Promise.all([
        supportService.getStats(),
        techService.getStats(),
        marketingService.getLeadSources(leadPeriod),
        salesService.getStats(),
        institutionalService.getMetrics(),
      ]);

      const kpis: KPI[] = [];
      const supportStats = supportStatsRes?.data || supportStatsRes;
      if (supportStats) {
        if (supportStats.avg_response_time) kpis.push({ id: "resp", title: "Avg Response Time", value: String(supportStats.avg_response_time) });
        if (supportStats.open_tickets) kpis.push({ id: "tickets", title: "Open Tickets", value: String(supportStats.open_tickets) });
      }
      const tStats = techStatsRes?.data || techStatsRes;
      if (tStats) {
        if (tStats.uptime) kpis.push({ id: "uptime", title: "Uptime", value: String(tStats.uptime) + "%" });
        if (tStats.incidents_7d) kpis.push({ id: "incidents", title: "Incidents (7d)", value: String(tStats.incidents_7d) });
      }
      const sStats = (salesStatsRes as any)?.data || salesStatsRes;
      if (sStats) {
        if (sStats.conversion_rate) kpis.push({ id: "conv", title: "Conversion Rate", value: String(sStats.conversion_rate) + "%" });
        if (sStats.avg_deal_size) kpis.push({ id: "deal", title: "Avg Deal Size", value: String(sStats.avg_deal_size) });
      }
      const metrics = instMetrics || {};
      if (metrics.engagement_rate != null) kpis.push({ id: "eng", title: "Engagement Rate", value: String(metrics.engagement_rate) + "%" });
      if (metrics.at_risk_users != null) kpis.push({ id: "risk", title: "At-Risk Accounts", value: String(metrics.at_risk_users) });

      const funnelSeries: SeriesPoint[] = [
        { name: "Leads", value: Number(sStats?.leads ?? sStats?.leads_count ?? 0) },
        { name: "MQL", value: Number(sStats?.mql ?? 0) },
        { name: "SQL", value: Number(sStats?.sql ?? 0) },
        { name: "Opportunities", value: Number(sStats?.opportunities ?? 0) },
        { name: "Won", value: Number(sStats?.won ?? 0) },
      ];

      type LeadRow = { name?: string; source?: string; cac?: number; cost_per_acquisition?: number };
      const channelCac = Array.isArray(marketingLeadSourcesRes?.data)
        ? (marketingLeadSourcesRes.data as LeadRow[]).map((d) => ({
            name: String(d.name ?? d.source ?? ""),
            value: Number(d.cac ?? d.cost_per_acquisition ?? 0),
          }))
        : [];

      const customerHealth = [
        { name: "Active", value: Number(metrics?.active_users_this_month ?? 0) },
        { name: "At-Risk", value: Number(metrics?.at_risk_users ?? 0) },
      ];

      const teamProductivity = [
        { name: "Tickets Resolved", value: Number(supportStats?.tickets_resolved_7d ?? 0) },
        { name: "Deployments", value: Number(tStats?.deployments_7d ?? 0) },
      ];

      set({ kpis, funnelSeries, channelCac, customerHealth, teamProductivity, error: undefined });
    } catch {
      set({ kpis: [], funnelSeries: [], channelCac: [], customerHealth: [], teamProductivity: [], error: "Failed to load COO dashboard data" });
    } finally {
      set({ isLoading: false });
    }
  },
}));

