/**
 * Support Live Chat Store
 *
 * Manages two views:
 *  - Customer: a single active session (`activeChat` + `messages`)
 *  - Agent:    a list of all open chats (`agentChats`) + selected session
 */
import { create } from 'zustand';
import { supportChatService, type ChatMessage, type SupportChat, type ChatStatus } from '@/lib/api/support-chat';
import { getEcho, disconnectEcho } from '@/lib/echo';

// ─── State shape ──────────────────────────────────────────────────────────────

interface SupportChatState {
  // Customer side
  activeChatUuid: string | null;
  activeChat: SupportChat | null;
  messages: ChatMessage[];
  status: ChatStatus | null;
  isLoading: boolean;
  isSending: boolean;
  error: string | null;

  // Agent side
  agentChats: SupportChat[];
  selectedChatUuid: string | null;
  selectedMessages: ChatMessage[];

  // Actions — customer
  startChat: () => Promise<void>;
  sendMessage: (text: string) => Promise<void>;
  closeChat: () => Promise<void>;
  loadChat: (uuid: string) => Promise<void>;

  // Actions — agent
  loadActiveChats: () => Promise<void>;
  selectChat: (uuid: string) => Promise<void>;
  agentReply: (text: string) => Promise<void>;
  handover: (uuid: string) => Promise<void>;
  release: (uuid: string) => Promise<void>;

  // WebSocket
  subscribeToChat: (uuid: string) => void;
  subscribeToAgentChannel: () => void;
  unsubscribeAll: () => void;
}

// ─── Store ────────────────────────────────────────────────────────────────────

export const useSupportChatStore = create<SupportChatState>((set, get) => ({
  // ── Initial state ──────────────────────────────────────────────────────────
  activeChatUuid: null,
  activeChat: null,
  messages: [],
  status: null,
  isLoading: false,
  isSending: false,
  error: null,

  agentChats: [],
  selectedChatUuid: null,
  selectedMessages: [],

  // ── Customer actions ───────────────────────────────────────────────────────

  startChat: async () => {
    set({ isLoading: true, error: null });
    try {
      const data = await supportChatService.start();
      set({
        activeChatUuid: data.chat_uuid,
        status: data.status,
        messages: data.messages,
        isLoading: false,
      });
      get().subscribeToChat(data.chat_uuid);
    } catch (e) {
      set({ isLoading: false, error: 'Could not start chat. Please try again.' });
    }
  },

  sendMessage: async (text: string) => {
    const { activeChatUuid } = get();
    if (!activeChatUuid || !text.trim()) return;

    const optimistic: ChatMessage = {
      id: Date.now(),
      sender_type: 'user',
      sender_id: null,
      message: text.trim(),
      metadata: null,
      is_read: false,
      created_at: new Date().toISOString(),
    };
    set((s) => ({ messages: [...s.messages, optimistic], isSending: true }));

    try {
      const data = await supportChatService.sendMessage(activeChatUuid, text);
      // Replace optimistic + add ai_reply from response
      set((s) => {
        const confirmed = s.messages.filter((m) => m.id !== optimistic.id);
        confirmed.push(data.user_message);
        if (data.ai_reply) confirmed.push(data.ai_reply);
        return { messages: confirmed, status: data.status, isSending: false };
      });
    } catch {
      set((s) => ({
        messages: s.messages.filter((m) => m.id !== optimistic.id),
        isSending: false,
        error: 'Message failed. Please try again.',
      }));
    }
  },

  closeChat: async () => {
    const { activeChatUuid } = get();
    if (!activeChatUuid) return;
    await supportChatService.close(activeChatUuid);
    get().unsubscribeAll();
    set({ activeChatUuid: null, activeChat: null, messages: [], status: 'closed' });
  },

  loadChat: async (uuid: string) => {
    set({ isLoading: true, error: null });
    try {
      const data = await supportChatService.getChat(uuid);
      set({
        activeChatUuid: uuid,
        activeChat: data.chat,
        messages: data.messages,
        status: data.chat.status,
        isLoading: false,
      });
      get().subscribeToChat(uuid);
    } catch {
      set({ isLoading: false, error: 'Could not load chat.' });
    }
  },

  // ── Agent actions ──────────────────────────────────────────────────────────

  loadActiveChats: async () => {
    try {
      const data = await supportChatService.activeChats();
      const chats = Array.isArray(data) ? data : (data as { data: SupportChat[] }).data ?? [];
      set({ agentChats: chats });
    } catch {
      // silent — polling can retry
    }
  },

  selectChat: async (uuid: string) => {
    set({ selectedChatUuid: uuid, selectedMessages: [], isLoading: true });
    try {
      const data = await supportChatService.getChat(uuid);
      set({ selectedMessages: data.messages, isLoading: false });
      get().subscribeToChat(uuid);
    } catch {
      set({ isLoading: false });
    }
  },

  agentReply: async (text: string) => {
    const { selectedChatUuid } = get();
    if (!selectedChatUuid || !text.trim()) return;
    set({ isSending: true });
    try {
      const msg = await supportChatService.agentReply(selectedChatUuid, text);
      set((s) => ({ selectedMessages: [...s.selectedMessages, msg], isSending: false }));
    } catch {
      set({ isSending: false });
    }
  },

  handover: async (uuid: string) => {
    await supportChatService.handover(uuid);
    // Refresh agent chat list so the status badge updates
    get().loadActiveChats();
  },

  release: async (uuid: string) => {
    await supportChatService.release(uuid);
    get().loadActiveChats();
  },

  // ── WebSocket ──────────────────────────────────────────────────────────────

  subscribeToChat: (uuid: string) => {
    const echo = getEcho();
    if (!echo) return;

    echo
      .private(`support.chat.${uuid}`)
      .listen('.support.message', (e: unknown) => {
        const { message } = e as { message: ChatMessage };
        // Append incoming message (deduplicate by id)
        set((s) => {
          const isCustomerView = s.activeChatUuid === uuid;
          const isAgentView = s.selectedChatUuid === uuid;

          if (isCustomerView) {
            const exists = s.messages.some((m) => m.id === message.id);
            if (exists) return {};
            return { messages: [...s.messages, message] };
          }
          if (isAgentView) {
            const exists = s.selectedMessages.some((m) => m.id === message.id);
            if (exists) return {};
            return { selectedMessages: [...s.selectedMessages, message] };
          }
          return {};
        });
      })
      .listen('.support.handover', (e: unknown) => {
        const { status } = e as { status: ChatStatus };
        set((s) => {
          if (s.activeChatUuid === uuid) return { status };
          return {};
        });
        // Refresh agent list on any handover event
        get().loadActiveChats();
      });
  },

  subscribeToAgentChannel: () => {
    const echo = getEcho();
    if (!echo) return;

    echo.private('support.agents').listen('.support.handover', () => {
      // A chat changed status — refresh the full list
      get().loadActiveChats();
    });
  },

  unsubscribeAll: () => {
    disconnectEcho();
  },
}));

import { create } from "zustand";
import { therapistService } from "@/lib/api/therapist";

export interface TherapistStat {
  title: string;
  value: string;
  subtitle: string;
  iconName?: string;
}

export interface Patient {
  id: number;
  uuid: string;
  first_name: string;   // mapped from display_name by the backend resource
  display_name: string;
  last_name: string | null;
  email: string | null; // null when patient has not consented to identity sharing
  email_protected: boolean;
  role_id?: number;
  is_active?: boolean;
  department?: string;
  created_at: string;
  profile_photo: string | null;
  avatar_url?: string | null;
  status?: string;
  identity_shared?: boolean;
}

const initialStats: TherapistStat[] = [
  {
    title: "Total Patients",
    value: "0",
    subtitle: "Loading...",
    iconName: "users"
  },
  {
    title: "Upcoming Sessions",
    value: "0",
    subtitle: "Loading...",
    iconName: "file-text"
  },
  {
    title: "Attendance Rate",
    value: "0%",
    subtitle: "Loading...",
    iconName: "calendar"
  },
];

export interface FinancialFlowData {
  month: string;
  moneyIn: number;
  moneyOut: number;
  moneyInChange: number;
  moneyOutChange: number;
}

export type LayoutDensity = "default" | "compact" | "comfortable";

interface TherapistState {
  stats: TherapistStat[];
  patients: Patient[];
  financialFlow: FinancialFlowData[];
  notes: Array<{
    id: number | string;
    clientId?: string | number;
    clientName?: string;
    sessionId?: string | number;
    category?: string;
    content?: string;
    tags?: string[];
    createdAt?: string;
    updatedAt?: string;
  }>;
  searchQuery: string;
  departmentFilter: string;
  statusFilter: string;
  layoutDensity: LayoutDensity;
  showAlertBanner: boolean;
  showStatsCards: boolean;
  showChart: boolean;
  showTable: boolean;
  consentRequired: boolean;
  consentMessage?: string;
  isLoadingPatients: boolean;

  setSearchQuery: (query: string) => void;
  setDepartmentFilter: (filter: string) => void;
  setStatusFilter: (filter: string) => void;
  clearFilters: () => void;

  setLayoutDensity: (density: LayoutDensity) => void;
  setShowAlertBanner: (show: boolean) => void;
  setShowStatsCards: (show: boolean) => void;
  setShowChart: (show: boolean) => void;
  setShowTable: (show: boolean) => void;
  resetLayout: () => void;
  setConsentRequired: (required: boolean, message?: string) => void;
  clearConsentRequired: () => void;

  // API Actions
  fetchStats: () => Promise<void>;
  fetchPatients: (params?: Record<string, unknown>) => Promise<void>;
  fetchFinancialFlow: (period: string) => Promise<void>;
  fetchNotes: (params?: Record<string, unknown>) => Promise<void>;
  createNote: (data: Record<string, unknown>) => Promise<void>;
  updateNote: (id: number | string, data: Record<string, unknown>) => Promise<void>;
  deleteNote: (id: number | string) => Promise<void>;
}

export const useTherapistStore = create<TherapistState>((set) => ({
  stats: initialStats,
  patients: [],
  financialFlow: [],
  notes: [],
  searchQuery: "",
  departmentFilter: "all",
  statusFilter: "all",
  layoutDensity: "default",
  showAlertBanner: true,
  showStatsCards: true,
  showChart: true,
  showTable: true,
  consentRequired: false,
  consentMessage: undefined,
  isLoadingPatients: false,

  setSearchQuery: (query) => set({ searchQuery: query }),
  setDepartmentFilter: (filter) => set({ departmentFilter: filter }),
  setStatusFilter: (filter) => set({ statusFilter: filter }),
  clearFilters: () =>
    set({
      searchQuery: "",
      departmentFilter: "all",
      statusFilter: "all",
    }),

  setLayoutDensity: (density) => set({ layoutDensity: density }),
  setShowAlertBanner: (show) => set({ showAlertBanner: show }),
  setShowStatsCards: (show) => set({ showStatsCards: show }),
  setShowChart: (show) => set({ showChart: show }),
  setShowTable: (show) => set({ showTable: show }),
  resetLayout: () =>
    set({
      showAlertBanner: true,
      showStatsCards: true,
      showChart: true,
      showTable: true,
      layoutDensity: "default",
    }),
  setConsentRequired: (required, message) =>
    set({
      consentRequired: required,
      consentMessage: message,
    }),
  clearConsentRequired: () =>
    set({
      consentRequired: false,
      consentMessage: undefined,
    }),

  fetchStats: async () => {
    try {
      const data = await therapistService.getStats();
      set({ stats: data as TherapistStat[] || undefined });
    } catch (error) {
      console.error("Failed to fetch therapist stats:", error);
    }
  },

  fetchPatients: async (params) => {
    set({ isLoadingPatients: true });
    try {
      const data = await therapistService.getPatients(params);
      // Backend returns a paginated object { data: Patient[], ... } or a plain array
      const items: Patient[] = Array.isArray(data)
        ? (data as Patient[])
        : ((data as { data?: Patient[] })?.data ?? []);
      set({ patients: items, isLoadingPatients: false });
    } catch (error) {
      console.error("Failed to fetch therapist patients:", error);
      set({ isLoadingPatients: false });
    }
  },

  fetchFinancialFlow: async (period) => {
    try {
      const data = await therapistService.getFinancialFlow(period);
      set({ financialFlow: data as FinancialFlowData[] || [] });
    } catch (error) {
      console.error("Failed to fetch therapist financial flow:", error);
      set({ financialFlow: [] });
    }
  },

  fetchNotes: async (params) => {
    try {
      const data = await therapistService.getNotes(params);
      const notesData = data as TherapistState['notes'] | { data?: TherapistState['notes'] };
      const rows = Array.isArray(notesData) ? notesData : Array.isArray((notesData as { data?: TherapistState['notes'] })?.data) ? (notesData as { data: TherapistState['notes'] }).data : [];
      set({ notes: rows });
    } catch (error) {
      console.error("Failed to fetch therapist notes:", error);
      set({ notes: [] });
    }
  },

  createNote: async (payload) => {
    try {
      const created = await therapistService.createNote(payload);
      const note = (created as any)?.data ?? created;
      set((state) => ({ notes: note ? [...state.notes, note as TherapistState['notes'][0]] : state.notes }));
    } catch (error) {
      console.error("Failed to create therapist note:", error);
    }
  },

  updateNote: async (id, payload) => {
    try {
      const updated = await therapistService.updateNote(id, payload);
      const noteData = updated as { data?: TherapistState['notes'][0] } | TherapistState['notes'][0];
      const note = (noteData as any)?.data ?? noteData;
      set((state) => ({
        notes: state.notes.map((n) => (String(n.id) === String(id) ? { ...n, ...(note as Partial<TherapistState['notes'][0]>) } : n)),
      }));
    } catch (error) {
      console.error("Failed to update therapist note:", error);
    }
  },

  deleteNote: async (id) => {
    try {
      await therapistService.deleteNote(id);
      set((state) => ({ notes: state.notes.filter((n) => String(n.id) !== String(id)) }));
    } catch (error) {
      console.error("Failed to delete therapist note:", error);
    }
  },
}));
